INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (16, 16, 'NADIE PUEDE INGRESAR EN ÉL NI EFECTUAR INVESTIGACIONES O REGISTROS SIN AUTORIZACIÓN DE LA PERSONA QUE LO HABITA O SIN MANDATO JUDICIAL, SALVO FLAGRANTE DELITO O MUY GRAVE PELIGRO DE SU PERPETRACIÓN. EL ENUNCIADO CORRESPONDE:', '["AL SECRETO Y LA INVIOLABILIDAD DE SUS COMUNICACIONES Y DOCUMENTOS PRIVADOS","A LA INVIOLABILIDAD DEL DOMICILIO","A LA INVIOLABILIDAD DE MORADA","A LA INVIOLABILIDAD DE PROPIEDAD","A LA IGUALDAD ANTE LA LEY"]'::jsonb, 'A LA INVIOLABILIDAD DEL DOMICILIO', 1, '(ART: 2)** [TITULO I] [CAPITULO I]', '180880', '2026-07-14T01:12:29.113429+00:00');
