INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (47, 47, 'TODA PERSONA TIENE DERECHO A QUE LOS SERVICIOS INFORMÁTICOS, COMPUTARIZADOS O NO, PÚBLICOS O PRIVADOS:', '["NO SUMINISTREN INFORMACIONES QUE AFECTEN LA INTIMIDAD PERSONAL Y FAMILIAR","SUMINISTREN INFORMACIONES QUE AFECTEN LA INTIMIDAD PERSONAL Y FAMILIAR","NO SUMINISTREN INFORMES DE INTELIGENCIA QUE AFECTEN LA INTIMIDAD DE LAS INSTITUCIONES","INTERCAMBIEN DATOS QUE ATENTEN CONTRA LA UNIDAD FAMILIAR","SUMINISTREN INFORMACIONES QUE AFECTEN AL CIUDADANO"]'::jsonb, 'NO SUMINISTREN INFORMACIONES QUE AFECTEN LA INTIMIDAD PERSONAL Y FAMILIAR', 0, '(ART: 2)** [TITULO I] [CAPITULO I]', '180916', '2026-07-14T01:12:29.113429+00:00');
