INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (50, 50, 'LAS FUERZAS ARMADAS ESTÁN CONSTITUIDAS POR EL EJÉRCITO, LA MARINA DE GUERRA Y LA FUERZA AÉREA. TIENEN COMO FINALIDAD PRIMORDIAL:', '["GARANTIZAR LA INDEPENDENCIA, LA SOBERANÍA Y LA INTEGRIDAD TERRITORIAL DE LA REPÚBLICA","ORGANIZAR Y DISPONER SUS RESERVAS PARA LA DEFENSA REGIONAL","GARANTIZAR, MANTENER Y RESTABLECER EL ORDEN INTERNO","GARANTIZAR EL ESTADO DE DERECHO DE LA REPÚBLICA","SUBORDINACIÓN AL PODER CONSTITUCIONAL, SIENDO DELIBERANTES"]'::jsonb, 'GARANTIZAR LA INDEPENDENCIA, LA SOBERANÍA Y LA INTEGRIDAD TERRITORIAL DE LA REPÚBLICA', 0, '(ART: 165)** [TITULO IV] [CAPITULO XII]', '180925', '2026-07-14T01:12:29.113429+00:00');
