INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (242, 242, 'EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ PASARÁ A LA SITUACIÓN DE RETIRO POR LÍMITE DE EDAD EN EL GRADO, EN ATENCIÓN A LA EDAD MÁXIMA ESTABLECIDA EN EL PRESENTE ARTÍCULO. ¿A QUÉ EDAD PASARÁ A LA SITUACIÓN DE RETIRO POR ESTA CAUSAL UN CAPITÁN DE ARMAS?', '["(45) AÑOS","(50) AÑOS","(47) AÑOS","(49) AÑOS","(48) AÑOS"]'::jsonb, '(49) AÑOS', 3, '(ART: 84)** [TITULO III] [CAPITULO VI]', '181313', '2026-07-14T01:12:29.113429+00:00');
