INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (246, 246, 'EL CAMBIO DE SITUACIÓN POLICIAL SE FORMALIZA MEDIANTE:', '["RESOLUCIÓN DE LA COMANDANCIA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ, PARA OFICIALES SUBALTERNOS DE ARMAS Y DE SERVICIOS","RESOLUCIÓN DE LA DIRECCIÓN DE RECURSOS HUMANOS DE LA POLICÍA NACIONAL DEL PERÚ, PARA OFICIALES SUBALTERNOS DE ARMAS Y DE SERVICIOS","RESOLUCIÓN DE LA DIRECCIÓN SUPERIOR DE LA POLICÍA NACIONAL DEL PERÚ, PARA OFICIALES SUBALTERNOS DE ARMAS Y DE SERVICIOS","RESOLUCIÓN DE LA DIRECCIÓN NACIONAL DE GESTIÓN INSTITUCIONAL DE LA POLICÍA NACIONAL DEL PERÚ, PARA","RESOLUCIÓN EN LA ORDEN GENERAL DE LA POLICÍA NACIONAL DEL PERÚ, PARA OFICIALES SUBALTERNOS DE ARMAS Y DE SERVICIOS"]'::jsonb, 'RESOLUCIÓN DE LA COMANDANCIA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ, PARA OFICIALES SUBALTERNOS DE ARMAS Y DE SERVICIOS', 0, '(ART: 64)** [TITULO III] [CAPITULO II]', '181317', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (247, 247, 'ES LA DEFINICIÓN DE OFICIAL DE SERVICIOS', '["PROFESIONAL EGRESADO DE LA ESCUELA DE OFICIALES DE LA POLICÍA NACIONAL DEL PERÚ, QUE HA SEGUIDO ESTUDIOS UNIVERSITARIOS","PROFESIONAL EGRESADO DE UNA UNIVERSIDAD, CON TÍTULO REGISTRADO EN LA SUPERINTENDENCIA NACIONAL DE EDUCACIÓN SUPERIOR UNIVERSITARIA (SUNEDU) E INSCRITO EN EL COLEGIO PROFESIONAL RESPECTIVO, CUANDO CORRESPONDA, QUE SE INCORPORA A LA POLICÍA NACIONAL DEL PERÚ MEDIANTE CONCURSO PÚBLICO","PROFESIONAL EGRESADO DE LAS ESCUELAS TÉCNICO SUPERIORES DE SUBOFICIALES DE LA POLICÍA NACIONAL DEL PERÚ Y QUE LUEGO DE SEGUIR EL PROCESO DE ASIMILACIÓN SE INCORPORA A LA ESCUELA DE OFICIALES","PROFESIONAL EGRESADO DE LOS INSTITUTOS SUPERIORES O CENTROS ACADÉMICOS CON VALOR OFICIAL, DEBIDAMENTE REGISTRADO ANTE LA ENTIDAD CORRESPONDIENTE, QUE SE INCORPORA A LA POLICÍA NACIONAL DEL PERÚ MEDIANTE CONCURSO PÚBLICO","PARA EFECTO DE LA PRESENTE NORMA, LA PALABRA PERSONAL SE REFIERE A OFICIALES Y SUBOFICIALES DE ARMAS Y SERVICIOS DE LA POLICÍA NACIONAL DEL PERÚ"]'::jsonb, 'PROFESIONAL EGRESADO DE UNA UNIVERSIDAD, CON TÍTULO REGISTRADO EN LA SUPERINTENDENCIA NACIONAL DE EDUCACIÓN SUPERIOR UNIVERSITARIA (SUNEDU) E INSCRITO EN EL COLEGIO PROFESIONAL RESPECTIVO, CUANDO CORRESPONDA, QUE SE INCORPORA A LA POLICÍA NACIONAL DEL PERÚ MEDIANTE CONCURSO PÚBLICO', 1, '(ART: 3)** [TITULO PRELIMINAR]', '181318', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (248, 248, 'PARA SER DESIGNADOS COMO AGREGADO POLICIAL, LOS OFICIALES GENERALES Y CORONELES DE ARMAS DEBEN SER EGRESADOS:', '["DEL CURSO DE MAESTRÍA Y ESTADO MAYOR EFECTUADO EN EL INSTITUTO DE ALTOS ESTUDIOS POLICIALES O EQUIVALENTE DEL PAÍS O EL EXTRANJERO","DEL CURSO DE ESTADO MAYOR DESARROLLADO EN LA ESCUELA DE POSTGRADO DE LA POLICÍA NACIONAL DEL PERÚ O EQUIVALENTE DEL PAÍS O EL EXTRANJERO","DEL PROGRAMA DE ALTO MANDO EN ORDEN INTERNO Y DESARROLLO NACIONAL DEL INSTITUTO DE ALTOS ESTUDIOS POLICIALES O EQUIVALENTE DEL PAÍS O EL EXTRANJERO","DEL PROGRAMA DE SENSIBILIZACIÓN EN DELITOS DE CORRUPCIÓN DE FUNCIONARIOS DE LA DIRECCIÓN CONTRA LA CORRUPCIÓN DE LA POLICÍA NACIONAL DEL PERÚ","DEL PROGRAMA DE COMANDO GENERAL Y DESARROLLO INTERNACIONAL DEL INSTITUTO DE ALTOS ESTUDIOS POLICIALES O EQUIVALENTE DEL PAÍS O EL EXTRANJERO"]'::jsonb, 'DEL PROGRAMA DE ALTO MANDO EN ORDEN INTERNO Y DESARROLLO NACIONAL DEL INSTITUTO DE ALTOS ESTUDIOS POLICIALES O EQUIVALENTE DEL PAÍS O EL EXTRANJERO', 2, '(ART: 35)** [TITULO II] [CAPITULO IV]', '181319', '2026-07-14T01:12:29.113429+00:00');
