INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (256, 256, 'UNA DE LAS CALIFICACIONES DE LAS CIRCUNSTANCIAS DEL SERVICIO EN LA QUE PARTICIPA EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ ES EL ACTO DEL SERVICIO, QUE SE DEFINE COMO:', '["ACCIÓN QUE DESARROLLA EL PERSONAL EN CUMPLIMIENTO DE SUS FUNCIONES, DEBERES U ORDEN SUPERIOR, EN TODO MOMENTO O CIRCUNSTANCIA","ACCIÓN QUE DESARROLLA EL PERSONAL EN CUMPLIMIENTO DE SUS ATRIBUCIONES, DERECHOS U ORDEN SUPERIOR, EN TODO MOMENTO O CIRCUNSTANCIA","ACTO QUE DESARROLLA EL PERSONAL EN CUMPLIMIENTO DE SUS LABORES, DEBERES U ORDEN INFERIOR, EN TODO MOMENTO O CIRCUNSTANCIA","ACCIÓN QUE DESARROLLA EL PERSONAL EN CUMPLIMIENTO DE SUS FUNCIONES, MISIONES Y ATRIBUCIONES, EN ALGÚN MOMENTO O CIRCUNSTANCIA","ACCIÓN QUE DESARROLLA EL PERSONAL EN CUMPLIMIENTO DE SUS FUNCIONES, DERECHOS U ORDEN SUPERIOR, EN TODO LUGAR O CIRCUNSTANCIALMENTE"]'::jsonb, 'ACCIÓN QUE DESARROLLA EL PERSONAL EN CUMPLIMIENTO DE SUS FUNCIONES, DEBERES U ORDEN SUPERIOR, EN TODO MOMENTO O CIRCUNSTANCIA', 0, '(ART: 63)** [TITULO III] [CAPITULO I]', '181327', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (257, 257, 'NO ESTAR SOMETIDO A PROCEDIMIENTO ADMINISTRATIVO DISCIPLINARIO COMO PRESUNTO INFRACTOR. ESTA CONSIDERADO COMO UNO DE LOS REQUISITOS PARA:', '["SER ASIGNADO EN COMISIÓN DEL SERVICIO O MISIÓN DE ESTUDIOS EN EL EXTRANJERO","SER ASIGNADO COMO INSTRUCTOR EN LA ESCUELA TÉCNICA SUPERIOR POLICÍA NACIONAL DEL PERÚ O EN EL EXTRANJERO","SER ASIGNADO COMO INSTRUCTOR EN LA ESCUELA DE POSTGRADO DE LA POLICÍA NACIONAL DEL PERÚ","SER ASIGNADO COMO INSTRUCTOR EN LA ESCUELA DE OFICIALES DE LA POLICÍA NACIONAL DEL PERÚ O EN EL EXTRANJERO","SER ASIGNADO COMO CATEDRÁTICO EN LA ESCUELA DE EDUCACIÓN CONTINUA DE LA POLICÍA NACIONAL DEL PERÚ O EN EL EXTRANJERO"]'::jsonb, 'SER ASIGNADO EN COMISIÓN DEL SERVICIO O MISIÓN DE ESTUDIOS EN EL EXTRANJERO', 0, '(ART: 34)** [TITULO II] [CAPITULO IV]', '181328', '2026-07-14T01:12:29.113429+00:00');
