INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (349, 349, 'EN LOS TIPOS DE PRUEBAS DE CONTROL Y CONFIANZA, LA EJECUCIÓN DE LA PRUEBA DE CONTROL Y CONFIANZA ES . ................ DE LAS PRUEBAS DE DESCARTE TOXICOLÓGICO O DE ALCOHOLEMIA QUE LA OFICINA DE CONTROL, CUMPLIMIENTO Y CONFIANZA DE LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL O LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ PUEDEN REALIZAR:', '["INDIFERENTE","EXCLUYENTE","INDEPENDIENTE","RELATIVA","SIMILAR"]'::jsonb, 'INDEPENDIENTE', 2, '(ART: 14) (item: 49)** [TITULO II] [CAPITULO II]', '181624', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (340, 340, 'EL DIRECTOR GENERAL DE LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL DETERMINARÁ LA POLÍTICA PARA LA APLICACION DE LA PRUEBA DE CONTROL Y CONFIANZA A LOS:', '["FUNCIONARIOS Y/O SERVIDORES CIVILES DE LAS OFICINAS A SU CARGO Y A LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","SERVIDORES CIVILES DE LAS OFICINAS A SU CARGO Y LA INSPECTORÍA REGIONAL DE LA POLICÍA NACIONAL DEL PERÚ","FUNCIONARIOS DE LAS OFICINAS A SU CARGO Y LA COMANDANCIA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","FUNCIONARIOS Y SERVIDORES CIVILES DE LAS OFICINAS A SU CARGO Y LAS INSPECTORÍAS DESCENTRALIZADAS DE LA POLICÍA NACIONAL DEL PERÚ","FUNCIONARIOS Y SERVIDORES CIVILES DE LAS OFICINAS NO A SU CARGO Y LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ"]'::jsonb, 'FUNCIONARIOS Y/O SERVIDORES CIVILES DE LAS OFICINAS A SU CARGO Y A LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ', 0, '(ART: 8) (item: 50)** [TITULO III]', '181615', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (353, 353, 'EFECTUARÁ LA PRUEBA DE INTEGRIDAD AL PERSONAL QUE FORMA PARTE DEL SISTEMA DISCIPLINARIO POLICIAL:', '["LA OFICINA ANTICORRUPCIÓN DE LA POLICÍA NACIONAL DEL PERÚ","LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","LA INSPECTORÍA DEL MINISTERIO INTERIOR","LA SECRETARIA GENERAL DE INTEGRIDAD INSTITUCIONAL","LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL"]'::jsonb, 'LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL', 4, '(ART: 14) (item: 50)** [TITULO IV]', '181628', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (341, 341, '¿SEÑALE CUAL ES LA FUNCIÓN DE LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ, RESPECTO A LAS DECLARACIONES JURADAS DE INGRESOS, BIENES Y RENTAS DEL PERSONAL POLICIAL?', '["GARANTIZAR EL CUMPLIMIENTO DE LA PRESENTACIÓN DE LAS DECLARACIONES JURADAS DE EGRESOS Y RENTAS DEL PERSONAL POLICIAL A NIVEL NACIONAL DE MANERA OPORTUNA","DISPONER QUE LOS ÓRGANOS COMPETENTES ADOPTEN LAS ACCIONES QUE CORRESPONDAN EN CASO DE NO ACREDITARSE LA DECLARACIÓN JURADA DE INGRESOS Y BIENES DEL PERSONAL POLICIAL A NIVEL NACIONAL DE MANERA OPORTUNA","INFORMAR SEMESTRALMENTE A LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL SOBRE EL INCUMPLIMIENTO DE LA PRESENTACIÓN DE LA DECLARACIÓN JURADA DE INGRESOS Y BIENES DEL PERSONAL POLICIAL A NIVEL NACIONAL DE MANERA OPORTUNA","GARANTIZAR EL CUMPLIMIENTO DE LA PRESENTACIÓN DE LAS DECLARACIONES JURADAS DE INGRESOS, BIENES Y RENTAS DEL PERSONAL POLICIAL A NIVEL NACIONAL DE MANERA OPORTUNA","INFORMAR TRIMESTRALMENTE A LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL SOBRE EL CUMPLIMIENTO DE LA PRESENTACIÓN DE LA DECLARACIÓN JURADA DE INGRESOS Y BIENES DEL PERSONAL A NIVEL NACIONAL DE MANERA OPORTUNA"]'::jsonb, 'GARANTIZAR EL CUMPLIMIENTO DE LA PRESENTACIÓN DE LAS DECLARACIONES JURADAS DE INGRESOS, BIENES Y RENTAS DEL PERSONAL POLICIAL A NIVEL NACIONAL DE MANERA OPORTUNA', 3, '(ART: 11) (item: 49)** [TITULO II] [CAPITULO I]', '181616', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (342, 342, 'EL SISTEMA DE DECLARACIONES JURADAS DE INGRESOS, BIENES Y RENTAS DEL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ, ES UN INSTRUMENTO MEDIANTE EL CUAL SE REALIZA:', '["LA ANOTACIÓN DE LAS DECLARACIONES JURADAS QUE PRESENTA EL PERSONAL POLICIAL","LA INSCRIPCIÓN DE LAS DECLARACIONES JURADAS QUE PRESENTA EL PERSONAL POLICIAL","EL CONTROL DE LAS DECLARACIONES JURADAS QUE PRESENTA EL PERSONAL POLICIAL","EL ARCHIVO DE LAS DECLARACIONES JURADAS QUE PRESENTA EL PERSONAL POLICIAL","EL REGISTRO Y PROCESAMIENTO DE LAS DECLARACIONES JURADAS QUE PRESENTA EL PERSONAL POLICIAL A NIVEL NACIONAL"]'::jsonb, 'EL REGISTRO Y PROCESAMIENTO DE LAS DECLARACIONES JURADAS QUE PRESENTA EL PERSONAL POLICIAL A NIVEL NACIONAL', 4, '(ART: 3) (item: 50)** [TITULO II]', '181617', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (343, 343, 'ES LA PERSONA SELECCIONADA E INSTRUIDA PARA PLANTEAR UNA SITUACION SIMULADA QUE PERMITA EVALUAR LA CONDUCTA ÍNTEGRA, PROBA, HONRADA, INCORRUPTIBLE E INSOBORNABLE DEL PERSONAL POLICIAL O CIVIL DEL SECTOR INTERIOR EN EL CUMPLIMIENTO DE SUS FUNCIONES?', '["EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","EL MINISTRO DEL INTERIOR","EL COMANDANTE GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","EL COMISIONADO DE INTEGRIDAD","LA INSPECTORÍA GENERAL DEL INTERIOR"]'::jsonb, 'EL COMISIONADO DE INTEGRIDAD', 3, '(ART: 13) (item: 50)** [TITULO IV]', '181618', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (344, 344, 'CONFORME AL ARTÍCULO 13 DEL DECRETO LEGISLATIVO 1291, EL COMISIONADO DE INTEGRIDAD ES LA PERSONA SELECCIONADA E INSTRUIDA PARA PLANTEAR UNA SITUACIÓN SIMULADA QUE:', '["PERMITA EVALUAR LA CONDUCTA INTEGRA DEL PERSONAL OFICIAL O CIVIL DEL SECTOR INTERIOR","PERMITA EVALUAR LA CONDUCTA INTEGRA, PROBA, HONRADA, INCORRUPTIBLE E INSOBORNABLE DEL PERSONAL POLICIAL O CIVIL DEL SECTOR INTERIOR","PERMITA EVALUAR LA INCONDUCTA INTEGRA, PROBA, HONRADA, INCORRUPTIBLE E INSOBORNABLE DEL PERSONAL POLICIAL O CIVIL DEL SECTOR INTERIOR","PERMITA REEVALUAR LA CONDUCTA INTEGRA, PROBA, HONRADA, INCORRUPTIBLE E INSOBORNABLE DEL PERSONAL POLICIAL O CIVIL DEL SECTOR INTERIOR","PERMITA EVALUAR LA CONDUCTA PSÍQUICA DEL PERSONAL POLICIAL O CIVIL DEL SECTOR INTERIOR"]'::jsonb, 'PERMITA EVALUAR LA CONDUCTA INTEGRA, PROBA, HONRADA, INCORRUPTIBLE E INSOBORNABLE DEL PERSONAL POLICIAL O CIVIL DEL SECTOR INTERIOR', 1, '(ART: 13) (item: 50)** [TITULO IV]', '181619', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (345, 345, 'EL PERSONAL POLICIAL QUE EJERZA LA ESPECIALIDAD DE CONTROL ADMINISTRATIVO DISCIPLINARIO TIENE EL SIGUIENTE INCENTIVO:', '["VACANTES NECESARIAS EN LOS PROCESOS DE ASCENSO AL GRADO INMEDIATO SUPERIOR Y POR ESPECIALIDAD","CONDECORACIÓN POR FUNCIÓN ADMINISTRATIVA Y DE APOYO OPERATIVO EFECTIVO EN EL MARCO DEL DECRETO LEGISLATIVO 1132","FELICITACIÓN POR FUNCIÓN ADMINISTRATIVA Y DE APOYO OPERATIVO EFECTIVO EN EL MARCO DEL DECRETO LEGISLATIVO 1132","CAPACITACIÓN PERMANENTE EN EL PAÍS Y EN EXTRANJERO POR CADA JERARQUÍA","PERMANENCIA EN LA ESPECIALIDAD HASTA EL TÉRMINO DE LA CARRERA POLICIAL"]'::jsonb, 'PERMANENCIA EN LA ESPECIALIDAD HASTA EL TÉRMINO DE LA CARRERA POLICIAL', 4, '(ART: 19) (item: 50)** [TITULO V]', '181620', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (346, 346, '¿QUIÉN SE ENCARGA DE ELABORAR LAS DIRECTIVAS QUE ESTABLECEN LOS PROTOCOLOS, PROCEDIMIENTOS, METAS, OBJETIVOS Y PLAZOS PARA LA APLICACIÓN DE LAS PRUEBAS?', '["LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","LA OFICINA DEL COMISIONADO DEL MININTER","A LA OFICINA DE INTEGRIDAD","LA OFICINA DE CONTROL, CUMPLIMIENTO Y CONFIANZA","LA OFICINA ANTICORRUPCIÓN DE LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ"]'::jsonb, 'LA OFICINA DE CONTROL, CUMPLIMIENTO Y CONFIANZA', 3, '(ART: 20) (item: 49)** [TITULO II] [CAPITULO II]', '181621', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (347, 347, 'UNA CARACTERÍSTICA DE LA PRUEBA DE INTEGRIDAD SEÑALA QUE, SI COMO RESULTADO DE LA PRUEBA SE PRESENTA UNA CONDUCTA TIPIFICADA COMO INFRACCIÓN DISCIPLINARIA O ILÍCITO PENAL, SE PROCEDERÁ:', '["DE ACUERDO A LO ESTABLECIDO EN EL RÉGIMEN DISCIPLINARIO DE LA POLICÍA NACIONAL DEL PERÚ","DE ACUERDO A LO NO ESTABLECIDO EN LA NORMATIVIDAD VIGENTE","DE ACUERDO A LO ESTABLECIDO EN LA NORMATIVIDAD VIGENTE","DE ACUERDO A LO ESTABLECIDO POR EL COMANDANTE GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","DE ACUERDO A LO ESTABLECIDO POR EL JEFE DE UNIDAD"]'::jsonb, 'DE ACUERDO A LO ESTABLECIDO EN LA NORMATIVIDAD VIGENTE', 2, '(ART: 16) (item: 50)** [TITULO IV]', '181622', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (348, 348, '¿QUIEN DETERMINARÁ LA POLÍTICA PARA LA APLICACIÓN DE LA PRUEBA DE CONTROL Y CONFIANZA A LOS FUNCIONARIOS, SERVIDORES CIVILES O POLICIALES DEL SECTOR INTERIOR?', '["LA CONTRALORÍA","LA INSPECTORÍA DEL MINISTERIO DEL INTERIOR","EL VICE MINISTRO DEL INTERIOR","EL MINISTRO DEL INTERIOR","LA INSPECTORIA GENERAL DE LA PNP"]'::jsonb, 'EL MINISTRO DEL INTERIOR', 3, '(ART: 8) (item: 50)** [TITULO III]', '181623', '2026-07-14T01:12:29.113429+00:00');
