INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (358, 358, 'ES UNA CARACTERÍSTICA DE LA PRUEBA DE CONTROL Y CONFIANZA:', '["EL SOMETIMIENTO A LA PRUEBA NO ES VOLUNTARIO","SE AFECTA LA INTIMIDAD DE LAS PERSONAS","NO SE AFECTA LA INTIMIDAD GRUPAL","NO SE AFECTA LA INTIMIDAD PERSONAL","EL SOMETIMIENTO A LA PRUEBA ES FACULTATIVO"]'::jsonb, 'NO SE AFECTA LA INTIMIDAD PERSONAL', 3, '(ART: 9) (item: 50)** [TITULO III]', '181633', '2026-07-14T01:12:29.113429+00:00');
