INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (361, 361, 'LA PRUEBA DE CONTROL Y CONFIANZA SE EFECTÚA MEDIANTE LA UTILIZACIÓN DEL:', '["POLÍGRAFO","COMPORTAMIENTO","TEST DE RAZONAMIENTO","EXAMEN PSICOLÓGICO","LEGAJO DEL PERSONAL"]'::jsonb, 'POLÍGRAFO', 0, '(ART: 7) (item: 50)** [TITULO III]', '181636', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (362, 362, 'DEL ENUNCIADO SIGUIENTE: ¿CUÁL CORRESPONDE A UNA CARACTERÍSTICA DE LA PRUEBA DE INTEGRIDAD SEGÚN EL DECRETO LEGISLATIVO 1291?', '["LA APLICACIÓN DE LA PRUEBA POR SÍ MISMA CONSTITUYE SANCIÓN PECUNIARIA","TIENE CARÁCTER ALEATORIO Y DE APLICACIÓN A NIVEL INTERNACIONAL","LA APLICACIÓN DE LA PRUEBA POR SÍ MISMA NO CONSTITUYE SANCIÓN DISCIPLINARIA","EL RESULTADO DE LA PRUEBA TIENE CARÁCTER DE INFORMACIÓN RESERVADA","EL SOMETIMIENTO A LA PRUEBA ES OBLIGATORIO BAJO SANCIÓN DISCIPLINARIA"]'::jsonb, 'LA APLICACIÓN DE LA PRUEBA POR SÍ MISMA NO CONSTITUYE SANCIÓN DISCIPLINARIA', 2, '(ART: 16) (item: 50)** [TITULO IV]', '181637', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (363, 363, 'UNA DE LAS FUNCIONES DE LA OFICINA DE CONTROL, CUMPLIMIENTO Y CONFIANZA; ES DICTAR LOS LINEAMIENTOS PARA:', '["GARANTIZAR EL CARÁCTER SECRETO Y CONFIDENCIAL DE LA INFORMACIÓN","GARANTIZAR LA CONFIDENCIALIDAD Y RESERVA DE LA INFORMACIÓN DE LAS DDJJ DE INGRESOS, BIENES Y RENTAS","GARANTIZAR EL CARÁCTER RESERVADO DE LA INFORMACIÓN","GARANTIZAR LA INSEGURIDAD DEL CASO DE LA INFORMACIÓN","GARANTIZAR LA DISCRECIÓN DEL CASO DE LA INFORMACIÓN"]'::jsonb, 'GARANTIZAR LA CONFIDENCIALIDAD Y RESERVA DE LA INFORMACIÓN DE LAS DDJJ DE INGRESOS, BIENES Y RENTAS', 1, '(ART: 10) (item: 49)** [TITULO II] [CAPITULO I]', '181638', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (364, 364, 'GESTIONAR A TRAVÉS DE LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL DEL MINISTERIO DEL INTERIOR, LA OBTENCIÓN DE INFORMACIÓN DE OTROS ORGANISMOS O ENTIDADES PÚBLICAS O PRIVADAS, PARA LA VERIFICACIÓN Y CONTRASTE DEL CONTENIDO DE LAS DECLARACIONES JURADAS, ES FUNCIÓN DE:', '["LA COMANDANCIA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","LA OFICINA DE ANTICORRUPCIÓN","LA OFICINA DE CONTROL DE IDENTIDAD","LA OFICINA DE CONTROL, CUMPLIMIENTO Y CONFIANZA","LA INSPECTORÍA REGIONAL DE LA POLICÍA NACIONAL DEL PERÚ"]'::jsonb, 'LA OFICINA DE CONTROL, CUMPLIMIENTO Y CONFIANZA', 3, '(ART: 10) (item: 49)** [TITULO II] [CAPITULO I]', '181639', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (365, 365, 'CONFORME AL DECRETO LEGISLATIVO 1291, LOS BENEFICIOS SEÑALADOS OTORGADOS AL PERSONAL POLICIAL QUE SEA SELECCIONADO PARA INTEGRAR EL:', '["SISTEMA DE LA LUCHA CONTRA LA CORRUPCIÓN POLICIAL","SISTEMA DE RÉGIMEN DISCIPLINARIO POLICIAL","SISTEMA DE LA OFICINA DE CORRUPCIÓN POLICIAL","SISTEMA DISCIPLINARIO DEL SECTOR INTERIOR","SISTEMA DISCIPLINARIO POLICIAL"]'::jsonb, 'SISTEMA DISCIPLINARIO POLICIAL', 4, '(ART: 19) (item: 50)** [TITULO V]', '181640', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (366, 366, 'ES EL RESPONSABLE DE EJERCER AUTORIDAD EN TODO LUGAR Y CIRCUNSTANCIA, ASÍ COMO MANTENER LA DISCIPLINA MEDIANTE LA INSTRUCCIÓN, EL MANDO JUSTO, EL BUEN EJEMPLO Y LA IMPARCIALIDAD:', '["EL ADMINISTRADO","EL SUPERIOR","EL PRESUNTO INFRACTOR","EL ÓRGANO DISCIPLINARIO","EL ÓRGANO DE INVESTIGACIÓN"]'::jsonb, 'EL SUPERIOR', 1, '(texto: 8)** [TITULO I] [CAPITULO III]', '177928', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (390, 390, 'COMETER LA INFRACCIÓN EN PRESENCIA DE SUBORDINADOS', '["CONSTITUYE UNA CIRCUNSTANCIA EXIMENTE","CONSTITUYE UNA CIRCUNSTANCIA ATENUANTE","CONSTITUYE UNA CIRCUNSTANCIA AGRAVANTE","CONSTITUYE UNA CIRCUNSTANCIA COMITANTE","CONSTITUYE UNA CIRCUNSTANCIA CONCOMITANTE"]'::jsonb, 'CONSTITUYE UNA CIRCUNSTANCIA AGRAVANTE', 2, '(texto: 56)** [TITULO IV] [CAPITULO I]', '177952', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (367, 367, 'EL SUPERIOR ES EL RESPONSABLE DE EJERCER AUTORIDAD EN TODO LUGAR Y CIRCUNSTANCIA, ASÍ COMO MANTENER LA DISCIPLINA MEDIANTE:', '["LA INSTRUCCIÓN, EL MANDO JUSTO, EL BUEN EJEMPLO Y LA IMPARCIALIDAD","EL EJERCICIO DEL MANDO Y DEL COMANDO","LA INSTRUCCIÓN, EL COMANDO JUSTO, EL BUEN CRITERIO Y LA IMPARCIALIDAD","LA INSTRUCCIÓN, EL MANDO, EL COMANDO, EL BUEN CRITERIO Y LA IMPARCIALIDAD","LA APLICACIÓN DE LOS PRINCIPIOS RECTORES PARA ESTIMULAR Y CORREGIR OPORTUNAMENTE AL SUBORDINADO"]'::jsonb, 'LA INSTRUCCIÓN, EL MANDO JUSTO, EL BUEN EJEMPLO Y LA IMPARCIALIDAD', 0, '(texto: 8)** [TITULO I] [CAPITULO III]', '177929', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (368, 368, 'OBEDECERÁ LAS ÓRDENES RECIBIDAS SIEMPRE QUE NO SEAN CONTRARIAS A LO SEÑALADO EN LA CONSTITUCIÓN POLÍTICA DEL PERÚ Y LA NORMATIVIDAD VIGENTE Y DARÁ CUENTA DE SU CUMPLIMIENTO AL SUPERIOR QUE LAS IMPARTIÓ:', '["EL SUBORDINADO","EL PRESUNTO INFRACTOR","EL PERSONAL POLICIAL","EL SANCIONADO","EL INFRACTOR"]'::jsonb, 'EL SUBORDINADO', 0, '(texto: 9)** [TITULO I] [CAPITULO III]', '177930', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (369, 369, '¿QUÉ SUCEDE CUANDO ALGÚN MIEMBRO DE LA POLICÍA NACIONAL DEL PERÚ, EN SITUACIÓN DE RETIRO, SE CONSIDERE AFECTADO POR UNA CONDUCTA QUE CONSTITUYA INFRACCIÓN COMETIDA POR OTRO MIEMBRO DE LA INSTITUCIÓN EN SITUACIÓN DE ACTIVIDAD?', '["NOTIFICARÁ AL PRESUNTO INFRACTOR PARA QUE PRESENTE SUS DESCARGOS","PRESENTARÁ SU QUEJA ANTE CUALQUIER ÓRGANO DEL SISTEMA DISCIPLINARIO","SOLICITARÁ AL PRESUNTO INFRACTOR LAS DISCULPAS DE CASO","LA LEY DE RÉGIMEN DISCIPLINARIO NO ALCANZA AL PERSONAL POLICIAL EN SITUACIÓN DE RETIRO","PODRÁ SOLICITAR LA INVESTIGACIÓN O SANCIÓN CORRESPONDIENTE"]'::jsonb, 'PODRÁ SOLICITAR LA INVESTIGACIÓN O SANCIÓN CORRESPONDIENTE', 4, '(texto: 10)** [TITULO I] [CAPITULO III]', '177931', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (370, 370, 'SURTE EFECTO INMEDIATO POR SU PROPIA NATURALEZA, NO SIENDO NECESARIA LA EMISIÓN DE RESOLUCIÓN ADICIONAL ALGUNA:', '["LA RESOLUCIÓN DE SANCIÓN POR INFRACCIÓN GRAVE Y MUY GRAVE FIRME DEBIDAMENTE NOTIFICADA","LA RESOLUCIÓN DE SANCIÓN POR INFRACCIÓN LEVE, GRAVE Y MUY GRAVE DEBIDAMENTE NOTIFICADA","LA ORDEN DE SANCIÓN","LA RESOLUCIÓN DE SANCIÓN POR INFRACCIÓN GRAVE Y MUY GRAVE DEBIDAMENTE NOTIFICADA","LA ORDEN DE SANCIÓN POR INFRACCIÓN GRAVE Y MUY GRAVE FIRME DEBIDAMENTE NOTIFICADA"]'::jsonb, 'LA RESOLUCIÓN DE SANCIÓN POR INFRACCIÓN GRAVE Y MUY GRAVE FIRME DEBIDAMENTE NOTIFICADA', 0, '(texto: 32)** [TITULO II] [CAPITULO II]', '177932', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (371, 371, 'SE NOTIFICA DE INMEDIATO AL INFRACTOR Y SE REMITIRÁ A LA DIRECCIÓN EJECUTIVA DE PERSONAL DENTRO DEL PLAZO DE 3 DÍAS HÁBILES, PARA SU CODIFICACIÓN, SISTEMATIZACIÓN Y ARCHIVO EN EL LEGAJO PERSONAL:', '["LA ORDEN DE SANCIÓN","LA SANCIÓN POR INFRACCIÓN LEVE","LA RESOLUCIÓN POR INFRACCIÓN LEVE","LA RESOLUCIÓN POR INFRACCIÓN GRAVE O MUY GRAVE","LA SANCIÓN POR INFRACCIÓN GRAVE O MUY GRAVE"]'::jsonb, 'LA SANCIÓN POR INFRACCIÓN LEVE', 1, '(texto: 32)** [TITULO II] [CAPITULO II]', '177933', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (372, 372, '¿QUÉ SUCEDE CUANDO ALGÚN MIEMBRO DE LA POLICÍA NACIONAL DEL PERÚ, EN SITUACIÓN DE DISPONIBILIDAD, SE CONSIDERE AFECTADO POR UNA CONDUCTA QUE CONSTITUYA INFRACCIÓN COMETIDA POR OTRO MIEMBRO DE LA INSTITUCIÓN EN SITUACIÓN DE DISPONIBILIDAD?', '["PODRÁ SOLICITAR LA INVESTIGACIÓN O SANCIÓN CORRESPONDIENTE","LA LEY DE RÉGIMEN DISCIPLINARIO NO ALCANZA AL PERSONAL POLICIAL EN SITUACIÓN DE DISPONIBILIDAD","SOLICITARÁ AL PRESUNTO INFRACTOR LAS DISCULPAS DE CASO","PRESENTARÁ SU QUEJA ANTE CUALQUIER ÓRGANO DEL SISTEMA DISCIPLINARIO","NOTIFICARÁ AL PRESUNTO INFRACTOR PARA QUE PRESENTE SUS DESCARGOS"]'::jsonb, 'PODRÁ SOLICITAR LA INVESTIGACIÓN O SANCIÓN CORRESPONDIENTE', 0, '(texto: 10)** [TITULO I] [CAPITULO III]', '177934', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (373, 373, '¿CUÁNDO EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ PODRÁ INFORMAR O DAR ENTREVISTAS A TRAVÉS DE LOS MEDIOS DE COMUNICACIÓN SOCIAL?', '["EN NINGUNA CIRCUNSTANCIA, YA QUE ESA FUNCIÓN LE CORRESPONDE A LOS ÓRGANOS ENCARGADOS DEL SISTEMA DE INFORMACIÓN Y COMUNICACIÓN SOCIAL DE LA INSTITUCIÓN","CUANDO TENGA AUTORIZACIÓN DEL SUPERIOR JERÁRQUICO","CUANDO TENGA AUTORIZACIÓN EXPRESA DE SU COMANDO","CUANDO SE TRATE DE TEMAS QUE NO AFECTEN LA IMAGEN INSTITUCIONAL Y NO SE RELACIONEN CON LOS ACTOS DEL SERVICIO POLICIAL","CUANDO SE TRATE DE LA AUTODEFENSA PERSONAL EN CASOS DE LA PRESUNTA COMISIÓN DE DELITOS DE FUNCIÓN"]'::jsonb, 'CUANDO TENGA AUTORIZACIÓN EXPRESA DE SU COMANDO', 2, '(texto: 11)** [TITULO I] [CAPITULO III]', '177935', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (374, 374, '¿CUÁNDO EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ PODRÁ INFORMAR O DAR ENTREVISTAS A TRAVÉS DE LOS MEDIOS DE COMUNICACIÓN SOCIAL?', '["CUANDO SE TRATE DE PRESENTAR LOGROS INSTITUCIONALES QUE ELEVEN LA IMAGEN INSTITUCIONAL","CUANDO TENGA AUTORIZACIÓN DEL SUPERIOR JERÁRQUICO","CUANDO TENGA AUTORIZACIÓN EXPRESA DE LOS ÓRGANOS ENCARGADOS DEL SISTEMA DE INFORMACIÓN Y COMUNICACIÓN SOCIAL DE LA INSTITUCIÓN","CUANDO SE TRATE DE TEMAS RELACIONADOS A LA SEGURIDAD CIUDADANA","CUANDO SE TRATE DE CASOS EMBLEMÁTICOS"]'::jsonb, 'CUANDO TENGA AUTORIZACIÓN EXPRESA DE LOS ÓRGANOS ENCARGADOS DEL SISTEMA DE INFORMACIÓN Y COMUNICACIÓN SOCIAL DE LA INSTITUCIÓN', 2, '(texto: 11)** [TITULO I] [CAPITULO III]', '177936', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (375, 375, 'SEÑALE UNO DE LOS CRITERIOS A CONSIDERAR PARA DETERMINAR LA SANCIÓN A IMPONER:', '["OBRAR COMO COLABORADOR EN LA INVESTIGACIÓN PARA EL ESCLARECIMIENTO DE LOS HECHOS","LAS CIRCUNSTANCIAS EN QUE SE COMETIÓ LA INFRACCIÓN","OBRAR POR UNA FUERZA FÍSICA IRRESISTIBLE PROVENIENTE DE UN TERCERO O DE LA NATURALEZA","CAUSAR UN DAÑO POR EVITAR OTRO MAYOR","OBRAR BAJO EL ESTADO DE ENFERMEDAD PSICÓTICA ACREDITADA"]'::jsonb, 'LAS CIRCUNSTANCIAS EN QUE SE COMETIÓ LA INFRACCIÓN', 1, '(texto: 31)** [TITULO II] [CAPITULO II]', '177937', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (376, 376, 'SEÑALE UNO DE LOS CRITERIOS A CONSIDERAR PARA DETERMINAR LA SANCIÓN A IMPONER:', '["ENCONTRARSE EN PERÍODO DE ASIMILACIÓN","TENER MENOS DE 3 MESES COMO EGRESADO DE LAS ESCUELAS DE FORMACIÓN","COMETER LA INFRACCIÓN EN PRESENCIA DE SUBORDINADOS","LA MAGNITUD DE LOS DAÑOS Y PERJUICIOS OCASIONADOS","LA REINCIDENCIA EN LA COMISIÓN DE INFRACCIONES ADMINISTRATIVAS"]'::jsonb, 'LA MAGNITUD DE LOS DAÑOS Y PERJUICIOS OCASIONADOS', 3, '(texto: 31)** [TITULO II] [CAPITULO II]', '177938', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (377, 377, 'SEÑALE UNO DE LOS CRITERIOS A CONSIDERAR PARA DETERMINAR LA SANCIÓN A IMPONER:', '["OBRAR EN SALVAGUARDA DE LA VIDA O INTEGRIDAD FÍSICA PROPIA O DE OTRAS PERSONAS, ACTUANDO CON LA DILIGENCIA DEBIDA","OBRAR POR DISPOSICIÓN DE UNA NORMA LEGAL","PROCEDER EN VIRTUD DE OBEDIENCIA AL SUPERIOR","CAUSAR UN DAÑO POR EVITAR OTRO MAYOR","LA REPARACIÓN O RESARCIMIENTO OPORTUNO DEL DAÑO ANTES DE LA SANCIÓN"]'::jsonb, 'LA REPARACIÓN O RESARCIMIENTO OPORTUNO DEL DAÑO ANTES DE LA SANCIÓN', 4, '(texto: 31)** [TITULO II] [CAPITULO II]', '177939', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (378, 378, 'SEÑALE UNO DE LOS CRITERIOS A CONSIDERAR PARA DETERMINAR LA SANCIÓN A IMPONER:', '["PROCEDER EN VIRTUD DE OBEDIENCIA AL SUPERIOR, SIEMPRE QUE LA ORDEN DE ESTE NO SEA MANIFIESTAMENTE ILÍCITA","OBRAR POR DISPOSICIÓN DE UNA NORMA LEGAL,","LOS ANTECEDENTES ADMINISTRATIVO-DISCIPLINARIOS REGISTRADOS EN EL REPORTE DE INFORMACIÓN PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ","OBRAR EN SALVAGUARDA DE LA VIDA O INTEGRIDAD FÍSICA PROPIA O DE OTRAS PERSONAS, ACTUANDO CON LA DILIGENCIA DEBIDA","LA REINCIDENCIA EN LA COMISIÓN DE INFRACCIONES ADMINISTRATIVAS"]'::jsonb, 'LOS ANTECEDENTES ADMINISTRATIVO-DISCIPLINARIOS REGISTRADOS EN EL REPORTE DE INFORMACIÓN PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ', 2, '(texto: 31)** [TITULO II] [CAPITULO II]', '177940', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (379, 379, 'SEÑALE UNO DE LOS CRITERIOS A CONSIDERAR PARA DETERMINAR LA SANCIÓN A IMPONER:', '["OBRAR POR UNA FUERZA FÍSICA IRRESISTIBLE PROVENIENTE DE UN TERCERO O DE LA NATURALEZA","EL GRADO DE COLABORACIÓN PARA EL ESCLARECIMIENTO DE LOS HECHOS","IDENTIFICAR DE MANERA CIERTA A LOS INFRACTORES VINCULADOS CON LOS HECHOS MATERIA DE INVESTIGACIÓN","EVITAR LA CONTINUIDAD, PERMANENCIA O EJECUCIÓN DE UNA INFRACCIÓN TIPIFICADA POR LA PRESENTE LEY","HABER CAUSADO UN DAÑO POR EVITAR OTRO MAYOR"]'::jsonb, 'EL GRADO DE COLABORACIÓN PARA EL ESCLARECIMIENTO DE LOS HECHOS', 1, '(texto: 31)** [TITULO II] [CAPITULO II]', '177941', '2026-07-14T01:12:29.113429+00:00');
