INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (380, 380, 'SEÑALE UNO DE LOS CRITERIOS A CONSIDERAR PARA DETERMINAR LA SANCIÓN A IMPONER:', '["OBRAR EN SALVAGUARDA DE LA VIDA O INTEGRIDAD FÍSICA PROPIA O DE OTRAS PERSONAS, ACTUANDO CON LA DILIGENCIA DEBIDA","OBRAR POR DISPOSICIÓN DE UNA NORMA LEGAL, EN CUMPLIMIENTO DE UN DEBER O EN VIRTUD DE UN MANDATO JUDICIAL O PRIVILEGIANDO UN DERECHO O UN BIEN JURÍDICO SUPERIOR, SIEMPRE QUE SE ACTÚE CON LA DILIGENCIA DEBIDA","PROCEDER EN VIRTUD DE OBEDIENCIA AL SUPERIOR, SIEMPRE QUE LA ORDEN DE ESTE NO SEA MANIFIESTAMENTE ILÍCITA","OBRAR BAJO EL ESTADO DE ENFERMEDAD PSICÓTICA ACREDITADA, QUE HAYA IMPEDIDO TOTALMENTE AL ACTOR APRECIAR EL CARÁCTER ILÍCITO DEL ACTO Y SUPRIMIDO SU CAPACIDAD PARA OBRAR LIBREMENTE","USO DEL CARGO PARA COMETER LA INFRACCIÓN"]'::jsonb, 'USO DEL CARGO PARA COMETER LA INFRACCIÓN', 4, '(texto: 31)** [TITULO II] [CAPITULO II]', '177942', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (381, 381, 'SEÑALE UNO DE LOS CRITERIOS A CONSIDERAR PARA DETERMINAR LA SANCIÓN A IMPONER:', '["COMETER LA INFRACCIÓN EN PRESENCIA DE SUBORDINADOS","LA CONFESIÓN ESPONTÁNEA Y SINCERA","LA REINCIDENCIA EN LA COMISIÓN DE INFRACCIONES ADMINISTRATIVAS","LA CONTINUIDAD EN LA COMISIÓN DE INFRACCIONES ADMINISTRATIVAS","LA PERMANENCIA EN LA COMISIÓN DE INFRACCIONES ADMINISTRATIVAS"]'::jsonb, 'LA CONFESIÓN ESPONTÁNEA Y SINCERA', 1, '(texto: 31)** [TITULO II] [CAPITULO II]', '177943', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (382, 382, 'SEÑALE UNO DE LOS CRITERIOS A CONSIDERAR PARA DETERMINAR LA SANCIÓN A IMPONER:', '["MAYOR RESPONSABILIDAD DEL EFECTIVO MÁS ANTIGUO EN LA COMISIÓN DE LA INFRACCIÓN","COMETER LA INFRACCIÓN EN PRESENCIA DE SUBORDINADOS","LA REINCIDENCIA EN LA COMISIÓN DE INFRACCIONES ADMINISTRATIVAS","TENER MENOS DE 3 MESES COMO EGRESADO DE LAS ESCUELAS DE FORMACIÓN","ENCONTRARSE EN PERÍODO DE ASIMILACIÓN"]'::jsonb, 'MAYOR RESPONSABILIDAD DEL EFECTIVO MÁS ANTIGUO EN LA COMISIÓN DE LA INFRACCIÓN', 0, '(texto: 31)** [TITULO II] [CAPITULO II]', '177944', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (383, 383, 'PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO POR INFRACCIÓN LEVE.- HABIENDO CONSTATADO O TOMADO CONOCIMIENTO DE LA COMISIÓN DE INFRACCIÓN LEVE DEL INVESTIGADO, SE NOTIFICA POR ESCRITO LA IMPUTACIÓN DE LA INFRACCIÓN PARA QUE FORMULE EL DESCARGO POR ESCRITO AL SUPERIOR QUE SANCIONA. ¿EN QUÉ PLAZO EL INVESTIGADO DEBE PRESENTAR SUS DESCARGOS?', '["2 DÍAS HÁBILES","3 DÍAS HÁBILES","1 DÍA HÁBIL","5 DÍAS HÁBILES","7 DÍAS HÁBILES"]'::jsonb, '1 DÍA HÁBIL', 2, '(texto: 62)** [TITULO IV] [CAPITULO II]', '177945', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (384, 384, 'PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO POR INFRACCIÓN LEVE.- ¿QUÉ PLAZO TIENE EL SANCIONADO PARA APELAR LA SANCIÓN IMPUESTA POR EL SUPERIOR?', '["3 DÍAS HÁBILES","5 DÍAS HÁBILES","15 DÍAS HÁBILES","20 DÍAS HÁBILES","10 DÍAS HÁBILES"]'::jsonb, '3 DÍAS HÁBILES', 0, '(texto: 62)** [TITULO IV] [CAPITULO II]', '177946', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (385, 385, 'PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO POR INFRACCIÓN LEVE.- EN SEGUNDA INSTANCIA RESUELVE EL JEFE DE UNIDAD O SUB UNIDAD POLICIAL DONDE PRESTA SERVICIOS EL SUPERIOR QUE SANCIONA, EN EL PLAZO DE:', '["3 DÍAS HÁBILES","15 DÍAS HÁBILES","10 DÍAS HÁBILES","5 DÍAS HÁBILES","1 DÍA HÁBIL"]'::jsonb, '5 DÍAS HÁBILES', 3, '(texto: 62)** [TITULO IV] [CAPITULO II]', '177947', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (386, 386, 'LA RESOLUCIÓN ABSOLUTORIA EN EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO, IMPLICA QUE EL INVESTIGADO QUE SE ENCUENTRE CON MEDIDA DE SUSPENSIÓN TEMPORAL DEL SERVICIO SERÁ REINCORPORADO AUTOMÁTICAMENTE AL SERVICIO ACTIVO, NO CONSIDERÁNDOSE COMO INTERRUPCIÓN DEL TIEMPO DE SERVICIOS, EL PERÍODO QUE DURÓ DICHA MEDIDA Y REINTEGRÁNDOSELE SOLO ...:', '["EL 30% NO PERCIBIDO DE LA REMUNERACIÓN CONSOLIDADA POR EL PERÍODO QUE DURÓ LA MEDIDA","EL 60% NO PERCIBIDO DE LA REMUNERACIÓN CONSOLIDADA POR EL PERÍODO QUE DURÓ LA MEDIDA","EL 80% NO PERCIBIDO DE LA REMUNERACIÓN CONSOLIDADA POR EL PERÍODO QUE DURÓ LA MEDIDA","EL 70% NO PERCIBIDO DE LA REMUNERACIÓN CONSOLIDADA POR EL PERÍODO QUE DURÓ LA MEDIDA","EL 50% NO PERCIBIDO DE LA REMUNERACIÓN CONSOLIDADA POR EL PERÍODO QUE DURÓ LA MEDIDA"]'::jsonb, 'EL 50% NO PERCIBIDO DE LA REMUNERACIÓN CONSOLIDADA POR EL PERÍODO QUE DURÓ LA MEDIDA', 4, '(texto: 82)** [TITULO V] [CAPITULO I]', '177948', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (387, 387, 'EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO PARA INFRACCIONES GRAVES O MUY GRAVES SE INICIA CON LA NOTIFICACIÓN DE LA RESOLUCIÓN DE INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO, EMITIDA POR EL ÓRGANO DE INVESTIGACIÓN CORRESPONDIENTE, PARA QUE EL INVESTIGADO TOME CONOCIMIENTO Y EJERZA SU DERECHO A LA DEFENSA; DEBIENDO FORMULAR SUS DESCARGOS EN UN PLAZO NO MAYOR DE ...:', '["15 DÍAS HÁBILES DE RECIBIDA VÁLIDAMENTE LA NOTIFICACIÓN","10 DÍAS HÁBILES DE RECIBIDA VÁLIDAMENTE LA NOTIFICACIÓN","20 DÍAS HÁBILES DE RECIBIDA VÁLIDAMENTE LA NOTIFICACIÓN","5 DÍAS HÁBILES DE RECIBIDA VÁLIDAMENTE LA NOTIFICACIÓN","7 DÍAS HÁBILES DE RECIBIDA VÁLIDAMENTE LA NOTIFICACIÓN"]'::jsonb, '10 DÍAS HÁBILES DE RECIBIDA VÁLIDAMENTE LA NOTIFICACIÓN', 1, '(texto: 63)** [TITULO IV] [CAPITULO III]', '177949', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (388, 388, 'PROCEDE RECURSO DE APELACIÓN CONTRA:', '["LA RESOLUCIÓN O DISPOSICIÓN SUPERIOR QUE DISPONE ACCIONES PRELIMINARES","LAS RESOLUCIONES DE SANCIÓN","LA RESOLUCIÓN DE LEVANTAMIENTO DE LA MEDIDA PREVENTIVA","LA RESOLUCIÓN DE INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","LAS RESOLUCIONES QUE AGOTAN LA VÍA ADMINISTRATIVA"]'::jsonb, 'LAS RESOLUCIONES DE SANCIÓN', 1, '(texto: 57)** [TITULO IV] [CAPITULO I]', '177950', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (389, 389, 'CONSTITUYE UNA CIRCUNSTANCIA ATENUANTE:', '["OBRAR POR UNA FUERZA FÍSICA IRRESISTIBLE PROVENIENTE DE UN TERCERO O DE LA NATURALEZA","LA CONFESIÓN SINCERA Y ESPONTÁNEA DE HABER COMETIDO LA INFRACCIÓN O COLABORACIÓN EN LA INVESTIGACIÓN PARA EL MEJOR ESCLARECIMIENTO DE LOS HECHOS","CAUSAR UN DAÑO POR EVITAR OTRO MAYOR, SIEMPRE QUE ESTE ÚLTIMO SEA EFECTIVO Y NO SE PUEDA RAZONABLEMENTE EXIGIR AL AUTOR EL SACRIFICIO DEL BIEN AMENAZADO Y QUE, DADAS LAS CIRCUNSTANCIAS, NO HAYA PODIDO EMPLEAR OTRO MEDIO MENOS PERJUDICIAL","OBRAR BAJO EL ESTADO DE ENFERMEDAD PSICÓTICA ACREDITADA, QUE HAYA IMPEDIDO TOTALMENTE AL ACTOR APRECIAR EL CARÁCTER ILÍCITO DEL ACTO Y SUPRIMIDO SU CAPACIDAD PARA OBRAR LIBREMENTE","PROCEDER EN VIRTUD DE OBEDIENCIA AL SUPERIOR, SIEMPRE QUE LA ORDEN DE ESTE NO SEA MANIFIESTAMENTE ILÍCITA"]'::jsonb, 'LA CONFESIÓN SINCERA Y ESPONTÁNEA DE HABER COMETIDO LA INFRACCIÓN O COLABORACIÓN EN LA INVESTIGACIÓN PARA EL MEJOR ESCLARECIMIENTO DE LOS HECHOS', 1, '(texto: 55)** [TITULO IV] [CAPITULO I]', '177951', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (405, 405, 'SON DILIGENCIAS QUE PUEDEN DISPONER Y REALIZAR LOS ÓRGANOS DE INVESTIGACIÓN COMPETENTES, SOLO CUANDO SEA NECESARIO IDENTIFICAR AL PRESUNTO INFRACTOR O INFRACTORES O UBICAR Y ACOPIAR INDICIOS, EVIDENCIAS, ELEMENTOS DE PRUEBA Y OTROS QUE SEAN PERTINENTES PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO:', '["LAS ACCIONES PREPARATORIAS","LAS ACCIONES PRELIMINARES","ACTOS DE INVESTIGACIÓN","ACCIONES DE INVESTIGACIÓN","LAS ACCIONES PREVIAS"]'::jsonb, 'LAS ACCIONES PREVIAS', 4, '(texto: 50)** [TITULO IV] [CAPITULO I]', '177976', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (391, 391, 'CONSTITUYE UNA CIRCUNSTANCIA ATENUANTE:', '["TENER MENOS DE 3 MESES COMO EGRESADO DE LAS ESCUELAS DE FORMACIÓN O ENCONTRARSE EN PERÍODO DE ASIMILACIÓN","OBRAR EN SALVAGUARDA DE LA VIDA O INTEGRIDAD FÍSICA PROPIA O DE OTRAS PERSONAS, ACTUANDO CON LA DILIGENCIA DEBIDA","OBRAR POR DISPOSICIÓN DE UNA NORMA LEGAL, EN CUMPLIMIENTO DE UN DEBER O EN VIRTUD DE UN MANDATO JUDICIAL O PRIVILEGIANDO UN DERECHO O UN BIEN JURÍDICO SUPERIOR, SIEMPRE QUE SE ACTÚE CON LA DILIGENCIA DEBIDA","PROCEDER EN VIRTUD DE OBEDIENCIA AL SUPERIOR, SIEMPRE QUE LA ORDEN DE ESTE NO SEA MANIFIESTAMENTE ILÍCITA","OBRAR BAJO EL ESTADO DE ENFERMEDAD PSICÓTICA ACREDITADA, QUE HAYA IMPEDIDO TOTALMENTE AL ACTOR APRECIAR EL CARÁCTER ILÍCITO DEL ACTO Y SUPRIMIDO SU CAPACIDAD PARA OBRAR LIBREMENTE"]'::jsonb, 'TENER MENOS DE 3 MESES COMO EGRESADO DE LAS ESCUELAS DE FORMACIÓN O ENCONTRARSE EN PERÍODO DE ASIMILACIÓN', 0, '(texto: 55)** [TITULO IV] [CAPITULO I]', '177953', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (392, 392, 'LA REINCIDENCIA EN LA COMISIÓN DE INFRACCIONES ADMINISTRATIVAS', '["CONSTITUYE UNA CIRCUNSTANCIA EXIMENTE","CONSTITUYE UNA CIRCUNSTANCIA ATENUANTE","CONSTITUYE UNA CIRCUNSTANCIA AGRAVANTE","CONSTITUYE UNA CIRCUNSTANCIA COMITANTE","CONSTITUYE UNA CIRCUNSTANCIA CONCOMITANTE"]'::jsonb, 'CONSTITUYE UNA CIRCUNSTANCIA AGRAVANTE', 2, '(texto: 56)** [TITULO IV] [CAPITULO I]', '177954', '2026-07-14T01:12:29.113429+00:00');
