INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (400, 400, 'SER NOTIFICADO DE LA RESOLUCIÓN QUE PONE FIN AL PROCEDIMIENTO-ADMINISTRATIVO DISCIPLINARIO', '["ES UNA OBLIGACIÓN DEL INVESTIGADO","ES UN DERECHO DEL INVESTIGADO","ES UNA OBLIGACIÓN DEL SISTEMA DISCIPLINARIO POLICIAL","ES UNA FACULTAD DEL INVESTIGADO","ES UNA FUNCIÓN DEL ÓRGANO DE INVESTIGACIÓN"]'::jsonb, 'ES UN DERECHO DEL INVESTIGADO', 1, '(texto: 52)** [TITULO IV] [CAPITULO I]', '177965', '2026-07-14T01:12:29.113429+00:00');
