INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (403, 403, 'CONOCER LOS HECHOS QUE SE LE IMPUTAN, LA INFRACCIÓN POR LA QUE ES INVESTIGADO Y LA SANCIÓN QUE LE CORRESPONDERÍA; CONSTITUYE:', '["UNA OBLIGACIÓN DEL INVESTIGADO","UN DERECHO DEL INVESTIGADO","UN DERECHO DEL ABOGADO DEFENSOR","UNA FACULTAD DEL INVESTIGADO","UNA FUNCIÓN DEL ÓRGANO DE INVESTIGACIÓN"]'::jsonb, 'UN DERECHO DEL INVESTIGADO', 1, '(texto: 52)** [TITULO IV] [CAPITULO I]', '177972', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (455, 455, 'SON AQUELLOS QUE NORMAN LAS RELACIONES INTERNAS Y EXTERNAS ENTRE LOS MIEMBROS DE LA INSTITUCIÓN Y DEMÁS AUTORIDADES, Y CON LA CIUDADANÍA EN GENERAL:', '["TRATO DEBIDO","SIGNOS Y EXPRESIONES DE RESPETO","NORMAS DE CONDUCTA","LA DISCIPLINA","NORMAS DE CORTESÍA"]'::jsonb, 'SIGNOS Y EXPRESIONES DE RESPETO', 1, '(texto: 15)** [TITULO I] [CAPITULO IV]', '178044', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (404, 404, 'LA VERIFICACIÓN DOCUMENTARIA; CONSTITUYE:', '["UNA DE LAS ACCIONES PRELIMINARES QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO","UNA DE LAS ACCIONES PREVIAS QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO","UNA DE LAS ACCIONES PREVENTIVAS QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO","UNA DE LAS ACCIONES PREPARATORIAS QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","UNO DE LOS ACTOS DE INVESTIGACIÓN QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO"]'::jsonb, 'UNA DE LAS ACCIONES PREVIAS QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO', null, '(texto: 50)** [TITULO IV] [CAPITULO I]', '177973', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (421, 421, 'EL PLAZO ORDINARIO DE LA ETAPA DE INVESTIGACIÓN PARA LAS INFRACCIONES MUY GRAVES SERÁ DE ...:', '["30 DÍAS HÁBILES","25 DÍAS HÁBILES","35 DÍAS HÁBILES","50 DÍAS HÁBILES","20 DÍAS HÁBILES"]'::jsonb, '35 DÍAS HÁBILES', 2, '(texto: 66)** [TITULO IV] [CAPITULO III]', '178002', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (406, 406, 'CONSTITUYE UNA FUNCIÓN DEL TRIBUNAL DE DISCIPLINA POLICIAL:', '["DISPONER A LOS ÓRGANOS DE INVESTIGACIÓN LA REALIZACIÓN DE ACCIONES DE INVESTIGACIÓN COMPLEMENTARIAS; EN CASO RESULTE NECESARIO","PONER EN CONOCIMIENTO DEL INTERESADO LA RESOLUCIÓN QUE RESUELVE EL PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO","CONOCE Y RESUELVE EN APELACIÓN O CONSULTA, LAS ABSOLUCIONES Y SANCIONES DE INFRACCIONES GRAVES Y LEVES, SIEMPRE QUE ESTAS HAYAN SIDO IMPUTADAS CON INFRACCIONES MUY GRAVES EN UN MISMO PROCEDIMIENTO ADMINISTRATIVO DISCIPLINARIO","PONER EN CONOCIMIENTO DE LA DIRECCIÓN EJECUTIVA DE PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ PARA SU REGISTRO Y EJECUCIÓN CORRESPONDIENTE, LA RESOLUCIÓN, DEBIDAMENTE NOTIFICADA AL INTERESADO, QUE RESUELVE EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","INVESTIGAR EN EL MARCO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO LOS HECHOS EN LOS CUALES SE ENCUENTRE INVOLUCRADO EL PERSONAL POLICIAL, QUE CONSTITUYAN INFRACCIONES GRAVES O MUY GRAVES TIPIFICADAS EN LA PRESENTE LEY"]'::jsonb, 'CONOCE Y RESUELVE EN APELACIÓN O CONSULTA, LAS ABSOLUCIONES Y SANCIONES DE INFRACCIONES GRAVES Y LEVES, SIEMPRE QUE ESTAS HAYAN SIDO IMPUTADAS CON INFRACCIONES MUY GRAVES EN UN MISMO PROCEDIMIENTO ADMINISTRATIVO DISCIPLINARIO', 2, '(texto: 49)** [TITULO III] [CAPITULO V]', '177978', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (407, 407, 'CONSTITUYE UNA FUNCIÓN DEL TRIBUNAL DE DISCIPLINA POLICIAL:', '["CONOCER Y RESOLVER EN ÚLTIMA Y DEFINITIVA INSTANCIA LOS RECURSOS DE APELACIÓN CONTRA LAS RESOLUCIONES QUE IMPONEN SANCIONES POR INFRACCIONES MUY GRAVES, ASÍ COMO LAS SANCIONES IMPUESTAS POR EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ. ASIMISMO, CONOCE Y RESUELVE LAS RESOLUCIONES EXPEDIDAS POR LOS ÓRGANOS DISCIPLINARIOS COMPETENTES, CONFORME LO ESTABLECE ESTA LEY","PONER EN CONOCIMIENTO DE LA DIRECCIÓN EJECUTIVA DE PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ PARA SU REGISTRO Y EJECUCIÓN CORRESPONDIENTE, LA RESOLUCIÓN, DEBIDAMENTE NOTIFICADA AL INTERESADO, QUE RESUELVE EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","PONER EN CONOCIMIENTO DEL INTERESADO LA RESOLUCIÓN QUE RESUELVE EL PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO","DISPONER A LOS ÓRGANOS DE INVESTIGACIÓN LA REALIZACIÓN DE ACCIONES DE INVESTIGACIÓN COMPLEMENTARIAS; EN CASO RESULTE NECESARIO","RESOLVER MEDIANTE RESOLUCIÓN DEBIDAMENTE MOTIVADA, EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES, SEGÚN CORRESPONDA"]'::jsonb, 'CONOCER Y RESOLVER EN ÚLTIMA Y DEFINITIVA INSTANCIA LOS RECURSOS DE APELACIÓN CONTRA LAS RESOLUCIONES QUE IMPONEN SANCIONES POR INFRACCIONES MUY GRAVES, ASÍ COMO LAS SANCIONES IMPUESTAS POR EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ. ASIMISMO, CONOCE Y RESUELVE LAS RESOLUCIONES EXPEDIDAS POR LOS ÓRGANOS DISCIPLINARIOS COMPETENTES, CONFORME LO ESTABLECE ESTA LEY', 0, '(texto: 49)** [TITULO III] [CAPITULO V]', '177980', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (408, 408, 'CONSTITUYE UNA FUNCIÓN DE LOS ÓRGANOS DE DECISIÓN DEL SISTEMA DISCIPLINARIO:', '["PONER EN CONOCIMIENTO DEL INTERESADO LA RESOLUCIÓN QUE RESUELVE EL PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO","FORMULAR EL INFORME ADMINISTRATIVO-DISCIPLINARIO CORRESPONDIENTE RECOMENDANDO LAS ACCIONES O SANCIONES QUE CORRESPONDAN","DISPONER O LEVANTAR LAS MEDIDAS PREVENTIVAS A LAS QUE SE REFIERE LA PRESENTE NORMA","INVESTIGAR EN EL MARCO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO LOS HECHOS EN LOS CUALES SE ENCUENTRE INVOLUCRADO EL PERSONAL POLICIAL, QUE CONSTITUYAN INFRACCIONES GRAVES O MUY GRAVES TIPIFICADAS EN LA PRESENTE LEY","EMITIR Y NOTIFICAR LAS RESOLUCIONES DE INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO"]'::jsonb, 'PONER EN CONOCIMIENTO DEL INTERESADO LA RESOLUCIÓN QUE RESUELVE EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO', null, '(texto: 48)** [TITULO III] [CAPITULO V]', '177982', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (409, 409, 'CONSTITUYE UNA FUNCIÓN DE LOS ÓRGANOS DE DECISIÓN DEL SISTEMA DISCIPLINARIO:', '["DISPONER O LEVANTAR LAS MEDIDAS PREVENTIVAS A LAS QUE SE REFIERE LA PRESENTE NORMA","FORMULAR EL INFORME ADMINISTRATIVO-DISCIPLINARIO CORRESPONDIENTE RECOMENDANDO LAS ACCIONES O SANCIONES QUE CORRESPONDAN","PONER EN CONOCIMIENTO DE LA AUTORIDAD COMPETENTE LA EXISTENCIA DE INDICIOS RAZONABLES QUE HAGAN PRESUMIR LA COMISIÓN DE UN DELITO, SIN PERJUICIO DE LA INVESTIGACIÓN DISCIPLINARIA CORRESPONDIENTE","RESOLVER MEDIANTE RESOLUCIÓN DEBIDAMENTE MOTIVADA, EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES, SEGÚN CORRESPONDA","CONOCER Y RESOLVER LOS RECURSOS DE APELACIÓN INTERPUESTOS CONTRA LAS RESOLUCIONES QUE DISPONEN MEDIDAS PREVENTIVAS POR INFRACCIONES MUY GRAVES"]'::jsonb, 'RESOLVER MEDIANTE RESOLUCIÓN DEBIDAMENTE MOTIVADA, EL PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES, SEGÚN CORRESPONDA', null, '(texto: 48)** [TITULO III] [CAPITULO V]', '177984', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (410, 410, 'CONSTITUYE UNA FUNCIÓN DE LOS ÓRGANOS DE DECISIÓN DEL SISTEMA DISCIPLINARIO:', '["RESOLVER EN CONSULTA LAS RESOLUCIONES QUE NO HAYAN SIDO APELADAS. EN ESTOS CASOS, EL TRIBUNAL PODRÁ APROBAR LAS RESOLUCIONES DE PRIMERA INSTANCIA, AGOTANDO LA VÍA ADMINISTRATIVA, O DECLARAR LA NULIDAD DE LA MISMA, DEBIENDO EN ESTE CASO EL ÓRGANO DE INVESTIGACIÓN EMITIR NUEVO PRONUNCIAMIENTO. LAS SANCIONES DE PASE A LA SITUACIÓN DE RETIRO QUE NO HAYAN SIDO IMPUGNADAS, NO SERÁN REVISADAS EN CONSULTA","REALIZAR ACCIONES PREVIAS PARA EL ACOPIO DE INDICIOS Y/O EVIDENCIAS QUE SUSTENTEN EL INICIO O NO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","EVALUAR LAS INVESTIGACIONES REALIZADAS POR LOS ÓRGANOS DE INVESTIGACIÓN POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES, SEGÚN CORRESPONDA","EMITIR Y NOTIFICAR LAS RESOLUCIONES DE INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","INVESTIGAR EN EL MARCO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO LOS HECHOS EN LOS CUALES SE ENCUENTRE INVOLUCRADO EL PERSONAL POLICIAL, QUE CONSTITUYAN INFRACCIONES GRAVES O MUY GRAVES TIPIFICADAS EN LA PRESENTE LEY"]'::jsonb, 'EVALUAR LAS INVESTIGACIONES REALIZADAS POR LOS ÓRGANOS DE INVESTIGACIÓN POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES, SEGÚN CORRESPONDA', 2, '(texto: 48)** [TITULO III] [CAPITULO V]', '177985', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (456, 456, 'EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ SANCIONADO CON RESOLUCIÓN FIRME POR LA COMISIÓN DE INFRACCIÓN GRAVE O MUY GRAVE QUE AFECTE LA FUNCIÓN QUE VENÍA DESEMPEÑANDO, NO PODRÁ CONTINUAR NI VOLVER A SER ASIGNADO AL CARGO QUE OCUPABA AL MOMENTO DE COMETER LA INFRACCIÓN O EN FUNCIONES ANÁLOGAS EN OTRA UNIDAD, POR UN PERÍODO DE ...:', '["4 AÑOS","5 AÑOS","3 AÑOS","10 AÑOS","2 AÑOS"]'::jsonb, '5 AÑOS', 1, '(texto: 13)** [TITULO I] [CAPITULO III]', '178045', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (411, 411, 'CONSTITUYE UNA FUNCIÓN DE LOS ÓRGANOS DE DECISIÓN DEL SISTEMA DISCIPLINARIO:', '["FORMULAR EL INFORME ADMINISTRATIVO-DISCIPLINARIO CORRESPONDIENTE RECOMENDANDO LAS ACCIONES O SANCIONES QUE CORRESPONDAN","ATENDER EL PEDIDO DE INFORME ORAL QUE PUDIESE EFECTUAR EL INVESTIGADO, SEÑALANDO LUGAR, FECHA Y HORA","PONER EN CONOCIMIENTO DE LA AUTORIDAD COMPETENTE LA EXISTENCIA DE INDICIOS RAZONABLES QUE HAGAN PRESUMIR LA COMISIÓN DE UN DELITO, SIN PERJUICIO DE LA INVESTIGACIÓN DISCIPLINARIA CORRESPONDIENTE","CONOCER Y RESOLVER EN ÚLTIMA Y DEFINITIVA INSTANCIA LOS RECURSOS DE APELACIÓN CONTRA LAS RESOLUCIONES QUE IMPONEN SANCIONES POR INFRACCIONES MUY GRAVES, ASÍ COMO LAS SANCIONES IMPUESTAS POR EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ. ASIMISMO CONOCE Y RESUELVE LAS RESOLUCIONES EXPEDIDAS POR LOS ÓRGANOS DISCIPLINARIOS COMPETENTES, CONFORME LO ESTABLECE ESTA LEY","CONOCER Y RESOLVER LOS RECURSOS DE APELACIÓN INTERPUESTOS CONTRA LAS RESOLUCIONES QUE DISPONEN MEDIDAS PREVENTIVAS POR INFRACCIONES MUY GRAVES"]'::jsonb, 'ATENDER EL PEDIDO DE INFORME ORAL QUE PUDIESE EFECTUAR EL INVESTIGADO, SEÑALANDO LUGAR, FECHA Y HORA', 1, '(texto: 48)** [TITULO III] [CAPITULO V]', '177986', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (439, 439, 'ES LA SANCIÓN ESCRITA QUE IMPONE EL SUPERIOR JERÁRQUICO U ÓRGANO DISCIPLINARIO COMPETENTE AL INFRACTOR POR LA COMISIÓN DE INFRACCIONES LEVES:', '["PASE A LA SITUACIÓN DE DISPONIBILIDAD POR MEDIDA DISCIPLINARIA","PASE A LA SITUACIÓN DE RETIRO POR MEDIDA DISCIPLINARIA","SANCIÓN SIMPLE","SANCIÓN DE RIGOR","ORDEN DE SANCIÓN"]'::jsonb, 'SANCIÓN SIMPLE', 2, '(texto: 30)** [TITULO II] [CAPITULO II]', '178021', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (412, 412, 'CONSTITUYE UNA FUNCIÓN DE LOS ÓRGANOS DE DECISIÓN DEL SISTEMA DISCIPLINARIO:', '["RECIBIR EL INFORME ELABORADO POR EL ÓRGANO DE INVESTIGACIÓN, PONIENDO EN CONOCIMIENTO DE TAL HECHO AL INVESTIGADO","REALIZAR ACCIONES PREVIAS PARA EL ACOPIO DE INDICIOS Y/O EVIDENCIAS QUE SUSTENTEN EL INICIO O NO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","EMITIR Y NOTIFICAR LAS RESOLUCIONES DE INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","INVESTIGAR EN EL MARCO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO LOS HECHOS EN LOS CUALES SE ENCUENTRE INVOLUCRADO EL PERSONAL POLICIAL, QUE CONSTITUYAN INFRACCIONES GRAVES O MUY GRAVES TIPIFICADAS EN LA PRESENTE LEY","DISPONER O LEVANTAR LAS MEDIDAS PREVENTIVAS A LAS QUE SE REFIERE LA PRESENTE NORMA"]'::jsonb, 'RECIBIR EL INFORME ELABORADO POR EL ÓRGANO DE INVESTIGACIÓN, PONIENDO EN CONOCIMIENTO DE TAL HECHO AL INVESTIGADO', 0, '(texto: 48)** [TITULO III] [CAPITULO V]', '177987', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (413, 413, 'ES COMPETENTE PARA RESOLVER EN PRIMERA INSTANCIA LOS PROCEDIMIENTOS ADMINISTRATIVO-DISCIPLINARIOS INVESTIGADOS POR LA OFICINA DE ASUNTOS INTERNOS POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES:', '["EL TRIBUNAL DE DISCIPLINA POLICIAL","LA INSPECTORÍA DESCENTRALIZADA DE LA POLICÍA NACIONAL DEL PERÚ CONSIDERANDO EL LUGAR DONDE SE COMETIÓ LA INFRACCIÓN","LA OFICINA DE ASUNTOS INTERNOS","OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL","EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ"]'::jsonb, 'EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ', 4, '(texto: 47)** [TITULO III] [CAPITULO V]', '177988', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (414, 414, 'CONSTITUYE UNA FUNCIÓN DE LOS ÓRGANOS DE INVESTIGACIÓN DEL SISTEMA DISCIPLINARIO:', '["RESOLVER EN CONSULTA LAS RESOLUCIONES QUE NO HAYAN SIDO APELADAS. EN ESTOS CASOS, EL TRIBUNAL PODRÁ APROBAR LAS RESOLUCIONES DE PRIMERA INSTANCIA, AGOTANDO LA VÍA ADMINISTRATIVA, O DECLARAR LA NULIDAD DE LA MISMA, DEBIENDO EN ESTE CASO EL ÓRGANO DE INVESTIGACIÓN EMITIR NUEVO PRONUNCIAMIENTO. LAS SANCIONES DE PASE A LA SITUACIÓN DE RETIRO QUE NO HAYAN SIDO IMPUGNADAS, NO SERÁN REVISADAS EN CONSULTA","CONOCER Y RESOLVER LOS RECURSOS DE APELACIÓN INTERPUESTOS CONTRA LAS RESOLUCIONES QUE DISPONEN MEDIDAS PREVENTIVAS POR INFRACCIONES MUY GRAVES","CONOCER Y RESOLVER EN ÚLTIMA Y DEFINITIVA INSTANCIA LOS RECURSOS DE APELACIÓN CONTRA LAS RESOLUCIONES QUE IMPONEN SANCIONES POR INFRACCIONES MUY GRAVES, ASÍ COMO LAS SANCIONES IMPUESTAS POR EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ. ASIMISMO CONOCE Y RESUELVE LAS RESOLUCIONES EXPEDIDAS POR LOS ÓRGANOS DISCIPLINARIOS COMPETENTES, CONFORME LO ESTABLECE ESTA LEY","ATENDER EL PEDIDO DE INFORME ORAL QUE PUDIESE EFECTUAR EL INVESTIGADO, SEÑALANDO LUGAR, FECHA Y HORA","FORMULAR EL INFORME ADMINISTRATIVO-DISCIPLINARIO CORRESPONDIENTE RECOMENDANDO LAS ACCIONES O SANCIONES QUE CORRESPONDAN"]'::jsonb, 'FORMULAR EL INFORME ADMINISTRATIVO-DISCIPLINARIO CORRESPONDIENTE RECOMENDANDO LAS ACCIONES O SANCIONES QUE CORRESPONDAN', 4, '(texto: 46)** [TITULO III] [CAPITULO IV]', '177991', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (415, 415, 'CONSTITUYE UNA FUNCIÓN DE LOS ÓRGANOS DE INVESTIGACIÓN DEL SISTEMA DISCIPLINARIO:', '["ATENDER EL PEDIDO DE INFORME ORAL QUE PUDIESE EFECTUAR EL INVESTIGADO, SEÑALANDO LUGAR, FECHA Y HORA","EVALUAR LAS INVESTIGACIONES REALIZADAS POR LOS ÓRGANOS DE INVESTIGACIÓN POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES, SEGÚN CORRESPONDA","INVESTIGAR EN EL MARCO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO LOS HECHOS EN LOS CUALES SE ENCUENTRE INVOLUCRADO EL PERSONAL POLICIAL, QUE CONSTITUYAN INFRACCIONES GRAVES O MUY GRAVES TIPIFICADAS EN LA PRESENTE LEY","RESOLVER MEDIANTE RESOLUCIÓN DEBIDAMENTE MOTIVADA, EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES, SEGÚN CORRESPONDA","DISPONER A LOS ÓRGANOS DE INVESTIGACIÓN LA REALIZACIÓN DE ACCIONES DE INVESTIGACIÓN COMPLEMENTARIAS; EN CASO RESULTE NECESARIO"]'::jsonb, 'INVESTIGAR EN EL MARCO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO LOS HECHOS EN LOS CUALES SE ENCUENTRE INVOLUCRADO EL PERSONAL POLICIAL, QUE CONSTITUYAN INFRACCIONES GRAVES O MUY GRAVES TIPIFICADAS EN LA PRESENTE LEY', 2, '(texto: 46)** [TITULO III] [CAPITULO IV]', '177993', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (416, 416, 'CONSTITUYE UNA FUNCIÓN DE LOS ÓRGANOS DE INVESTIGACIÓN DEL SISTEMA DISCIPLINARIO:', '["DISPONER A LOS ÓRGANOS DE INVESTIGACIÓN LA REALIZACIÓN DE ACCIONES DE INVESTIGACIÓN COMPLEMENTARIAS; EN CASO RESULTE NECESARIO","EMITIR Y NOTIFICAR LAS RESOLUCIONES DE INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","PONER EN CONOCIMIENTO DEL INTERESADO LA RESOLUCIÓN QUE RESUELVE EL PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO","PONER EN CONOCIMIENTO DE LA DIRECCIÓN EJECUTIVA DE PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ PARA SU REGISTRO Y EJECUCIÓN CORRESPONDIENTE, LA RESOLUCIÓN, DEBIDAMENTE NOTIFICADA AL INTERESADO, QUE RESUELVE EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","RECIBIR EL INFORME ELABORADO POR EL ÓRGANO DE INVESTIGACIÓN, PONIENDO EN CONOCIMIENTO DE TAL HECHO AL INVESTIGADO"]'::jsonb, 'EMITIR Y NOTIFICAR LAS RESOLUCIONES DE INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO', 1, '(texto: 46)** [TITULO III] [CAPITULO IV]', '177994', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (417, 417, 'CONSTITUYE UNA FUNCIÓN DE LOS ÓRGANOS DE INVESTIGACIÓN DEL SISTEMA DISCIPLINARIO:', '["REALIZAR ACCIONES PREVIAS PARA EL ACOPIO DE INDICIOS Y/O EVIDENCIAS QUE SUSTENTEN EL INICIO O NO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","RECIBIR EL INFORME ELABORADO POR EL ÓRGANO DE INVESTIGACIÓN, PONIENDO EN CONOCIMIENTO DE TAL HECHO AL INVESTIGADO","ATENDER EL PEDIDO DE INFORME ORAL QUE PUDIESE EFECTUAR EL INVESTIGADO, SEÑALANDO LUGAR, FECHA Y HORA","EVALUAR LAS INVESTIGACIONES REALIZADAS POR LOS ÓRGANOS DE INVESTIGACIÓN POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES, SEGÚN CORRESPONDA","RESOLVER MEDIANTE RESOLUCIÓN DEBIDAMENTE MOTIVADA, EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES, SEGÚN CORRESPONDA"]'::jsonb, 'REALIZAR ACCIONES PREVIAS PARA EL ACOPIO DE INDICIOS Y/O EVIDENCIAS QUE SUSTENTEN EL INICIO O NO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO', 0, '(texto: 46)** [TITULO III] [CAPITULO IV]', '177995', '2026-07-14T01:12:29.113429+00:00');
