INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (626, 626, '¿CUÁL ES EL TIEMPO MÍNIMO DE SERVICIO REALES Y EFECTIVOS EN LA INSTITUCIÓN QUE DEBE TENER UN COMANDANTE DE SERVICIOS PARA POSTULAR AL GRADO INMEDIATO SUPERIOR?', '["6 AÑOS","12 AÑOS","18 AÑOS","24 AÑOS","25 AÑOS"]'::jsonb, '18 AÑOS', 2, '(texto: 9)** [TITULO II] [CAPITULO II]', '186767', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (475, 475, 'EL PRESIDENTE DEL TRIBUNAL DE DISCIPLINA POLICIAL ES DESIGNADO POR:', '["EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","EL COMANDANTE GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","MINISTRO DEL INTERIOR","EL PRESIDENTE DE LA REPÚBLICA","LOS TITULARES DE LAS SALAS"]'::jsonb, 'MINISTRO DEL INTERIOR', 2, '(texto: 42)** [TITULO III] [CAPITULO III]', '178077', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (476, 476, 'EL TRIBUNAL DE DISCIPLINA POLICIAL TIENE SU SEDE PRINCIPAL EN:', '["CHICLAYO","AREQUIPA","LA CAPITAL DE LA REPÚBLICA","CUZCO","CAÑETE"]'::jsonb, 'LA CAPITAL DE LA REPÚBLICA', 2, '(texto: 41)** [TITULO III] [CAPITULO III]', '178085', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (477, 477, '¿POR CUÁNTOS VOCALES ESTA CONFORMADO CADA SALA DEL TRIBUNAL DE DISCIPLINA POLICIAL?', '["4 VOCALES","7 VOCALES","5 VOCALES","2 VOCALES","3 VOCALES"]'::jsonb, '3 VOCALES', 4, '(texto: 41)** [TITULO III] [CAPITULO III]', '178086', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (478, 478, 'EL TRIBUNAL DE DISCIPLINA POLICIAL PARA EL EJERCICIO DE SUS FUNCIONES CUENTA CON AUTONOMÍA:', '["TÉCNICA Y FUNCIONAL","TÉCNICA Y ADMINISTRATIVA","ADMINISTRATIVA Y FUNCIONAL","OPERATIVA Y ADMINISTRATIVA","TÉCNICA Y OPERATIVA"]'::jsonb, 'TÉCNICA Y FUNCIONAL', 0, '(texto: 41)** [TITULO III] [CAPITULO III]', '178087', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (479, 479, 'EL TRIBUNAL DE DISCIPLINA POLICIAL ES LA ÚLTIMA INSTANCIA ADMINISTRATIVA EN EL PROCEDIMIENTO DISCIPLINARIO INICIADO POR INFRACCIONES:', '["GRAVES Y MUY GRAVES","MUY GRAVES","LEVES, GRAVES Y MUY GRAVES","LEVES Y GRAVES","LEVES Y MUY GRAVES"]'::jsonb, 'MUY GRAVES', 1, '(texto: 41)** [TITULO III] [CAPITULO III]', '178089', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (480, 480, '¿DE QUIÉN DEPENDE EL TRIBUNAL DE DISCIPLINA POLICIAL?', '["DEPENDE DEL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","DEPENDE DE LA OFICINA GENERAL DE CONTROL INTERNO","DEPENDE DEL MINISTRO DEL INTERIOR","DEPENDE DE LA OFICINA GENERAL DE ASUNTOS INTERNOS","DEPENDE DEL CONSEJO SUPREMO DE JUSTICIA MILITAR POLICIAL"]'::jsonb, 'DEPENDE DEL MINISTRO DEL INTERIOR', 2, '(texto: 41)** [TITULO III] [CAPITULO III]', '178090', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (481, 481, 'CONSTITUYE UN IMPEDIMENTO PARA INTERVENIR COMO INTEGRANTE DE LOS ÓRGANOS DEL SISTEMA DISCIPLINARIO:', '["SI PERSONALMENTE, O BIEN SU CÓNYUGE, CONVIVIENTE O ALGÚN PARIENTE DENTRO DEL CUARTO GRADO DE CONSANGUINIDAD O SEGUNDO DE AFINIDAD, TUVIERE INTERÉS EN EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO QUE SE INVESTIGA O EN OTRO SEMEJANTE, CUYA RESOLUCIÓN PUEDA INFLUIR EN LA SITUACIÓN DE AQUEL","SI HA TENIDO INTERVENCIÓN COMO ASESOR, PERITO O TESTIGO EN EL MISMO PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO, O SI COMO INSTRUCTOR HUBIERE MANIFESTADO PREVIAMENTE SU PARECER SOBRE EL MISMO, DE MODO QUE PUDIERA ENTENDERSE QUE SE HA PRONUNCIADO SOBRE EL ASUNTO, SALVO LA RECTIFICACIÓN DE ERRORES O LA DECISIÓN DEL RECURSO DE RECONSIDERACIÓN","SER DEUDOR, ACREEDOR, FIADOR DEL INVESTIGADO O DEL DENUNCIANTE, O TENER INTERESES COMUNES CON ESTOS ÚLTIMOS","CUANDO TUVIERE AMISTAD ÍNTIMA, ENEMISTAD MANIFIESTA O CONFLICTO DE INTERESES OBJETIVO CON CUALQUIERA DE LAS PARTES QUE INTERVIENEN EN EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO, QUE SE HAGAN PATENTES MEDIANTE ACTITUDES O HECHOS EVIDENTES EN EL PROCEDIMIENTO","SI ES CÓNYUGE, CONVIVIENTE, PARIENTE DENTRO DEL CUARTO GRADO DE CONSANGUINIDAD O SEGUNDO DE AFINIDAD, CON CUALQUIERA DE LAS PARTES O CON SUS REPRESENTANTES"]'::jsonb, 'SER DEUDOR, ACREEDOR, FIADOR DEL INVESTIGADO O DEL DENUNCIANTE, O TENER INTERESES COMUNES CON ESTOS ÚLTIMOS', 2, '(texto: 40)** [TITULO III] [CAPITULO II]', '178092', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (482, 482, 'CONSTITUYE UN IMPEDIMENTO PARA INTERVENIR COMO INTEGRANTE DE LOS ÓRGANOS DEL SISTEMA DISCIPLINARIO:', '["SI PERSONALMENTE, O BIEN SU CÓNYUGE, CONVIVIENTE O ALGÚN PARIENTE DENTRO DEL CUARTO GRADO DE CONSANGUINIDAD O SEGUNDO DE AFINIDAD, TUVIERE INTERÉS EN EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO QUE SE INVESTIGA O EN OTRO SEMEJANTE, CUYA RESOLUCIÓN PUEDA INFLUIR EN LA SITUACIÓN DE AQUEL","CUANDO TUVIERE O HUBIESE TENIDO EN LOS ÚLTIMOS DOCE MESES, RELACIÓN DE SERVICIO O DE SUBORDINACIÓN CON CUALQUIERA DE LAS PARTES O TERCEROS DIRECTAMENTE INTERESADOS EN EL ACTO RESOLUTIVO","SI ES CÓNYUGE, CONVIVIENTE, PARIENTE DENTRO DEL CUARTO GRADO DE CONSANGUINIDAD O SEGUNDO DE AFINIDAD, CON CUALQUIERA DE LAS PARTES O CON SUS REPRESENTANTES","SI HA TENIDO INTERVENCIÓN COMO ASESOR, PERITO O TESTIGO EN EL MISMO PROCEDIMIENTO ADMINISTRATIVO- DISCIPLINARIO, O SI COMO INSTRUCTOR HUBIERE MANIFESTADO PREVIAMENTE SU PARECER SOBRE EL MISMO, DE MODO QUE PUDIERA ENTENDERSE QUE SE HA PRONUNCIADO SOBRE EL ASUNTO, SALVO LA RECTIFICACIÓN DE ERRORES O LA DECISIÓN DEL RECURSO DE RECONSIDERACIÓN","SER DENUNCIANTE DE LOS HECHOS O HABER SIDO DENUNCIADO ANTES POR ALGUNO DE LOS INVESTIGADOS O DENUNCIANTES"]'::jsonb, 'SER DENUNCIANTE DE LOS HECHOS O HABER SIDO DENUNCIADO ANTES POR ALGUNO DE LOS INVESTIGADOS O DENUNCIANTES', 4, '(texto: 40)** [TITULO III] [CAPITULO II]', '178093', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (483, 483, '¿QUÉ ÓRGANO DISCIPLINARIO ES COMPETENTE EN SEGUNDA INSTANCIA PARA EL CASO DE INFRACCIONES GRAVES SANCIONADAS POR LAS INSPECTORÍAS DESCENTRALIZADAS?', '["LA OFICINA DE ASUNTOS INTERNOS","LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL","LA INSPECTORÍA MACRO REGIONAL","EL TRIBUNAL DE DISCIPLINA POLICIAL","EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ"]'::jsonb, 'LA INSPECTORÍA MACRO REGIONAL', 2, '(texto: 39)** [TITULO III] [CAPITULO II]', '178097', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (484, 484, '¿QUÉ ÓRGANO DISCIPLINARIO ES COMPETENTE PARA EL CASO DE INFRACCIONES GRAVES Y MUY GRAVES, SANCIONADAS POR LAS INSPECTORÍAS DESCENTRALIZADAS O EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ?', '["EL TRIBUNAL DE DISCIPLINA POLICIAL","LA INSPECTORÍA MACRO REGIONAL","LA INSPECTORÍA REGIONAL","LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL","LA OFICINA DE ASUNTOS INTERNOS"]'::jsonb, 'EL TRIBUNAL DE DISCIPLINA POLICIAL', 0, '(texto: 39)** [TITULO III] [CAPITULO II]', '178098', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (485, 485, 'CONSTITUYE UN ÓRGANO DE DECISIÓN EN SEGUNDA INSTANCIA, POR LA COMISIÓN DE INFRACCIONES GRAVES:', '["LA INSPECTORÍA DESCENTRALIZADA COMPETENTE","LA INSPECTORÍA MACRO REGIONAL","EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL","LA OFICINA DE ASUNTOS INTERNOS"]'::jsonb, 'LA INSPECTORÍA MACRO REGIONAL', 1, '(texto: 39)** [TITULO III] [CAPITULO II]', '178099', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (486, 486, 'CONSTITUYE UN ÓRGANO DE DECISIÓN EN PRIMERA INSTANCIA POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES:', '["LA INSPECTORÍA MACRO REGIONAL COMPETENTE","EL TRIBUNAL DE DISCIPLINA POLICIAL","EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL, A TRAVÉS DE LA OFICINA DE ASUNTOS INTERNOS","LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ, A TRAVÉS DE LAS OFICINAS DE DISCIPLINA"]'::jsonb, 'EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ', 2, '(texto: 39)** [TITULO III] [CAPITULO II]', '178105', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (487, 487, 'LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ, CONSTITUYE UN ÓRGANO DISCIPLINARIO, A TRAVÉS DE:', '["INSPECTORÍA REGIONAL","LA OFICINA DE ASUNTOS INTERNOS","INSPECTORÍA MACRO REGIONAL","OFICINAS DE DISCIPLINA DE LAS UNIDADES ADMINISTRATIVAS","INSPECTORÍA TERRITORIALES"]'::jsonb, 'INSPECTORÍA MACRO REGIONAL', 2, '(texto: 36)** [TITULO III] [CAPITULO II]', '178122', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (488, 488, 'ES UN ÓRGANO DISCIPLINARIO:', '["EL TRIBUNAL DE DISCIPLINA POLICIAL","EL TRIBUNAL DISCIPLINARIO POLICIAL","EL CONSEJO DE DISCIPLINA POLICIAL","EL CONSEJO DISCIPLINARIO POLICIAL","EL TRIBUNAL DISCIPLINARIO DEL MINISTERIO DEL INTERIOR"]'::jsonb, 'EL TRIBUNAL DE DISCIPLINA POLICIAL', 0, '(texto: 36)** [TITULO III] [CAPITULO II]', '178124', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (489, 489, 'ES UN ÓRGANO DISCIPLINARIO:', '["EL TRIBUNAL DISCIPLINARIO POLICIAL","EL CONSEJO DE DISCIPLINA POLICIAL","LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ","EL CONSEJO DISCIPLINARIO POLICIAL","EL TRIBUNAL DISCIPLINARIO DEL MINISTERIO DEL INTERIOR"]'::jsonb, 'LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ', 2, '(texto: 36)** [TITULO III] [CAPITULO II]', '178126', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (490, 490, 'TIENEN POR FINALIDAD INVESTIGAR O IMPONER SANCIONES, DE ACUERDO CON LO ESTABLECIDO EN LA PRESENTE LEY Y SU REGLAMENTO:', '["EL INSTRUCTOR","LA INVESTIGACIÓN ADMINISTRATIVA-DISCIPLINARIA","EL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO","LOS ÓRGANOS DISCIPLINARIOS","EL SISTEMA DISCIPLINARIO POLICIAL"]'::jsonb, 'LOS ÓRGANOS DISCIPLINARIOS', 3, '(texto: 36)** [TITULO III] [CAPITULO II]', '178127', '2026-07-14T01:12:29.113429+00:00');
