INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (492, 492, 'DOCENTES.- CONFORME A LAS DISPOSICIONES DEL REGLAMENTO, PUEDEN EJERCER LA DOCENCIA:', '["LOS OFICIALES","LOS SUBOFICIALES","LOS DIRECTIVOS Y MIEMBROS DE LOS CONSEJOS DE LA ESCUELA","LOS DIRECTIVOS Y ADMINISTRATIVOS","LOS DIRECTIVOS Y MIEMBROS DE LOS CONSEJOS NACIONALES"]'::jsonb, 'LOS DIRECTIVOS Y MIEMBROS DE LOS CONSEJOS DE LA ESCUELA', 2, '(ART: 10) [TITULO II] [CAPITULO II]', '181505', '2026-07-14T01:12:29.113429+00:00');
