INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (496, 496, 'ES PRINCIPIO DE LA FORMACIÓN PROFESIONAL POLICIAL:', '["COMPETENCIA","INVESTIGACIÓN E INNOVACIÓN","CONTINUIDAD","ÉTICA","MORAL"]'::jsonb, 'INVESTIGACIÓN E INNOVACIÓN', 1, '(ART: 5) [TITULO I] [CAPITULO I]', '181509', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (497, 497, 'SON LOS QUE CUMPLEN TODOS LOS REQUISITOS SEÑALADOS EN LAS NORMAS QUE REGULAN LOS PROCESOS DE ADMISIÓN, SUPERAN SATISFACTORIAMENTE SUS ETAPAS DE SELECCIÓN Y SE ENCUENTRAN MATRICULADOS EN ALGUNA DE ELLAS:', '["DISCENTES","DOCENTES","ESTUDIANTES DE LAS ESCUELAS DE LA DIRECCIÓN DE EDUCACIÓN Y DOCTRINA DE LA POLICÍA NACIONAL DEL PERÚ","PARTICIPANTES","ALUMNOS"]'::jsonb, 'ESTUDIANTES DE LAS ESCUELAS DE LA DIRECCIÓN DE EDUCACIÓN Y DOCTRINA DE LA POLICÍA NACIONAL DEL PERÚ', 2, '(ART: 11) [TITULO II] [CAPITULO II]', '181510', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (498, 498, 'NO PUEDE RESTRINGIRSE O RETIRARSE LA CONDICIÓN DE ESTUDIANTE POR HECHOS VINCULADOS A:', '["MEDIDA DISCIPLINARIA","ACTOS INDECOROSOS","MÉRITOS ALCANZADOS","PATERNIDAD","VIOLENCIA FAMILIAR"]'::jsonb, 'PATERNIDAD', 3, '(ART: 11) [TITULO II] [CAPITULO II]', '181511', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (499, 499, 'EL CONSEJO ACADÉMICO Y EL CONSEJO DISCIPLINARIO SUPERIOR CONSTITUYEN:', '["PRIMERA Y SEGUNDA INSTANCIA","PRIMERA INSTANCIA","PRIMERA Y SEGUNDA INSTANCIA RESPECTIVAMENTE","SEGUNDA INSTANCIA","SEGUNDA Y ÚLTIMA INSTANCIA"]'::jsonb, 'SEGUNDA INSTANCIA', 3, '(ART: 22) [TITULO III] [CAPITULO V]', '181512', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (500, 500, 'NO ES UNA CAUSAL DE SEPARACIÓN PARA ESTUDIANTES DE PREGRADO DE LA DIRECCIÓN DE EDUCACIÓN Y DOCTRINA DE LA POLICÍA NACIONAL DEL PERÚ:', '["NO HABER ALCANZADO NOTA APROBATORIA MÍNIMA DE 13 EN CUALQUIERA DE LAS ASIGNATURAS O EN EL PROMEDIO GENERAL DE RENDIMIENTO ACADÉMICO EN UN PERIODO, SEMESTRE, CICLO O MÓDULO; INCLUYENDO EL FACTOR DISCIPLINA","NO SOLICITAR REINCORPORACIÓN LUEGO DEL PERÍODO DE GRAVIDEZ, CONFORME AL REGLAMENTO","PARTICIPAR EN LA ALTERACIÓN DEL ORDEN INTERNO","NO APROBAR LOS EXÁMENES DE REINCORPORACIÓN","RETIRO VOLUNTARIO, SALVO QUE SE ENCUENTRE INCURSO EN PROCESO DE INVESTIGACIÓN ADMINISTRATIVA ACADÉMICA Y/O DISCIPLINARIA"]'::jsonb, 'PARTICIPAR EN LA ALTERACIÓN DEL ORDEN INTERNO', 2, '(ART: 24) [TITULO III] [CAPITULO VI]', '181513', '2026-07-14T01:12:29.113429+00:00');
