INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (523, 523, 'ES UNA FUNCIÓN DE LA DIRECCIÓN DE LA DIREDDOC:', '["ASESORAR AL JEFE DE ESTADO MAYOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ EN MATERIA DE CULTURA ORGANIZACIONAL Y DOCTRINA DE LA POLICÍA NACIONAL DEL PERÚ","ASESORAR AL COMANDO INSTITUCIONAL EN MATERIA DE CULTURA ORGANIZACIONAL Y DOCTRINA DE LA POLICÍA NACIONAL DEL PERÚ","ASESORAR AL SUB DIRECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ EN MATERIA DE CULTURA ORGANIZACIONAL Y DOCTRINA DE LA POLICÍA NACIONAL DEL PERÚ","ASESORAR AL DIRECTOR DE LA ENFPP DE LA POLICÍA NACIONAL DEL PERÚ EN MATERIA DE CULTURA ORGANIZACIONAL Y DOCTRINA DE LA POLICÍA NACIONAL DEL PERÚ","ASESORAR AL DIRECTOR DE LA ESCUELA DE POSGRADO DE LA POLICÍA NACIONAL DEL PERÚ EN MATERIA DE CULTURA ORGANIZACIONAL Y DOCTRINA DE LA POLICÍA NACIONAL DEL PERÚ"]'::jsonb, 'ASESORAR AL COMANDO INSTITUCIONAL EN MATERIA DE CULTURA ORGANIZACIONAL Y DOCTRINA DE LA POLICÍA NACIONAL DEL PERÚ', 1, '(ART: 9) REGLAMENTO [TITULO I] [CAPITULO III]', '181536', '2026-07-14T01:12:29.113429+00:00');
