INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (530, 530, 'ES UNA FUNCIÓN DE LA DIVISIÓN ACADÉMICA DE LA DIREDDOC:', '["PARTICIPAR EN LA FORMULACIÓN Y GESTIÓN DEL PLAN ESTRATÉGICO EDUCATIVO DE LA ENFPP, CONJUNTAMENTE CON EL SUB DIRECTOR, EL JEFE DE LA DIVISIÓN ADMINISTRATIVA Y EL JEFE DE LA DIVISIÓN DE INVESTIGACIÓN, PARA LA APROBACIÓN DE LA DIRECCIÓN DE LA ENFPP","ELABORAR, PROPONER Y PUBLICAR EL REGLAMENTO INTERNO Y PROSPECTO DE ADMISIÓN, SEGÚN CORRESPONDA, PARA SER APROBADOS POR LA DIRECCIÓN DE LA ENFPP","EVALUAR LA IDONEIDAD, APTITUDES Y COMPETENCIAS DE LOS POSTULANTES A LOS PROGRAMAS ACADÉMICOS OFRECIDOS POR LA ENFPP","INFORMAR Y DIFUNDIR LOS PROCESOS DE ADMISIÓN A CARGO DE LA ENFPP, EN COORDINACIÓN CON LA UNIDAD DE COMUNICACIONES Y PROYECCIÓN SOCIAL","DIFUNDIR, PUBLICAR, ANALIZAR Y EVALUAR LOS RESULTADOS DE LOS EXÁMENES Y PROCESOS DE ADMISIÓN"]'::jsonb, 'PARTICIPAR EN LA FORMULACIÓN Y GESTIÓN DEL PLAN ESTRATÉGICO EDUCATIVO DE LA ENFPP, CONJUNTAMENTE CON EL SUB DIRECTOR, EL JEFE DE LA DIVISIÓN ADMINISTRATIVA Y EL JEFE DE LA DIVISIÓN DE INVESTIGACIÓN, PARA LA APROBACIÓN DE LA DIRECCIÓN DE LA ENFPP', 0, '(ART: 25) REGLAMENTO [TITULO I] [CAPITULO V]', '181544', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (532, 532, 'EN CASO LA SOLICITUD SE PRESENTE EN LA UNIDAD DE RECEPCIÓN DOCUMENTARIA DE LA ENTIDAD, LA SOLICITUD DEBE CONTENER, ADEMÁS, (. ........ ), DE NO SABER FIRMAR O ESTAR IMPEDIDO DE HACERLO. ESTE REQUISITO NO ES EXIGIBLE CUANDO LA SOLICITUD SE PRESENTA POR CANALES DIFERENTES A LA UNIDAD DE RECEPCIÓN DOCUMENTARIA', '["LA IDENTIDAD DE LA ADMINISTRACIÓN PÚBLICA","LA IDENTIDAD DEL FUNCIONARIO PÚBLICO","LA IDENTIDAD DEL SOLICITANTE","LA CALIDAD DEL SOLICITANTE","LA CALIDAD DE LA INFORMACIÓN QUE SE SOLICITA"]'::jsonb, 'LA IDENTIDAD DEL SOLICITANTE', 2, '(texto: 13)** [TITULO III]', '186277', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (533, 533, 'RESPECTO AL PROCEDIMIENTO DE ACCESO A LA INFORMACIÓN PÚBLICA. INDIQUE, ¿QUÉ PLAZO TIENE LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA A LA CUÁL SE HAYA PRESENTADO LA SOLICITUD DE INFORMACIÓN, PARA OTORGARLA?', '["DEBE OTORGARLA EN UN PLAZO NO MAYOR DE 7 DÍAS HÁBILES","DEBE OTORGARLA EN UN PLAZO NO MAYOR DE 5 DÍAS HÁBILES","DEBE OTORGARLA EN UN PLAZO NO MAYOR DE 15 DÍAS HÁBILES","DEBE OTORGARLA EN UN PLAZO NO MAYOR DE 30 DÍAS HÁBILES","DEBE OTORGARLA EN UN PLAZO NO MAYOR DE 10 DÍAS HÁBILES"]'::jsonb, 'DEBE OTORGARLA EN UN PLAZO NO MAYOR DE 10 DÍAS HÁBILES', 4, '(texto: 11)** [TITULO III]', '186278', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (534, 534, 'RESPECTO AL PROCEDIMIENTO DE ACCESO A LA INFORMACIÓN PÚBLICA, DE NO MEDIAR RESPUESTA EN EL PLAZO PREVISTO, EL SOLICITANTE PUEDE CONSIDERAR:', '["APROBADO SU PEDIDO","DENEGADO SU PEDIDO","APLICAR EL SILENCIO ADMINISTRATIVO POSITIVO","APLICAR EL SILENCIO ADMINISTRATIVO","DESESTIMADO SU PEDIDO"]'::jsonb, 'DENEGADO SU PEDIDO', 1, '(texto: 11)** [TITULO III]', '186279', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (535, 535, 'RESPECTO AL PROCEDIMIENTO DE ACCESO A LA INFORMACIÓN PÚBLICA, ¿QUÉ PLAZO TIENE EL SOLICITANTE PARA INTERPONER RECURSO DE APELACIÓN LUEGO DE QUE SU SOLICITUD HA SIDO DENEGADA?', '["EN UN PLAZO NO MAYOR DE 10 DÍAS CALENDARIO","EN UN PLAZO NO MAYOR DE 5 DÍAS CALENDARIO","EN UN PLAZO NO MAYOR DE 15 DÍAS CALENDARIO","EN UN PLAZO NO MAYOR DE 20 DÍAS CALENDARIO","EN UN PLAZO NO MAYOR DE 30 DÍAS CALENDARIO"]'::jsonb, 'EN UN PLAZO NO MAYOR DE 15 DÍAS CALENDARIO', 2, '(texto: 11)** [TITULO III]', '186280', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (536, 536, 'RESPECTO AL PROCEDIMIENTO DE ACCESO A LA INFORMACIÓN PÚBLICA, ¿QUÉ SUCEDE CUANDO EL TRIBUNAL DE TRANSPARENCIA Y ACCESO A LA INFORMACIÓN PÚBLICA NO RESUELVE EL RECURSO DE APELACIÓN EN EL PLAZO MÁXIMO DE 10 DÍAS HÁBILES, ANTE LA DENEGATORIA DE LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA A ENTREGAR LA INFORMACIÓN SOLICITADA?', '["SE PRORROGA EL PLAZO POR 10 DÍAS HÁBILES POR ÚNICA VEZ","EL SOLICITANTE PODRÁ DAR POR AGOTADA LA VÍA ADMINISTRATIVA","EL SOLICITANTE PODRÁ INTERPONER RECURSO EXTRAORDINARIO DE QUEJA ANTE LA AUTORIDAD NACIONAL DE TRANSPARENCIA Y ACCESO A LA INFORMACIÓN PÚBLICA","EL SOLICITANTE PODRÁ RECURRIR ANTE LA AUTORIDAD NACIONAL DE TRANSPARENCIA Y ACCESO A LA INFORMACIÓN PÚBLICA","EL TRIBUNAL DE TRANSPARENCIA Y ACCESO A LA INFORMACIÓN PÚBLICA TENDRÁ UN PLAZO EXTRAORDINARIO DE 5 DÍAS PARA RESOLVER"]'::jsonb, 'EL SOLICITANTE PODRÁ DAR POR AGOTADA LA VÍA ADMINISTRATIVA', 1, '(texto: 11)** [TITULO III]', '186283', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (537, 537, '¿QUIÉNES ESTÁN OBLIGADAS A INFORMAR SOBRE LAS CARACTERÍSTICAS DE LOS SERVICIOS PÚBLICOS QUE PRESTA, SUS TARIFAS Y SOBRE LAS FUNCIONES ADMINISTRATIVAS QUE EJERCE?', '["TODA PERSONA SUJETAS AL RÉGIMEN PRIVADO DESCRITAS EN EL INCISO 8 DEL ARTÍCULO PRIMERO DEL TÍTULO PRELIMINAR DE LA LEY 7444 QUE GESTIONEN SERVICIOS PÚBLICOS O EJERZAN FUNCIONES ADMINISTRATIVAS DEL SECTOR PÚBLICO BAJO CUALQUIER MODALIDAD","TODA PERSONA NATURAL O JURÍDICA SUJETAS AL RÉGIMEN PRIVADO DESCRITAS EN EL INCISO 8 DEL ARTÍCULO PRIMERO DEL TÍTULO PRELIMINAR DE LA LEY 27444 QUE GESTIONEN SERVICIOS PÚBLICOS O EJERZAN FUNCIONES ADMINISTRATIVAS DEL SECTOR PÚBLICO BAJO CUALQUIER MODALIDAD","LAS PERSONAS JURÍDICAS SUJETAS AL RÉGIMEN PRIVADO DESCRITAS EN EL INCISO 8 DEL ARTÍCULO PRIMERO DEL TÍTULO PRELIMINAR DE LA LEY 27444 QUE GESTIONEN SERVICIOS PÚBLICOS O EJERZAN FUNCIONES ADMINISTRATIVAS DEL SECTOR PÚBLICO BAJO CUALQUIER MODALIDAD","TODA PERSONA NATURAL O JURÍDICA SUJETAS AL RÉGIMEN ESPECIAL DESCRITAS EN EL INCISO 8 DEL ARTÍCULO PRIMERO DEL TÍTULO PRELIMINAR DE LA LEY 27444 QUE GESTIONEN SERVICIOS PÚBLICOS O EJERZAN FUNCIONES ADMINISTRATIVAS DEL SECTOR PÚBLICO BAJO CUALQUIER MODALIDAD","LAS PERSONAS JURÍDICAS SUJETAS AL RÉGIMEN ESPECIAL DESCRITAS EN EL INCISO 8 DEL ARTÍCULO PRIMERO DEL TÍTULO PRELIMINAR DE LA LEY 27444 QUE GESTIONEN SERVICIOS PÚBLICOS O EJERZAN FUNCIONES ADMINISTRATIVAS DEL SECTOR PÚBLICO BAJO CUALQUIER MODALIDAD"]'::jsonb, 'LAS PERSONAS JURÍDICAS SUJETAS AL RÉGIMEN PRIVADO DESCRITAS EN EL INCISO 8 DEL ARTÍCULO PRIMERO DEL TÍTULO PRELIMINAR DE LA LEY 27444 QUE GESTIONEN SERVICIOS PÚBLICOS O EJERZAN FUNCIONES ADMINISTRATIVAS DEL SECTOR PÚBLICO BAJO CUALQUIER MODALIDAD', 2, '(texto: 9)** [TITULO III]', '186284', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (538, 538, 'RESPECTO AL PROCEDIMIENTO DE ACCESO A LA INFORMACIÓN PÚBLICA, SABEMOS QUE TODA SOLICITUD DE INFORMACIÓN DEBE SER DIRIGIDA AL FUNCIONARIO DESIGNADO POR LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA PARA REALIZAR ESTA LABOR. EN CASO DE QUE ÉSTE NO HUBIERA SIDO DESIGNADO, ¿A QUIÉN SE DIRIGE LA SOLICITUD?', '["LA SOLICITUD SE DIRIGE A CUALQUIER OTRO FUNCIONARIO PÚBLICO DE LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA","LA SOLICITUD SE DIRIGE AL TITULAR DEL PLIEGO","LA SOLICITUD SE DIRIGE AL DIRECTOR ADMINISTRATIVO DE LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA O QUIEN HAGA SUS VECES","LA SOLICITUD SE DIRIGE AL FUNCIONARIO QUE TIENE EN SU PODER LA INFORMACIÓN REQUERIDA O AL SUPERIOR INMEDIATO","LA SOLICITUD SE DIRIGE A LA SECRETARIA O MESA DE PARTES DE LA OFICINA U ÁREA DE LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA QUE TENGA LA INFORMACIÓN REQUERIDA"]'::jsonb, 'LA SOLICITUD SE DIRIGE AL FUNCIONARIO QUE TIENE EN SU PODER LA INFORMACIÓN REQUERIDA O AL SUPERIOR INMEDIATO', 3, '(texto: 11)** [TITULO III]', '186285', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (539, 539, 'RESPECTO AL PROCEDIMIENTO DE ACCESO A LA INFORMACIÓN PÚBLICA. ¿QUÉ SUCEDE CUÁNDO EXCEPCIONALMENTE PARA LA ENTIDAD, SEA MATERIALMENTE IMPOSIBLE CUMPLIR CON EL PLAZO SEÑALADO EN EL LITERAL B, DEBIDO A CAUSAS JUSTIFICADAS RELACIONADAS A LA COMPROBADA Y MANIFIESTA FALTA DE CAPACIDAD LOGÍSTICA, U OPERATIVA, O DE RECURSOS HUMANOS DE LA ENTIDAD, O AL SIGNIFICATIVO VOLUMEN DE LA INFORMACIÓN SOLICITADA?', '["EL SOLICITANTE PUEDE INTERPONER EL RECURSO DE APELACIÓN ANTE EL TRIBUNAL DE TRANSPARENCIA Y ACCESO A LA INFORMACIÓN PÚBLICA","EL SOLICITANTE PUEDE CONSIDERAR DENEGADO SU PEDIDO","EL SOLICITANTE PODRÁ RECURRIR EN QUEJA ANTE AUTORIDAD NACIONAL DE TRANSPARENCIA Y ACCESO A LA INFORMACIÓN PÚBLICA","EL SOLICITANTE PODRÁ DAR POR AGOTADA LA VÍA ADMINISTRATIVA","POR ÚNICA VEZ LA ENTIDAD DEBE COMUNICAR AL SOLICITANTE LA FECHA EN QUE PROPORCIONARÁ LA INFORMACIÓN SOLICITADA DE FORMA DEBIDAMENTE FUNDAMENTADA"]'::jsonb, 'POR ÚNICA VEZ LA ENTIDAD DEBE COMUNICAR AL SOLICITANTE LA FECHA EN QUE PROPORCIONARÁ LA INFORMACIÓN SOLICITADA DE FORMA DEBIDAMENTE FUNDAMENTADA', 4, '(texto: 11)** [TITULO III]', '186288', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (540, 540, 'PROMOVER LA TRANSPARENCIA DE LOS ACTOS DEL ESTADO Y REGULAR EL DERECHO FUNDAMENTAL DEL ACCESO A LA INFORMACIÓN CONSAGRADO EN EL NUMERAL 5 DEL ARTÍCULO 2 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ, CONSTITUYE:', '["ALCANCE DE LA LEY 27806","EL OBJETO DE LA LEY 27806","LA NATURALEZA DE LA LEY 27806","EL OBJETIVO DE LA LEY 27806","EL OBJETO DEL REGLAMENTO DE LA LEY 27806"]'::jsonb, 'ALCANCE DE LA LEY 27806', 0, '(texto: 1)** [TITULO I]', '186289', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (541, 541, 'LA PRESENTE LEY TIENE POR FINALIDAD PROMOVER LA TRANSPARENCIA DE LOS ACTOS DEL ESTADO Y REGULAR EL DERECHO FUNDAMENTAL DEL ACCESO A LA INFORMACIÓN CONSAGRADO EN EL:', '["NUMERAL 2 DEL ARTÍCULO 2 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ","NUMERAL 4 DEL ARTÍCULO 2 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ","NUMERAL 24 DEL ARTÍCULO 2 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ","NUMERAL 1 DEL ARTÍCULO 2 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ","NUMERAL 5 DEL ARTÍCULO 2 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ"]'::jsonb, 'NUMERAL 5 DEL ARTÍCULO 2 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ', 4, '(texto: 1)** [TITULO I]', '186290', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (542, 542, 'PARA EFECTOS DE LA PRESENTE LEY SE ENTIENDE POR ENTIDADES DE LA ADMINISTRACIÓN PÚBLICA A LAS SEÑALADAS EN EL:', '["ARTÍCULO 1 DEL TÍTULO I DE LA LEY 27444","ARTÍCULO 1 DEL TÍTULO III DE LA LEY 27444","ARTÍCULO SEGUNDO DEL TÍTULO PRELIMINAR DE LA LEY 27444","ARTÍCULO 2 DEL TÍTULO PRELIMINAR DE LA LEY 27444","ARTÍCULO PRIMERO DEL TÍTULO SEGUNDO DE LA LEY 27444"]'::jsonb, 'ARTÍCULO 1 DEL TÍTULO I DE LA LEY 27444', 0, '(texto: 2)** [TITULO I]', '186291', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (543, 543, 'RESPECTO AL PROCEDIMIENTO DE ACCESO A LA INFORMACIÓN PÚBLICA, ¿QUÉ SUCEDE EN EL SUPUESTO QUE LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA NO ESTÉ OBLIGADA A POSEER LA INFORMACIÓN SOLICITADA Y CONOZCA SU UBICACIÓN O DESTINO?', '["LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA DEBE PONER EN CONOCIMIENTO DE DICHA CIRCUNSTANCIA AL SOLICITANTE PARA QUE ÉSTE LO RE ENCAUSE","LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA DEBE RE ENCAUSAR LA SOLICITUD HACIA LA ENTIDAD OBLIGADA O HACIA LA QUE LA POSEA, Y PONER EN CONOCIMIENTO DE DICHA CIRCUNSTANCIA AL SOLICITANTE","LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA DEBE DEVOLVER LA SOLICITUD AL SOLICITANTE Y HACERLE CONOCER DICHA CIRCUNSTANCIA","LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA DEBE PONER EN CONOCIMIENTO DE DICHA CIRCUNSTANCIA AL SOLICITANTE","EL SOLICITANTE DEBE RE ENCAUSAR SU PEDIDO HACIA LA ENTIDAD QUE POSEA LA INFORMACIÓN SOLICITADA, PREVIA DEVOLUCIÓN DE SU SOLICITUD, LA MISMA QUE DEBE NOTIFICARSE DENTRO DE LOS 3 DÍAS HÁBILES DE RECIBIDA"]'::jsonb, 'LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA DEBE RE ENCAUSAR LA SOLICITUD HACIA LA ENTIDAD OBLIGADA O HACIA LA QUE LA POSEA, Y PONER EN CONOCIMIENTO DE DICHA CIRCUNSTANCIA AL SOLICITANTE', 1, '(texto: 11)** [TITULO III]', '186292', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (544, 544, 'RESPECTO AL PROCEDIMIENTO DE ACCESO A LA INFORMACIÓN PÚBLICA, LA DENEGATORIA AL ACCESO A LA INFORMACIÓN SE SUJETA A LO DISPUESTO EN EL SEGUNDO PÁRRAFO DEL ARTÍCULO:', '["15 DE LA PRESENTE LEY","7 DE LA PRESENTE LEY","16 DE LA PRESENTE LEY","18 DE LA PRESENTE LEY","13 DE LA PRESENTE LEY"]'::jsonb, '13 DE LA PRESENTE LEY', 4, '(texto: 11)** [TITULO III]', '186293', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (545, 545, 'EL MINISTERIO DE ECONOMÍA Y FINANZAS PUBLICARÁ, ADICIONALMENTE A LO ESTABLECIDO EN EL ARTÍCULO 25 DE LA PRESENTE NORMA, LOS PROYECTOS DE LA LEY DE ENDEUDAMIENTO, EQUILIBRIO FINANCIERO Y PRESUPUESTO Y SU EXPOSICIÓN DE MOTIVOS, DENTRO DE:', '["LOS 2 PRIMEROS DÍAS HÁBILES DE OCTUBRE","LOS 2 PRIMEROS DÍAS HÁBILES DE AGOSTO","LOS 2 PRIMEROS DÍAS HÁBILES DE SETIEMBRE","LOS 2 PRIMEROS DÍAS HÁBILES DE DICIEMBRE","LOS 2 PRIMEROS DÍAS HÁBILES DE NOVIEMBRE"]'::jsonb, 'LOS 2 PRIMEROS DÍAS HÁBILES DE SETIEMBRE', 2, '(texto: 26)** [TITULO IV] [CAPITULO I]', '186295', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (546, 546, 'RESPECTO A LA DENEGATORIA DE ACCESO A LA INFORMACIÓN PÚBLICA; SI EL REQUERIMIENTO DE INFORMACIÓN NO HUBIERE SIDO SATISFECHO, LA RESPUESTA HUBIERE SIDO AMBIGUA, O NO SE HUBIEREN CUMPLIDO LAS EXIGENCIAS PRECEDENTES, SE CONSIDERARÁ QUE EXISTIÓ:', '["NEGLIGENCIA EN BRINDARLA","NEGATIVA EN BRINDARLA","IMPEDIMENTO EN BRINDARLA","DENEGATORIA EN BRINDARLA","VOLUNTAD MANIFIESTA EN DENEGARLA"]'::jsonb, 'NEGATIVA EN BRINDARLA', 1, '(texto: 13)** [TITULO III]', '186296', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (547, 547, 'RESPECTO A LA DENEGATORIA DE ACCESO A LA INFORMACIÓN PÚBLICA; NO SE PODRÁ NEGAR INFORMACIÓN CUANDO SE SOLICITE QUE ESTA SEA ENTREGADA EN UNA DETERMINADA FORMA O MEDIO, SIEMPRE QUE:', '["LA ENTIDAD ASUMA EL COSTO QUE SUPONGA EL PEDIDO","SE TENGA LA LOGÍSTICA NECESARIA PARA ATENDER EL PEDIDO","EL SOLICITANTE ASUMA EL COSTO QUE SUPONGA EL PEDIDO","EL PEDIDO NO REPRESENTE NINGÚN COSTO","EL SOLICITANTE SEA OTRA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA"]'::jsonb, 'EL SOLICITANTE ASUMA EL COSTO QUE SUPONGA EL PEDIDO', 2, '(texto: 13)** [TITULO III]', '186297', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (548, 548, '"SE APLICA A TODAS LAS INSTITUCIONES INTEGRANTES DEL SISTEMA DE JUSTICIA: PODER JUDICIAL, MINISTERIO PÚBLICO, JUNTA NACIONAL DE JUSTICIA, TRIBUNAL CONSTITUCIONAL Y ACADEMIA DE LA MAGISTRATURA". EL PÁRRAFO ANTERIOR SE REFIERE A:', '["ÁMBITO DE APLICACIÓN","TRANSPARENCIA EN LOS PODERES DEL ESTADO","TRANSPARENCIA EN EL PODER JUDICIAL","ÁMBITO DE APLICACIÓN DE TRANSPARENCIA EN EL PODER JUDICIAL","RÉGIMEN DE TRANSPARENCIA EN EL SISTEMA JUDICIAL"]'::jsonb, 'ÁMBITO DE APLICACIÓN', 0, '(texto: 38)** [TITULO VI]', '186298', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (556, 556, 'EL OSCE PUBLICARÁ TRIMESTRALMENTE:', '["EL PRESUPUESTO EN FORMA CONSOLIDADA, ANTES DEL 31 DE DICIEMBRE DEL AÑO PREVIO AL INICIO DEL PERÍODO DE EJECUCIÓN PRESUPUESTAL","EL BALANCE, ASÍ COMO LA CUENTA DE AHORRO, INVERSIÓN Y FINANCIAMIENTO, TRIMESTRALMENTE","LOS ESTADOS FINANCIEROS AUDITADOS, DENTRO DE LOS 120 DÍAS CALENDARIO DE CONCLUIDO EL EJERCICIO FISCAL","LA INFORMACIÓN DE LAS ADQUISICIONES Y CONTRATACIONES REALIZADAS POR LAS ENTIDADES DE LA ADMINISTRACIÓN PÚBLICA, CUYO VALOR REFERENCIAL HAYA SIDO IGUAL O SUPERIOR A 50 UNIDADES IMPOSITIVAS TRIBUTARIAS","LOS INDICADORES DE GESTIÓN QUE LE SERÁN APLICADOS, CUANDO SE HAYAN CELEBRADO CONVENIOS DE GESTIÓN"]'::jsonb, 'LA INFORMACIÓN DE LAS ADQUISICIONES Y CONTRATACIONES REALIZADAS POR LAS ENTIDADES DE LA ADMINISTRACIÓN PÚBLICA, CUYO VALOR REFERENCIAL HAYA SIDO IGUAL O SUPERIOR A 50 UNIDADES IMPOSITIVAS TRIBUTARIAS', 3, '(texto: 29)** [TITULO IV] [CAPITULO I]', '186307', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (549, 549, 'EL MINISTERIO DE ECONOMÍA Y FINANZAS PUBLICARÁ, ADICIONALMENTE A LO ESTABLECIDO EN EL ARTÍCULO 25 DE LA PRESENTE NORMA, LOS INGRESOS Y GASTOS DEL GOBIERNO CENTRAL E INSTANCIAS DESCENTRALIZADAS COMPRENDIDAS EN LA LEY DE PRESUPUESTO DEL SECTOR PÚBLICO, DE CONFORMIDAD CON LOS CLASIFICADORES DE INGRESOS, GASTOS Y FINANCIAMIENTO VIGENTE, TRIMESTRALMENTE, INCLUYENDO EL PRESUPUESTO ANUAL Y EL DEVENGADO, DE ACUERDO A LOS SIGUIENTES CRITERIOS:', '["CLASIFICADOR PROGRAMÁTICO (FUNCIÓN/PROGRAMA); POR GENÉRICA DE GASTO; Y POR FUENTE DE FINANCIAMIENTO","CLASIFICADOR FUNCIONAL (FUNCIÓN/PROGRAMA); POR GENÉRICA DE GASTO; Y POR FUENTE DE ENDEUDAMIENTO","IDENTIFICACIÓN INSTITUCIONAL; POR GENÉRICA DE INGRESO; Y POR FUENTE DE FINANCIAMIENTO","CLASIFICADOR FUNCIONAL (FUNCIÓN/PROGRAMA)Y POR GENÉRICA DE GASTO","IDENTIFICACIÓN INSTITUCIONAL; CLASIFICADOR FUNCIONAL (FUNCIÓN/PROGRAMA); POR GENÉRICA DE GASTO; Y POR FUENTE DE FINANCIAMIENTO"]'::jsonb, 'IDENTIFICACIÓN INSTITUCIONAL; CLASIFICADOR FUNCIONAL (FUNCIÓN/PROGRAMA); POR GENÉRICA DE GASTO; Y POR FUENTE DE FINANCIAMIENTO', 4, '(texto: 26)** [TITULO IV] [CAPITULO I]', '186299', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (550, 550, 'RESPECTO A LA DENEGATORIA DE ACCESO A LA INFORMACIÓN PÚBLICA INDIQUE LA RESPUESTA CORRECTA:', '["LA DENEGATORIA AL ACCESO A LA INFORMACIÓN SOLICITADA DEBE SER DEBIDAMENTE FUNDAMENTADA POR LAS EXCEPCIONES DE LOS ARTÍCULOS 15 A 17 DE ESTA LEY; Y EL PLAZO POR EL QUE SE PROLONGARÁ DICHO IMPEDIMENTO","LA SOLICITUD DE INFORMACIÓN IMPLICA LA OBLIGACIÓN DE LAS ENTIDADES DE LA ADMINISTRACIÓN PÚBLICA DE CREAR O PRODUCIR INFORMACIÓN CON LA QUE NO CUENTE O NO TENGA OBLIGACIÓN DE CONTAR AL MOMENTO DE EFECTUARSE EL PEDIDO","LA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA DEBERÁ COMUNICAR POR ESCRITO QUE LA DENEGATORIA DE LA SOLICITUD SE DEBE A LA EXISTENCIA DE DATOS EN SU PODER RESPECTO DE LA INFORMACIÓN SOLICITADA","ESTA LEY FACULTA QUE LOS SOLICITANTES EXIJAN A LAS ENTIDADES QUE EFECTÚEN EVALUACIONES O ANÁLISIS DE LA INFORMACIÓN QUE POSEAN","NO CALIFICA EN ESTA LIMITACIÓN EL PROCESAMIENTO DE DATOS PREEXISTENTES DE ACUERDO CON LO QUE ESTABLEZCAN LAS NORMAS REGLAMENTARIAS, SALVO QUE ELLO NO IMPLIQUE RECOLECTAR O GENERAR NUEVOS DATOS"]'::jsonb, 'LA DENEGATORIA AL ACCESO A LA INFORMACIÓN SOLICITADA DEBE SER DEBIDAMENTE FUNDAMENTADA POR LAS EXCEPCIONES DE LOS ARTÍCULOS 15 A 17 DE ESTA LEY; Y EL PLAZO POR EL QUE SE PROLONGARÁ DICHO IMPEDIMENTO', 0, '(texto: 13)** [TITULO III]', '186300', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (600, 600, 'ES LA PROMOCIÓN DEL OFICIAL Y SUBOFICIAL EN SITUACIÓN DE ACTIVIDAD AL GRADO POLICIAL INMEDIATO SUPERIOR. NOS REFERIMOS A:', '["ASCENSO","PROMOVER","ACCESO ORDINARIO","ACCESO EXTRAORDINARIO","EL GRADO"]'::jsonb, 'ASCENSO', 0, '(texto: 4)** [TITULO II] [CAPITULO I]', '186717', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (551, 551, 'EL MINISTERIO DE ECONOMÍA Y FINANZAS PUBLICARÁ, ADICIONALMENTE A LO ESTABLECIDO EN EL ARTÍCULO 25 DE LA PRESENTE NORMA, LOS INGRESOS Y GASTOS DEL GOBIERNO CENTRAL E INSTANCIAS DESCENTRALIZADAS COMPRENDIDAS EN LA LEY DE PRESUPUESTO DEL SECTOR PÚBLICO, DE CONFORMIDAD CON LOS CLASIFICADORES DE INGRESOS, GASTOS Y FINANCIAMIENTO VIGENTE, TRIMESTRALMENTE, INCLUYENDO:', '["INGRESOS Y GASTOS","GASTOS DE CAPITAL","INGRESOS DE CAPITAL","EL PRESUPUESTO ANUAL Y EL DEVENGADO","CUENTAS POR PAGAR"]'::jsonb, 'EL PRESUPUESTO ANUAL Y EL DEVENGADO', 3, '(texto: 26)** [TITULO IV] [CAPITULO I]', '186302', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (552, 552, 'INDIQUE TODAS LAS INSTITUCIONES QUE CONFORMAN EL SISTEMA DE JUSTICIA:', '["PODER JUDICIAL, MINISTERIO PÚBLICO, JUNTA NACIONAL DE JUSTICIA, Y TRIBUNAL CONSTITUCIONAL","SISTEMA JUDICIAL, MINISTERIO PÚBLICO, JUNTA NACIONAL DE JUSTICIA, Y TRIBUNAL CONSTITUCIONAL","PODER JUDICIAL, MINISTERIO PÚBLICO, TRIBUNAL CONSTITUCIONAL Y ACADEMIA DE LA MAGISTRATURA","PODER JUDICIAL, MINISTERIO PÚBLICO, Y TRIBUNAL CONSTITUCIONAL","PODER JUDICIAL, MINISTERIO PÚBLICO, JUNTA NACIONAL DE JUSTICIA, TRIBUNAL CONSTITUCIONAL Y ACADEMIA DE LA MAGISTRATURA"]'::jsonb, 'PODER JUDICIAL, MINISTERIO PÚBLICO, JUNTA NACIONAL DE JUSTICIA, TRIBUNAL CONSTITUCIONAL Y ACADEMIA DE LA MAGISTRATURA', 4, '(texto: 38)** [TITULO VI]', '186303', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (553, 553, 'INCLUIRÁ UN CUADRO DE CONSISTENCIA CON EL MARCO MACROECONÓMICO MULTIANUAL, DESAGREGADO LOS INGRESOS, GASTOS Y RESULTADO ECONÓMICO PARA EL CONJUNTO DE LAS ENTIDADES DENTRO DEL ÁMBITO DE LA LEY ANUAL DE PRESUPUESTO, DEL RESTO DE ENTIDADES QUE CONFORMAN EL SECTOR PÚBLICO CONSOLIDADO:', '["LA EXPOSICIÓN DE MOTIVOS DE LA LEY ANUAL DE ENDEUDAMIENTO","LA EXPOSICIÓN DE MOTIVOS DE LA LEY DE EQUILIBRIO FINANCIERO","LA EXPOSICIÓN DE MOTIVOS DE LA LEY ANUAL DE PRESUPUESTO","LA EXPOSICIÓN DE MOTIVOS DE LA LEY MARCO DEL SISTEMA FINANCIERO DEL ESTADO","LA EXPOSICIÓN DE MOTIVOS DE LA LEY DE ESTADOS FINANCIEROS DEL ESTADO"]'::jsonb, 'LA EXPOSICIÓN DE MOTIVOS DE LA LEY ANUAL DE PRESUPUESTO', 2, '(texto: 31)** [TITULO IV] [CAPITULO II]', '186304', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (554, 554, 'TODO PROYECTO DE LEY QUE MODIFIQUE EL GASTO TRIBUTARIO, DEBERÁ ESTAR ACOMPAÑADO DE UNA:', '["ESTIMACIÓN TRIMESTRAL DEL IMPACTO QUE DICHA MEDIDA TENDRÍA SOBRE EL PRESUPUESTO PÚBLICO Y SU EFECTO POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA","ESTIMACIÓN SEMESTRAL DEL IMPACTO QUE DICHA MEDIDA TENDRÍA SOBRE EL PRESUPUESTO PÚBLICO Y SU EFECTO POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA","ESTIMACIÓN BI ANUAL DEL IMPACTO QUE DICHA MEDIDA TENDRÍA SOBRE EL PRESUPUESTO PÚBLICO Y SU EFECTO POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA","ESTIMACIÓN PERIÓDICA DEL IMPACTO QUE DICHA MEDIDA TENDRÍA SOBRE EL PRESUPUESTO PÚBLICO Y SU EFECTO POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA","ESTIMACIÓN ANUAL DEL IMPACTO QUE DICHA MEDIDA TENDRÍA SOBRE EL PRESUPUESTO PÚBLICO Y SU EFECTO POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA"]'::jsonb, 'ESTIMACIÓN ANUAL DEL IMPACTO QUE DICHA MEDIDA TENDRÍA SOBRE EL PRESUPUESTO PÚBLICO Y SU EFECTO POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA', 4, '(texto: 30)** [TITULO IV] [CAPITULO II]', '186305', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (555, 555, 'CONJUNTAMENTE CON LA LEY DE PRESUPUESTO, LA LEY DE EQUILIBRIO FINANCIERO Y LA LEY DE ENDEUDAMIENTO INTERNO Y EXTERNO, EL PODER EJECUTIVO REMITIRÁ AL CONGRESO:', '["UN INFORME DETALLADO Y DOCUMENTADO DEL EFECTO QUE TENDRÁ EL DESTINO DEL PRESUPUESTO PÚBLICO, POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA","UN ESTIMADO DEL EFECTO QUE TENDRÁ EL DESTINO DEL PRESUPUESTO, POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA","UN ESTIMADO DEL EFECTO QUE TENDRÁ EL DESTINO DEL GASTO TRIBUTARIO, POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA","UN ESTIMADO DEL EFECTO QUE TENDRÁ EL DESTINO DEL GASTO PÚBLICO, POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA","UN ESTIMADO DEL EFECTO QUE TENDRÁ EL DESTINO DE LOS INGRESOS TRIBUTARIOS, POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA"]'::jsonb, 'UN ESTIMADO DEL EFECTO QUE TENDRÁ EL DESTINO DEL GASTO TRIBUTARIO, POR REGIONES, SECTORES ECONÓMICOS Y SOCIALES, SEGÚN SU NATURALEZA', 2, '(texto: 30)** [TITULO IV] [CAPITULO II]', '186306', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (557, 557, 'EL OSCE PUBLICARÁ, TRIMESTRALMENTE, INFORMACIÓN DE LAS ADQUISICIONES Y CONTRATACIONES REALIZADAS POR LAS ENTIDADES DE LA ADMINISTRACIÓN PÚBLICA, CUYO VALOR REFERENCIAL HAYA SIDO IGUAL O SUPERIOR A:', '["100 UNIDADES IMPOSITIVAS TRIBUTARIAS","80 UNIDADES IMPOSITIVAS TRIBUTARIAS","50 UNIDADES IMPOSITIVAS TRIBUTARIAS","30 UNIDADES IMPOSITIVAS TRIBUTARIAS","90 UNIDADES IMPOSITIVAS TRIBUTARIAS"]'::jsonb, '50 UNIDADES IMPOSITIVAS TRIBUTARIAS', 2, '(texto: 29)** [TITULO IV] [CAPITULO I]', '186308', '2026-07-14T01:12:29.113429+00:00');
