INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (559, 559, 'LA ONP, EN CALIDAD DE SECRETARÍA TÉCNICA DEL FONDO CONSOLIDADO DE RESERVA PREVISIONAL (FCR), PUBLICARÁ, ADICIONALMENTE A LO ESTABLECIDO EN EL ARTÍCULO 25, LA INFORMACIÓN REFERENTE A LA SITUACIÓN DE LOS ACTIVOS FINANCIEROS DEL FCR Y DEL FONAHPU, COLOCADOS EN LAS ENTIDADES FINANCIERAS Y NO FINANCIERAS Y EN ORGANISMOS MULTILATERALES DONDE SE ENCUENTREN DEPOSITADOS LOS RECURSOS DE LOS REFERIDOS FONDOS, ASÍ COMO LOS COSTOS DE ADMINISTRACIÓN, LAS TASAS DE INTERÉS, Y LOS INTERESES DEVENGADOS:', '["BIMESTRALMENTE","ANUALMENTE","TRIMESTRALMENTE","ANTES DEL 31 DE MARZO DE CADA AÑO","ANTES DEL 31 DE DICIEMBRE DE CADA AÑO"]'::jsonb, 'TRIMESTRALMENTE', 2, '(texto: 28)** [TITULO IV] [CAPITULO I]', '186310', '2026-07-14T01:12:29.113429+00:00');
