INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (567, 567, 'LAS ENTIDADES QUE FORMAN PARTE DEL SISTEMA DE JUSTICIA ESTÁN OBLIGADAS A PUBLICAR EN SUS RESPECTIVOS PORTALES DE TRANSPARENCIA, POR LO MENOS, LA SIGUIENTE INFORMACIÓN:', '["LOS INFORMES TRIMESTRALES DE LAS ENTIDADES QUE INTEGRAN EL SISTEMA DE JUSTICIA SOBRE LAS ACTIVIDADES REALIZADAS EN EL MARCO DE SUS COMPETENCIAS","LOS INFORMES ELABORADOS POR LAS OFICINAS DE CONTROL DEL PODER JUDICIAL Y DEL MINISTERIO PÚBLICO O LAS QUE HAGAN SUS VECES","LOS INFORMES ELABORADOS POR EL PODER JUDICIAL Y EL MINISTERIO PÚBLICO","LA DECLARACIÓN JURADA DE CONFLICTOS DE LOS JUECES, FISCALES Y, EN GENERAL, DE LOS MIEMBROS DEL SISTEMA DE JUSTICIA","LA DECLARACIÓN JURADA DE INGRESOS Y RENTAS DE LOS JUECES, FISCALES Y, EN GENERAL, DE LOS MIEMBROS DEL SISTEMA DE JUSTICIA"]'::jsonb, 'LOS INFORMES ELABORADOS POR LAS OFICINAS DE CONTROL DEL PODER JUDICIAL Y DEL MINISTERIO PÚBLICO O LAS QUE HAGAN SUS VECES', 1, '(texto: 39)** [TITULO VI]', '186324', '2026-07-14T01:12:29.113429+00:00');
