INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (569, 569, '¿QUÉ DEBE SER PUBLICADO POR LAS ENTIDADES QUE FORMAN PARTE DEL SISTEMA DE JUSTICIA EN SUS RESPECTIVOS PORTALES DE TRANSPARENCIA, CON UNA SUMILLA EN LENGUAJE SENCILLO Y AMIGABLE, CONFORME A LOS LINEAMIENTOS Y DIRECTRICES ESTABLECIDOS POR EL MINISTERIO DE JUSTICIA Y DERECHOS HUMANOS, A TRAVÉS DE LA AUTORIDAD NACIONAL DE PROTECCIÓN DE DATOS PERSONALES, Y EN COORDINACIÓN CON EL PODER JUDICIAL Y EL MINISTERIO PÚBLICO?', '["LA HOJA DE VIDA DEL JUEZ O DEL FISCAL, DE LOS MIEMBROS DE LA JUNTA NACIONAL DE JUSTICIA, DEL TRIBUNAL CONSTITUCIONAL Y DEL CONSEJO DIRECTIVO DE LA ACADEMIA DE LA MAGISTRATURA","LA DECLARACIÓN JURADA DE INTERESES DE LOS JUECES, FISCALES Y, EN GENERAL, DE LOS MIEMBROS DEL SISTEMA DE JUSTICIA","TODAS LAS SENTENCIAS JUDICIALES, DICTÁMENES FISCALES Y JURISPRUDENCIA","LA RELACIÓN DE ENTREVISTAS Y VISITAS QUE TENGAN LOS JUECES Y FISCALES Y, EN GENERAL, DE LOS MIEMBROS DE LA JUNTA NACIONAL DE JUSTICIA, DEL TRIBUNAL CONSTITUCIONAL Y DE LA ACADEMIA DE LA MAGISTRATURA","LOS INFORMES ANUALES DE LAS ENTIDADES QUE INTEGRAN EL SISTEMA DE JUSTICIA"]'::jsonb, 'TODAS LAS SENTENCIAS JUDICIALES, DICTÁMENES FISCALES Y JURISPRUDENCIA', 2, '(texto: 39)** [TITULO VI]', '186328', '2026-07-14T01:12:29.113429+00:00');
