INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (581, 581, 'LAS ENTIDADES DE LA ADMINISTRACIÓN PÚBLICA CUYO PRESUPUESTO NO FORME PARTE DEL PRESUPUESTO GENERAL DE LA REPÚBLICA, DEBEN APROBAR ÉSTE A MÁS TARDAR AL:', '["30 DE DICIEMBRE DEL AÑO PREVIO A SU ENTRADA EN VIGENCIA, POR EL ÓRGANO CORRESPONDIENTE ESTABLECIDO EN LAS NORMAS VIGENTES","31 DE DICIEMBRE DEL AÑO PREVIO A SU ENTRADA EN VIGENCIA, POR EL ÓRGANO CORRESPONDIENTE ESTABLECIDO EN LAS NORMAS VIGENTES","31 DE MARZO DEL AÑO PREVIO A SU ENTRADA EN VIGENCIA, POR EL ÓRGANO CORRESPONDIENTE ESTABLECIDO EN LAS NORMAS VIGENTES","30 DE AGOSTO DEL AÑO PREVIO A SU ENTRADA EN VIGENCIA, POR EL ÓRGANO CORRESPONDIENTE ESTABLECIDO EN LAS NORMAS VIGENTES","15 DE DICIEMBRE DEL AÑO PREVIO A SU ENTRADA EN VIGENCIA, POR EL ÓRGANO CORRESPONDIENTE ESTABLECIDO EN LAS NORMAS VIGENTES"]'::jsonb, '15 DE DICIEMBRE DEL AÑO PREVIO A SU ENTRADA EN VIGENCIA, POR EL ÓRGANO CORRESPONDIENTE ESTABLECIDO EN LAS NORMAS VIGENTES', 4, '(texto: 33)** [TITULO IV] [CAPITULO II]', '186341', '2026-07-14T01:12:29.113429+00:00');
