INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (584, 584, 'EL MINISTERIO DE ECONOMÍA Y FINANZAS PUBLICARÁ, ADICIONALMENTE A LO ESTABLECIDO EN EL ARTÍCULO 25 DE LA PRESENTE NORMA, LA SIGUIENTE INFORMACIÓN:', '["INFORMACIÓN CONTENIDA EN EL REGISTRO DE PROCESOS DE SELECCIÓN DE CONTRATACIONES Y ADQUISICIONES, ESPECIFICANDO: LOS VALORES REFERENCIALES, NOMBRES DE CONTRATISTAS, MONTOS DE LOS CONTRATOS, PENALIDADES Y SANCIONES Y COSTO FINAL, DE SER EL CASO","LOS PROGRESOS REALIZADOS EN LOS INDICADORES DE DESEMPEÑO ESTABLECIDOS EN LOS PLANES ESTRATÉGICOS INSTITUCIONALES O EN LOS INDICADORES QUE LES SERÁN APLICADOS, EN EL CASO DE ENTIDADES QUE HAYAN SUSCRITO CONVENIOS DE GESTIÓN","SU PRESUPUESTO, ESPECIFICANDO: LOS INGRESOS, GASTOS, FINANCIAMIENTO, Y RESULTADOS OPERATIVOS DE CONFORMIDAD CON LOS CLASIFICADORES PRESUPUESTALES VIGENTES","EL BALANCE DEL FONDO DE ESTABILIZACIÓN FISCAL (FEF) DENTRO DE LOS 30 DÍAS CALENDARIO DE CONCLUIDO EL EJERCICIO FISCAL","LOS PROYECTOS DE INVERSIÓN PÚBLICA EN EJECUCIÓN, ESPECIFICANDO: EL PRESUPUESTO TOTAL DE PROYECTO, EL PRESUPUESTO DEL PERÍODO CORRESPONDIENTE Y SU NIVEL DE EJECUCIÓN Y EL PRESUPUESTO ACUMULADO"]'::jsonb, 'EL BALANCE DEL FONDO DE ESTABILIZACIÓN FISCAL (FEF) DENTRO DE LOS 30 DÍAS CALENDARIO DE CONCLUIDO EL EJERCICIO FISCAL', 3, '(texto: 26)** [TITULO IV] [CAPITULO I]', '186345', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (601, 601, 'LOS PROCESOS DE ASCENSO SON ANUALES. EL CRONOGRAMA DE SUS ETAPAS PARA OFICIALES Y SUBOFICIALES ES APROBADO Y PUBLICADO ANUALMENTE. ÚNICAMENTE SE AGREGA AL LEGAJO DE ASCENSO LA INFORMACIÓN QUE CORRESPONDA AL AÑO ANTERIOR A LA CONVOCATORIA AL PROCESO HASTA EL ÚLTIMO DÍA HÁBIL DEL MES DE....:', '["ABRIL DEL AÑO DEL PROCESO","JUNIO DEL AÑO DEL PROCESO","MARZO DEL AÑO DEL PROCESO","JULIO DEL AÑO DEL PROCESO","MAYO DEL AÑO DEL PROCESO"]'::jsonb, 'MARZO DEL AÑO DEL PROCESO', 2, '(texto: 5)** [TITULO II] [CAPITULO I]', '186719', '2026-07-14T01:12:29.113429+00:00');
