INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (631, 631, 'RESPECTO DE LA NULIDAD DE LOS ACTOS ADMINISTRATIVOS, SEÑALE USTED EL CONCEPTO INCORRECTO:', '["LOS ADMINISTRADOS LA PLANTEAN POR MEDIO DE LOS RECURSOS ADMINISTRATIVOS","LA NULIDAD SERÁ CONOCIDA Y DECLARADA POR LA AUTORIDAD SUPERIOR DE QUIEN DICTÓ EL ACTO","SI SE TRATARA DE UN ACTO DICTADO POR UNA AUTORIDAD QUE NO ESTÁ SOMETIDA A SUBORDINACIÓN JERÁRQUICA, LA NULIDAD SE DECLARARÁ POR RESOLUCIÓN DE LA MISMA AUTORIDAD","LA RESOLUCIÓN QUE DECLARA LA NULIDAD, ADEMÁS DISPONDRÁ LO CONVENIENTE PARA HACER EFECTIVA LA RESPONSABILIDAD DEL EMISOR DEL ACTO INVÁLIDO","RESPECTO DEL ACTO DECLARADO NULO, LOS SERVIDORES PÚBLICOS DEBERÁN OPONERSE A SU EJECUCIÓN, FUNDANDO Y MOTIVANDO SU NEGATIVA"]'::jsonb, 'RESPECTO DEL ACTO DECLARADO NULO, LOS SERVIDORES PÚBLICOS DEBERÁN OPONERSE A SU EJECUCIÓN, FUNDANDO Y MOTIVANDO SU NEGATIVA', 4, '(ART: 11)** [TITULO I] [CAPITULO II]', '181833', '2026-07-14T01:12:29.113429+00:00');
