INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (640, 640, 'EN EL ARTÍCULO VI - TÍTULO PRELIMINAR DE LA LEY 27444 - PRECEDENTES ADMINISTRATIVOS:', '["LA SOLA MODIFICACIÓN DE LOS CRITERIOS NO FACULTA A LA REVISIÓN DE OFICIO, EN SEDE ADMINISTRATIVA DE LOS ACTOS FIRMES","LA MODIFICACIÓN DE LOS CRITERIOS FACULTA A LA REVISIÓN DE OFICIO, EN SEDE ADMINISTRATIVA DE LOS ACTOS FIRMES","LA SOLA MODIFICACIÓN DE LOS CRITERIOS NO FACULTA A LA REVISIÓN DE PARTE, EN SEDE ADMINISTRATIVA DE LOS ACTOS FIRMES","LA SOLA MODIFICACIÓN DE LOS CRITERIOS FACULTA A LA REVISIÓN DE OFICIO, EN SEDE ADMINISTRATIVA DE LOS ACTOS CONSENTIDOS","LA MODIFICACIÓN DE LOS CRITERIOS FACULTA A LA REVISIÓN DE OFICIO, EN SEDE ADMINISTRATIVA DE LOS ACTOS EJECUTADOS"]'::jsonb, 'LA SOLA MODIFICACIÓN DE LOS CRITERIOS NO FACULTA A LA REVISIÓN DE OFICIO, EN SEDE ADMINISTRATIVA DE LOS ACTOS FIRMES', 0, '(ART: VI)** [TITULO PRELIMINAR]', '181843', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (641, 641, 'PRECISE MEDIANTE QUE RECURSOS PROCEDE LA CONTRADICCIÓN EN LA VÍA ADMINISTRATIVA:', '["RECURSO DE IMPUGNACIÓN","RECURSOS ADMINISTRATIVOS","RECURSOS DE LA DOBLE INSTANCIA","RECURSO DE CONTRADICCIÓN","RECURSO DE HÁBEAS DATA"]'::jsonb, 'RECURSOS ADMINISTRATIVOS', 1, '(ART: 206)** [TITULO III] [CAPITULO II]', '181844', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (642, 642, 'TITULO I. CAPÍTULO I. DE LOS ACTOS ADMINISTRATIVOS.- ARTÍCULO 3 - REQUISITOS DE VALIDEZ DE LOS ACTOS ADMINISTRATIVOS.- SON REQUISITOS DE VALIDEZ DE LOS ACTOS ADMINISTRATIVOS: (SEÑALE EL INCORRECTO):', '["LA COMPETENCIA","OBJETO O CONTENIDO","FINALIDAD PÚBLICA","MOTIVACIÓN","PROCEDIMIENTO SINGULAR"]'::jsonb, 'PROCEDIMIENTO SINGULAR', 4, '(ART: 3)** [TITULO I] [CAPITULO I]', '181845', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (643, 643, 'MODALIDADES DEL ACTO ADMINISTRATIVO: UNA MODALIDAD ACCESORIA ......:', '["NO PUEDE SER APLICADA CONTRA EL FIN PERSEGUIDO POR EL ACTO ADMINISTRATIVO","PUEDE SER APLICADA CONTRA EL FIN PERSEGUIDO POR EL ACTO ADMINISTRATIVO","PUEDE SER APLICADA CON EL FIN PERSEGUIDO POR EL ACTO ADMINISTRATIVO","NO PUEDE SER APLICADA CON EL FIN PERSEGUIDO POR EL ACTO ADMINISTRATIVO","PUEDE SER APLICADA SIN EL FIN PERSEGUIDO POR EL ACTO ADMINISTRATIVO"]'::jsonb, 'NO PUEDE SER APLICADA CONTRA EL FIN PERSEGUIDO POR EL ACTO ADMINISTRATIVO', 0, '(ART: 2)** [TITULO I] [CAPITULO I]', '181846', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (644, 644, 'ART. 113 - REQUISITOS DE LOS ESCRITOS.- TODO ESCRITO QUE SE PRESENTE ANTE CUALQUIER ENTIDAD DEBE CONTENER ENTRE OTROS LO SIGUIENTE: (SEÑALE EL INCORRECTO)', '["LA DIRECCIÓN DEL LUGAR DONDE SE DESEA RECIBIR LAS NOFICIACIONES DEL PROCEDIMIENTO","LA RELACIÓN DE DOMICILIOS ANTERIORES DONDE HA RADICADO PARA UNA REFERENCIA","LA RELACIÓN DE DOCUMENTOS Y ANEXOS QUE ACOMPAÑA, INDICADOS EN EL TUPA","LA IDENTIFICACIÓN DEL EXPEDIENTE DE LA MATERIA, TRATÁNDOSE DE PROCEDIMIENTOS YA INICIADOS","LA EXPRESIÓN CONCRETA DE LO PEDIDO LOS FUNDAMENTOS DE HECHO Y DE SER POSIBLE LOS DE DERECHO"]'::jsonb, 'LA RELACIÓN DE DOMICILIOS ANTERIORES DONDE HA RADICADO PARA UNA REFERENCIA', 1, '(ART: 113)** [TITULO II] [CAPITULO III]', '181847', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (645, 645, 'ART.133: INICIO DE CÓMPUTO: EL PLAZO EXPRESADO EN DÍAS ES CONTADO A PARTIR DEL (............... ) DE AQUEL EN QUE SE PRACTIQUE LA NOTIFICACIÓN O LA PUBLICACIÓN DEL ACTO, SALVO QUE ÉSTE SEÑALE UNA FECHA POSTERIOR, O QUE SEA NECESARIO EFECTUAR PUBLICACIONES SUCESIVAS, EN CUYO CASO EL CÓMPUTO ES INICIADO A PARTIR DE LA ÚLTIMA', '["DÍA HÁBIL SIGUIENTE","DÍA NO LABORABLE SIGUIENTE","DÍA SIGUIENTE","DÍA POSTERIOR DE LA PUBLICACIÓN DEL ACTO","DÍA CALENDARIO SIGUIENTE"]'::jsonb, 'DÍA HÁBIL SIGUIENTE', 0, '(ART: 133)** [TITULO II] [CAPITULO IV]', '181851', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (646, 646, 'ART. 190.- PRECISE USTED EL MOMENTO EN QUE PUEDE REALIZARSE EL DESISTIMIENTO DE ALGÚN ACTO REALIZADO EN EL PROCEDIMIENTO ADMINISTRATIVO:', '["PUEDE REALIZARSE DESPUÉS DE 24 HORAS DE PRODUCIRSE LOS EFECTOS","PUEDE REALIZARSE HASTA TRES DÍAS DE HABERSE PRODUCIDO LOS EFECTOS","PUEDE REALIZARSE ANTES DE QUE HAYA PRODUCIDO EFECTOS","PUEDE REALIZARSE EN CUALQUIER ESTADO DEL PROCEDIMIENTO","PUEDE REALIZARSE DESPUÉS DE HABERSE PRODUCIDO EFECTOS"]'::jsonb, 'PUEDE REALIZARSE ANTES DE QUE HAYA PRODUCIDO EFECTOS', 2, '(ART: 190)** [TITULO II] [CAPITULO VIII]', '181852', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (647, 647, 'TRATÁNDOSE DEL PLAZO PARA EL CUMPLIMIENTO DE ACTOS PROCEDIMENTALES INTERNOS A CARGO DE LAS ENTIDADES, LA NORMA LEGAL PUEDE ESTABLECER QUE SU CÓMPUTO SEA EN DÍAS..... :', '["DE LUNES A MIÉRCOLES","IMPARES","CALENDARIO","PARES","FERIADOS"]'::jsonb, 'CALENDARIO', 2, '(ART: 139)** [TITULO II] [CAPITULO IV]', '181853', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (648, 648, 'DE LOS CONCEPTOS CONTENIDOS EN EL TÍTULO PRELIMINAR DE LA LEY 27444 Y QUE SE DETALLAN A CONTINUACIÓN, SEÑALE USTED CUÁL ES EL INCORRECTO:', '["LA PRESENTE LEY REGULA LAS ACTUACIONES DE LA FUNCIÓN ADMINISTRATIVA DEL ESTADO Y EL PROCEDIMIENTO ADMINISTRATIVO COMÚN DESARROLLADOS EN LAS ENTIDADES","SON FUENTES DEL PROCEDIMIENTO ADMINISTRATIVO LAS DISPOSICIONES CONSTITUCIONALES","LA PRESENTE LEY TIENE POR FINALIDAD ESTABLECER EL RÉGIMEN JURÍDICO APLICABLE PARA QUE LA ACTUACIÓN DE LA ADMINISTRACIÓN PÚBLICA SIRVA A LA PROTECCIÓN DEL INTERÉS GENERAL","LA LEY 27444 SERÁ DE APLICACIÓN A TODAS LAS ENTIDADES DE LA ADMINISTRACIÓN PÚBLICA","ES FINALIDAD DE LA LEY 27444 GARANTIZAR LOS DERECHOS E INTERESES DE LA ADMINISTRACIÓN"]'::jsonb, 'ES FINALIDAD DE LA LEY 27444 GARANTIZAR LOS DERECHOS E INTERESES DE LA ADMINISTRACIÓN', 4, '[TITULO PRELIMINAR]', '181854', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (649, 649, 'EL SIGUIENTE ENUNCIADO : LOS SUJETOS DEL PROCEDIMIENTO ADMINISTRATIVO DEBEN HACER PREVALECER EL CUMPLIMIENTO DE LA FINALIDAD DEL ACTO PROCEDIMENTAL, SOBRE AQUELLOS FORMALISMOS CUYA REALIZACIÓN NO INCIDA EN SU VALIDEZ, NO DETERMINEN ASPECTOS IMPORTANTES EN LA DECISIÓN FINAL, NO DISMINUYAN LAS GARANTÍAS DEL PROCEDIMIENTO, NI CAUSEN INDEFENSIÓN A LOS ADMINISTRADOS. CORRESPONDE AL PRINCIPIO DE:', '["EFICACIA","LEGALIDAD","DEBIDO PROCEDIMIENTO","IMPULSO DE OFICIO","INFORMALISMO"]'::jsonb, 'EFICACIA', 0, '(ART: IV)** [TITULO PRELIMINAR]', '181855', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (650, 650, 'DE LOS TÍTULOS PLANTEADOS A CONTINUACIÓN, UNO DE ELLOS NO CORRESPONDE A LOS REQUISITOS DE VALIDEZ DE LOS ACTOS ADMINISTRTAIVOS:', '["MOTIVACIÓN","PROCEDIMIENTO REGULAR","OBJETO O CONTENIDO","COMPETENCIA","SIMPLICIDAD"]'::jsonb, 'SIMPLICIDAD', 4, '(ART: 3)** [TITULO I] [CAPITULO I]', '181856', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (651, 651, 'ART.207 - RECURSOS ADMINISTRATIVOS.- UNO DE LOS RECURSOS ADMINISTRATIVOS ES EL DE: (SEÑALE EL CORRECTO)', '["HÁBEAS DATA","RECONSIDERACIÓN","INCONSTITUCIONALIDAD","IMPUGNATORIO","TRÁMITE"]'::jsonb, 'RECONSIDERACIÓN', 1, '(ART: 207)** [TITULO III] [CAPITULO II]', '181857', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (652, 652, 'TODO ESCRITO QUE SE PRESENTE ANTE CUALQUIER ENTIDAD DEBE CONTENER LO SIGUIENTE: (SEÑALE LA RESPUESTA INCORRECTA)', '["NOMBRES Y APELLIDOS COMPLETOS DOMICILIO Y NÚMERO DE DNI O CARNÉ DE EXTRANJERIA DEL ADMINISTRADO","LA EXPRESIÓN CONCRETA DEL PEDIDO","LUGAR, FECHA, FIRMA O HUELLA DIGITAL EN CASO DE NO SABER FIRMAR O ESTAR IMPEDIDO","LA INDICACIÓN DEL ÓRGANO, LA ENTIDAD O LA AUTORIDAD A LA CUÁL ESTÁ DIRIGIDA","NOMBRE Y DNI DEL AUXILIAR DE CONTABILIDAD DE LA EMPRESA A LA CUÁL SE LE DEMANDA"]'::jsonb, 'NOMBRE Y DNI DEL AUXILIAR DE CONTABILIDAD DE LA EMPRESA A LA CUÁL SE LE DEMANDA', 4, '(ART: 113)** [TITULO II] [CAPITULO III]', '181858', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (653, 653, 'TODA NOTIFICACIÓN DEBERÁ PRACTICARSE A MÁS TARDAR DENTRO DEL PLAZO DE:', '["TRES DÍAS","CUATRO DÍAS","CINCO DÍAS","SIETE DÍAS","QUINCE DÍAS"]'::jsonb, 'CINCO DÍAS', 2, '(ART: 24)** [TITULO I] [CAPITULO III]', '181859', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (654, 654, 'PRECISE USTED QUÉ RESPONSABILIDAD GENERA EL INCUMPLIMIENTO INJUSTIFICADO DE LOS PLAZOS PREVISTOS PARA LAS ACTUACIONES DE LAS ENTIDADES', '["RESPONSABILIDAD PENAL PARA LA AUTORIDAD OBLIGADA","RESPONSABILIDAD JUDICIAL PARA LA AUTORIDAD OBLIGADA","RESPONSABILIDAD ADMINISTRATIVA Y PENAL","RESPONSABILIDAD PENAL Y CIVIL","RESPONSABILIDAD DISCIPLINARIA PARA LA AUTORIDAD OBLIGADA"]'::jsonb, 'RESPONSABILIDAD DISCIPLINARIA PARA LA AUTORIDAD OBLIGADA', 4, '(ART: 143)** [TITULO II] [CAPITULO IV]', '181860', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (655, 655, 'PRECISE USTED EN ATENCIÓN A QUE RAZONES, LA AUTORIDAD A CARGO DEL PROCEDIMIENTO, PUEDE REDUCIR PLAZOS O ANTICIPAR LOS TÉRMINOS:', '["OPORTUNIDAD Y CONVIVENCIA","CELERIDAD Y PRONTITUD","OPORTUNIDAD O CONVENIENCIA","OPORTUNIDAD Y CELERIDAD","PRONTITUD Y CELERIDAD"]'::jsonb, 'OPORTUNIDAD O CONVENIENCIA', 2, '(ART: 141)** [TITULO II] [CAPITULO IV]', '181861', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (703, 703, '(. ................), ESTIMARÁ EN TODO O EN PARTE O DESESTIMARÁ LAS PRETENSIONES FORMULADAS EN EL MISMO, O DECLARARÁ SU INADMISIÓN', '["EL CONTENIDO DEL RECURSO","LA RESOLUCIÓN DEL RECURSO","EL PROVEÍDO DEL RECURSO","LOS ANEXOS DEL RECURSO","LA RESOLUCIÓN PLANTEADA EN LOS ANEXOS"]'::jsonb, 'LA RESOLUCIÓN DEL RECURSO', 1, '(ART: 217)** [TITULO III] [CAPITULO II]', '181914', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (656, 656, 'ART. IV - PRINCIPIOS DEL PROCEDIMIENTO ADMINISTRATIVO.- PRINCIPIO DE PRESUNCIÓN DE VERACIDAD.- EN LA TRAMITACIÓN DEL PROCEDIMIENTO ADMINISTRATIVO, SE PRESUME QUE LOS DOCUMENTOS Y DECLARACIONES FORMULADOS POR LOS ADMINISTRADOS EN LA FORMA PRESCRITA POR ESTA LEY, RESPONDEN:', '["A LA VERDAD DE LOS HECHOS QUE ELLOS AFIRMAN","NO NECESARIAMENTE A LA VERDAD","A LA VERDAD Y NO TIENEN QUE SER VERIFICADAS EN NINGÚN MOMENTO","A UNA PRESUNCIÓN DE VERDAD","CATEGORICAMENTE A UNA VERDAD"]'::jsonb, 'A LA VERDAD DE LOS HECHOS QUE ELLOS AFIRMAN', 0, '(ART: IV)** [TITULO PRELIMINAR]', '181862', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (657, 657, 'SON FALTAS ADMINISTRATIVAS. SEÑALE LA INCORRECTA', '["DEMORAR JUSTIFICADAMENTE LA REMISIÓN DE DATOS","RESOLVER SIN MOTIVACIÓN ALGÚN ASUNTO SOMETIDO A SU COMPETENCIA","INTIMIDAR DE ALGUNA MANERA A QUIEN DESEE PLANTEAR QUEJA ADMINISTRATIVA O CONTRADECIR SUS DECISIONES","INCURRIR EN ILEGALIDAD MANIFIESTA","NO ENTREGAR, DENTRO DEL TÉRMINO LEGAL, LOS DOCUMENTOS RECIBIDOS A LA AUTORIDAD QUE DEBA DECIDIR U OPINAR SOBRE ELLOS"]'::jsonb, 'DEMORAR JUSTIFICADAMENTE LA REMISIÓN DE DATOS', 0, '(ART: 239)** [TITULO IV] [CAPITULO II]', '181863', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (693, 693, 'PRECISE CUÁL DE LOS ENUNCIADOS QUE SE ENUMERA A CONTINUACIÓN, CONSTITUYE UN RECURSO ADMINISTRATIVO QUE RECONOCE COMO TAL LA LEY 27444', '["RECURSOS DE IMPUGNACIÓN","RECURSOS DE SOBRESEIMIENTO","RECURSO DE CONTRADICCIÓN","RECURSO DE APELACIÓN","RECURSO DE LA DOBLE INSTANCIA"]'::jsonb, 'RECURSO DE APELACIÓN', 3, '(ART: 209)** [TITULO III] [CAPITULO II]', '181902', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (658, 658, 'EL SIGUIENTE ENUNCIADO: QUIENES PARTICIPAN EN EL PROCEDIMIENTO DEBEN AJUSTAR SU ACTUACIÓN DE TAL MODO QUE SE DOTE AL TRÁMITE DE LA MÁXIMA DINÁMICA POSIBLE, EVITANDO ACTUACIONES PROCESALES QUE DIFICULTEN SU DESENVOLVIMIENTO O CONSTITUYAN MEROS FORMALISMOS, A FIN DE ALCANZAR UNA DECISIÓN EN TIEMPO RAZONABLE, SIN QUE ELLO RELEVE A LAS A UTO RI DA DE S DEL RESPETO AL DEBIDO PRO CE DI MIE NT O O VULNERE EL ORDENAMIENTO...CORRESPONDE AL PRINCIPIO DE:', '["IMPARCIALIDAD","IMPULSO DE OFICIO","VERDAD MATERIAL","EFICACIA","CELERIDAD"]'::jsonb, 'CELERIDAD', 4, '(ART: IV)** [TITULO PRELIMINAR]', '181864', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (659, 659, 'RECIBIDA LA SOLICITUD O LA DISPOSICIÓN DE AUTORIDAD SUPERIOR, SEGÚN EL CASO, PARA INICIAR UN PROCEDIMIENTO, LAS AUTORIDADES DE OFICIO DEBEN ASEGURARSE DE SU PROPIA COMPETENCIA PARA PROSEGUIR CON EL NORMAL DESARROLLO DEL PROCEDIMIENTO, SIGUIENDO LOS CRITERIOS APLICABLES AL CASO DE LA MATERIA : (SEÑALE LA CORRECTA)', '["EL TERRITORIO, EL TIEMPO, EL GRADO O LA CUANTÍA","EL TERRITORIO, EL TIEMPO, EL VALOR APLICABLE","EL TERRITORIO, EL ESPACIO Y LA CUANTÍA","EL TIEMPO, EL ESPACIO, EL VALOR APLICABLE Y LA CUANTÍA","EL TIEMPO, EL ESPACIO, Y LA AUTORIDAD QUE LE CORRESPONDA DE ACUERDO A DONDE SE HALLAN SUCEDIDO LOS HECHOS"]'::jsonb, 'EL TERRITORIO, EL TIEMPO, EL GRADO O LA CUANTÍA', 0, '(ART: 80)** [TITULO II] [CAPITULO II] [SUBCAPITULO IV]', '181865', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (660, 660, 'LUEGO DE RESUELTO EL CONFLICTO DE COMPETENCIA, EL ÓRGANO QUE RESULTE COMPETENTE PARA CONOCER EL ASUNTO CONTINUA EL PROCEDIMIENTO SEGÚN SU ESTADO Y CONSERVA TODO LO ACTUADO, SALVO AQUELLO:', '["QUE NO ESTE TÉCNICAMENTE DESCRITO","QUE NO SE HAYA EFECTUADO EN SU TIEMPO Y TERRITORIO","QUE NO SEA JURÍDICAMENTE POSIBLE","QUE NO ESTÉ RESUELTO POR EL ÓRGANO COMPETENTE","QUE NO ESTÉ DE ACUERDO AL CRITERIO DEL ÓRGANO QUE RESULTE COMPETENTE"]'::jsonb, 'QUE NO SEA JURÍDICAMENTE POSIBLE', 2, '(ART: 87)** [TITULO II] [CAPITULO II] [SUBCAPITULO IV]', '181866', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (661, 661, 'INDIQUE USTED DE LOS SIGUIENTES ENUNCIADOS, CUÁL CORRESPONDE AL PRINCIPIO DE IMPARCIALIDAD', '["LAS NORMAS DE PROCEDIMIENTO DEBEN SER INTERPRETADAS EN FORMA FAVORABLE A LA ADMISIÓN Y DECISIÓN FINAL DE LAS PRETENSIONES DE LOS ADMINISTRADOS, DE MODO QUE SUS DERECHOS E INTERESES NO SEAN AFECTADOS","EN LA TRAMITACIÓN DEL PROCEDIMIENTO ADMINISTRATIVO, SE PRESUME QUE LOS DOCUMENTOS Y DECLARACIONES FORMULADOS POR LOS ADMINISTRADOS EN LA FORMA PRESCRITA POR ESTA LEY, RESPONDEN A LA VERDAD DE LOS HECHOS","LAS AUTORIDADES ADMINISTRATIVAS ACTÚAN SIN NINGUNA CLASE DE DISCRIMINACIÓN ENTRE LOS ADMINISTRADOS, OTORGÁNDOLES TRATAMIENTO Y TUTELA IGUALITARIOS FRENTE AL PROCEDIMIENTO, RESOLVIENDO CONFORME AL ORDENAMIENTO JURÍDICO Y CON ATENCIÓN AL INTERÉS GENERAL","LAS AUTORIDADES ADMINISTRATIVAS DEBEN ACTUAR CON RESPETO A LA CONSTITUCIÓN, LA LEY Y AL DERECHO, DENTRO DE LAS FACULTADES QUE LE ESTÉN ATRIBUIDAS Y DE ACUERDO CON LOS FINES PARA LOS QUE LES FUERON CONFERIDAS","QUIENES PARTICIPAN EN EL PROCEDIMIENTO DEBEN AJUSTAR SU ACTUACIÓN DE TAL MODO QUE SE DOTE AL TRÁMITE DE LA MÁXIMA DINÁMICA POSIBLE, EVITANDO ACTUACIONES PROCESALES QUE DIFICULTEN SU DESENVOLVIMIENTO O CONSTITUYAN MEROS FORMALISMOS, A FIN DE ALCANZAR UNA DECISIÓN EN TIEMPO RAZONABLE, SIN QUE ELLO RELEVE A LAS AUTORIDADES DEL RESPETO AL DEBIDO PROCEDIMIENTO O VULNERE EL ORDENAMIENTO"]'::jsonb, 'LAS AUTORIDADES ADMINISTRATIVAS ACTÚAN SIN NINGUNA CLASE DE DISCRIMINACIÓN ENTRE LOS ADMINISTRADOS, OTORGÁNDOLES TRATAMIENTO Y TUTELA IGUALITARIOS FRENTE AL PROCEDIMIENTO, RESOLVIENDO CONFORME AL ORDENAMIENTO JURÍDICO Y CON ATENCIÓN AL INTERÉS GENERAL', 2, '(ART: IV)** [TITULO PRELIMINAR]', '181867', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (662, 662, 'EL PRINCIPIO DE IMPULSO DE OFICIO CONSIDERA QUE:', '["LAS AUTORIDADES DEBEN DIRIGIR E IMPULSAR DE OFICIO EL PROCEDIMIENTO Y ORDENAR LA REALIZACIÓN O PRÁCTICA DE LOS ACTOS QUE RESULTEN CONVENIENTES PARA EL ESCLARECIMIENTO Y RESOLUCIÓN DE LAS CUESTIONES NECESARIAS","LA TRAMITACIÓN DE LOS PROCEDIMIENTOS ADMINISTRATIVOS SE SUSTENTARÁ EN LA APLICACIÓN DE LA FISCALIZACIÓN POSTERIOR","LA AUTORIDAD ADMINISTRATIVA DEBERÁ BRINDAR A LOS ADMINISTRADOS O SUS REPRESENTANTES INFORMACIÓN VERAZ, COMPLETA Y CONFIABLE SOBRE CADA TRÁMITE, DE MODO TAL QUE A SU INICIO, EL ADMINISTRADO PUEDA TENER UNA CONCIENCIA BASTANTE CERTERA DE CUÁL SERÁ EL RESULTADO FINAL QUE SE OBTENDRÁ","LA AUTORIDAD ADMINISTRATIVA DEBERÁ ESTABLECER REQUISITOS SIMILARES PARA TRÁMITES SIMILARES, GARANTIZANDO QUE LAS EXCEPCIONES A LOS PRINCIPIOS GENERALES NO SERÁN CONVERTIDOS EN LA REGLA GENERAL","NINGUNO"]'::jsonb, 'LAS AUTORIDADES DEBEN DIRIGIR E IMPULSAR DE OFICIO EL PROCEDIMIENTO Y ORDENAR LA REALIZACIÓN O PRÁCTICA DE LOS ACTOS QUE RESULTEN CONVENIENTES PARA EL ESCLARECIMIENTO Y RESOLUCIÓN DE LAS CUESTIONES NECESARIAS', 0, '(ART: IV)** [TITULO PRELIMINAR]', '181868', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (663, 663, 'ART. 191.- PRECISE USTED CUÁL ES LA FORMA EN QUE LA AUTORIDAD ADMINISTRATIVA PODRÁ DECLARAR EL ABANDONO DEL PROCEDIMIENTO INICIADO A SOLICITUD DEL ADMINISTRADO:', '["DE OFICIO","A SOLICITUD DEL ADMINISTRADO","DE OFICIO O A SOLICITUD DEL ADMINISTRADO","OFICIO DE LA ENTIDAD ADMINISTRATIVA","A SOLICITUD DEL ADMINISTRADOR"]'::jsonb, 'DE OFICIO O A SOLICITUD DEL ADMINISTRADO', 2, '(ART: 191)** [TITULO II] [CAPITULO VIII]', '181869', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (664, 664, 'INTEGRA UN SISTEMA ORGÁNICO QUE TIENE AUTONOMÍA RESPECTO DE OTRAS RAMAS DEL DERECHO:', '["LAS RONDAS CAMPESINAS","LOS PODERES DEL ESTADO","LA JUSTICIA CIVIL MILITAR","EL ORDENAMIENTO JERÁRQUICO ADMINISTRATIVO","EL ORDENAMIENTO JURÍDICO ADMINISTRATIVO"]'::jsonb, 'EL ORDENAMIENTO JURÍDICO ADMINISTRATIVO', 4, '(ART: V)** [TITULO PRELIMINAR]', '181870', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (716, 716, 'LAS UNIDADES DE RECEPCIÓN DOCUMENTAL ORIENTAN............. EN LA PRESENTACIÓN DE SUS SOLICITUDES Y FORMULARIOS, QUEDANDO OBLIGADAS A RECIBIRLOS Y DARLES INGRESO PARA INICIAR O IMPULSAR LOS PROCEDIMIENTOS, SIN QUE EN NINGÚN CASO PUEDA CALIFICAR, NEGAR O DIFERIR SU ADMISIÓN', '["A LOS TESTIGOS","A LA ADMINISTRACIÓN","AL ADMINISTRADO","A LOS IMPUTADOS","A LA ENTIDAD"]'::jsonb, 'AL ADMINISTRADO', 2, '(ART: 124)** [TITULO II] [CAPITULO III]', '181929', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (665, 665, 'ART. 12 - EFECTOS DE LA DECLARACIÓN DE NULIDAD.- LA DECLARACIÓN DE NULIDAD TENDRÁ EFECTO DECLARATIVO Y RETROACTIVO A LA FECHA DEL ACTO, SALVO :', '["DERECHOS ADQUIRIDOS POR LOS ADMINISTRADOS, EN CUYO CASO OPERARÁ CONFORME A LEY","DERECHOS ADQUIRIDOS DE BUENA FE POR TERCEROS, EN CUYO CASO OPERARÁ A FUTURO","OBLIGACIONES ADQUIRIDOS DE BUENA FE POR LOS ADMINISTRADOS, EN CUYO CASO OPERARÁ A FUTURO","DERECHOS CONCEDIDOS DE BUENA FE A TERCEROS, EN CUYO CASO OPERARÁ A FUTURO","DERECHOS ADQUIRIDOS DE BUENA FE POR TERCEROS, EN CUYO CASO OPERARÁ DE INMEDIATO CONFORME A LEY"]'::jsonb, 'DERECHOS ADQUIRIDOS DE BUENA FE POR TERCEROS, EN CUYO CASO OPERARÁ A FUTURO', 1, '(ART: 12)** [TITULO I] [CAPITULO II]', '181871', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (666, 666, 'SON FUENTES DEL PROCEDIMIENTO ADMINISTRATIVO, SEÑALE EL CORRECTO:', '["LA LEGALIDAD","EL DEBIDO PROCEDIMIENTO","LA RAZONABILIDAD","LAS DISPOSICIONES CONSTITUCIONALES","LA IMPARCIALIDAD"]'::jsonb, 'LAS DISPOSICIONES CONSTITUCIONALES', 3, '(ART: V)** [TITULO PRELIMINAR]', '181872', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (667, 667, 'EL SIGUIENTE ENUNCIADO : LAS NORMAS DE PROCEDIMIENTO DEBEN SER INTERPRETADAS EN FORMA FAVORABLE A LA ADMISIÓN Y DECISIÓN FINAL DE LAS PRETENSIONES DE LOS ADMINISTRADOS, DE MODO QUE SUS DERECHOS E INTERESES NO SEAN AFECTADOS POR LA EXIGENCIA DE ASPECTOS FORMALES QUE PUEDAN SER SUBSANADOS DENTRO DEL PROCEDIMIENTO, SIEMPRE QUE DICHA EXCUSA NO AFECTE DERECHOS DE TERCEROS O EL INTERÉS PÚBLICO. CORRESPONDE AL PRINCIPIO DE:', '["RAZONABILIDAD","IMPARCIALIDAD","INFORMALISMO","EFICACIA","LEGALIDAD"]'::jsonb, 'INFORMALISMO', 2, '(ART: IV)** [TITULO PRELIMINAR]', '181873', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (694, 694, 'PARA MANTENER REUNIDAS TODAS LAS ACTUACIONES PARA RESOLVER, CUÁNTOS EXPEDIENTES PUEDEN ORGANIZARSE PARA LA SOLUCIÓN DE UN MISMO CASO? MARCA LA CORRECTA:', '["SÓLO UN EXPEDIENTE","LOS EXPEDIENTES NECESARIOS Y SOLICITADOS POR EL ADMINISTRADO","DOS EXPEDIENTES","TRES EXPEDIENTES","LOS EXPEDIENTES NECESARIOS DISPUESTO POR LA ADMINISTRACIÓN"]'::jsonb, 'SÓLO UN EXPEDIENTE', 0, '(ART: 150)** [TITULO II] [CAPITULO V]', '181903', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (668, 668, 'REQUISITOS DE LOS ESCRITOS.-TODO ESCRITO QUE SE PRESENTE ANTE CUALQUIER ENTIDAD DEBE CONTENER LO SIGUIENTE: (SEÑALE EL REQUISITO INCORRECTO)', '["NOMBRES Y APELLIDOS COMPLETOS, DOMICILIO Y DNI O CARNE DE EXTRANJERÍA DEL ADMINISTRADO","EXPRESIÓN CONCRETA DE LO PEDIDO","LUGAR, FECHA, FIRMA O HUELLA DIGITAL, EN CASO DE NO SABER FIRMAR O ESTAR IMPEDIDO","NOMBRES Y APELLIDOS COMPLETOS DE SU CÓNYUGE, PADRES E HIJOS COMO FILIACIÓN","LA INDICACIÓN DEL ÓRGANO, LA ENTIDAD O LA AUTORIDAD A LA CUÁL ES DIRIGIDO"]'::jsonb, 'NOMBRES Y APELLIDOS COMPLETOS DE SU CÓNYUGE, PADRES E HIJOS COMO FILIACIÓN', 3, '(ART: 113)** [TITULO II] [CAPITULO III]', '181874', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (669, 669, 'SON ACTOS ADMINISTRATIVOS: (SEÑALE LA RESPUESTA CORRECTA)', '["LAS DECLARACIONES DE LAS ENTIDADES QUE, EN EL MARCO DE LAS NORMAS DE DERECHO PÚBLICO ESTÉN DESTINADAS A PRODUCIR EFECTOS JURÍDICOS SOBRE LOS INTERESES, OBLIGACIONES O DERECHOS DE LOS ADMINISTRADOS DENTRO DE UNA SITUACIÓN CONCRETA","LOS ACTOS DE ADMINISTRACIÓN INTERNA DE LAS ENTIDADES DESTINADAS A ORGANIZAR O HACER FUNCIONAR SUS PROPIAS ACTIVIDADES O SERVICIOS","LOS COMPORTAMIENTOS Y ACTIVIDADES MATERIALES DE LAS ENTIDADES","LOS COMPORTAMIENTOS Y ACTIVIDADES SUBJETIVAS DE LAS ENTIDADES","LOS ACTOS DE ADMINISTRACIÓN EXTERNA DE LAS ENTIDADES"]'::jsonb, 'LAS DECLARACIONES DE LAS ENTIDADES QUE, EN EL MARCO DE LAS NORMAS DE DERECHO PÚBLICO ESTÉN DESTINADAS A PRODUCIR EFECTOS JURÍDICOS SOBRE LOS INTERESES, OBLIGACIONES O DERECHOS DE LOS ADMINISTRADOS DENTRO DE UNA SITUACIÓN CONCRETA', 0, '(ART: 1)** [TITULO I] [CAPITULO I]', '181875', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (670, 670, 'LA COPIA DE CUALQUIER DOCUMENTO PÚBLICO, SIEMPRE QUE EXISTA CONSTANCIA DE QUE ES AUTÉNTICA, SEÑALE LA RESPUESTA CORRECTA:', '["GOZA DE LA MISMA VALIDEZ Y EFICACIA QUE ÉSTOS","SÓLO GOZA DE EFICACIA","SÓLO GOZA DE VALIDEZ","NO ES VÁLIDA","GOZA DE PRIORIDAD EN SU ATENCIÓN"]'::jsonb, 'GOZA DE LA MISMA VALIDEZ Y EFICACIA QUE ÉSTOS', 0, '(ART: 43)** [TITULO II] [CAPITULO I]', '181876', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (671, 671, 'CUÁNDO EL ERROR EN LA CALIFICACIÓN DEL RECURSO POR PARTE DEL RECURRENTE NO SERÁ OBSTÁCULO PARA SU TRAMITACIÓN? : MARCA LA CORRECTA', '["SI EL ESCRITO ESTÁ CORREGIDO POR EL ABOGADO DEFENSOR","SI SOLICITA VERBALMENTE QUE SE ACEPTE SU RECURSO","SI DEL ESCRITO SE DEDUZCA SU VERDADERO CARÁCTER","SI EL ESCRITO SE PRESENTÓ A MANUSCRITO","NO PUEDE ARTICULARLOS"]'::jsonb, 'SI DEL ESCRITO SE DEDUZCA SU VERDADERO CARÁCTER', 2, '(ART: 213)** [TITULO III] [CAPITULO II]', '181877', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (672, 672, 'SE DECLARA ABANDONO DEL PROCEDIMIENTO, CUANDO EL ADMINISTRADO INCUMPLA ALGÚN TRÁMITE QUE SE HUBIERA SIDO REQUERIDO QUE PRODUZCA PARALIZACIÓN POR : MARCA EL CORRECTO:', '["10 DÍAS","30 DÍAS","07 DÍAS","15 DÍAS","20 DÍAS"]'::jsonb, '30 DÍAS', 1, '(ART: 191)** [TITULO II] [CAPITULO VIII]', '181878', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (673, 673, 'LA INTERPOSICIÓN DE CUALQUIER RECURSO, EXCEPTO LOS CASOS EN QUE UNA NORMA LEGAL ESTABLEZCA LO CONTRARIO, NO SUSPENDERÁ LA EJECUCIÓN DEL ACTO IMPUGNADO; NO OBSTANTE LO DISPUESTO EN EL NUMERAL ANTERIOR, LA AUTORIDAD A QUIEN COMPETA RESOLVER EL RECURSO SUSPENDE DE OFICIO O A PETICIÓN DE PARTE LA EJECUCIÓN DEL ACTO RECURRIDO CUANDO CONCURRA ALGUNA DE LAS SIGUIENTES CIRCUNSTANCIAS:', '["QUE LA EJECUCIÓN NO CAUSE PERJUICIOS DE IMPOSIBLE REPARACIÓN","QUE SE APRECIE OBJETIVAMENTE LA EXISTENCIA DE UN VICIO DE NULIDAD TRASCENDENTE","QUE SE APRECIE OBJETIVAMENTE LA EXISTENCIA DE UN VICIO DE NULIDAD INTRASCENDENTE","QUE LA EJECUCIÓN NO CAUSE PERJUICIOS DE DIFÍCIL REPARACIÓN","QUE EL DAÑO CAUSADO SEA TRASCENDENTE"]'::jsonb, 'QUE SE APRECIE OBJETIVAMENTE LA EXISTENCIA DE UN VICIO DE NULIDAD TRASCENDENTE', 1, '(ART: 216)** [TITULO III] [CAPITULO II]', '181879', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (674, 674, 'EL PLAZO MÁXIMO PARA ACTOS DE MERO TRÁMITE Y DECIDIR PETICIONES DE ESE CARÁCTER ES :', '["02 DÍAS","07 DÍAS","05 DÍAS","03 DÍAS","EN EL DÍA"]'::jsonb, '03 DÍAS', 3, '(ART: 132)** [TITULO II] [CAPITULO IV]', '181880', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (675, 675, 'EL RÉGIMEN DE LA NOTIFICACIÓN CONSISTE EN : MARCA LA INCORRECTA', '["NOTIFICAR EN EL ÚLTIMO DOMICILIO QUE LA PERSONA, A QUIÉN DEBA NOTIFICAR, HAYA SEÑALADO ANTE EL ÓRGANO ADMINISTRATIVO","EN CASO NO HAYA SEÑALADO DOMICILIO, SE DEBE AGOTAR SU BÚSQUEDA MEDIANTE LOS MEDIOS QUE SE ENCUENTREN A SU ALCANCE","NOTIFICAR EN EL DOMICILIO QUE CONSTA EN EL EXPEDIENTE","SI NO SE ENCUENTRA LA PERSONA, SE ENTREGA AL VECINO","EN EL ACTO DE NOTIFICACIÓN DEBE ENTREGARSE COPIA DEL ACTO DE NOTIFICACIÓN"]'::jsonb, 'SI NO SE ENCUENTRA LA PERSONA, SE ENTREGA AL VECINO', 3, '(ART: 21)** [TITULO I] [CAPITULO III]', '181881', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (676, 676, 'LA LEY 27444 SEÑALA QUE, LOS ACTOS ADMINISTRATIVOS QUE AGOTEN LA VIA ADMINISTRATIVA PODRÁN SER:', '["IMPUGNADOS ANTE EL MISMO ÓRGANO QUE DICTO EL ACTO RESOLUTIVO","IMPUGNADOS ANTE EL SUPERIOR JERÁRQUICO DEL MISMO ÓRGANO QUE DICTO EL ACTO RESOLUTIVO","IMPUGNADOS ANTE EL PODER JUDICIAL","APELADOS ANTE EL MISMO ÓRGANO QUE DICTO EL ACTO RESOLUTIVO","APELADOS ANTE EL SUPERIOR JERÁRQUICO DEL MISMO ÓRGANO QUE DICTO EL ACTO RESOLUTIVO"]'::jsonb, 'IMPUGNADOS ANTE EL PODER JUDICIAL', 2, '(ART: 218)** [TITULO III] [CAPITULO II]', '181882', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (717, 717, 'EL PROCEDIMIENTO ADMINISTRATIVO ES PROMOVIDO........... POR EL ÓRGANO COMPETENTE O INSTANCIA DEL ADMINISTRADO, SALVO QUE POR DISPOSICIÓN LEGAL O POR SU FINALIDAD CORRESPONDA SER INICIADO EXCLUSIVAMENTE DE OFICIO O A INSTANCIA DEL INTERESADO', '["DE PARTE","DE OFICIO","A SOLICTUD","EN UN PLAZO","CON INFORME"]'::jsonb, 'DE OFICIO', 1, '(ART: 103)** [TITULO II] [CAPITULO III]', '181930', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (677, 677, 'MARQUE LA INCORRECTA: EL CITATORIO SE RIGE POR EL RÉGIMEN COMÚN DE LA NOTIFICACIÓN, HACIENDO CONSTAR EN ELLA LO SIGUIENTE:', '["LA DISPOSICIÓN LEGAL QUE FACULTA AL ÓRGANO A REALIZAR ESTA CITACIÓN","EL DESAGRAVIO, EN CASO DE INASISTENCIA AL REQUERIMIENTO","LOS NOMBRES Y APELLIDOS DEL CITADO","EL NOMBRE Y LA DIRECCIÓN DEL ÓRGANO QUE CITA, CON INDICACIÓN DE LA AUTOPRIDAD REQUIRIENTE","EL OBJETO Y ASUNTO DE LA COMPARECENCIA"]'::jsonb, 'EL DESAGRAVIO, EN CASO DE INASISTENCIA AL REQUERIMIENTO', 1, '(ART: 59)** [TITULO II] [CAPITULO II] [SUBCAPITULO I]', '181884', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (678, 678, 'LAS AUTORIDADES ADMINISTRATIVAS NO PODRÁN DEJAR DE RESOLVER LAS CUESTIONES QUE SE LES PROPONGA, POR DEFICIENCIA DE SUS FUENTES; EN TALES CASOS, ACUDIRÁN A:', '["EL PRINCIPIO DE IGUALDAD PROCESAL","EL PRINCIPIO DE LA DOBLE INSTANCIA","LOS PRINCIPIOS DEL PROCEDIMIENTO ADMINISTRATIVO","LOS PRINCIPIOS DEL DERECHO PENAL","LOS PRINCIPIOS DEL DERECHO LABORAL"]'::jsonb, 'LOS PRINCIPIOS DEL PROCEDIMIENTO ADMINISTRATIVO', 2, '(ART: VIII)** [TITULO PRELIMINAR]', '181885', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (679, 679, 'INDIQUE CUÁL ES EL ENUNCIADO CORRECTO QUE CORRESPONDE A LA COPIA DE LOS ESCRITOS:', '["EL ESCRITO ES PRESENTADO EN PAPEL MEMBRETADO","EL ESCRITO ES PRESENTADO EN ORIGINAL SIN COPIA","EL ESCRITO ES PRESENTADO EN ORIGINAL ACOMPAÑADO DE COPIA ILEGIBLE","EL CARGO ASÍ EXPEDIDO TIENE EL MISMO VALOR LEGAL QUE EL ORIGINAL","LA COPIA DEL ESCRITO ES DEVUELTA AL ADMINISTRADO CON EL SELLO DE RECEPCIÓN Y SIN FIRMA DE LA AUTORIDAD"]'::jsonb, 'EL CARGO ASÍ EXPEDIDO TIENE EL MISMO VALOR LEGAL QUE EL ORIGINAL', 3, '(ART: 114)** [TITULO II] [CAPITULO III]', '181886', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (680, 680, 'SE ENTIENDE POR PROCEDIMIENTO ADMINISTRATIVO AL (. ......................... ) TRAMITADOS EN LAS ENTIDADES, CONDUCENTES A LA EMISIÓN DE UN ACTO ADMINISTRATIVO QUE CONDUZCA EFECTOS JURÍDICOS INDIVIDUALES O INDIVIDUALIZABLES SOBRE INTERESES, OBLIGACIONES O DERECHOS DE LOS ADMINISTRADOS. (SEÑALE LA FRASE CORRECTA)', '["CONJUNTO DECISIONES","CONJUNTO DE NORMAS","CONJUNTO DE DISPOSICIONES LEGALES","CONJUNTO DE ACTOS Y DILIGENCIAS","TEMA DE DECISIÓN"]'::jsonb, 'CONJUNTO DE ACTOS Y DILIGENCIAS', 3, '(ART: 29)** [TITULO II] [CAPITULO I]', '181887', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (707, 707, 'LOS ADMINISTRADOS PUEDEN EN CUALQUIER MOMENTO DEL PROCEDIMIENTO:', '["FORMULAR ALEGACIONES","APORTAR DOCUMENTOS","APORTAR OTROS ELEMENTOS DE JUICIO","TODAS LAS ANTERIORES","SERÁN ANALIZADOS POR LA AUTORIDAD , AL RESOLVER"]'::jsonb, 'TODAS LAS ANTERIORES', 3, '(ART: 161)** [TITULO II] [CAPITULO VI]', '181918', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (681, 681, 'ALCANCES DE LA NULIDAD.- LA NULIDAD PARCIAL DEL ACTO ADMINISTRATIVO NO ALCANZA A LAS OTRAS PARTES DEL ACTO QUE RESULTEN (. .......................... ) DE LA PARTE NULA, SALVO QUE SEA SU CONSECUENCIA, NI IMPIDE LA PRODUCCIÓN DE EFECTOS PARA LOS CUALES NO OBSTANTE, EL ACTO PUEDA SER IDÓNEO, SALVO DISPOSICIÓN LEGAL EN CONTRARIO. ( SEÑALE LO CORRECTO)', '["CONSECUENCIA","INDEPENDIENTES","DEPENDIENTES","PROCEDENCIA","ACTUACIONES"]'::jsonb, 'INDEPENDIENTES', 1, '(ART: 13)** [TITULO I] [CAPITULO II]', '181888', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (682, 682, 'CAPACIDAD PROCESAL.- TIENEN CAPACIDAD PROCESAL ANTE LAS ENTIDADES LAS PERSONAS QUE GOZAN DE (. ........................ ) CONFORME A LAS LEYES. (COMPLETE LO CORRECTO)', '["SUFRAGIO","LA ACTUACIÓN","CAPACIDAD JURÍDICA","CAPACIDAD ECONÓMICA","PLACER"]'::jsonb, 'CAPACIDAD JURÍDICA', 2, '(ART: 52)** [TITULO II] [CAPITULO II] [SUBCAPITULO I]', '181889', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (683, 683, 'A FALTA DE PLAZO ESTABLECIDO POR LEY EXPRESA, LAS ACTUACIONES DEBEN PRODUCIRSE DENTRO DE LO SIGUIENTE: (MARQUE EL ENUNCIADO CORRECTO)', '["PARA LA RECEPCIÓN Y DERIVACIÓN DE UN ESCRITO A LA UNIDAD COMPETENTE: AL TERCER DÍA DE SU PRESENTACIÓN","PARA ACTOS DE MERO TRÁMITE Y DECIDIR PETICIONES DE ESE CARÁCTER: EN SEIS DÍAS","PARA EMISIÓN DE DICTÁMENES EN: TRES DÍAS","PARA ACTOS DE MERO TRÁMITE Y DECIDIR PETICIONES DE ESE CARÁCTER: EN TRES DÍAS","PARA ACTO DE REVISIÓN DE EXPEDIENTE: CINCO DÍAS"]'::jsonb, 'PARA ACTOS DE MERO TRÁMITE Y DECIDIR PETICIONES DE ESE CARÁCTER: EN TRES DÍAS', 3, '(ART: 132)** [TITULO II] [CAPITULO IV]', '181890', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (684, 684, 'PRECISE USTED CUÁL DE LOS SIGUIENTES ENUNCIADOS ES EL CORRECTO:', '["EL RECURSO DE APELACIÓN SE INTERPONDRÁ CUANDO LA IMPUGNACIÓN NO SE SUSTENTE EN DIFERENTE INTERPRETACIÓN DE LAS PRUEBAS PRODUCIDAS","EL RECURSO DE APELACIÓN SE INTERPONDRÁ CUANDO LA IMPUGNACIÓN SE SUSTENTE EN IGUAL INTERPRETACIÓN DE LAS PRUEBAS PRODUCIDAS","EL RECURSO DE APELACIÓN SE INTERPONDRÁ CUANDO LA IMPUGNACIÓN SE SUSTENTE EN DIFERENTE INTERPRETACIÓN DE LAS PRUEBAS PRODUCIDAS","EL RECURSO DE APELACIÓN NO SE INTERPONDRÁ CUANDO LA IMPUGNACIÓN SE SUSTENTE EN DIFERENTE INTERPRETACIÓN DE LAS PRUEBAS PRODUCIDAS","EL TÉRMINO PARA INTERPONER RECURSOS ES DE TRES DÍAS"]'::jsonb, 'EL RECURSO DE APELACIÓN SE INTERPONDRÁ CUANDO LA IMPUGNACIÓN SE SUSTENTE EN DIFERENTE INTERPRETACIÓN DE LAS PRUEBAS PRODUCIDAS', 2, '(ART: 209)** [TITULO III] [CAPITULO II]', '181892', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (685, 685, 'DE LOS SIGUIENTES ENUNCIADOS RELATIVOS A LA ACUMULACIÓN DE SOLICITUDES, SEÑALE USTED EL QUE ES CORRECTO:', '["PUEDEN ACUMULARSE EN UN SOLO ESCRITO MÁS DE UNA PETICIÓN SIEMPRE QUE SE TRATE DE ASUNTOS CONEXOS QUE PERMITAN TRAMITARSE Y RESOLVERSE CONJUNTAMENTE, PERO NO PLANTEAMIENTOS SUBSIDIARIOS O ALTERNATIVOS","PUEDE ACUMULARSE EN UN SOLO ESCRITO MÁS DE UNA PETICIÓN AÚN CUANDO NO SE TRATE DE ASUNTOS CONEXOS","LAS PRETENSIONES NO CONEXAS OBJETIVAMENTE PUEDEN SER ACUMULADAS CUANDO PROVENGAN DEL MISMO ADMINISTRADO","NO PROCEDE LA DENEGACIÓN DE LA ACUMULACIÓN CUANDO VARIAS PRETENSIONES SON PROPUESTAS PARA QUE LA AUTORIDAD ESTIME UNA U OTRA","DENEGADA LA ACUMULACIÓN, LA AUTORIDAD NO DEBE REQUERIR AL ADMINISTRADO PARA QUE PRESENTE SUS ESCRITOS POR SEPARADO"]'::jsonb, 'PUEDEN ACUMULARSE EN UN SOLO ESCRITO MÁS DE UNA PETICIÓN SIEMPRE QUE SE TRATE DE ASUNTOS CONEXOS QUE PERMITAN TRAMITARSE Y RESOLVERSE CONJUNTAMENTE, PERO NO PLANTEAMIENTOS SUBSIDIARIOS O ALTERNATIVOS', 0, '(ART: 116)** [TITULO II] [CAPITULO III]', '181893', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (686, 686, 'RESPONSABILIDAD POR INCUMPLIMIENTO DE PLAZOS.- EL INCUMPLIMIENTO INJUSTIFICADO DE LOS PLAZOS PREVISTOS PARA LAS ACTUACIONES DE LAS ENTIDADES GENERA RESPONSABILIDAD (. .............) PARA LA AUTORIDAD OBLIGADA, SIN PERJUICIO DE LA RESPONSABILIDAD CIVIL POR LOS DAÑOS Y PERJUICIOS QUE PUDIERA HABER ACASIONADO: (SEÑALE LA RESPUESTA CORRECTA)', '["PENAL","ECONÓMICA","DISCIPLINARIA","PATRIMONIAL","COMPARTIDA"]'::jsonb, 'DISCIPLINARIA', 2, '(ART: 143)** [TITULO II] [CAPITULO IV]', '181895', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (687, 687, 'TODA NOTIFICACIÓN DEBERÁ PRACTICARSE A MÁS TARDAR DENTRO DEL PLAZO DE 5 DÍAS A PARTIR DE LA EXPEDICIÓN DEL ACTO QUE SE NOTIFIQUE Y DEBERÁ CONTENER:(SEÑALE LO INCORRECTO)', '["EL TEXTO ÍNTEGRO DEL ACTO ADMINISTRATIVO, INCLUYENDO SU MOTIVACIÓN","LA IDENTIFICACIÓN DEL PROCEDIMIENTO DENTRO DEL CUÁL HAYA SIDO DICTADO","LA AUTORIDAD E INSTITUCIÓN DE LA CUÁL PROCEDE EL ACTO Y SU DIRECCIÓN","LA FECHA DE VIGENCIA DEL ACTO NOTIFICADO, Y CON LA MENCIÓN DE SI AGOTARE LA VÍA ADMINISTRATIVA","LA EXPRESIÓN DE LOS RECURSOS QUE NO PROCEDEN Y LA ENTIDAD ANTE LA CUÁL DEBE PRESENTARSE LA DOCUMENTACIÓN Y EL PLAZO DE CADUCIDAD"]'::jsonb, 'LA EXPRESIÓN DE LOS RECURSOS QUE NO PROCEDEN Y LA ENTIDAD ANTE LA CUÁL DEBE PRESENTARSE LA DOCUMENTACIÓN Y EL PLAZO DE CADUCIDAD', 4, '(ART: 24)** [TITULO I] [CAPITULO III]', '181896', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (688, 688, 'PRECISE USTED CUÁL ES EL ENUNCIADO CORRECTO QUE ESTABLECE UNO DE LOS DEBERES GENERALES DE LOS ADMINISTRADOS EN EL PROCEDIMIENTO:', '["COMPROBAR PREVIAMENTE A SU PRESENTACIÓN ANTE LA ENTIDAD, LA FALSIFICACIÓN Y AUTENCIDAD DE LA DOCUMENTACIÓN SUCEDÁNEA","FORMULAR PRETENSIONES O ARTICULACIONES ILEGALES, DE DECLARAR HECHOS CONTRARIOS A LA VERDAD O NO CONFIRMADOS COMO SI FUERAN FEHACIENTES","PRESTAR SU COLABORACIÓN PARA EL PERTINENTE ESCLARECIMIENTO DE LOS HECHOS","PROPORCIONAR A LA AUTORIDAD SÓLO LA INFORMACIÓN DIRIGIDA A NO IDENTIFICAR A OTROS ADMINISTRADOS NO COMPARECIENTES CON INTERÉS LEGÍTIMO EN EL PROCEDIMIENTO","EVITAR PRESTAR CUALQUIER TIPO DE INFORMACIÓN Y COLABORACIÓN PARA EL ESCLARECIENTO DE LOS HECHOS"]'::jsonb, 'PRESTAR SU COLABORACIÓN PARA EL PERTINENTE ESCLARECIMIENTO DE LOS HECHOS', 2, '(ART: 56)** [TITULO II] [CAPITULO II] [SUBCAPITULO I]', '181897', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (689, 689, 'ORIENTAN AL ADMINISTRADO EN LA PRESENTACIÓN DE SUS SOLICITUDES Y FORMULARIOS, QUEDANDO OBLIGADAS A RECIBIRLOS Y DARLES INGRESO PARA INICIAR O IMPULSAR LOS PROCEDIMIENTOS, SIN QUE EN NINGÚN CASO PUEDA CALIFICAR, NEGAR O DIFERIR SU ADMISIÓN:', '["LAS UNIDADES DE RECEPCIÓN DOCUMENTAL","EL SUPERIOR JERÁRQUICO","LOS ABOGADOS DE OFICIO","LOS ABOGADOS DE LA ADMINISTRACIÓN PÚBLICA","LAS PROCURADURIAS PÚBLICAS"]'::jsonb, 'LAS UNIDADES DE RECEPCIÓN DOCUMENTAL', 0, '(ART: 124)** [TITULO II] [CAPITULO III]', '181898', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (690, 690, 'EL TÉRMINO PARA LA INTERPOSICIÓN DE LOS RECURSOS ADMINISTRATIVOS ES DE (15) DÍAS PERENTORIOS, Y DEBERÁN RESOLVERSE EN EL PLAZO DE :', '["QUINCE (15) DÍAS","DIEZ (10) DÍAS","AL TÉRMINO DE LA DISTANCIA","24 HORAS","TREINTA (30) DÍAS"]'::jsonb, 'TREINTA (30) DÍAS', 4, '(ART: 207)** [TITULO III] [CAPITULO II]', '181899', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (691, 691, 'ES UN REQUISITO DE VALIDEZ DE LOS ACTOS ADMINISTRATIVOS: (SEÑALE LA RESPUESTA INCORRECTA):', '["COMPETENCIA","OBJETO O CONTENIDO","FINALIDAD PÚBLICA O PRIVADA","MOTIVACIÓN","PROCEDIMIENTO REGULAR"]'::jsonb, 'FINALIDAD PÚBLICA O PRIVADA', 2, '(ART: 3)** [TITULO I] [CAPITULO I]', '181900', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (692, 692, 'AGOTAMIENTO DE LA VÍA ADMINISTRATIVA.- LOS ACTOS ADMINISTRATIVOS QUE AGOTAN LA VÍA ADMINISTRATIVA PODRÁN SER IMPUGNADAS ANTE EL PODER JUDICIAL, MEDIANTE:', '["PROCESO CONTENCIOSO - DISCIPLINARIO","PROCESO JUDICIAL COMÚN","PROCESO CONTENCIOSO ECONÓMICO","PROCESO CONTENCIOSO ADMINISTRATIVO","PROCESO SUMARIO"]'::jsonb, 'PROCESO CONTENCIOSO ADMINISTRATIVO', 3, '(ART: 218)** [TITULO III] [CAPITULO II]', '181901', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (708, 708, 'LA CARGA DE LA PRUEBA SE RIGE POR EL PRINCIPIO DE (..... ) ESTABLECIDO EN LA PRESENTE LEY', '["CELERIDAD","LEGALIDAD","IMPULSO DE OFICIO","INFORMALISMO","EFICIENCIA"]'::jsonb, 'IMPULSO DE OFICIO', 2, '(ART: 162)** [TITULO II] [CAPITULO VI]', '181919', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (695, 695, 'INDIQUE, DE LOS ENUNCIADOS SIGUIENTES, RESPECTO A REQUISITOS DE LOS ESCRITOS.- CUÁL ES EL INCORRECTO:', '["LUGAR, FECHA, FIRMA O HUELLA DIGITAL, EN CASO DE NO SABER FIRMAR O ESTAR IMPEDIDO","NOMBRES Y APELLIDOS COMPLETOS, DOMICILIO Y NÚMERO DE DOCUMENTO NACIONAL DE IDENTIDAD O CARNÉ DE EXTRANJERÍA DEL ADMINISTRADO","LA EXPRESIÓN CONCRETA DE LO PEDIDO, LOS FUNDAMENTOS DE HECHO QUE LO APOYE Y CUANDO LE SEA POSIBLE, LOS DE DERECHO","LA INDICACIÓN DEL ÓRGANO, LA ENTIDAD O LA AUTORIDAD A LA CUÁL ES DIRIGIDA","CERTIFICADOS DE ESTUDIO"]'::jsonb, 'CERTIFICADOS DE ESTUDIO', 4, '(ART: 113)** [TITULO II] [CAPITULO III]', '181904', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (696, 696, 'INDIQUE USTED DE LOS ENUNCIADOS SIGUIENTES CUÁL ES EL CORRECTO, RESPECTO AL CONTENIDO DE LA LEY N 27444:', '["REGULA LAS ACTUACIONES DE LA FUNCIÓN ADMINISTRATIVA DEL ESTADO Y EL PROCEDIMIENTO ADMINISTRATIVO COMÚN DESARROLLADOS EN LAS ENTIDADES","REGULA LAS ACTUACIONES DEL ESTADO Y EL PROCEDIMIENTO ECONÓMICO DE LAS ENTIDADES","REGULA LOS ACTOS PROTOCOLARES DEL ESTADO Y EL PROCEDIMIENTO ADMINISTRATIVO DE LA BANDA","REGULA LAS ACTUACIONES FINANCIERAS DE LAS ENTIDADES","CONTIENE NORMAS PARTICULARES PARA LAS ACTUACIONES DE LA FUNCIÓN ADMINISTRATIVA DEL ESTADO Y, REGULA TODOS LOS PROCEDIMIENTOS ADMINISTRATIVOS DESARROLLADOS EN LAS ENTIDADES, INCLUYENDO LOS PROCEDIMIENTOS ESPECIALES"]'::jsonb, 'REGULA LAS ACTUACIONES DE LA FUNCIÓN ADMINISTRATIVA DEL ESTADO Y EL PROCEDIMIENTO ADMINISTRATIVO COMÚN DESARROLLADOS EN LAS ENTIDADES', 0, '(ART: II)** [TITULO PRELIMINAR]', '181906', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (697, 697, 'EN EL ACTO DE NOTIFICACIÓN : MARCA EL CORRECTO', '["SE CONDUCE AL NOTIFICADO ANTE LA AUTORIDAD SOLICITANTE","SE ENTREGA COPIA DEL ACTO NOTIFICADO","SE LE COMUNICA SU DETENCIÓN","SE PROCEDE A RECABAR SUS GENERALES DE LEY","SE CONDUCE AL NOTIFICADO AL MINISTERIO PÚBLICO"]'::jsonb, 'SE ENTREGA COPIA DEL ACTO NOTIFICADO', 1, '(ART: 21)** [TITULO I] [CAPITULO III]', '181907', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (698, 698, 'LA AUTORIDAD ORDENARÁ QUE SE REHAGA LA NOTIFICACIÓN, EN EL SIGUIENTE CASO: MARCA LA CORRECTA', '["QUE SE DEMUESTRE QUE LA NOTIFICACIÓN SE HA REALIZADO SIN LAS FORMALIDADES Y REQUISITOS LEGALES","POR CONVENIR AL ADMINISTRADO","CUANDO EXISTAN NUEVAS PRUEBAS","CUANDO SE SOLICITA LA NULIDAD DEL PROCESO","NO SE PUEDE REHACER LA NOTIFICACIÓN"]'::jsonb, 'QUE SE DEMUESTRE QUE LA NOTIFICACIÓN SE HA REALIZADO SIN LAS FORMALIDADES Y REQUISITOS LEGALES', 0, '(ART: 26)** [TITULO I] [CAPITULO III]', '181908', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (699, 699, 'VIGENCIA DE LAS NOTIFICACIONES.- LAS NOTIFICACIONES SURTIRÁN EFECTO CONFORME A LAS SIGUIENTES REGLAS: (SEÑALE EL INCORRECTO)', '["LAS NOTIFICACIONES PERSONALES: EL DÍA QUE HUBIEREN SIDO REALIZADOS","LAS CURSADAS MEDIANTE CORREO CERTIFICADO, OFICIO, CORREO ELECTRÓNICO Y ANÁLOGOS: EL DÍA QUE CONSTE HABER SIDO RECIBIDAS","LAS NOTIFICACIONES TELEFÓNICAS: EL MISMO DÍA","LAS NOTIFICACIONES POR PUBLICACIONES: A PARTIR DEL DÍA DE LA ÚLTIMA PUBLICACIÓN EN EL DIARIO OFICIAL","CUANDO POR DISPOSICIÓN LEGAL EXPRESA, UN ACTO ADMINISTRATIVO DEBE SER A LA VEZ NOTIFICADO PERSONALMENTE AL ADMINISTRADO Y PUBLICADO PARA RESGUARDAR DERECHOS O INTERÉSES DE LA ÚLTIMA NOTIFICACIÓN"]'::jsonb, 'LAS NOTIFICACIONES TELEFÓNICAS: EL MISMO DÍA', 2, '(ART: 25)** [TITULO I] [CAPITULO III]', '181910', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (700, 700, 'NOTIFICACIONES DEFECTUOSAS.- LA DESESTIMACIÓN DEL CUESTIONAMIENTO A LA VALIDEZ DE UNA NOTIFICACIÓN, CAUSA QUE DICHA NOTIFICACIÓN: ( SEÑALE LO CORRECTO)', '["INVALIDE EL PROCEDIMIENTO ADMINISTRATIVO","SE HAGA CONSTAR ASÍ EN ACTA O RESOLUCIÓN","OPERE DESDE LA FECHA EN QUE FUE REALIZADA","TENGA VALIDEZ DESDE EL DÍA HÁBIL SIGUIENTE EN QUE FUE REALIZADA","OPERE DESDE EL DÍA EN QUE LA AUTORIDAD ADMINISTRATIVA IMPARTIÓ LA ORDEN DE NOTIFICACIÓN"]'::jsonb, 'OPERE DESDE LA FECHA EN QUE FUE REALIZADA', 2, '(ART: 26)** [TITULO I] [CAPITULO III]', '181911', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (701, 701, 'INDEPENDENCIA DE LOS VICIOS DEL ACTO ADMINISTRATIVO.- LOS VICIOS INCURRIDOS EN LA EJECUCIÓN DE UN ACTO ADMINISTRATIVO, O EN SU NOTIFICACIÓN A LOS ADMINISTRADOS SON:', '["INDEPENDIENTES DE SU VALIDEZ","DEPENDIENTES DE SU VALIDEZ","SON INDEPENDIENTES Y DEPENDIENTES DE SU VALIDEZ","SON VÁLIDOS A PESAR DEL VICIO INCURRIDO","NO SON VÁLIDOS"]'::jsonb, 'INDEPENDIENTES DE SU VALIDEZ', 0, '(ART: 15)** [TITULO I] [CAPITULO II]', '181912', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (702, 702, 'RECURSO DE RECONSIDERACION.- EN LOS CASOS DE ACTOS ADMINISTRATIVOS, EMITIDOS POR ÓRGANOS QUE CONSTITUYEN ÚNICA INSTANCIA: (INDIQUE LA RESPUESTA CORRECTA)', '["SE REQUIERE NECESARIAMENTE DE NUEVA PRUEBA","NO SE REQUIERE NUEVA PRUEBA","SE REQUIERE DE NUEVOS TESTIMONIOS OBLIGATORIAMENTE","SE REQUIERE DE NUEVO TESTIMONIO","NO SE REQUIERE DE RECURSO DE RECONSIDERACIÓN"]'::jsonb, 'NO SE REQUIERE NUEVA PRUEBA', 1, '(ART: 208)** [TITULO III] [CAPITULO II]', '181913', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (704, 704, 'CONSERVACIÓN DEL ACTO.- SON ACTOS ADMINISTRATIVOS AFECTADOS POR VICIOS NO TRASCENDENTES LOS SIGUIENTES: (SEÑALE LA INCORRECTA)', '["EL ACTO CUYO CONTENIDO SEA IMPRECISO O INCONGRUENTE CON LAS CUESTIONES SURGIDAS EN LA MOTIVACIÓN","EL ACTO EMITIDO CON INFRACCIÓN A LAS FORMALIDADES NO ESENCIALES DEL PROCEDIMIENTO","EL ACTO EMITIDO CON UNA MOTIVACIÓN INSUFICIENTE O PARCIAL","LA CONTRAVENCIÓN A LA CONSTITUCIÓN, A LAS LEYES O A LAS NORMAS REGLAMENTARIAS","AQUELLOS EMITIDOS CON OMISIÓN DE DOCUMENTACIÓN NO ESENCIAL"]'::jsonb, 'LA CONTRAVENCIÓN A LA CONSTITUCIÓN, A LAS LEYES O A LAS NORMAS REGLAMENTARIAS', 3, '(ART: 14)** [TITULO I] [CAPITULO II]', '181915', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (705, 705, 'LOS PRINCIPIOS DEL PROCEDIMIENTO ADMINISTRATIVO:', '["SON DE NATURALEZA ANALOGA","NO SON DE NATURALEZA ANALOGA","TIENEN CARÁCTER TAXATIVO","NO TIENEN CARÁCTER TAXATIVO","NO SIRVEN DE CRITERIO INTERPRETATIVO PARA RESOLVER LAS CUESTIONES QUE PUEDAN SUSCITARSE EN LA APLICACIÓN DE LAS REGLAS DE PROCEDIMIENTO"]'::jsonb, 'NO TIENEN CARÁCTER TAXATIVO', 3, '(ART: IV)** [TITULO PRELIMINAR]', '181916', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (706, 706, 'TRANSCURSO DEL PLAZO. SEÑALE LA INCORRECTA', '["CUANDO EL PLAZO ES SEÑALADO POR DÍAS, SE ENTENDERÁ POR HÁBILES CONSECUTIVOS, EXCLUYENDO DEL CÓMPUTO AQUELLOS NO LABORABLES DEL SERVICIO, Y LOS FERIADOS NO LABORABLES DE ORDEN NACIONAL O REGIONAL","CUANDO EL ÚLTIMO DÍA DEL PLAZO O LA FECHA DETERMINADA ES INHÁBIL O POR CUALQUIER OTRA CIRCUNSTANCIA LA ATENCIÓN AL PÚBLICO ESE DÍA NO FUNCIONE DURANTE EL HORARIO NORMAL, SON ENTENDIDOS PRORROGADOS AL PRIMER DÍA HÁBIL SIGUIENTE","CUANDO EL PLAZO ES FIJADO EN MESES O AÑOS, ES CONTADO DE FECHA A FECHA, CONCLUYENDO EL DÍA IGUAL AL DEL MES O AÑO QUE INICIÓ, COMPLETANDO EL NÚMERO DE MESES O AÑOS FIJADOS PARA EL LAPSO","CUANDO EL PLAZO ES SEÑALADO POR MESES, SE ENTENDERÁ POR HÁBILES CONSECUTIVOS, INCLUYENDO DEL CÓMPUTO AQUELLOS NO LABORABLES DEL SERVICIO, Y LOS FERIADOS NO LABORABLES DE ORDEN NACIONAL O REGIONAL","SI EN EL MES DE VENCIMIENTO NO HUBIERE DÍA IGUAL A AQUEL EN QUE COMENZÓ EL CÓMPUTO, ES ENTENDIDO QUE EL PLAZO EXPIRA EL PRIMER DÍA HÁBIL DEL SIGUIENTE MES CALENDARIO"]'::jsonb, 'CUANDO EL PLAZO ES SEÑALADO POR MESES, SE ENTENDERÁ POR HÁBILES CONSECUTIVOS, INCLUYENDO DEL CÓMPUTO AQUELLOS NO LABORABLES DEL SERVICIO, Y LOS FERIADOS NO LABORABLES DE ORDEN NACIONAL O REGIONAL', 3, '(ART: 134)** [TITULO II] [CAPITULO IV]', '181917', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (709, 709, 'CUANDO LA ADMINISTRACIÓN NO TENGA POR CIERTOS LOS HECHOS ALEGADOS POR LOS ADMINISTRADOS O LA NATURALEZA DEL PROCEDIMIENTO LO EXIJA, LA ENTIDAD DISPONE LA ACTUACIÓN DE PRUEBA, SIGUIENDO EL CRITERIO DE CONCENTRACIÓN PROCESAL, FIJANDO UN PERÍODO QUE PARA EL EFECTO NO SERÁ MENOR DE TRES DÍAS NI MAYOR DE QUINCE, CONTADOS A PARTIR DE SU PLANTEAMIENTO', '["CARGA DE LA PRUEBA","ACTUACIÓN PROBATORIA","ALEGACIONES","ACTOS DE INSTRUCCIÓN","ACCESO A LA INFORMACIÓN DEL EXPEDIENTE"]'::jsonb, 'ACTUACIÓN PROBATORIA', 1, '(ART: 163)** [TITULO II] [CAPITULO VI]', '181920', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (710, 710, 'OMISIÓN DEL INFORME. MARQUE LA CORRECTA', '["ORDENAR LA DESTITUCIÓN INMEDIATA DEL FUNCIONARIO OMISO SIN PROCESO PREVIO","EXTENDER EL PLAZO PARA LA PRESENTACIÓN DEL INFORME SIN COMUNICACIÓN AL ADMINISTRADO","PRESCINDIR DEL INFORME O CITAR AL INFORMANTE PARA QUE EN FECHA ÚNICA Y EN UNA SESIÓN, A LA CUAL PUEDE ASISTIR EL ADMINISTRADO, PRESENTE SU PARECER VERBALMENTE","SOLICITAR OBLIGATORIAMENTE EL INFORME POR VÍA JUDICIAL ANTES DE CONTINUAR EL PROCEDIMIENTO","SANCIONAR DE INMEDIATO AL ADMINISTRADO POR FALTA DE COLABORACIÓN"]'::jsonb, 'PRESCINDIR DEL INFORME O CITAR AL INFORMANTE PARA QUE EN FECHA ÚNICA Y EN UNA SESIÓN, A LA CUAL PUEDE ASISTIR EL ADMINISTRADO, PRESENTE SU PARECER VERBALMENTE', 2, '(ART: 174)** [TITULO II] [CAPITULO VI]', '181921', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (711, 711, '¿QUIEN TIENE LA CARGA DE LA COMPARECENCIA DE LOS TESTIGOS EN EL LUGAR, FECHA Y HORA FIJADOS?', '["LA ADMINISTRACIÓN","EL PROPONENTE DE LA PRUEBA DE TESTIGOS","EL ADMINISTRADO","EL TITULAR DE LA ENTIDAD","EL TITULAR DEL PROCESO ADMINISTRATIVO COMPETENCIAL"]'::jsonb, 'EL PROPONENTE DE LA PRUEBA DE TESTIGOS', 1, '(ART: 175)** [TITULO II] [CAPITULO VI]', '181922', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (712, 712, 'ACTUACIONES PROBATORIAS QUE AFECTEN A TERCEROS', '["SIEMPRE PREVALECE SOBRE LOS DERECHOS FUNDAMENTALES DE LOS TERCEROS, DADO EL INTERÉS PÚBLICO SUBYACENTE","LOS TERCEROS TIENEN EL DEBER DE COLABORAR PARA LA PRUEBA DE LOS HECHOS CON RESPETO DE SUS DERECHOS CONSTITUCIONALES","PUEDE SER EXIGIDO POR LA ADMINISTRACIÓN SIN NECESIDAD DE GARANTIZAR NINGÚN TIPO DE PROTECCIÓN A LOS DERECHOS INDIVIDUALES DE LOS TERCEROS","SOLAMENTE OPERA CUANDO LOS TERCEROS HAN SIDO PARTE FORMAL DEL PROCEDIMIENTO ADMINISTRATIVO PRINCIPAL","IMPLICA QUE LOS TERCEROS DEBEN SOMETERSE A LAS ACTUACIONES PROBATORIAS SIN POSIBILIDAD DE OBJETAR POR RAZONES CONSTITUCIONALES"]'::jsonb, 'LOS TERCEROS TIENEN EL DEBER DE COLABORAR PARA LA PRUEBA DE LOS HECHOS CON RESPETO DE SUS DERECHOS CONSTITUCIONALES', 1, '(ART: 179)** [TITULO II] [CAPITULO VI]', '181924', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (713, 713, 'LOS ERRORES MATERIAL O ARITMÉTICO EN LOS ACTOS ADMINISTRATIVOS (. .......... ), EN CUALQUIER MOMENTO, DE OFICIO O A INSTANCIA DE LOS ADMINISTRADOS, SIEMPRE QUE NO SE ALTERE LO SUSTANCIAL DE SU CONTENIDO NI EL SENTIDO DE LA DECISIÓN', '["PUEDEN SER RECTIFICADOS SIN EFECTO RETROACTIVO","NO PUEDEN SER RECTIFICADOS CON EFECTO RETROACTIVO","PUEDEN SER RECTIFICADOS CON EFECTO RETROACTIVO","PUEDEN SER RECTIFICADOS CON EFECTO DEVOLUTIVO","NO PUEDEN SER RECTIFICADOS CON EFECTO DEVOLUTIVO"]'::jsonb, 'PUEDEN SER RECTIFICADOS CON EFECTO RETROACTIVO', 2, '(ART: 201)** [TITULO III] [CAPITULO I]', '181925', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (714, 714, 'RECURSOS ADMINISTRATIVOS.- CONSTATADA LA EXISTENCIA DE UNA CAUSAL DE NULIDAD, LA AUTORIDAD, ADEMÁS DE LA DECLARACIÓN DE NULIDAD, RESOLVERÁ SOBRE EL FONDO DEL ASUNTO, DE CONTARSE CON LOS ELEMENTOS SUFICIENTES PARA ELLO. CUANDO NO SEA POSIBLE PRONUNCIARSE SOBRE EL FONDO DEL ASUNTO, SE DISPONDRÁ:', '["SU PROCEDENCIA","SU ADMISIÓN","SU INADMISIÓN","SU IMPROCEDENCIA","LA REPOSICIÓN DEL PROCEDIMIENTO AL MOMENTO EN QUE EL VICIO SE PRODUJO"]'::jsonb, 'LA REPOSICIÓN DEL PROCEDIMIENTO AL MOMENTO EN QUE EL VICIO SE PRODUJO', 4, '(ART: 217)** [TITULO III] [CAPITULO II]', '181926', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (715, 715, 'RESPECTO A LAS RESPONSABILIDADES DE LA ADMINISTRACIÓN PÚBLICA SEÑALE LA RESPUESTA CORRECTA:', '["LAS ENTIDADES NO SON PATRIMONIALMENTE RESPONSABLES FRENTE A LOS ADMINISTRADOS POR LOS DAÑOS DIRECTOS E INMEDIATOS CAUSADOS POR LOS ACTOS DE LA ADMINISTRACIÓN","LAS ENTIDADES NO SON PATRIMONIALMENTE RESPONSABLES FRENTE A LOS ADMINISTRADOS POR LOS DAÑOS DIRECTOS E INMEDIATOS CAUSADOS POR LOS SERVICIOS PÚBLICOS DIRECTAMENTE PRESTADOS POR AQUELLAS","HAY LUGAR A LA REPARACIÓN POR PARTE DE LA ADMINISTRACIÓN, CUANDO EL DAÑO FUERA CONSECUENCIA DE CASO FORTUITO O FUERZA MAYOR, DE HECHO DETERMINANTE DEL ADMINISTRADO DAMNIFICADO O DE TERCERO","HAY LUGAR A REPARACIÓN POR PARTE DE LA ADMINISTRACIÓN, CUANDO LA ENTIDAD HUBIERE ACTUADO RAZONABLE Y PROPORCIONALMENTE EN DEFENSA DE LA VIDA, INTEGRIDAD","LA DECLARATORIA DE NULIDAD DE UN ACTO ADMINISTRATIVO EN SEDE ADMINISTRATIVA O POR RESOLUCIÓN JUDICIAL NO PRESUPONE NECESARIAMENTE DERECHO A LA INDEMNIZACIÓN"]'::jsonb, 'LA DECLARATORIA DE NULIDAD DE UN ACTO ADMINISTRATIVO EN SEDE ADMINISTRATIVA O POR RESOLUCIÓN JUDICIAL NO PRESUPONE NECESARIAMENTE DERECHO A LA INDEMNIZACIÓN', 4, '(ART: 238)** [TITULO V] [CAPITULO I]', '181928', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (788, 788, '¿QUIÉNES PRESERVARÁN EL PRINCIPIO DE IGUALDAD PROCESAL?', '["LOS FISCALES","LOS JUECES","LA POLICÍA NACIONAL","EL ÓRGANO JURISDICCIONAL","LOS REPRESENTANTES DEL MINISTERIO PÚBLICO"]'::jsonb, 'LOS JUECES', 1, '(ART: I) [TITULO PRELIMINAR]', '184365', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (718, 718, 'DE UN PLAZO IMPRORROGABLE PARA REALIZAR UNA ACTUACIÓN O EJERCER UNA FACULTAD PROCESAL, PREVIO APERCIBIMIENTO, LA ENTIDAD DECLARA DECAÍDO EL DERECHO AL CORRESPONDIENTE ACTO, NOTIFICANDO LA DECISIÓN', '["AL TÉRMINO","AL CADUCAR","AL VENCIMIENTO","AL INICIO","AL COMIENZO"]'::jsonb, 'AL VENCIMIENTO', 2, '(ART: 140)** [TITULO II] [CAPITULO IV]', '181932', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (719, 719, 'DEL PROCEDIMIENTO ADMINISTRATIVO.- RESPECTO AL IMPULSO DEL PROCEDIMIENTO, SEÑALE LA RESPUESTA CORRECTA:', '["LA AUTORIDAD COMPETENTE, PREVIO PEDIDO DE PARTE, DEBE PROMOVER TODA ACTUACIÓN QUE FUESE NECESARIA PARA SU TRAMITACIÓN","LA AUTORIDAD COMPETENTE, PREVIO PEDIDO DE PARTE, DEBE SUPERAR CUALQUIER OBSTÁCULO QUE SE OPONGA A REGULAR TRAMITACIÓN DEL PROCEDIMIENTO","LA AUTORIDAD COMPETENTE, PREVIO PEDIDO DE PARTE, DEBE DETERMINAR LA NORMA APLICABLE AL CASO AUN CUANDO NO HAYA SIDO INVOCADA O FUERE ERRÓNEA LA CITA LEGAL","LA AUTORIDAD COMPETENTE, PREVIO PEDIDO DE PARTE, DEBE EVITAR EL ENTORPECIMIENTO O DEMORA A CAUSA DE DILIGENCIAS INNECESARIAS O MERAMENTE FORMALES","LA AUTORIDAD COMPETENTE, AUN SIN PEDIDO DE PARTE, DEBE PROMOVER TODA ACTUACIÓN QUE FUESE NECESARIA PARA SU TRAMITACIÓN"]'::jsonb, 'LA AUTORIDAD COMPETENTE, AUN SIN PEDIDO DE PARTE, DEBE PROMOVER TODA ACTUACIÓN QUE FUESE NECESARIA PARA SU TRAMITACIÓN', 4, '(ART: 145)** [TITULO II] [CAPITULO V]', '181933', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (741, 741, 'EL CITATORIO SE RIGE POR EL RÉGIMEN COMÚN DE LA NOTIFICACIÓN; ES UNA:', '["FORMALIDAD DE LA COMPARECENCIA","COMPARECENCIA PERSONAL","FORMALIDAD DE TERCEROS ADMINISTRADOS","ACCIÓN DE SUMINISTRO DE INFORMACIÓN A LAS ENTIDADES","FORMA DE DEBERES GENERALES DE LOS ADMINISTRADOS EN EL PROCEDIMIENTO"]'::jsonb, 'FORMALIDAD DE LA COMPARECENCIA', 0, '(ART: 59)** [TITULO II] [CAPITULO II] [SUBCAPITULO I]', '181961', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (720, 720, '¿EN CUÁL DE LOS SIGUIENTES ESCENARIOS UNA MEDIDA CAUTELAR DICTADA EN UN PROCEDIMIENTO ADMINISTRATIVO CADUCA DE PLENO DERECHO?', '["CUANDO SE EMITE LA RESOLUCIÓN QUE PONE FIN AL PROCEDIMIENTO","CUANDO TRANSCURRE EL PLAZO FIJADO PARA LA EJECUCIÓN DE LA MEDIDA CAUTELAR","CUANDO EL ADMINISTRADO SOLICITA EXPRESAMENTE LA CADUCIDAD DE LA MEDIDA Y ESTO ES ACEPTADO POR LA AUTORIDAD","CUANDO LA ENTIDAD ADMINISTRATIVA DECIDE EN CUALQUIER MOMENTO REVOCAR LA MEDIDA SIN MOTIVACIÓN ALGUNA","CUANDO SE INTERPONEN RECURSOS ADMINISTRATIVOS CONTRA LA MEDIDA CAUTELAR Y ESTOS NO SON RESUELTOS EN EL PLAZO LEGAL"]'::jsonb, 'CUANDO SE EMITE LA RESOLUCIÓN QUE PONE FIN AL PROCEDIMIENTO', 0, '(ART: 146)** [TITULO II] [CAPITULO V]', '181934', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (721, 721, 'EN EL IMPULSO Y TRAMITACIÓN DE CASOS DE UNA MISMA NATURALEZA, SE SIGUE RIGUROSAMENTE EL ORDEN DE INGRESO, Y SE RESUELVEN CONFORME LO VAYA PERMITIENDO SU ESTADO, DANDO CUENTA AL SUPERIOR DE LOS MOTIVOS DE DEMORA EN EL CUMPLIMIENTO DE LOS PLAZOS DE LEY, QUE NO PUEDAN SER REMOVIDOS DE OFICIO. EL REFERIDO PÁRRAFO CONSTITUYE UNA REGLA PARA ASEGURAR EL CUMPLIMIENTO DEL PRINCIPIO DE:', '["LEGALIDAD","EFICIENCIA","IMPULSO DE OFICIO","CELERIDAD","INFORMALISMO"]'::jsonb, 'CELERIDAD', 3, '(ART: 148)** [TITULO II] [CAPITULO V]', '181936', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (722, 722, 'EN NINGÚN CASO LA AUTORIDAD PODRÁ ALEGAR DEFICIENCIAS DEL ADMINISTRADO NO ADVERTIDAS A LA PRESENTACIÓN DE LA SOLICITUD, COMO FUNDAMENTO PARA DENEGAR SU PRETENSIÓN. EL REFERIDO PÁRRAFO CONSTITUYE UNA REGLA PARA ASEGURAR EL CUMPLIMIENTO DEL PRINCIPIO DE:', '["LEGALIDAD","EFICIENCIA","IMPULSO DE OFICIO","CELERIDAD","INFORMALISMO"]'::jsonb, 'CELERIDAD', 3, '(ART: 148)** [TITULO II] [CAPITULO V]', '181937', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (723, 723, 'DEL PROCEDIMIENTO ADMINISTRATIVO.- LOS EXPEDIENTES SON COMPAGINADOS SIGUIENDO EL ORDEN REGULAR DE LOS DOCUMENTOS QUE LO INTEGRAN, FORMANDO CUERPOS CORRELATIVOS QUE NO EXCEDAN DE (. ..... ), SALVO CUANDO TAL LÍMITE OBLIGARA A DIVIDIR ESCRITOS O DOCUMENTOS QUE CONSTITUYAN UN SOLO TEXTO, EN CUYO CASO SE MANTENDRÁ SU UNIDAD', '["TRESCIENTOS FOLIOS","QUINIENTOS FOLIOS","CIEN FOLIOS","DOSCIENTOS FOLIOS","CINCUENTA FOLIOS"]'::jsonb, 'DOSCIENTOS FOLIOS', 3, '(ART: 152)** [TITULO II] [CAPITULO V]', '181938', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (724, 724, '¿EN QUÉ MOMENTO, LOS ADMINISTRADOS PUEDEN FORMULAR QUEJA CONTRA LOS DEFECTOS DE TRAMITACIÓN Y, EN ESPECIAL, LOS QUE SUPONGAN PARALIZACIÓN, INFRACCIÓN DE LOS PLAZOS ESTABLECIDOS LEGALMENTE, INCUMPLIMIENTO DE LOS DEBERES FUNCIONALES U OMISIÓN DE TRÁMITES QUE DEBEN SER SUBSANADOS?', '["EN CUALQUIER MOMENTO","ANTES DEL INICIO DEL PROCEDIMIENTO","ANTES DE LA RESOLUCIÓN DEFINITIVA DEL ASUNTO EN LA INSTANCIA RESPECTIVA","ANTES DE LA APORTACIÓN DE PRUEBAS","ANTES DE LA APELACIÓN"]'::jsonb, 'EN CUALQUIER MOMENTO', 0, '(ART: 158)** [TITULO II] [CAPITULO V]', '181939', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (725, 725, '¿QUIEN TIENE A CARGO ASEGURAR LA REGULARIDAD DE LAS DELIBERACIONES Y EJECUTAR SUS ACUERDOS.?', '["EL SECRETARIO DEL ÓRGANO COLEGIADO","EL DIRECTOR DEL ÓRGANO COLEGIADO","EL PRESIDENTE DEL ÓRGANO COLEGIADO","EL DECANO DEL ÓRGANO COLEGIADO","EL TITULAR DEL ÓRGANO COLEGIADO"]'::jsonb, 'EL PRESIDENTE DEL ÓRGANO COLEGIADO', 2, '(ART: 96)** [TITULO II] [CAPITULO II] [SUBCAPITULO V]', '181941', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (726, 726, 'AUTORIDADES DE LOS ÓRGANOS COLEGIADOS.- CADA ÓRGANO COLEGIADO DE LAS ENTIDADES ES REPRESENTADO POR UN ( ............... ), A CARGO DE ASEGURAR LA REGULARIDAD DE LAS DELIBERACIONES Y EJECUTAR SUS ACUERDOS, Y CUENTA CON UN SECRETARIO, A CARGO DE PREPARAR LA AGENDA, LLEVAR, ACTUALIZAR Y CONSERVAR LAS ACTAS DE LAS SESIONES, COMUNICAR LOS ACUERDOS, OTORGAR COPIAS Y DEMÁS ACTOS PROPIOS DE LA NATURALEZA DEL CARGO', '["SECRETARIO","PRESIDENTE","DIRECTOR","DECANO","TITULAR"]'::jsonb, 'PRESIDENTE', 1, '(ART: 96)** [TITULO II] [CAPITULO II] [SUBCAPITULO V]', '181942', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (727, 727, '(. .... ), ES PROMOVIDO DE OFICIO POR EL ÓRGANO COMPETENTE O INSTANCIA DEL ADMINISTRADO, SALVO QUE POR DISPOSICIÓN LEGAL O POR SU FINALIDAD CORRESPONDA SER INICIADO EXCLUSIVAMENTE DE OFICIO O A INSTANCIA DEL INTERESADO', '["LOS PROCEDIMIENTOS DE LA ADMINISTRACIÓN","LOS ACTOS ADMINISTRATIVOS","EL PROCEDIMIENTO ADMINISTRATIVO","LOS ACTOS DE LA ADMINISTRACIÓN","LOS DOCUMENTOS ADMINISTRATIVOS"]'::jsonb, 'EL PROCEDIMIENTO ADMINISTRATIVO', 2, '(ART: 103)** [TITULO II] [CAPITULO III]', '181943', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (728, 728, 'RESPECTO A LA FUENTE DE LA COMPETENCIA DE LAS ENTIDADES ADMINISTRATIVAS, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES DESCRIBE CORRECTAMENTE EL ORIGEN Y REGULACIÓN DE DICHA COMPETENCIA?', '["LA COMPETENCIA DE LAS ENTIDADES ADMINISTRATIVAS PUEDE ESTABLECERSE VÁLIDAMENTE MEDIANTE ACUERDOS MUNICIPALES Y RESOLUCIONES ADMINISTRATIVAS DE CARÁCTER GENERAL A FALTA DE DISPOSICIÓN CONSTITUCIONAL O LEGAL","LA COMPETENCIA DE LAS ENTIDADES TIENE SU ORIGEN DIRECTO EN LA PRÁCTICA ADMINISTRATIVA Y LA COSTUMBRE, Y PUEDE SER RECONOCIDA POR REGLAMENTOS EMITIDOS POR LA ADMINISTRACIÓN CENTRAL","LA COMPETENCIA DE LAS ENTIDADES TIENE SU FUENTE EN LA CONSTITUCIÓN Y LA LEY, Y ES REGLAMENTADA POR NORMAS ADMINISTRATIVAS QUE SE DERIVAN DE DICHAS FUENTES","LAS ENTIDADES ADQUIEREN COMPETENCIA PRINCIPALMENTE DE LOS TRATADOS INTERNACIONALES RATIFICADOS POR EL ESTADO, EN CUYO CASO LA LEY SOLO TIENE FUNCIÓN INTERPRETATIVA","EL EJERCICIO DE COMPETENCIA DEVIENE VÁLIDO SIEMPRE QUE PROVENGA DE UNA NORMA REGLAMENTARIA EMITIDA POR LA ENTIDAD INVOLUCRADA, SIN NECESIDAD DE FUNDAMENTO LEGAL EXPLÍCITO"]'::jsonb, 'LA COMPETENCIA DE LAS ENTIDADES TIENE SU FUENTE EN LA CONSTITUCIÓN Y LA LEY, Y ES REGLAMENTADA POR NORMAS ADMINISTRATIVAS QUE SE DERIVAN DE DICHAS FUENTES', 2, '(ART: 61)** [TITULO II] [CAPITULO II] [SUBCAPITULO II]', '181945', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (729, 729, 'RESPECTO A LA SUPLENCIA DE LOS TITULARES DE ÓRGANOS ADMINISTRATIVOS, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES ES CORRECTA SOBRE EL PROCESO DE SUPLENCIA TEMPORAL EN CASO DE VACANCIA O AUSENCIA JUSTIFICADA?', '["LA SUPLENCIA SOLO PROCEDE ANTE LA AUSENCIA DEL TITULAR, EXCLUYENDO CASOS DE VACANCIA DEFINITIVA","LA SUPLENCIA TEMPORAL ES AUTOMÁTICAMENTE EJERCIDA POR EL SERVIDOR CON MAYOR ANTIGÜEDAD EN LA ENTIDAD, SIN NECESIDAD DE DESIGNACIÓN","LA SUPLENCIA TEMPORAL CORRESPONDE ÚNICAMENTE AL SUBALTERNO INMEDIATO DEL TITULAR, SIGUIENDO EL ORDEN JERÁRQUICO DEL REGLAMENTO INTERNO","LA SUPLENCIA DE LOS TITULARES DE ÓRGANOS ADMINISTRATIVOS, EN CASO DE VACANCIA O AUSENCIA JUSTIFICADA, DEBE SER DISPUESTA POR QUIEN TIENE COMPETENCIA PARA REALIZAR EL NOMBRAMIENTO DE DICHO TITULAR","LA SUPLENCIA SOLO PUEDE DISPONERSE SI LA VACANCIA ES PRODUCTO DE UNA SANCIÓN ADMINISTRATIVA VIGENTE"]'::jsonb, 'LA SUPLENCIA DE LOS TITULARES DE ÓRGANOS ADMINISTRATIVOS, EN CASO DE VACANCIA O AUSENCIA JUSTIFICADA, DEBE SER DISPUESTA POR QUIEN TIENE COMPETENCIA PARA REALIZAR EL NOMBRAMIENTO DE DICHO TITULAR', 3, '(ART: 73)** [TITULO II] [CAPITULO II] [SUBCAPITULO II]', '181946', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (742, 742, 'LA REALIZACIÓN DE ACTIVIDADES CON CARÁCTER MATERIAL, TÉCNICO O DE SERVICIOS DE COMPETENCIA DE UN ÓRGANO PUEDE SER ENCARGADA A OTROS ÓRGANOS O ENTIDADES POR RAZONES DE EFICACIA, O CUANDO LA ENCARGADA POSEA LOS MEDIOS IDÓNEOS PARA SU DESEMPEÑO POR SÍ MISMA; SE REFIERE A:', '["DELEGACIÓN DE COMPETENCIA","DEBER DE VIGILANCIA DEL DELEGANTE","ENCARGO DE GESTIÓN","AVOCACIÓN DE COMPETENCIA","DELEGACIÓN DE FIRMA"]'::jsonb, 'ENCARGO DE GESTIÓN', 2, '(ART: 71)** [TITULO II] [CAPITULO II] [SUBCAPITULO II]', '181962', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1287, 1287, 'LA LEY CONTRA EL CRIMEN ORGANIZADO ES APLICABLE A LOS DELITOS:', '["CONTRA LA SALUD PÚBLICA","CONTRA LA INTRANQUILIDAD PÚBLICA","DE PELIGRO COMÚN","CONTRA LA VIDA HUMANA DEPENDIENTE","DE ABANDONO DE PERSONA EN PELIGRO"]'::jsonb, 'CONTRA LA SALUD PÚBLICA', 0, '(texto: 3)** [TITULO I]', '185306', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (730, 730, '¿CUÁL ES LA CONSECUENCIA PRINCIPAL RESPECTO DE LAS COSTAS CUANDO UNA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA SOLICITA LA COLABORACIÓN DE OTRA ENTIDAD?', '["LA ENTIDAD QUE SOLICITA LA COLABORACIÓN DEBE ASUMIR LOS COSTOS ADMINISTRATIVOS Y TASAS QUE ELLO OCASIONE","LA ENTIDAD QUE RECIBE LA SOLICITUD PUEDE EXIGIR EL PAGO DE DERECHOS ADMINISTRATIVOS SI ASÍ LO CONSIDERA PERTINENTE","LA SOLICITUD DE COLABORACIÓN SÍ PUEDE GENERAR EL PAGO DE TASAS, PERO ÚNICAMENTE SI EXISTE UNA DISPOSICIÓN EXPRESA EN UNA REGLAMENTACIÓN INTERNA","LA SOLICITUD DE COLABORACIÓN NO DETERMINA EL PAGO DE TASA POR DICHO CONCEPTO, SIN PERJUICIO DEL PAGO DE LAS TASAS REGULARES","EL PAGO DE CUALQUIER CONCEPTO QUEDARÁ A DISCRECIÓN DEL ÓRGANO ADMINISTRATIVO SUPERIOR A AMBAS ENTIDADES"]'::jsonb, 'LA SOLICITUD DE COLABORACIÓN NO DETERMINA EL PAGO DE TASA POR DICHO CONCEPTO, SIN PERJUICIO DEL PAGO DE LAS TASAS REGULARES', 3, '(ART: 79)** [TITULO II] [CAPITULO II] [SUBCAPITULO III]', '181947', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (731, 731, 'EN TODO CONFLICTO DE COMPETENCIA, EL ÓRGANO A QUIEN SE REMITE EL EXPEDIENTE DICTA RESOLUCIÓN IRRECURRIBLE DENTRO DEL PLAZO DE (. .. )', '["TRES DÍAS","CUATRO DÍAS","DOS DÍAS","CINCO DÍAS","DIEZ DÍAZ"]'::jsonb, 'CUATRO DÍAS', 1, '(ART: 85)** [TITULO II] [CAPITULO II] [SUBCAPITULO IV]', '181948', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (732, 732, '¿QUIÉN ES COMPETENTE PARA RESOLVER LOS CONFLICTOS POSITIVOS O NEGATIVOS DE COMPETENCIA DENTRO DE UNA MISMA ENTIDAD ADMINISTRATIVA CUANDO EXISTEN DIVERSAS AUTORIDADES INVOLUCRADAS?', '["EL SUPERIOR JERÁRQUICO COMÚN DE LAS AUTORIDADES EN CONFLICTO","EL PRESIDENTE DEL CONSEJO DE MINISTROS, POR DELEGACIÓN EXPRESA DEL TITULAR DE LA ENTIDAD","EL TRIBUNAL CONSTITUCIONAL, POR VÍA DE CONSULTA ADMINISTRATIVA","LA DEFENSORÍA DEL PUEBLO, COMO ÓRGANO IMPARCIAL EXTERNO A LA ENTIDAD","EL JUEZ DE LO CONTENCIOSO ADMINISTRATIVO DESIGNADO PARA LA CIRCUNSCRIPCIÓN TERRITORIAL CORRESPONDIENTE"]'::jsonb, 'EL SUPERIOR JERÁRQUICO COMÚN DE LAS AUTORIDADES EN CONFLICTO', 0, '(ART: 86)** [TITULO II] [CAPITULO II] [SUBCAPITULO IV]', '181949', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (733, 733, '¿CUÁL DE LAS SIGUIENTES AFIRMACIONES DEFINE CORRECTAMENTE QUIÉNES SON CONSIDERADOS ADMINISTRADOS RESPECTO DE UN PROCEDIMIENTO ADMINISTRATIVO CONCRETO?', '["SOLAMENTE QUIENES INICIAN UN PROCEDIMIENTO ADMINISTRATIVO PUEDEN SER CONSIDERADOS ADMINISTRADOS, SIN IMPORTAR LA AFECTACIÓN DE INTERESES DE TERCEROS","SOLO LAS PERSONAS JURÍDICAS, YA QUE SOLO ELLAS PUEDEN OSTENTAR DERECHOS COLECTIVOS ANTE LA ADMINISTRACIÓN PÚBLICA","QUIENES LO PROMUEVAN COMO TITULARES DE DERECHOS O INTERESES LEGÍTIMOS INDIVIDUALES O COLECTIVOS","CUALQUIER PERSONA NATURAL O JURÍDICA, INDEPENDIENTEMENTE DE ESTAR INVOLUCRADOS EN EL PROCEDIMIENTO O DE SER AFECTADOS POR LA DECISIÓN ADMINISTRATIVA","SOLAMENTE TITULARES DE DERECHOS PATRIMONIALES INDIVIDUALES PUEDEN SER ADMINISTRADOS EN EL PROCEDIMIENTO REGULADO POR EL ARTÍCULO 51"]'::jsonb, 'QUIENES LO PROMUEVAN COMO TITULARES DE DERECHOS O INTERESES LEGÍTIMOS INDIVIDUALES O COLECTIVOS', 2, '(ART: 51)** [TITULO II] [CAPITULO II] [SUBCAPITULO I]', '181951', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (734, 734, 'LOS ACTOS ADMINISTRATIVOS DEBERÁN EXPRESARSE POR ESCRITO, SALVO QUE POR LA NATURALEZA Y CIRCUNSTANCIA DEL CASO, EL ORDENAMIENTO JURÍDICO HAYA PREVISTO OTRA FORMA, SIEMPRE QUE PERMITA TENER CONSTANCIA DE SU EXISTENCIA, SE REFIERE A UNA:', '["OBJETO O CONTENIDO DEL ACTO ADMINISTRATIVO","FORMA DE LOS ACTOS ADMINISTRATIVOS","MOTIVACIÓN DEL ACTO ADMINISTRATIVO","REQUISITOS DE VALIDEZ DEL ACTO ADMINISTRATIVO","RÉGIMEN DE LOS ACTOS DE LA ADMNISTRACIÓN INTERNA"]'::jsonb, 'FORMA DE LOS ACTOS ADMINISTRATIVOS', 1, '(ART: 4)** [TITULO I] [CAPITULO I]', '181952', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (735, 735, 'ES VÁLIDO EL ACTO ADMNINISTRATIVO DICTADO CONFORME AL ORDENAMIENTO JURÍDICO; SE REFIERE A:', '["VALIDEZ DEL ACTO ADMINISTRATIVO","PRESUNCIÓN DE VALIDEZ","CAUSALES DE NULIDAD","INSTANCIA COMPETENTE PARA DECLARAR LA NULIDAD","ALCANCES DE LA NULIDAD"]'::jsonb, 'VALIDEZ DEL ACTO ADMINISTRATIVO', 0, '(ART: 8)** [TITULO I] [CAPITULO II]', '181953', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (736, 736, 'LA NULIDAD DE UN ACTO SÓLO IMPLICA LA DE LOS SUCESIVOS EN EL PROCEDIMIENTO CUANDO ESTÉN VINCULADOS A ÉL; SE REFIERE A:', '["CONSERVACIÓN DEL ACTO","INDEPENDENCIA DE LOS VICIOS DEL ACTO ADMINISTRATIVO","INSTANCIA COMPETENTE PARA DECLARAR LA NULIDAD","CAUSALES DE NULIDAD","ALCANCES DE LA NULIDAD"]'::jsonb, 'ALCANCES DE LA NULIDAD', 4, '(ART: 13)** [TITULO I] [CAPITULO II]', '181954', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (737, 737, 'LA AUTORIDAD PODRÁ DISPONER EN EL MISMO ACTO ADMINISTRATIVO QUE TENGA EFICACIA ANTICIPADA A SU EMISIÓN, SÓLO SI FUERA MÁS FAVORABLE A LOS ADMINISTRADOS, Y SIEMPRE QUE NO LESIONE DERECHOS FUNDAMENTALES O INTERESES DE BUENA FE LEGALMENTE PROTEGIDOS A TERCEROS Y QUE EXISTIERA EN LA FECHA A LA QUE PRETENDA RETROTRAERSE LA EFICACIA DEL ACTO EL SUPUESTO DE HECHO JUSTIFICATIVO PARA SU ADOPCIÓN; SE REFIERE A LA:', '["EFICACIA ANTICIPADA DEL ACTO ADMINISTRATIVO","OBLIGACIÓN DE NOTIFICAR","DISPENSA DE NOTIFICACIÓN","MODALIDADES DE NOTIFICACIÓN","EFICACIA DEL ACTO ADMINISTRATIVO"]'::jsonb, 'EFICACIA ANTICIPADA DEL ACTO ADMINISTRATIVO', 0, '(ART: 17)** [TITULO I] [CAPITULO III]', '181955', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (738, 738, 'SE HARÁ EN EL DOMICILIO QUE CONSTE EN EL EXPEDIENTE, O EN EL ÚLTIMO DOMICILIO QUE LA PERSONA A QUIÉN DEBA NOTIFICAR HAYA SEÑALADO ANTE EL ÓRGANO ADMNINISTRATIVO EN OTRO PROCEDIMIENTO ANÁLOGO EN LA PROPIA ENTIDAD DENTRO DEL ÚLTIMO AÑO; SE REFIERE A:', '["RÉGIMEN DE LA NOTIFICACIÓN PERSONAL","EL ACTO DE NOTIFICACIÓN","NOTIFICACIÓN A PLURALIDAD DE INTERESADOS","MODALIDADES DE NOTIFICACIÓN","DISPENSA DE NOTIFICACIÓN"]'::jsonb, 'RÉGIMEN DE LA NOTIFICACIÓN PERSONAL', 0, '(ART: 21)** [TITULO I] [CAPITULO III]', '181956', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (739, 739, 'EL PLAZO QUE TRANSCURRA DESDE EL INICIO DE UN PROCEDIMEINTO ADMINISTRATIVO DE EVALUACIÓN PREVIA HASTA QUE SEA DICTADA LA RESOLUCIÓN RESPECTIVA, NO PUEDE EXCEDER DE:', '["VEINTE (20) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS CUYO CUMPLIMIENTO REQUIERA UNA DURACIÓN MAYOR","VEINTICINCO (25) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS CUYO CUMPLIMIENTO REQUIERA UNA DURACIÓN MAYOR","TREINTA (30) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS CUYO CUMPLIMIENTO REQUIERA UNA DURACIÓN MAYOR","TRES (3) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS CUYO CUMPLIMIENTO REQUIERA UNA DURACIÓN MAYOR","CINCO (5) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS CUYO CUMPLIMIENTO REQUIERA UNA DURACIÓN MAYOR"]'::jsonb, 'TREINTA (30) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS CUYO CUMPLIMIENTO REQUIERA UNA DURACIÓN MAYOR', 2, '(ART: 35)** [TITULO II] [CAPITULO I]', '181958', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (740, 740, 'SOLAMENTE SERÁN INCLUIDOS COMO REQUISITOS EXIGIDOS PARA LA REALIZACIÓN DE CADA PROCEDIMIENTO ADMINISTRATIVO AQUELLOS QUE RAZONABLEMENTE SEAN INDISPENSABLES PARA OBTENER EL PRONUNCIAMIENTO CORRESPONDIENTE, ATENDIENDO ADEMÁS A SUS COSTOS Y BENEFICIOS; SE REFIERE A:', '["CONSIDERACIONES PARA ESTRUCTURAR EL PROCEDIMIENTO","DOCUMENTACIÓN PROHIBIDA DE SOLICITAR","DOCUMENTOS","APROBACIÓN DEL TEXTO ÚNICO DE PROCEDIMIENTOS ADMINSITRATIVOS","CONTENIDO DEL TEXTO ÚNICO DE PROCEDIMIENTOS ADMINSITRATIVOS"]'::jsonb, 'CONSIDERACIONES PARA ESTRUCTURAR EL PROCEDIMIENTO', 0, '(ART: 39)** [TITULO II] [CAPITULO I]', '181959', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1301, 1301, 'LA LEY CONTRA EL CRIMEN ORGANIZADO ES APLICABLE A LOS DELITOS DE:', '["HOMICIDIO SIMPLE","DISCRIMINACIÓN","TRÁFICO ILÍCITO DE MIGRANTES","PATRIMONIO","HOMICIDIO PRETERINTENCIONAL"]'::jsonb, 'TRÁFICO ILÍCITO DE MIGRANTES', 2, '(texto: 3)** [TITULO I]', '185348', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (743, 743, 'LA SOLICITUD DE COLABORACIÓN NO DETERMINA EL PAGO DE TASA POR DICHO CONCEPTO, SIN PERJUICIO DEL PAGO DE LAS TASAS REGULARES', '["COSTAS DE LA COLABORACIÓN","MEDIOS DE COLABORACIÓN INTERINSTITUCIONAL","EJECUCIÓN DE LA COLABORACIÓN ENTRE AUTORIDADES","COSTAS DE COLABORACIÓN","CONTTROL DE COMPETENCIA"]'::jsonb, 'COSTAS DE LA COLABORACIÓN', 0, '(ART: 79)** [TITULO II] [CAPITULO II] [SUBCAPITULO III]', '181963', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (744, 744, 'EL ACTO ADMINISTRATIVO ES EFICAZ A PARTIR DE QUE LA NOTIFICACIÓN LEGALMENTE REALIZADA PRODUCE:', '["SUS EFECTOS","SUS DEFECTOS","BENEFICIOS","DAÑOS Y PERJUICIOS","SUS EFECTOS ILEGALES"]'::jsonb, 'SUS EFECTOS', 0, '(ART: 16)** [TITULO I] [CAPITULO III]', '181964', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (745, 745, 'UNA MODALIDAD ACCESORIA NO PUEDE SER APLICADA CONTRA EL FIN PERSEGUIDO POR:', '["EL ACTO ADMINISTRATIVO","EL ACTO JUDICIAL","EL ACTO POLICIAL","EL ACTO LEGISLATIVO","EL ACTO ADMINISTRATIVO LEGAL"]'::jsonb, 'EL ACTO ADMINISTRATIVO', 0, '(ART: 2)** [TITULO I] [CAPITULO I]', '181965', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (746, 746, 'EL ACTO ADMINISTRATIVO DEBE SER DEBIDAMENTE MOTIVADO EN PROPORCIÓN AL CONTENIDO Y CONFORME AL:', '["ORDENAMIENTO JUDICIAL","ORDENAMIENTO LEGAL","ORDENAMIENTO JURÍDICO","ORDENAMIENTO ADMINISTRATIVO","ORDENAMIENTO MOTIVADO"]'::jsonb, 'ORDENAMIENTO JURÍDICO', 2, '(ART: 3)** [TITULO I] [CAPITULO I]', '181966', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (747, 747, 'DEBE SER EXPRESA, MEDIANTE UNA RELACIÓN CONCRETA Y DIRECTA DE LOS HECHOS PROBADOS RELEVANTES DEL CASO ESPECÍFICO, Y LA EXPOSICIÓN DE LAS RAZONES JURÍDICAS Y NORMATIVAS QUE CON REFERENCIA DIRECTA A LOS ANTERIORES JUSTIFICAN EL ACTO ADOPTADO. CORRESPONDE A:', '["LA RESOLUCIÓN","LA MOTIVACIÓN","LA DOCTRINA","LA ORDEN","LA CASUISTICA"]'::jsonb, 'LA MOTIVACIÓN', 1, '(ART: 6)** [TITULO I] [CAPITULO I]', '181967', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (748, 748, 'TODO ACTO ADMINISTRATIVO, SE CONSIDERA VÁLIDO EN TANTO SU PRETENDIDA NULIDAD NO SEA DECLARADA POR AUTORIDAD ADMINISTRATIVA O JURISDICCIONAL SEGÚN CORRESPONDA; SE REFIERE A:', '["CAUSALES DE NULIDAD","VALIDEZ DEL ACTO ADMINISTRATIVO","PRESUNCIÓN DE VALIDEZ","PRESUNCIÓN LEGAL","INSTANCIA COMPETENTE"]'::jsonb, 'PRESUNCIÓN DE VALIDEZ', 2, '(ART: 9)** [TITULO I] [CAPITULO II]', '181968', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (749, 749, 'LOS ACTOS ADMINISTRATIVOS QUE SEAN CONSTITUTIVOS DE INFRACCIÓN PENAL, O QUE SE DICTEN COMO CONSECUENCIA DE LA MISMA, ES UNA DE LAS:', '["CAUSALES DE NULIDAD","VALIDEZ DEL ACTO ADMINISTRATIVO","PRESUNCIÓN DE VALIDEZ","INSTANCIA COMPETENTE PARA DECLARAR LA NULIDAD","ALCANCES DE LA NULIDAD"]'::jsonb, 'CAUSALES DE NULIDAD', 0, '(ART: 10)** [TITULO I] [CAPITULO II]', '181969', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (750, 750, 'EL ACTO CUYO CONTENIDO SEA IMPRECISO O INCONGRUENTE CON LAS CUESTIONES SURGIDAS EN LA MOTIVACIÓN; ES UNO DE LOS:', '["ACTOS ADMINISTRATIVOS AFECTADOS POR VICIOS NO TRASCENDENTES","ACTOS ADMINISTRATIVOS AFECTADOS POR VICIOS TRASCENDENTES","VICIOS DEL ACTO ADMINISTRATIVO","ALCANCES DE LA NULIDAD","ACTOS DE LA PRESUNCIÓN DE VALIDEZ"]'::jsonb, 'ACTOS ADMINISTRATIVOS AFECTADOS POR VICIOS NO TRASCENDENTES', 0, '(ART: 14)** [TITULO I] [CAPITULO II]', '181970', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (751, 751, 'SIN PERJUICIO DE LAS COORDINACIONES ESPECÍFICAS ENTRE EL FISCAL Y LA POLICÍA NACIONAL EN EL MARCO DE SUS COMPETENCIAS PARA CADA CASO, EL FISCAL DE LA NACIÓN REGULARÁ MEDIANTE INSTRUCCIONES GENERALES:', '["LOS REQUISITOS CONVENIENTES A LAS INFORMALIDADES DE LAS ACTUACIONES DE INVESTIGACIÓN","LOS REQUISITOS NORMATIVOS Y LAS FORMALIDADES DE LAS DENUNCIAS","LOS REQUISITOS LEGALES Y LAS FORMALIDADES DE LAS ACTUACIONES DE INVESTIGACIÓN QUE DEBEN CUMPLIR LOS FISCALES","LOS REQUISITOS LEGALES Y LAS INFORMALIDADES EN EL DESARROLLO DE LA INVESTIGACIÓN PREPARATORIA","LAS EXCUSAS LEGALES Y LAS FORMALIDADES CORRESPONDIENTES DE LA INVESTIGACIÓN"]'::jsonb, 'LOS REQUISITOS LEGALES Y LAS FORMALIDADES DE LAS ACTUACIONES DE INVESTIGACIÓN QUE DEBEN CUMPLIR LOS FISCALES', 2, '(ART: 69)** [LIBRO PRIMERO] [SECCION IV] [TITULO I] [CAPITULO II]', '184328', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (752, 752, '¿QUÉ AUTORIDAD PODRÁ INFORMAR A LOS MEDIOS DE COMUNICACIÓN SOCIAL ACERCA DE LA IDENTIDAD DE LOS IMPUTADOS?', '["EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA","EL JUEZ PENAL","EL MINISTERIO PÚBLICO","LA POLICÍA","EL DEFENSOR DEL PUEBLO"]'::jsonb, 'LA POLICÍA', 3, '(ART: 70) [LIBRO PRIMERO] [SECCION IV] [TITULO I] [CAPITULO II]', '184329', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (753, 753, 'LA POLICÍA PODRÁ INFORMAR A LOS MEDIOS DE COMUNICACIÓN SOCIAL ACERCA DE LA IDENTIDAD DE LOS IMPUTADOS. CUANDO SE TRATE DE LA VÍCTIMA, REQUERIRÁ:', '["PREVIA AUTORIZACIÓN DEL FISCAL","PREVIA AUTORIZACIÓN DEL JUEZ PENAL","AUTORIZACIÓN PREVIA DEL JUEZ DE LA INVESTIGACIÓN PREPARATORIA","AUTORIZACIÓN PREVIA DE LA POLICÍA NACIONAL DEL PERÚ","PREVIA AUTORIZACIÓN DEL DEFENSOR DEL PUEBLO"]'::jsonb, 'PREVIA AUTORIZACIÓN DEL FISCAL', 0, '(ART: 70) [LIBRO PRIMERO] [SECCION IV] [TITULO I] [CAPITULO II]', '184330', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (754, 754, '¿A TRAVÉS DE QUIÉN EL IMPUTADO PUEDE HACER VALER LOS DERECHOS QUE LA CONSTITUCIÓN Y LAS LEYES LA CONCEDEN?', '["SU REPRESENTANTE LEGAL","EL DEFENSOR DEL PUEBLO","DE SU ABOGADO DEFENSOR","LA CORTE INTERAMERICANA DE DERECHOS HUMANOS","EL JUEZ PENAL"]'::jsonb, 'DE SU ABOGADO DEFENSOR', 2, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184331', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (789, 789, 'EL ESTADO, ES QUIEN GARANTIZA LA:', '["REPARACIÓN POR LOS ERRORES PROCESALES","MOTIVACIÓN DE UN JUICIO JUSTO","INDEMNIZACIÓN POR LOS ERRORES JUDICIALES","DEBIDA OBSERVANCIA DEL PROCESO","CANCELACIÓN POR LOS ERRORES JUDICIALES"]'::jsonb, 'INDEMNIZACIÓN POR LOS ERRORES JUDICIALES', 2, '(ART: I) [TITULO PRELIMINAR]', '184366', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (755, 755, 'CONOCER LOS CARGOS FORMULADOS EN SU CONTRA Y, EN CASO DE DETENCIÓN, A QUE SE LE EXPRESE LA CAUSA O MOTIVO DE DICHA MEDIDA, ES UN:', '["DERECHO DEL IMPUTADO","POTESTAD DEL PROCESADO","DERECHO DEL ENCAUSADO","DERECHO DEL PROCESADO","DERECHO DEL DETENIDO"]'::jsonb, 'DERECHO DEL IMPUTADO', 0, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184332', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (756, 756, 'CUANDO EL IMPUTADO CONSIDERE QUE DURANTE LAS DILIGENCIAS PRELIMINARES O EN LA INVESTIGACIÓN PREPARATORIA NO SE HAN DADO CUMPLIMIENTO A ESTAS DISPOSICIONES, O QUE SUS DERECHOS NO SON RESPETADOS O QUE ES OBJETO DE MEDIDAS LIMITATIVAS DE DERECHOS INDEBIDAS O DE REQUERIMIENTOS ILEGALES; PUEDE ACUDIR:', '["AL JUEZ RESPECTIVO QUE LLEVA LA INVESTIGACIÓN","A SU ABOGADO DEFENSOR, PARA QUE HAGA PREVALECER SUS DERECHOS","EN VÍA DE CONSULTA AL JUEZ DE LA INVESTIGACIÓN INTERMEDIA","AL FISCAL QUE SE ENCUENTRA DIRIGIENDO LA INVESTIGACIÓN","EN VÍA DE TUTELA AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA"]'::jsonb, 'EN VÍA DE TUTELA AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA', 4, '(ART: 71)** [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184333', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (757, 757, '¿QUIÉN DEBE SER ASISTIDO DESDE LOS ACTOS INICIALES DE INVESTIGACIÓN POR UN ABOGADO DEFENSOR?', '["EL IMPUTADO","LA VÍCTIMA","LOS TESTIGOS","PERSONAS VINCULADAS AL HECHO PUNIBLE","LOS FAMILIARES"]'::jsonb, 'EL IMPUTADO', 0, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184334', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (758, 758, 'EL IMPUTADO TIENE DERECHO A ABSTENERSE DE DECLARAR; Y, SI ACEPTA HACERLO, A QUE SU ABOGADO DEFENSOR ESTÉ PRESENTE EN SU DECLARACIÓN Y EN TODAS LAS DILIGENCIAS EN QUE:', '["SE SOLICITE SU AUSENCIA","SE REQUIERE SU PRESENCIA","SE SOLICITE SU PARTICIPACIÓN DURANTE LA INVESTIGACIÓN","SE REQUIERA DE SU INTERVENCIÓN PARA EL ESCLARECIMIENTO","SE LE NOTIFIQUE PARA DECLARAR RESPECTO AL HECHO DELICTUOSO COMETIDO"]'::jsonb, 'SE REQUIERE SU PRESENCIA', 1, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184335', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (795, 795, 'DEBE RESOLVERSE A FAVOR DEL IMPUTADO EN CASO DE:', '["INTERRUPCIÓN DE LAS INVESTIGACIONES","FALLECIMIENTO DEL IMPUTADO","DUDA SOBRE LA RESPONSABILIDAD PENAL","ANOMALÍA PSÍQUICA COMPROBADA","MINORÍA DE EDAD DEL IMPUTADO"]'::jsonb, 'DUDA SOBRE LA RESPONSABILIDAD PENAL', 2, '(ART: II) [TITULO PRELIMINAR]', '184372', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (759, 759, 'EL IMPUTADO TIENE DERECHO A QUE NO SE EMPLEE EN SU CONTRA MEDIOS COACTIVOS, INTIMIDATORIOS O CONTRARIOS A SU DIGNIDAD, NI A SER SOMETIDO A TÉCNICAS O MÉTODOS QUE INDUZCAN O ALTEREN:', '["LAS PREMINENCIAS RESPECTO A SU DETENCIÓN","SUS DECLARACIONES RELACIONADAS AL HECHO","SU LIBRE VOLUNTAD O A SUFRIR UNA RESTRICCIÓN NO AUTORIZADA","LOS MEDIOS DE PRUEBA OFRECIDOS EN SU MOMENTO","LOS MECANISMOS DE DEFENSA POR PARTE DE SU ABOGADO DEFENSOR"]'::jsonb, 'SU LIBRE VOLUNTAD O A SUFRIR UNA RESTRICCIÓN NO AUTORIZADA', 2, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184336', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (760, 760, 'EL IMPUTADO CUANDO SU ESTADO DE SALUD ASÍ LO REQUIERA, TIENE DERECHO A SER EXAMINADO POR MÉDICO LEGISTA O EN SU DEFECTO POR:', '["UN NEURÓLOGO DE SER EL CASO","UN TÉCNICO DE SALUD MÁS PRÓXIMO","UN MÉDICO GENERAL","OTRO PROFESIONAL DE LA SALUD","OTRO MÉDICO DE LA ESPECIALIDAD QUE EN EL MOMENTO SE NECESITE"]'::jsonb, 'OTRO PROFESIONAL DE LA SALUD', 3, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184337', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (761, 761, '¿QUIÉNES FIRMAN EN EL ACTA SOBRE EL CUMPLIMIENTO DE LOS DERECHOS DEL IMPUTADO?', '["EL IMPUTADO, EL ABOGADO Y LA POLICÍA NACIONAL","EL ABOGADO DEFENSOR Y EL MINISTERIO PÚBLICO","EL DEFENSOR DEL PUEBLO","LOS FAMILIARES","EL IMPUTADO Y LA AUTORIDAD CORRESPONDIENTE"]'::jsonb, 'EL IMPUTADO Y LA AUTORIDAD CORRESPONDIENTE', 4, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184338', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (762, 762, '¿QUÉ DEBERÁ DE REALIZARSE, SI EL IMPUTADO SE REHÚSA A FIRMAR EN ACTA?', '["SE HARÁ CONSTAR LA ABSTENCIÓN, Y SE CONSIGNARÁ EL MOTIVO SI LO EXPRESARE","NO SE HARÁ CONSTAR LA ABSTENCIÓN, SI ASÍ LO EXPRESARE","SE HARÁ CONSTATAR LA DECISIÓN, Y SE CONSIGNARÁ EL MOTIVO SI LO EXPRESARE","NO SE HARÁ CONSTAR DICHA OBSERVACIÓN, SIN CONSIGNAR EL MOTIVO SI ASÍ LO EXPRESARE","NO SE HARÁ CONSTAR LA DECISIÓN"]'::jsonb, 'SE HARÁ CONSTAR LA ABSTENCIÓN, Y SE CONSIGNARÁ EL MOTIVO SI LO EXPRESARE', 0, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184339', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (763, 763, '¿QUIÉN PUEDE ACUDIR EN VÍA DE TUTELA AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA, PARA QUE SUBSANE LA OMISIÓN, O DICTE LA MEDIDA DE CORRECCIÓN O DE PROTECCIÓN QUE CORRESPONDA?', '["EL IMPUTADO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS LIMITATIVAS","EL PROCESADO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS LIMITATIVAS","EL SENTENCIADO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS LIMITATIVAS","EL INVESTIGADO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS LIMITATIVAS","EL INTERVENIDO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS LIMITATIVAS"]'::jsonb, 'EL IMPUTADO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS LIMITATIVAS', 0, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184340', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (764, 764, '¿QUIÉN SERÁ IDENTIFICADO POR SU NOMBRE, DATOS PERSONALES, SEÑAS PARTICULARES Y, CUANDO CORRESPONDA, POR SUS IMPRESIONES DIGITALES A TRAVÉS DE LA OFICINA TÉCNICA RESPECTIVA?', '["EL PROCESADO","EL IMPUTADO","EL INVESTIGADO","EL DETENIDO","EL AUTOR"]'::jsonb, 'EL IMPUTADO', 1, '(ART: 72) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184341', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (765, 765, '¿QUÉ SE DEBERÁ REALIZAR SI EL IMPUTADO SE ABSTIENE DE PROPORCIONAR DATOS QUE LO IDENTIFICAN O LO HAGA FALSAMENTE?', '["SE LE IDENTIFICARÁ POR MEDIO DE LOS IMPUTADOS O POR OTROS MEDIOS ÚTILES, AUN CONTRA SU VOLUNTAD","SE LE IDENTIFICARÁ POR LOS PERITOS O POR OTROS MEDIOS ÚTILES, AUN CONTRA SU VOLUNTAD","SE LE IDENTIFICARÁ POR TESTIGOS O POR OTROS MEDIOS ÚTILES, AUN CONTRA SU VOLUNTAD","SE LE IDENTIFICARÁ POR PERITOS O POR OTROS MEDIOS ÚTILES, AUN SEA VOLUNTARIO","SE LE IDENTIFICARÁ POR LOS AGRAVIADOS O POR OTROS MEDIOS CIENTÍFICOS, AUN CONTRA SU VOLUNTAD"]'::jsonb, 'SE LE IDENTIFICARÁ POR TESTIGOS O POR OTROS MEDIOS ÚTILES, AUN CONTRA SU VOLUNTAD', 2, '(ART: 72)** [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184342', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (766, 766, '¿QUÉ SUCEDERÁ SI HUBIERA DUDA SOBRE LOS DATOS OBTENIDOS EN LA IDENTIFICACIÓN DEL IMPUTADO?', '["ALTERARÁ EL CURSO DE LAS ACTUACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS PODRÁN SER CORREGIDOS EN SU OPORTUNIDAD","ALTERARÁ EL CURSO DE LAS ACTUACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS NO PODRÁN SER CORREGIDOS EN CUALQUIER OPORTUNIDAD","ALTERARÁ EL CURSO DE LAS ACTUACIONES JUDICIALES Y LOS ERRORES SOBRE ELLOS NO PODRÁN SER CORREGIDOS EN CUALQUIER OPORTUNIDAD","NO ALTERARÁ EL CURSO DE LAS ACTUACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS PODRÁN SER CORREGIDOS EN CUALQUIER OPORTUNIDAD","ALTERARÁ EL CURSO DE LAS INVESTIGACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS NO PODRÁN SER CORREGIDOS EN CUALQUIER OPORTUNIDAD"]'::jsonb, 'NO ALTERARÁ EL CURSO DE LAS ACTUACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS PODRÁN SER CORREGIDOS EN CUALQUIER OPORTUNIDAD', 3, '(ART: 72) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184343', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (767, 767, 'LOS JUECES, LOS FISCALES O LA POLICÍA NACIONAL DEBEN HACER SABER AL IMPUTADO DE MANERA INMEDIATA Y COMPRENSIBLE, QUE TIENE DERECHO A:', '["SER ASISTIDO POR UN JURISTA EN LA MATERIA QUE DIO LUGAR A SU DETENCIÓN","SER ASISTIDO POR UN ABOGADO DE OFICIO, CUANDO NO CUENTE CON LOS MEDIOS ECONÓMICOS SUFICIENTES","SER ASISTIDO POR UN ABOGADO DE LA DEFENSORÍA DEL PUEBLO","SER ASISTIDO DESDE LOS ACTOS INICIALES POR UN ABOGADO DEFENSOR","SER ASISTIDO POR UN ASESOR LEGAL DEL PODER JUDICIAL"]'::jsonb, 'SER ASISTIDO DESDE LOS ACTOS INICIALES POR UN ABOGADO DEFENSOR', 3, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184344', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (768, 768, 'LOS JUECES, LOS FISCALES O LA POLICÍA NACIONAL DEBEN HACER SABER AL IMPUTADO DE MANERA INMEDIATA Y COMPRENSIBLE, QUE TIENE DERECHO A:', '["NEGARSE A MANIFESTAR RESPECTO A LOS MOTIVOS QUE DIO ORIGEN A SU DETENCIÓN","ABSTENERSE DE DECLARAR; Y, SI ACEPTA HACERLO, A QUE SU ABOGADO DEFENSOR ESTÉ PRESENTE","ABSTENERSE DE BRINDAR ENTREVISTAS; Y, SI ASÍ LO QUISIERA, DEBERÁ ESTAR PRESENTE SU ABOGADO DEFENSOR","ABSTENERSE DE EFECTUAR COMENTARIOS ADVERSOS A LA INVESTIGACIÓN DE LA POLICÍA NACIONAL","ABSTENERSE DE EFECTUAR COMENTARIOS ADVERSOS A LA INVESTIGACIÓN DEL MINISTERIO PÚBLICO"]'::jsonb, 'ABSTENERSE DE DECLARAR; Y, SI ACEPTA HACERLO, A QUE SU ABOGADO DEFENSOR ESTÉ PRESENTE', 1, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184345', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (769, 769, 'LOS JUECES, LOS FISCALES O LA POLICÍA NACIONAL DEBEN HACER SABER AL IMPUTADO DE MANERA INMEDIATA Y COMPRENSIBLE QUE TIENE DERECHO A:', '["QUE NO SE LE VIOLENTE FÍSICA NI PSICOLÓGICAMENTE","SER RESPETADO EN TODO MOMENTO, BRINDÁNDOSELE ALIMENTACIÓN COMPLETA Y ABRIGO","PODER ENTABLAR DIÁLOGO CON ALGÚN REPRESENTANTE DE LA CRUZ ROJA INTERNACIONAL","EXPRESAR SU MALESTAR A LA DEFENSORÍA DEL PUEBLO, SOBRE SU DETENCIÓN","QUE NO SE EMPLEE EN SU CONTRA MEDIOS COACTIVOS, INTIMIDATORIOS O CONTRARIOS A SU DIGNIDAD"]'::jsonb, 'QUE NO SE EMPLEE EN SU CONTRA MEDIOS COACTIVOS, INTIMIDATORIOS O CONTRARIOS A SU DIGNIDAD', 4, '(ART: 71) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184346', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (796, 796, 'EL AGRAVIADO TIENE DERECHO A SER INFORMADO DEL RESULTADO DEL PROCEDIMIENTO, AUN CUANDO NO HAYA INTERVENIDO EN ÉL:', '["SIEMPRE QUE LO SOLICITE","PREVIA CONSULTA AL FISCAL","CUANDO EL JUEZ PENAL LO AUTORICE","SIN NECESIDAD DE SOLICITARLO","A TRAVÉS DEL DEFENSOR DEL PUEBLO"]'::jsonb, 'SIEMPRE QUE LO SOLICITE', 0, '(ART: 95) [LIBRO PRIMERO] [SECCION IV] [TITULO IV] [CAPITULO I]', '184373', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (770, 770, 'AL PROCESADO QUE ALTERE EL ORDEN EN UN ACTO PROCESAL, SE LE APERCIBIRÁ CON LA SUSPENSIÓN DE LA DILIGENCIA Y DE CONTINUARLA', '["CON LA SOLA INTERVENCIÓN DE SU ABOGADO DEFENSOR Y DEMÁS SUJETOS PROCESALES","CON LA SOLA INTERVENCIÓN DE SU ABOGADO DEFENSOR Y SIN LA PARTICIPACIÓN DE LOS SUJETOS PROCESALES","CON LA SOLA INTERVENCIÓN DE SU ABOGADO DEFENSOR Y UN REPRESENTANTE LEGAL","CON LA SOLA INTERVENCIÓN DE UN TESTIGO Y DEMÁS SUJETOS PROCESALES","CON LA SOLA INTERVENCIÓN DEL AGRAVIADO Y DEMÁS SUJETOS PROCESALES"]'::jsonb, 'CON LA SOLA INTERVENCIÓN DE SU ABOGADO DEFENSOR Y DEMÁS SUJETOS PROCESALES', 0, '(ART: 73) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184347', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (771, 771, '¿QUÉ SUCEDERÍA SI EL ABOGADO DEFENSOR SE SOLIDARIZA Y ABANDONA LA DILIGENCIA?', '["SERÁ SUSTITUIDO POR UNO NOMBRADO DE PARTE","SERÁ SUSTITUIDO POR UNO NOMBRADO DE OFICIO","NO SERÁ SUSTITUIDO Y CONTINUARÁ EL ABOGADO DE OFICIO","NO SERÁ SUSTITUIDO POR UNO NOMBRADO POR EL MINISTERIO PÚBLICO","SERÁ SUSTITUIDO INMEDIATAMENTE"]'::jsonb, 'SERÁ SUSTITUIDO POR UNO NOMBRADO DE OFICIO', 1, '(ART: 73)** [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184348', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (772, 772, 'CUANDO SE ESTABLEZCA LA MINORÍA DE EDAD DEL IMPUTADO, ¿QUIÉN PUEDE SOLICITAR AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA, CORTE LA SECUELA DEL PROCESO Y PONGA AL ADOLESCENTE A DISPOSICIÓN DEL FISCAL DE FAMILIA?', '["EL ABOGADO DEFENSOR","LOS FAMILIARES","EL FISCAL O CUALQUIERA DE LAS PARTES","EL REPRESENTANTE DE LA DEFENSORÍA DEL PUEBLO","EL JUEZ DE MENORES"]'::jsonb, 'EL FISCAL O CUALQUIERA DE LAS PARTES', 2, '(ART: 74) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184349', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (773, 773, '¿QUÉ ACCIONES DICTARÁ EL JUEZ CUANDO SE ACREDITA LA MINORÍA DE EDAD EN LA ETAPA INTERMEDIA O EN EL JUICIO ORAL, PREVIA AUDIENCIA Y CON LA INTERVENCIÓN DE LAS PARTES?', '["DICTARÁ LOS PROVEÍDOS NECESARIOS","CONSULTARÁ SOBRE LA RESOLUCIÓN CORRESPONDIENTE","IMPARTIRÁ LAS DISPOSICIONES PERTINENTES","DICTARÁ LA RESOLUCIÓN CORRESPONDIENTE","NO DICTARÁ NINGUNA RESOLUCIÓN"]'::jsonb, 'DICTARÁ LA RESOLUCIÓN CORRESPONDIENTE', 3, '(ART: 74) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184350', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (774, 774, 'CUANDO SE ESTABLEZCA LA MINORÍA DE EDAD DEL IMPUTADO, EN TODOS LOS CASOS:', '["SOLAMENTE EN ESTE CASO NO SE DEJARÁ A SALVO EL DERECHO DEL ACTOR CIVIL PARA QUE LO HAGA VALER EN OTRA VÍA ADMINISTRATIVA","EN TODOS ESTOS CASOS SE DEJARÁ A SALVO EL DERECHO DEL ACTOR CIVIL PARA QUE LO HAGA VALER EN CUALQUIER VÍA","EN NINGÚN CASO EL ACTOR CIVIL TIENE DERECHO PARA QUE LO HAGA VALER EN LA VÍA PERTINENTE","NO SE DEJARÁ A SALVO EL DERECHO DEL ACTOR CIVIL PARA QUE LO HAGA PREVALECER EN LA ETAPA INTERMEDIA","SE DEJARÁ A SALVO EL DERECHO DEL ACTOR CIVIL PARA QUE LO HAGA VALER EN LA VÍA PERTINENTE"]'::jsonb, 'SE DEJARÁ A SALVO EL DERECHO DEL ACTOR CIVIL PARA QUE LO HAGA VALER EN LA VÍA PERTINENTE', 4, '(ART: 74) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184351', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (775, 775, 'EL JUEZ, A REQUERIMIENTO DEL FISCAL O DE LAS DEMÁS PARTES, PREVIA CONSTATACIÓN, DECLARARÁ CONTUMAZ AL IMPUTADO CUANDO:', '["NO OBEDEZCA, PESE A DESCONOCER DE SU EMISIÓN, UNA ORDEN DE DETENCIÓN O PRISIÓN","OBEDEZCA, AL TENER CONOCIMIENTO DE SU EMISIÓN, UNA ORDEN DE DETENCIÓN O PRISIÓN","DESACATE, PESE A TENER CONOCIMIENTO DE SU INDUCCIÓN, UNA ORDEN EN SU CONTRA O PRISIÓN","DESOBEDEZCA, PESE A SER CONSCIENTE DE SU EMISIÓN, UNA PAPELETA DE DETENCIÓN O PRIVATIVA DE LIBERTAD","NO OBEDEZCA, PESE A TENER CONOCIMIENTO DE SU EMISIÓN, UNA ORDEN DE DETENCIÓN O PRISIÓN"]'::jsonb, 'NO OBEDEZCA, PESE A TENER CONOCIMIENTO DE SU EMISIÓN, UNA ORDEN DE DETENCIÓN O PRISIÓN', 4, '(ART: 79) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184352', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (776, 776, 'EN CASO DE INIMPUTABILIDAD DEL PROCESADO, ¿CUÁNDO DISPONDRÁ EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA LA PRÁCTICA DE UN EXAMEN POR UN PERITO ESPECIALIZADO?', '["SEGÚN EL ESTADO DE LA CAUSA, SOLAMENTE DISPONDRÁ A PEDIDO DE PARTE","SEGÚN EL ESTADO DE LA CAUSA, DISPONDRÁ, DE OFICIO O A PEDIDO DE PARTE","SEGÚN EL ESTADO DE SOBRESEIMIENTO, SOLAMENTE DISPONDRÁ DE OFICIO","SEGÚN EL ESTADO DE SOBRESEIMIENTO, SOLAMENTE DISPONDRÁ A PEDIDO DE PARTE","SEGÚN EL CASO DEL JUICIO"]'::jsonb, 'SEGÚN EL ESTADO DE LA CAUSA, DISPONDRÁ, DE OFICIO O A PEDIDO DE PARTE', 1, '(ART: 75) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184353', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (790, 790, 'LAS RESOLUCIONES SON RECURRIBLES, EN:', '["EL RECURSO DE APELACIÓN","EN EL DESARROLLO DEL PROCESO","EL MODO COMO LO SOLICITE EL ABOGADO DEFENSOR","LA FORMA Y CIRCUNSTANCIAS ESTABLECIDAS","LOS CASOS Y MODOS PREVISTOS POR LEY"]'::jsonb, 'LOS CASOS Y MODOS PREVISTOS POR LEY', 4, '(ART: I) [TITULO PRELIMINAR]', '184367', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (777, 777, 'RECIBIDO EL INFORME PERICIAL, PREVIA AUDIENCIA, CON INTERVENCIÓN DE LAS PARTES Y DEL PERITO, SI EL JUEZ CONSIDERA SI EXISTEN INDICIOS SUFICIENTES PARA ESTIMAR ACREDITADO EL ESTADO DE INIMPUTABILIDAD DEL PROCESADO:', '["NO DICTARÁ RESOLUCIÓN NI PROCEDIMIENTO DE SEGURIDAD","DICTARÁ LA RESOLUCIÓN SOBRE EL RESULTADO DEL EXAMEN MÉDICO, INSTANDO LA INCOACIÓN DEL PROCEDIMIENTO DE SEGURIDAD","DICTARÁ LA RESOLUCIÓN CORRESPONDIENTE INSTANDO LA INCOACIÓN DEL PROCEDIMIENTO DE SEGURIDAD","DICTARÁ LA RESOLUCIÓN CORRESPONDIENTE INSTANDO LA COACCIÓN DEL INICIO DEL PROCEDIMIENTO","DICTARÁ LA RESOLUCIÓN PERTINENTE INSTANDO LA PLANIFICACIÓN DEL PROCEDIMIENTO DE SEGURIDAD"]'::jsonb, 'DICTARÁ LA RESOLUCIÓN CORRESPONDIENTE INSTANDO LA INCOACIÓN DEL PROCEDIMIENTO DE SEGURIDAD', 2, '(ART: 75) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184354', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (778, 778, '¿EN QUÉ CONSISTE LA ANOMALÍA PSÍQUICA SOBREVENIDA?', '["ANTES DE COMETER EL DELITO LE SOBREVIENE ANOMALÍA PSÍQUICA GRAVE AL IMPUTADO","DURANTE LA REALIZACIÓN DEL DELITO LE SOBREVIENE ANOMALÍA PSÍQUICA GRAVE AL IMPUTADO","CUANDO DESPUÉS DE COMETIDO EL DELITO LE SOBREVIENE ANOMALÍA PSÍQUICA GRAVE AL IMPUTADO","CUANDO DESPUÉS DE COMETIDO LA INFRACCIÓN LE SOBREVIENE ANOMALÍA PSÍQUICA AL PROCESADO","CUANDO DESPUÉS DE COMETIDO EL DELITO LE SOBREVIENE ANOMALÍA PSÍQUICA GRAVE AL AGRAVIADO"]'::jsonb, 'CUANDO DESPUÉS DE COMETIDO EL DELITO LE SOBREVIENE ANOMALÍA PSÍQUICA GRAVE AL IMPUTADO', 2, '(ART: 76) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184355', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (779, 779, 'ANOMALÍA PSÍQUICA SOBREVENIDA.- SI DEL ANÁLISIS DE LO ACTUADO, EL ÓRGANO JURISDICCIONAL ADVIERTE QUE EL IMPUTADO PRESENTA ANOMALÍA PSÍQUICA GRAVE QUE LE IMPIDE CONTINUAR CON LA CAUSA:', '["CONSULTARÁ LA SUSPENSIÓN DEL PROCESO HASTA QUE EL TRATAMIENTO DE LA DOLENCIA HAGA POSIBLE REINICIARLO","DISPONDRÁ LA SUSPENSIÓN DEL PROCESADO HASTA QUE EL TRATAMIENTO DE LA DOLENCIA SEA POSIBLE INICIARLO","NO DISPONDRÁ LA SUSPENSIÓN DEL PROCESO Y CONTINUARÁ CON EL TRATAMIENTO DE LA DOLENCIA","DISPONDRÁ LA SUSPENSIÓN DEL PROCESO HASTA QUE EL TRATAMIENTO DE LA DOLENCIA HAGA POSIBLE REINICIARLO","DISPONDRÁ EL TRATAMIENTO HASTA QUE EL IMPUTADO SUPERE SU DOLENCIA"]'::jsonb, 'DISPONDRÁ LA SUSPENSIÓN DEL PROCESO HASTA QUE EL TRATAMIENTO DE LA DOLENCIA HAGA POSIBLE REINICIARLO', 3, '(ART: 76) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184356', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (780, 780, 'ANOMALÍA PSÍQUICA SOBREVENIDA.- ¿CUÁNDO SE IMPEDIRÁ LA DECLARACIÓN DEL IMPUTADO O EL JUICIO?', '["CUANDO LO DISPONGA EL JUEZ DURANTE EL PROCESO SIN PERJUICIO DE QUE SE PROSIGA CON LA INVESTIGACIÓN DEL HECHO","CUANDO LO DISPONGA EL FISCAL DURANTE EL PROCESO SIN PERJUICIO DE QUE SE PROSIGA CON LA INVESTIGACIÓN DEL HECHO","CUANDO LO ORDENE EL FISCAL EN EL PROCESO SIN PERJUICIO DE QUE SE PROSIGA CON LA INVESTIGACIÓN DEL HECHO","SE SUSPENDE A SOLICITUD DE PARTE","SEGUN EL MOMENTO QUE SE ORDENE, SIN PERJUICIO DE QUE SE PROSIGA CON LA INVESTIGACIÓN DEL HECHO"]'::jsonb, 'SEGUN EL MOMENTO QUE SE ORDENE, SIN PERJUICIO DE QUE SE PROSIGA CON LA INVESTIGACIÓN DEL HECHO', 4, '(ART: 76) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184357', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (781, 781, '¿QUÉ DISPONDRÁ EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA CUANDO EL IMPUTADO ENFERMARA DURANTE LA PRIVACIÓN DE SU LIBERTAD?', '["DISPONDRÁ SU INMEDIATA EVALUACIÓN POR PARTE DEL MÉDICO LEGISTA O, EN SU DEFECTO, DEL PERITO MÉDICO QUE DESIGNE","DISPONDRÁ SU INMEDIATA EVALUACIÓN POR PARTE DEL MÉDICO CIRUJANO O, EN SU DEFECTO, DEL PERITO GRAFOTÉCNICO QUE DESIGNE","DISPONDRÁ SU INMEDIATA EVALUACIÓN POR PARTE DEL MÉDICO CIRUJANO O, EN SU DEFECTO, POR UNA JUNTA MÉDICA","DISPONDRÁ SU EVALUACIÓN POR PARTE DEL MÉDICO LEGISTA O, EN SU DEFECTO, DEL PERITO MÉDICO QUE DESIGNE EL DIRECTOR DEL INPE","DISPONDRÁ SU INMEDIATA EVALUACIÓN POR PARTE DEL MÉDICO FORENSE O, EN SU DEFECTO, DEL PERITO MÉDICO QUE DESIGNE"]'::jsonb, 'DISPONDRÁ SU INMEDIATA EVALUACIÓN POR PARTE DEL MÉDICO LEGISTA O, EN SU DEFECTO, DEL PERITO MÉDICO QUE DESIGNE', 0, '(ART: 77) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184358', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (782, 782, 'ENFERMEDAD DEL IMPUTADO.- EVACUADO EL DICTAMEN, SE PODRÁ ORDENAR, SI FUERE NECESARIO:', '["EL INGRESO DEL IMPUTADO A UN CENTRO HOSPITALARIO","EL INGRESO DEL AGRAVIADO A UN CENTRO HOSPITALARIO","EL INGRESO DEL IMPUTADO A UNA CENTRO MÉDICO PRIVADO","QUE EL PROCESADO VISITE UNA CLÍNICA PRIVADA","EL INGRESO DEL TESTIGO A UN CENTRO HOSPITALARIO ESTATAL"]'::jsonb, 'EL INGRESO DEL IMPUTADO A UN CENTRO HOSPITALARIO', 0, '(ART: 77) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184359', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (783, 783, 'ENFERMEDAD DEL IMPUTADO.- CUANDO SE REQUIERA DE INFRAESTRUCTURA Y ATENCIÓN MÉDICA ESPECIALIZADA QUE NO EXISTA EN UN CENTRO HOSPITALARIO ESTATAL', '["EN CUALQUIER CASO, SE PODRÁ AUTORIZAR SU INTERNAMIENTO EN UNA CLÍNICA PRIVADA","EN CASOS EXCEPCIONALES, SE PODRÁ AUTORIZAR SU INTERNAMIENTO EN UNA CLÍNICA PRIVADA","CUANDO LO REQUIERA LA FAMILIA, SE PODRÁ AUTORIZAR SU INTERNAMIENTO EN UNA CLÍNICA PRIVADA","CUANDO LA FAMILIA TENGA RECURSOS SUFICIENTES PARA SU INTERNAMIENTO EN UNA CLÍNICA PRIVADA","EL ABOGADO DEFENSOR PODRÁ CONDUCIRLO A UNA CLÍNICA PRIVADA"]'::jsonb, 'EN CASOS EXCEPCIONALES, SE PODRÁ AUTORIZAR SU INTERNAMIENTO EN UNA CLÍNICA PRIVADA', 1, '(ART: 77) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184360', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (784, 784, 'EL DIRECTOR DEL CENTRO HOSPITALARIO EN DONDE EL PROCESADO RECIBA ASISTENCIA MÉDICA O PSIQUIÁTRICA, DEBERÁ:', '["INFORMAR BIMESTRALMENTE AL FISCAL Y AL JUEZ ACERCA DEL ESTADO DE SALUD DEL PACIENTE","INFORMAR SEMESTRALMENTE AL FISCAL Y AL JUEZ ACERCA DEL ESTADO DE SALUD DEL PACIENTE","INFORMAR TRIMESTRALMENTE AL FISCAL Y AL JUEZ ACERCA DEL ESTADO DE SALUD DEL PACIENTE","INFORMAR BIMESTRALMENTE AL ABOGADO DEFENSOR Y AL JUEZ ACERCA DEL ESTADO DE SALUD DEL PACIENTE","INFORMAR SEMESTRALMENTE SOLAMENTE AL FISCAL ACERCA DEL ESTADO DE SALUD DEL PACIENTE"]'::jsonb, 'INFORMAR TRIMESTRALMENTE AL FISCAL Y AL JUEZ ACERCA DEL ESTADO DE SALUD DEL PACIENTE', 2, '(ART: 78) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184361', '2026-07-14T01:12:29.113429+00:00');
