INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (786, 786, 'UN JUICIO PREVIO, ORAL, PÚBLICO Y CONTRADICTORIO, ES UN DERECHO QUE LE CORRESPONDE:', '["AL IMPUTADO","AL PROCESADO","AL INVESTIGADO","A TODA PERSONA","AL AUTOR"]'::jsonb, 'A TODA PERSONA', 3, '(ART: I) [TITULO PRELIMINAR]', '184363', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (787, 787, 'LA CONSTITUCIÓN Y ESTE CÓDIGO, PREVÉN QUE:', '["LOS AUTORES INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y DERECHOS","LOS IMPLICADOS INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y DERECHOS","LAS PARTES INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y DERECHOS","LOS INVESTIGADOS INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y DERECHOS","LOS CÓMPLICES INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y DERECHOS"]'::jsonb, 'LAS PARTES INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y DERECHOS', 2, '(ART: I) [TITULO PRELIMINAR]', '184364', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (791, 791, '¿A QUIÉNES SE CONSIDERA INOCENTE?', '["AL IMPLICADO EN LA COMISIÓN DE UN HECHO DELICTUOSO, Y DEBE SER TRATADO COMO AL AUTOR, MIENTRAS SE ESTABLECE SU SITUACIÓN","A TODA PERSONA IMPUTADA DE LA COMISIÓN DE UN HECHO PUNIBLE Y DEBE SER TRATADA COMO TAL, MIENTRAS NO SE DEMUESTRE LO CONTRARIO","AL INVESTIGADO POR DELITO FLAGRANTE, Y DEBE SER TRATADA COMO TAL, MIENTRAS NO SE DEMUESTRE LO CONTRARIO","AL PROCESADO QUE NO PUEDA DEMOSTRAR FEHACIENTEMENTE SU INOCENCIA","AL IMPUTADO DE DELITOS GRAVES, CONVICTO Y CONFESO, CUANDO SE DEMUESTRE SU AUTORÍA"]'::jsonb, 'A TODA PERSONA IMPUTADA DE LA COMISIÓN DE UN HECHO PUNIBLE Y DEBE SER TRATADA COMO TAL, MIENTRAS NO SE DEMUESTRE LO CONTRARIO', 1, '(ART: II) [TITULO PRELIMINAR]', '184368', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (792, 792, 'NINGÚN FUNCIONARIO O AUTORIDAD PÚBLICA PUEDE PRESENTAR A UNA PERSONA COMO:', '["AUTOR DE UN HECHO DELICTUOSO, HASTA QUE SE DECLARE SU INOCENCIA","INVESTIGADO DE UN DELITO GRAVE, HASTA QUE LO DISPONGA EL JUEZ","IMPUTADO DE UN HECHO PENAL, HASTA QUE SE DESARROLLE EL PROCESO JUDICIAL","CULPABLE O BRINDAR INFORMACIÓN EN TAL SENTIDO","IMPLICADO EN UN HECHO PUNIBLE, HASTA CONFIRMAR SU AUTORÍA"]'::jsonb, 'CULPABLE O BRINDAR INFORMACIÓN EN TAL SENTIDO', 3, '(ART: II) [TITULO PRELIMINAR]', '184369', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (793, 793, '¿EN QUÉ CASO PROCEDERÁ EL ARRESTO CIUDADANO?', '["ANTES DE LAS 72 HORAS DE COMETIDO EL HECHO DELICTUOSO","EN ESTADO DE FLAGRANCIA DELICTIVA","DESPUÉS DE LAS 72 HORAS DE COMETIDO EL HECHO DELICTUOSO","EL AGENTE COMETIÓ EL HECHO DELICTIVO, HABIENDO TRANSCURRIDO LAS CUARENTA Y OCHO (48) HORAS","EL AGENTE ES ENCONTRADO DESPUÉS DE VEINTICUATRO (24) HORAS DESPUÉS DE LA PERPETRACIÓN DEL DELITO"]'::jsonb, 'EN ESTADO DE FLAGRANCIA DELICTIVA', 1, '(ART: 260) [LIBRO SEGUNDO] [SECCION III] [TITULO II]', '184370', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (794, 794, 'EL MINISTERIO PÚBLICO ES EL TITULAR DEL EJERCICIO PÚBLICO DE LA ACCIÓN PENAL EN LOS DELITOS Y TIENE EL DEBER DE:', '["LA CARGA DE LA PRUEBA","INVESTIGAR PRELIMINARMENTE","LA CARGA PROCESAL","DAR LOS LINEAMIENTOS DE ACCIÓN A LA POLICÍA NACIONAL","ESTABLECER LA AUTORÍA DEL IMPLICADO"]'::jsonb, 'LA CARGA DE LA PRUEBA', 0, '(ART: IV) [TITULO PRELIMINAR]', '184371', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (929, 929, 'EL QUE MATA A OTRO, ESTE ENUNCIADO CORRESPONDE A LA DEFINICIÓN DE:', '["HOMICIDIO AGRAVADO","HOMICIDIO PREMEDITADO","HOMICIDIO SIMPLE","HOMICIDIO CALIFICADO","HOMICIDIO CON CRUELDAD"]'::jsonb, 'HOMICIDIO SIMPLE', 2, '(ART: 106)** [LIBRO SEGUNDO] [TITULO I] [CAPITULO I]', '183950', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (797, 797, 'INTERDICCIÓN DE LA PERSECUCIÓN PENAL MÚLTIPLE, SE REFIERE A:', '["QUE SE PROCESE A UNA O MÁS PERSONAS POR UN MISMO HECHO","QUE EL INCULPADO PIDA SU SEPARACIÓN DEL PROCESO","QUE EL AUTOR SOLICITE LA PRESCRIPCIÓN DE SU CASO","QUE EL INVESTIGADO EXIJA LA PRESENCIA DEL FISCAL","QUE NADIE PODRÁ SER PROCESADO NI SANCIONADO MÁS DE UNA VEZ POR UN MISMO HECHO"]'::jsonb, 'QUE NADIE PODRÁ SER PROCESADO NI SANCIONADO MÁS DE UNA VEZ POR UN MISMO HECHO', 4, '(ART: III) [TITULO PRELIMINAR]', '184374', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (798, 798, '¿LA POLICÍA QUÉ DOCUMENTO REDACTARÁ DONDE SE HAGA CONSTAR LA ENTREGA Y LAS DEMÁS CIRCUNSTANCIAS DE LA INTERVENCIÓN?', '["UN INFORME","UN OFICIO","UN PARTE","UN ACTA","UN ATESTADO"]'::jsonb, 'UN ACTA', 3, '(ART: 260) [LIBRO SEGUNDO] [SECCION III] [TITULO II]', '184375', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (799, 799, 'ES UNO DE LOS DERECHOS DEL AGRAVIADO, A SER ESCUCHADO ANTES DE CADA DECISIÓN QUE:', '["EXPLIQUE LA HABILITACIÓN O SUSPENSIÓN DE LA ACCIÓN PENAL","IMPLIQUE LA EXTINCIÓN O SUSPENSIÓN DE LA ACCIÓN PENAL","IMPLIQUE LA ACCIÓN O EXTENSIÓN DE LA ACCIÓN PENAL","EXPLIQUE LA EXTINCIÓN O INCLUSIÓN DE LA ACCIÓN PENAL","IMPLIQUE LA CONCLUSIÓN DE LA ACCIÓN PENAL"]'::jsonb, 'IMPLIQUE LA EXTINCIÓN O SUSPENSIÓN DE LA ACCIÓN PENAL', 1, '(ART: 95) [LIBRO PRIMERO] [SECCION IV] [TITULO IV] [CAPITULO I]', '184376', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (800, 800, 'SALVO LAS EXCEPCIONES PREVISTAS EN LA CONSTITUCIÓN, SOLO PODRÁN DICTARSE POR LA AUTORIDAD JUDICIAL:', '["LAS RESOLUCIONES QUE LIMITAN DERECHOS FUNDAMENTALES","LAS DIRECTIVAS QUE LIMITAN DERECHOS FUNDAMENTALES","LAS CAUSAS QUE LIMITAN DERECHOS FUNDAMENTALES","LAS MEDIDAS QUE LIMITAN DERECHOS FUNDAMENTALES","LAS MOTIVACIONES QUE LIMITAN DERECHOS FUNDAMENTALES"]'::jsonb, 'LAS MEDIDAS QUE LIMITAN DERECHOS FUNDAMENTALES', 3, '(ART: VI) [TITULO PRELIMINAR]', '184377', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (801, 801, 'EL AGRAVIADO TIENE DERECHO A RECIBIR UN TRATO DIGNO Y RESPETUOSO POR PARTE DE LAS AUTORIDADES COMPETENTES, Y A LA PROTECCIÓN DE SU INTEGRIDAD, INCLUYENDO LA DE SU FAMILIA. EN LOS PROCESOS POR DELITOS CONTRA LA LIBERTAD SEXUAL SE:', '["CONSERVARÁ SU IDENTIDAD PREVIA CONSULTA AL FISCAL","PRESERVARÁ SU IDENTIDAD","CONSERVARÁ SU IDENTIDAD","CONSERVARÁ SU IDENTIDAD CON AUTORIZACIÓN DEL JUEZ PENAL","OCULTARÁ SU IDENTIDAD"]'::jsonb, 'PRESERVARÁ SU IDENTIDAD', 1, '(ART: 95) [LIBRO PRIMERO] [SECCION IV] [TITULO IV] [CAPITULO I]', '184378', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (802, 802, 'SERÁ INTERPRETADA RESTRICTIVAMENTE:', '["LA NORMA QUE OTORGUE BENEFICIOS AL IMPUTADO","LA LEY MÁS FAVORABLE AL IMPUTADO","LA LEY QUE COACTE LA LIBERTAD O EL EJERCICIO DE LOS DERECHOS PROCESALES","LA NORMA QUE GENERA EL INICIO DEL PROCESO","LA NORMA QUE FAVOREZCA A LOS CÓMPLICES"]'::jsonb, 'LA LEY QUE COACTE LA LIBERTAD O EL EJERCICIO DE LOS DERECHOS PROCESALES', 2, '(ART: VII) [TITULO PRELIMINAR]', '184379', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (803, 803, 'LAS PRUEBAS OBTENIDAS, DIRECTA O INDIRECTAMENTE, CON VIOLACIÓN DEL CONTENIDO ESENCIAL DE LOS DERECHOS FUNDAMENTALES DE LA PERSONA:', '["TAMBIÉN SON VÁLIDAS, MIENTRAS NO DIGA LO CONTRARIO EL FISCAL","CARECEN DE EFECTO LEGAL","NO ESTÁN PERMITIDAS EN EL PROCESO","SE VAN DESCARTANDO DURANTE LA INVESTIGACIÓN POLICIAL","SE ADMITEN SI SON NECESARIAS EN LA INVESTIGACIÓN"]'::jsonb, 'CARECEN DE EFECTO LEGAL', 1, '(ART: VIII) [TITULO PRELIMINAR]', '184380', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (804, 804, 'EL MINISTERIO PÚBLICO ES TITULAR DEL EJERCICIO DE LA ACCIÓN PENAL EN LOS DELITOS Y TIENE EL DEBER DE LA CARGA DE LA PRUEBA, ADEMÁS:', '["COORDINA CON EL JUEZ PARA EL INICIO DEL PROCESO","VERIFICAR LA SALUD FÍSICA Y MENTAL DEL IMPUTADO","RECIBE LOS LINEAMIENTOS DEL JUEZ DEL CASO","ASUME LA CONDUCCIÓN DE LA INVESTIGACIÓN","PLANTEA LOS ALEGATOS DURANTE LA FASE PRELIMINAR"]'::jsonb, 'ASUME LA CONDUCCIÓN DE LA INVESTIGACIÓN', 3, '(ART: IV) [TITULO PRELIMINAR]', '184381', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (805, 805, 'CONTRA SÍ MISMO, CONTRA SU CÓNYUGE, O SUS PARIENTES DENTRO DEL CUARTO GRADO DE CONSANGUINIDAD O SEGUNDO DE AFINIDAD:', '["NADIE PUEDE SER OBLIGADO O INDUCIDO A DECLARAR O A RECONOCER CULPABILIDAD","EL IMPUTADO ESTA OBLIGADO A RECONOCER SU PARTICIPACIÓN","EL AUTOR PUEDE DECLARAR SU CULPABILIDAD EN CASO DE FLAGRANCIA","EL IMPLICADO SI ES QUE ASÍ LO DESEA PUEDE RECONOCER SU AUTORÍA","EL PROCESADO A TRAVÉS DE SU ABOGADO DEFENSOR, PUEDE MANIFESTAR LO CONVENIENTE PARA ÉL"]'::jsonb, 'NADIE PUEDE SER OBLIGADO O INDUCIDO A DECLARAR O A RECONOCER CULPABILIDAD', 0, '(ART: IX) [TITULO PRELIMINAR]', '184382', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (806, 806, '¿POR QUÉ EL AGRAVIADO PUEDE IMPUGNAR EL SOBRESEIMIENTO Y LA SENTENCIA ABSOLUTORIA?', '["POR SER UN PEDIDO DEL FISCAL","PORQUE NO ESTAR DE ACUERDO","PORQUE ES UN DERECHO","PORQUE ES UN UN DEBER","POR SER UNA DISPOSICIÓN JUDICIAL"]'::jsonb, 'PORQUE ES UN DERECHO', 2, '(ART: 95) [LIBRO PRIMERO] [SECCION IV] [TITULO IV] [CAPITULO I]', '184383', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (906, 906, 'CONCLUIDO EL DEBATE PROBATORIO, EN QUE ORDEN SE DESARROLLARÁ LA DISCUSIÓN FINAL, ALEGATOS DE LOS ABOGADOS DEL ACTOR CIVIL Y DEL TERCERO CIVIL', '["TERCER ORDEN","SEGUNDO ORDEN","QUINTO ORDEN","PRIMER ORDEN","CUARTO ORDEN"]'::jsonb, 'SEGUNDO ORDEN', 1, '(ART: 386) [LIBRO TERCERO] [SECCION III] [TITULO V]', '184483', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (807, 807, 'EL MINISTERIO PÚBLICO ESTÁ OBLIGADO A ACTUAR CON OBJETIVIDAD, INDAGANDO LOS HECHOS CONSTITUTIVOS DEL DELITO, LOS QUE DETERMINEN Y ACREDITEN LA RESPONSABILIDAD O INOCENCIA DEL IMPUTADO. CON ESTA FINALIDAD:', '["COORDINA PERMANENTEMENTE CON EL JUEZ DE LA INVESTIGACIÓN PRELIMINAR","VELA POR QUE EL DESARROLLO DEL PROCESO INVESTIGATIVO SE EFECTÚE SIN CUESTIONAMIENTOS","BUSCA EN TODO MOMENTO INCRIMINAR AL IMPUTADO, PARA QUE RECIBA LA PENA QUE LE CORRESPONDA","CONDUCE JURÍDICAMENTE LOS ACTOS DE INVESTIGACIÓN QUE REALIZA LA POLICÍA NACIONAL DEL PERÚ","PLANTEA LOS LINEAMIENTOS DEL TRABAJO INVESTIGATIVO Y RECOLECCIÓN DE INDICIOS QUE REALIZA LA POLICÍA NACIONAL"]'::jsonb, 'CONDUCE JURÍDICAMENTE LOS ACTOS DE INVESTIGACIÓN QUE REALIZA LA POLICÍA NACIONAL DEL PERÚ', 3, '(ART: IV)** [TITULO PRELIMINAR]', '184384', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (808, 808, '¿CUÁNDO SERÁ INFORMADO EL AGRAVIADO SOBRE SUS DERECHOS?', '["DESPUÉS DE INTERPONER LA DENUNCIA, AL DECLARAR PREVENTIVAMENTE O EN SU PRIMERA INTERVENCIÓN EN LA CAUSA","CUANDO INTERPONGA UN RECURSO DE QUEJA, POSTERIOR A SU DECLARACIÓN O EN SU PRIMERA INTERVENCIÓN EN LA CAUSA","CUANDO INTERPONGA LA DENUNCIA, AL DECLARAR PREVENTIVAMENTE O EN SU SEGUNDA INTERVENCIÓN EN LA CAUSA","CUANDO INTERPONGA LA DENUNCIA, AL DECLARAR PREVENTIVAMENTE O EN SU PRIMERA INTERVENCIÓN EN LA CAUSA","CUANDO INTERPONGA LA DENUNCIA, AL DECLARAR PREVENTIVAMENTE O POSTERIOR A SU PRIMERA INTERVENCIÓN EN LA CAUSA"]'::jsonb, 'CUANDO INTERPONGA LA DENUNCIA, AL DECLARAR PREVENTIVAMENTE O EN SU PRIMERA INTERVENCIÓN EN LA CAUSA', 3, '(ART: 95) [LIBRO PRIMERO] [SECCION IV] [TITULO IV] [CAPITULO I]', '184385', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (809, 809, 'LA CITACIÓN AL IMPUTADO CON DOMICILIO CONOCIDO Y PROCESAL, SERÁ REQUERIDO PARA SU CONCURRENCIA AL JUICIO BAJO APERCIBIMIENTO DE:', '["SER ABSUELTO","SER SENTENCIADO EN AUSENCIA","SER DECLARADO CONTUMAZ","SER DECLARADO REO AUSENTE","SER CONDENADO"]'::jsonb, 'SER DECLARADO CONTUMAZ', 2, '(ART: 367) [LIBRO TERCERO] [SECCION III] [TITULO II]', '184386', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (810, 810, 'SI UN SOLO ACUSADO O SIENDO VARIOS NINGUNO CONCURRE A LA APERTURA DE LA AUDIENCIA, SIN JUSTIFICAR SU INASISTENCIA, SE:', '["SERA SENTENCIADO COMO REO - CONTUMAZ","CITADO PARA UNA FECHA, SIN PERJUICIO DE DECLARAR CONTUMAZ","SEÑALARÁ NUEVO DÍA Y HORA, SIN PERJUICIO DE DECLARARLOS CONTUMACES","NO SERA CITADO PARA UN NUEVO DÍA Y HORA","SERA DECLARADO CONTUMAZ"]'::jsonb, 'SEÑALARÁ NUEVO DÍA Y HORA, SIN PERJUICIO DE DECLARARLOS CONTUMACES', 2, '(ART: 367) [LIBRO TERCERO] [SECCION III] [TITULO II]', '184387', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (811, 811, 'LAS MEDIDAS QUE LIMITAN DERECHOS FUNDAMENTALES, SE IMPONDRÁN MEDIANTE RESOLUCIÓN MOTIVADA, A INSTANCIA DE:', '["LA PARTE PROCESAL LEGITIMADA","LA SOLITUD DEL AGRAVIADO","DEL ABOGADO DEFENSOR DEL IMPUTADO","DEL FISCAL DE LA INVESTIGACIÓN PREPARATORIA","DEL JUEZ DE LA ETAPA PRELIMINAR"]'::jsonb, 'LA PARTE PROCESAL LEGITIMADA', 0, '(ART: VI) [TITULO PRELIMINAR]', '184388', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (812, 812, 'EN QUE CASOS NO PODRÁ REALIZARSE LA AUDIENCIA:', '["CUANDO NO CONCURRE EL ACUSADO","SIN PRESENCIA DEL ACUSADO Y SU DEFENSOR","CUANDO NO CONCURRE EL ABOGADO DEFENSOR","CUANDO NO CONCURRE EL FISCAL PROVINCIAL","CUANDO CONCURRE EL ACUSADO Y SU DEFENSOR"]'::jsonb, 'SIN PRESENCIA DEL ACUSADO Y SU DEFENSOR', 1, '(ART: 367) [LIBRO TERCERO] [SECCION III] [TITULO II]', '184389', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (813, 813, 'EL SUPERIOR JERÁRQUICO DE UN FISCAL, DE OFICIO O A INSTANCIA DEL AFECTADO, PODRÁ REEMPLAZARLO CUANDO NO CUMPLE ADECUADAMENTE CON SUS FUNCIONES O INCURRE EN IRREGULARIDADES. TAMBIÉN PODRÁ HACERLO PREVIA LAS INDAGACIONES QUE CONSIDERE CONVENIENTE, CUANDO:', '["SE HAYAN DETECTADO ACTOS DE CORRUPCIÓN","ESTÉ INCURSO EN LAS CAUSALES DE RECUSACIÓN ESTABLECIDAS","SE COMPRUEBE UNA CONDUCTA INDECOROSA","FALTE A SU CÓDIGO DE ÉTICA PROFESIONAL","SE LE SORPRENDA EN FLAGRANCIA DEL DELITO DE EXTORSIÓN"]'::jsonb, 'ESTÉ INCURSO EN LAS CAUSALES DE RECUSACIÓN ESTABLECIDAS', 1, '(ART: 62) [LIBRO PRIMERO] [SECCION IV] [TITULO I] [CAPITULO I]', '184390', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (814, 814, 'DE CONFORMIDAD CON LA LEY, AL FISCAL DE LA NACIÓN LE CORRESPONDE ESTABLECER LA:', '["ENTREGA DE LOS LINEAMIENTOS DE ACCIÓN A LOS FISCALES","EFICACIA DE LAS FACULTADES A LOS REPRESENTANTES DEL MINISTERIO PÚBLICO","DISTRIBUCIÓN DE FUNCIONES DE LOS MIEMBROS DEL MINISTERIO PÚBLICO","CREACIÓN LAS DIRECTRICES PARA EL DESARROLLO DE LA INVESTIGACIÓN PRELIMINAR","EJECUCIÓN DE LAS POLÍTICAS DE TRABAJO PARA LOS FISCALES"]'::jsonb, 'DISTRIBUCIÓN DE FUNCIONES DE LOS MIEMBROS DEL MINISTERIO PÚBLICO', 2, '(ART: 63) [LIBRO PRIMERO] [SECCION IV] [TITULO I] [CAPITULO I]', '184391', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (815, 815, 'TODO MEDIO DE PRUEBA SERÁ VALORADO SÓLO SI HA SIDO OBTENIDO E INCORPORADO AL PROCESO POR UN PROCEDIMIENTO:', '["INVESTIGATIVO PRELIMINAR","CON PARTICIPACIÓN DE LA POLICÍA NACIONAL","REGULAR CON PARTICIPACIÓN DEL FISCAL","CONSTITUCIONALMENTE LEGÍTIMO","QUE LE FAVOREZCA AL IMPUTADO"]'::jsonb, 'CONSTITUCIONALMENTE LEGÍTIMO', 3, '(ART: VIII) [TITULO PRELIMINAR]', '184392', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (816, 816, 'CUANDO SON VARIOS LOS ACUSADOS, Y ALGUNO DE ELLOS NO CONCURRA, LA AUDIENCIA SE:', '["SE SUSPENDERÁ LA AUDIENCIA","INICIARÁ CON LOS ASISTENTES","INICIARÁ CUANDO CONCURRAN TODOS LOS ASISTENTES","NO SE INICIARÁ LA AUDIENCIA","SE REPROGRAMARÁ LA AUDIENCIA"]'::jsonb, 'INICIARÁ CON LOS ASISTENTES', 1, '(ART: 367) [LIBRO TERCERO] [SECCION III] [TITULO II]', '184393', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (817, 817, 'TODA PERSONA TIENE DERECHO INVIOLABLE E IRRESTRICTO, A QUE SE LE CONCEDA UN TIEMPO RAZONABLE PARA:', '["MEDITAR SOBRE SU CASO Y DECLARAR VOLUNTARIAMENTE","QUE PUEDA RECONOCER SU CULPA","QUE COORDINE CON SU ABOGADO DEFENSOR","QUE PREPARE SU DEFENSA","QUE HAGA LAS CONSULTAS PERTINENTES"]'::jsonb, 'QUE PREPARE SU DEFENSA', 3, '(ART: IX) [TITULO PRELIMINAR]', '184394', '2026-07-14T01:12:29.113429+00:00');
