INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (819, 819, 'TODA PERSONA TIENE DERECHO INVIOLABLE E IRRESTRICTO, A:', '["INTERVENIR, EN PLENA IGUALDAD, EN LA ACTIVIDAD PROBATORIA","OBJETAR LAS CUESTIONES QUE NO TIENEN QUE VER CON SU CASO","MEDITAR SOBRE SU CASO Y DECLARAR VOLUNTARIAMENTE","QUE PUEDA RECONOCER SU PARTICIPACIÓN EN EL HECHO DELICTUOSO QUE SE LE IMPUTA","QUE COORDINE CON SU ABOGADO DEFENSOR PARA DARLE MAYORES APORTES"]'::jsonb, 'INTERVENIR, EN PLENA IGUALDAD, EN LA ACTIVIDAD PROBATORIA', 0, '(ART: IX) [TITULO PRELIMINAR]', '184396', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (820, 820, 'EN QUÉ CASO AL ACUSADO AUSENTE O CONTUMAZ, SE LE INCORPORARÁ A LA AUDIENCIA:', '["CUANDO ES NO HABIDO","CUANDO SEA CAPTURADO","CUANDO SEA CITADO FORMALMENTE","CUANDO ACEPTA SU RESPONSABILIDAD","CUANDO NO ACEPTA SU RESPONSABILIDAD"]'::jsonb, 'CUANDO SEA CAPTURADO', 1, '(ART: 367) [LIBRO TERCERO] [SECCION III] [TITULO II]', '184397', '2026-07-14T01:12:29.113429+00:00');
