INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (864, 864, 'NO SE SUSPENDE LA INVESTIGACIÓN PREPARATORIA NI LA ETAPA INTERMEDIA RESPECTO DEL CONTUMAZ O AUSENTE, POR LA:', '["AUSENCIA DEL ABOGADO DEFENSOR","INASISTENCIA DE LOS TESTIGOS AL PROCESO","FALTA DE ELEMENTOS DE PRUEBA OFRECIDAS POR EL FISCAL","DECLARACIÓN DE CONTUMACIA O AUSENCIA","SITUACIÓN DE SALUD FÍSICA O MENTAL DEL IMPUTADO"]'::jsonb, 'DECLARACIÓN DE CONTUMACIA O AUSENCIA', 3, '(ART: 79) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184441', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (865, 865, 'EL TEXTO: EL SERVICIO NACIONAL DE LA DEFENSA DE OFICIO, A CARGO DEL MINISTERIO DE JUSTICIA, PROVEERÁ LA DEFENSA GRATUITA A TODOS AQUELLOS QUE DENTRO DEL PROCESO PENAL, POR SUS ESCASOS RECURSOS NO PUEDAN DESIGNAR UN ABOGADO, SE REFIERE A:', '["UN ABOGADO DE OFICIO","UN ABOGADO DEFENSOR","QUE NO SE VULNERE LOS DERECHOS DEL IMPUTADO","UN PROCESO PENAL JUSTO","DERECHO A LA DEFENSA TÉCNICA"]'::jsonb, 'DERECHO A LA DEFENSA TÉCNICA', 4, '(ART: 80) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO II]', '184442', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (866, 866, 'EN EL EXAMEN DE TESTIGOS, QUIÉN CONDUCIRÁ EL EXAMEN AL TESTIGO MENOR DE DIECISÉIS AÑOS DE EDAD:', '["EL FISCAL DE LA FAMILIA","EL ABOGADO DEFENSOR","EL FISCAL","EL JUEZ","FISCAL DE INVESTIGACIÓN PREPARATORIA"]'::jsonb, 'EL JUEZ', 3, '(ART: 378) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184443', '2026-07-14T01:12:29.113429+00:00');
