INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (868, 868, 'CÓMO SE INICIA EL EXAMEN DE LOS PERITOS:', '["CON SU PRESENTACIÓN, DETALLANDO SU HOJA DE VIDA","CON LA EXPOSICIÓN BREVE DEL CONTENIDO Y CONCLUSIONES DEL DICTAMEN PERICIAL","CON LA EXPOSICIÓN BREVE DE SU CARRERA","CON LA EXPOSICIÓN BREVE DEL CASO","CON LA EXPOSICIÓN DEL MÉTODO EMPLEADO"]'::jsonb, 'CON LA EXPOSICIÓN BREVE DEL CONTENIDO Y CONCLUSIONES DEL DICTAMEN PERICIAL', 1, '(ART: 378) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184445', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (869, 869, 'SI UN TESTIGO O PERITO DECLARA QUE YA NO SE ACUERDA DE UN HECHO, QUÉ PROCEDIMIENTO SE UTILIZA:', '["SE LE ENTREGARÁ SU DECLARACIÓN O PERITAJE, SEGÚN CORRESPONDA, A FIN DE QUE RECUERDE","SE DARÁ POR CONCLUIDA SU PARTICIPACIÓN Y SE DISPONDRÁ SU SALIDA DE LA SALA","SE PUEDE LEER LA PARTE CORRESPONDIENTE DEL ACTO SOBRE SU INTERROGATORIO ANTERIOR PARA HACER MEMORIA","SE PRESCINDIRÁ SU PARTICIPACIÓN Y SE NOMBRARÁ UN PERITO JUDICIAL","SERÁ SUSPENDIDO DEL REGISTRO RESPECTIVO Y NO SE LE TOMARÁ EN CUENTA PARA OTRAS DILIGENCIAS"]'::jsonb, 'SE PUEDE LEER LA PARTE CORRESPONDIENTE DEL ACTO SOBRE SU INTERROGATORIO ANTERIOR PARA HACER MEMORIA', 2, '(ART: 378) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184446', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (870, 870, 'QUIÉNES ESTÁN AUTORIZADOS PARA CONSULTAR DOCUMENTOS, NOTAS ESCRITAS Y PUBLICACIONES DURANTE SU INTERROGATORIO:', '["EL ABOGADO DEFENSOR","LOS PERITOS","LOS TESTIGOS","LOS AGRAVIADOS","EL FISCAL"]'::jsonb, 'LOS PERITOS', 1, '(ART: 378) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184447', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (871, 871, 'DURANTE EL CONTRAINTERROGATORIO, QUIÉNES PODRÁN CONFRONTAR AL PERITO O TESTIGO CON SUS PROPIOS DICHOS U OTRAS VERSIONES DE LOS HECHOS PRESENTADAS EN EL JUICIO:', '["EL ABOGADO DEFENSOR Y EL ACUSADO","EL FISCAL Y EL ABOGADO DEFENSOR","LAS PARTES","EL ABOGADO DEFENSOR Y EL SENTENCIADO","EL O LOS AGRAVIADOS"]'::jsonb, 'LAS PARTES', 2, '(ART: 378) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184448', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (872, 872, 'A SOLICITUD DE QUIÉN, EL JUEZ PODRÁ AUTORIZAR UN NUEVO INTERROGATORIO DE LOS TESTIGOS O PERITOS QUE YA HUBIERAN DECLARADO EN LA AUDIENCIA:', '["EL FISCAL PROVINCIAL","DEL FISCAL DE INVESTIGACIÓN PREPARATORIA","DEL ABOGADO DEFENSOR","DE ALGUNA DE LAS PARTES","DEL FISCAL"]'::jsonb, 'DE ALGUNA DE LAS PARTES', 3, '(ART: 378) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184449', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (873, 873, 'QUÉ ACCIÓN ADOPTA EL JUEZ, CUANDO EL TESTIGO O PERITO, OPORTUNAMENTE CITADO, NO HAYA COMPARECIDO AL JUICIO ORAL:', '["ORDENARÁ QUE SU JEFE INMEDIATO ADOPTE LAS ACCIONES RESPECTIVAS","ORDENARÁ QUE SEA CITADO NUEVAMENTE","ORDENARÁ QUE SEA CONDUCIDO COMPULSIVAMENTE","ORDENARÁ QUE SEA SANCIONADO","ORDENARÁ QUE SEA MULTADO"]'::jsonb, 'ORDENARÁ QUE SEA CONDUCIDO COMPULSIVAMENTE', 2, '(ART: 379) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184450', '2026-07-14T01:12:29.113429+00:00');
