INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (874, 874, 'QUÉ SUCEDE CON EL JUICIO, SI EL TESTIGO O PERITO NO PUEDE SER LOCALIZADO PARA SU CONDUCCIÓN COMPULSIVA:', '["SE REANUDARÁ CUANDO ES UBICADO Y CITADO","CONTINUARÁ CON PRESCINDENCIA DE ESA PRUEBA","CONTINUARÁ CUANDO ES UBICADO Y CONDUCIDO COMPULSIVAMENTE","SE SUSPENDERÁ","CULMINARÁ CON LA SENTENCIA ÚNICA"]'::jsonb, 'CONTINUARÁ CON PRESCINDENCIA DE ESA PRUEBA', 1, '(ART: 379) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184451', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (875, 875, 'EN QUE CASO, EL JUEZ, DE OFICIO O A SOLICITUD DE PARTE, PUEDE ORDENAR QUE EL ACUSADO NO ESTÉ PRESENTE EN LA AUDIENCIA DURANTE UN INTERROGATORIO', '["SI ES DE TEMER QUE OTRO PROCESADO, UN TESTIGO O UN PERITO DIRÁ LA VERDAD","SI ES DE TEMER QUE OTRO PROCESADO, UN TESTIGO O UN PERITO NO DIRÁ LA VERDAD EN SU PRESENCIA","NO ES DE TEMER QUE OTRO PROCESADO, UN TESTIGO O UN PERITO DIRÁ LA VERDAD","SI ES DE TEMER QUE EL AGRAVIADO DIRÁ LA VERDAD","SI ES DE PRESUMIR QUE OTRO AGRAVIADO DIRÁ LA VERDAD"]'::jsonb, 'SI ES DE TEMER QUE OTRO PROCESADO, UN TESTIGO O UN PERITO NO DIRÁ LA VERDAD EN SU PRESENCIA', 1, '(ART: 380) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184452', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (876, 876, 'LOS TESTIGOS Y PERITOS QUE NO PUEDAN CONCURRIR A LA SALA DE AUDIENCIAS POR UN IMPEDIMENTO JUSTIFICADO, DONDE SERÁN EXAMINADOS POR EL JUEZ:', '["YA NO LOS EXAMINARÁ","EN EL LUGAR DONDE TRABAJAN","EN EL LUGAR DONDE SE HALLEN","EN EL LUGAR DONDE SEÑALE EL JUEZ","EN EL LUGAR DONDE LOS SOLICITAN"]'::jsonb, 'EN EL LUGAR DONDE SE HALLEN', 2, '(ART: 381) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184453', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (877, 877, 'SI LOS TESTIGOS Y PERITOS SE ENCUENTRAN EN LUGAR DISTINTO AL DEL JUICIO, QUE ACCIÓN ADOPTARÁ EL JUEZ:', '["NO SE TRASLADARÁ Y REPROGRAMARÁ EL JUICIO ORAL","SE TRASLADARÁ HASTA EL MISMO O EMPLEARA EL SISTEMA DE VIDEO COFERENCIA","SOLICITARÁ QUE POR EXHORTO SE LLEVE A CABO EL JUICIO","RESCINDIRÁ DE DICHA ACTUACIÓN PROCESAL","DARÁ POR CONCLUIDO EL PROCESO"]'::jsonb, 'SE TRASLADARÁ HASTA EL MISMO O EMPLEARA EL SISTEMA DE VIDEO COFERENCIA', 1, '(ART: 381) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184454', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (878, 878, 'SI LOS TESTIGOS Y PERITOS SE ENCUENTRAN EN LUGAR DISTINTO AL DEL JUICIO, QUE ACCIÓN ADOPTARÁ EL JUEZ:', '["EMPLEARÁ EL SISTEMA DE VÍDEO CONFERENCIA","EMPLEARÁ EL SISTEMA DE VÍDEO VIGILANCIA","EMPLEARÁ EL SISTEMA DE EXHORTO","EMPLEARÁ EL SISTEMA DE CONFERENCIA","EMPLEARÁ EL SISTEMA DE TELECONFERENCIA"]'::jsonb, 'EMPLEARÁ EL SISTEMA DE VÍDEO CONFERENCIA', 0, '(ART: 381) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184455', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (879, 879, 'EN CASOS EXCEPCIONALES, SI SE CUENTA CON LOS MEDIOS TÉCNICOS CORRESPONDIENTES, LA PRACTICA DE LA PRUEBA, SE REPRODUCIRÁ A TRAVÉS DE:', '["TELECONFERENCIA","VIDEO, FILMACIÓN O AUDIO","VIDEO CONFERENCIA","PRUEBA ANTICIPADA","PRUEBA PRECONSTITUIDA"]'::jsonb, 'VIDEO, FILMACIÓN O AUDIO', 1, '(ART: 381) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184456', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (880, 880, 'QUÉ SERÁN EXHIBIDOS EN EL DEBATE Y PODRÁN SER EXAMINADOS POR LAS PARTES', '["LAS PRUEBAS DOCUMENTALES","LOS INSTRUMENTOS O EFECTOS DEL DELITO, QUE OBREN O HAYAN SIDO INCORPORADOS AL JUICIO","LAS PRUEBAS PERICIALES","LAS PRUEBAS DEL DELITO","LAS ESPECIES RECUPERADAS"]'::jsonb, 'LOS INSTRUMENTOS O EFECTOS DEL DELITO, QUE OBREN O HAYAN SIDO INCORPORADOS AL JUICIO', 1, '(ART: 382) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184457', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (881, 881, 'LOS VESTIGIOS INCAUTADOS O RECOGIDOS, SERÁN EXHIBIDOS EN EL DEBATE Y PODRÁN SER EXAMINADOS POR LAS PARTES, SIEMPRE:', '["QUE HAYAN SIDO INCORPORADOS CON POSTERIORIDAD AL JUICIO","QUE OBREN O HAYAN SIDO INCORPORADOS CON ANTERIORIDAD AL JUICIO","QUE FUERON OFRECIDOS EN EL JUICIO","AQUELLOS QUE FUERON RECUPERADOS","AQUELLOS QUE FUERON ADMITIDOS CON POSTERIORIDAD JUICIO"]'::jsonb, 'QUE OBREN O HAYAN SIDO INCORPORADOS CON ANTERIORIDAD AL JUICIO', 1, '(ART: 382) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184458', '2026-07-14T01:12:29.113429+00:00');
