INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (883, 883, '¿QUÉ DOCUMENTOS PODRÁN SER INCORPORADOS AL JUICIO PARA SU LECTURA?', '["LA DECLARACIÓN DEL AGRAVIADO","LAS DECLARACIONES Y ENTREVISTAS","LAS MANIFESTACIONES","LAS ACTAS CONTENIENDO LA PRUEBA ANTICIPADA","LA DECLARACIÓN DE LOS TESTIGOS"]'::jsonb, 'LAS ACTAS CONTENIENDO LA PRUEBA ANTICIPADA', 3, '(ART: 383) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184460', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (884, 884, '¿QUÉ DOCUMENTOS PODRÁN SER INCORPORADOS AL JUICIO PARA SU LECTURA?', '["LA PRUEBA NO DOCUMENTAL","LA DENUNCIA, LA PRUEBA DOCUMENTAL O DE INFORMES, Y LAS CERTIFICACIONES Y CONSTATACIONES","LA PRUEBA DOCUMENTAL O DE INFORMES, Y LAS CONSTATACIONES","LOS INFORMES MÉDICOS","LAS REFERENCIAS"]'::jsonb, 'LA DENUNCIA, LA PRUEBA DOCUMENTAL O DE INFORMES, Y LAS CERTIFICACIONES Y CONSTATACIONES', 1, '(ART: 383) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184461', '2026-07-14T01:12:29.113429+00:00');
