INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (891, 891, 'INDIQUE QUE DOCUMENTOS NO SON ORALIZABLES EN LA AUDIENCIA:', '["LAS ACTAS QUE SE REFIEREN A LA PRUEBA QUE NO FUERON ACTUADAS EN LA AUDIENCIA","LOS DOCUMENTOS O ACTAS QUE SE REFIEREN A LA PRUEBA ACTUADA EN LA AUDIENCIA","LOS DOCUMENTOS DONDE NO ACTUARON EL FISCAL","LOS DOCUMENTOS DONDE NO ACTUARON LAS PARTES","LOS DOCUMENTOS DONDE ACTUARON CON EL FISCAL"]'::jsonb, 'LOS DOCUMENTOS O ACTAS QUE SE REFIEREN A LA PRUEBA ACTUADA EN LA AUDIENCIA', 1, '(ART: 383)** [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184468', '2026-07-14T01:12:29.113429+00:00');
