INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (900, 900, '¿QUÉ ES LO QUE NO ALTERARÁ EL CURSO DE LAS ACTUACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS PODRÁN SER CORREGIDOS EN CUALQUIER OPORTUNIDAD?', '["LAS CONCLUSIONES","LAS RESOLUCIONES","LAS SENTENCIAS","LA DUDA SOBRE LOS DATOS OBTENIDOS","LA INVESTIGACIÓN PREPARATORIA"]'::jsonb, 'LA DUDA SOBRE LOS DATOS OBTENIDOS', 3, '(ART: 72) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO I]', '184477', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (901, 901, 'TODA PERSONA PARA QUE PREPARE SU DEFENSA, TAMBIÉN TIENE DERECHO A QUE SE LE CONCEDA UN:', '["ABOGADO DE OFICIO","TIEMPO RAZONABLE","ASESORAMIENTO ADECUADO","PROCESO JUSTO","ASESOR LEGAL ESPECIALIZADO"]'::jsonb, 'TIEMPO RAZONABLE', 1, '(ART: IX) [TITULO PRELIMINAR]', '184478', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (902, 902, '¿CUÁNDO SE LE COMUNICARÁ AL IMPUTADO, DETALLADAMENTE EL HECHO OBJETO DE IMPUTACIÓN, LOS ELEMENTOS DE CONVICCIÓN Y DE PRUEBAS EXISTENTES, Y LAS DISPOSICIONES PENALES QUE SE CONSIDEREN APLICABLES?', '["UNA VEZ QUE SE INICIE LA INVESTIGACIÓN","CUANDO ESTÉ PRESENTE EL FISCAL","ANTES DE INICIADO EL PROCESO","DESPUÉS DE HABERSE LE IDENTIFICADO PLENAMENTE","ANTES DE COMENZAR LA DECLARACIÓN"]'::jsonb, 'ANTES DE COMENZAR LA DECLARACIÓN', 4, '(ART: 87) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO III]', '184479', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (903, 903, 'SI PARA CONOCER LOS HECHOS, SIEMPRE QUE SEA POSIBLE, QUE NO SE HAYA REALIZADO DICHA DILIGENCIA EN LA INVESTIGACIÓN PREPARATORIA O ESTA RESULTARÁ MANIFIESTAMENTE INSUFICIENTE, PREVIO DEBATE DE LOS INTERVINIENTES, QUIEN Y EN QUE CASOS ORDENARÁ LA REALIZACIÓN DE UNA INSPECCIÓN O DE UNA RECONSTRUCCIÓN:', '["EL FISCAL DE INVESTIGACIÓN PREPARATORIA, A PEDIDO DE PARTE","EL JUEZ DE PAZ DE OFICIO","EL JUEZ PENAL, A PEDIDO DE PARTE","EL JUEZ PENAL, DE OFICIO O A PEDIDO DE PARTE","EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA"]'::jsonb, 'EL JUEZ PENAL, DE OFICIO O A PEDIDO DE PARTE', 3, '(ART: 385) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184480', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (904, 904, 'EXCEPCIONALMENTE, UNA VEZ CULMINADA LA RECEPCIÓN DE LAS PRUEBAS, PODRÁ DISPONER, DE OFICIO O A PEDIDO DE PARTE, LA ACTUACIÓN DE NUEVOS MEDIOS PROBATORIOS:', '["EL FISCAL DE INVESTIGACIÓN PREPARATORIA","EL JUEZ PENAL","EL FISCAL","EL FISCAL PROVINCIAL","EL PROCURADOR PÚBLICO"]'::jsonb, 'EL JUEZ PENAL', 1, '(ART: 385) [LIBRO TERCERO] [SECCION III] [TITULO IV]', '184481', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (905, 905, 'CONCLUIDO EL DEBATE PROBATORIO, EN QUE ORDEN SE DESARROLLARÁ LA EXPOSICIÓN ORAL DEL FISCAL', '["TERCER ORDEN","PRIMER ORDEN","SEGUNDO ORDEN","CUARTO ORDEN","QUINTO ORDEN"]'::jsonb, 'PRIMER ORDEN', 1, '(ART: 386) [LIBRO TERCERO] [SECCION III] [TITULO V]', '184482', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (909, 909, 'EN CASO DE MANIFIESTO ABUSO DE LA PALABRA, QUE PARTE DEL PROCESO, LLAMARÁ LA ATENCIÓN AL ORADOR Y, SI ÉSTE PERSISTIERE, PODRÁ FIJARLE UN TIEMPO LÍMITE, EN EL QUE INDEFECTIBLEMENTE DARÁ POR CONCLUIDO EL ALEGATO', '["EL FISCAL DE INVESTIGACIÓN PREPARATORIA","EL FISCAL","EL JUEZ PENAL","EL FISCAL PROVINCIAL","EL ABOGADO DEL ACUSADO"]'::jsonb, 'EL JUEZ PENAL', 2, '(ART: 386) [LIBRO TERCERO] [SECCION III] [TITULO V]', '184486', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (910, 910, 'EN QUÉ CASO, EL JUEZ PENAL DECLARARÁ CERRADO EL DEBATE:', '["CULMINADA EL ALEGADO DEL TERCER CIVIL","CULMINADA LA DEFENSA DEL ACUSADO","CULMINADA LA AUTODEFENSA DEL ACUSADO","CULMINADA EL ALEGADO DEL AGRAVIADO","CULMINADA LA DILIGENCIA DEL SENTENCIADO"]'::jsonb, 'CULMINADA LA AUTODEFENSA DEL ACUSADO', 2, '(ART: 386) [LIBRO TERCERO] [SECCION III] [TITULO V]', '184487', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (911, 911, 'SI EL FISCAL CONSIDERA QUE DEL JUICIO HAN SURGIDO NUEVAS RAZONES PARA PEDIR AUMENTO O DISMINUCIÓN DE LA PENA O LA REPARACIÓN CIVIL SOLICITADAS EN LA ACUSACIÓN ESCRITA, QUE ACCIONES ADOPTARÁ AL RESPECTO:', '["LAS ADECUARÁ A SU ACUSACIÓN VERBAL Y SOLICITARÁ LA PENA O REPARACIÓN CIVIL","SOLICITARÁ DICHAS CONCLUSIONES","DESTACARÁ DICHAS RAZONES Y PEDIRÁ LA ADECUACIÓN DE LA PENA O REPARACIÓN CIVIL","MANTENDRÁ LA ADECUACIÓN DE LA PENA O REPARACIÓN CIVIL","NO DESTACARÁ DICHAS RAZONES Y NO PEDIRÁ LA ADECUACIÓN DE LA PENA O REPARACIÓN CIVIL"]'::jsonb, 'DESTACARÁ DICHAS RAZONES Y PEDIRÁ LA ADECUACIÓN DE LA PENA O REPARACIÓN CIVIL', 2, '(ART: 387) [LIBRO TERCERO] [SECCION III] [TITULO V]', '184490', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (912, 912, 'EN QUE CASOS EL JUZGADOR, ELEVARÁ LOS AUTOS AL FISCAL JERÁRQUICAMENTE SUPERIOR PARA QUE DECIDA, DENTRO DEL TERCER DÍA:', '["NO DISCREPA DEL REQUERIMIENTO DEL FISCAL","SI DISCREPA DEL REQUERIMIENTO DEL ABOGADO DEFENSOR","SI DISCREPA DEL REQUERIMIENTO DEL FISCAL","SI DISCREPA DEL REQUERIMIENTO DEL ABOGADO DE LA PARTE CIVIL","NO DISCREPA DEL REQUERIMIENTO DEL ABOGADO DE LA PARTE CIVIL"]'::jsonb, 'SI DISCREPA DEL REQUERIMIENTO DEL FISCAL', 2, '(ART: 387)** [LIBRO TERCERO] [SECCION III] [TITULO V]', '184492', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (913, 913, 'EN EL ALEGATO ORAL DEL ACTOR CIVIL, EL ABOGADO ESTÁ PROHIBIDO DE:', '["ACUSAR AL PROCESADO","CALIFICAR EL DELITO","ABOGAR POR EL IMPUTADO","PETICIONAR LA REPARACIÓN CIVIL","DEFENDER A SU PATROCINADO"]'::jsonb, 'CALIFICAR EL DELITO', 1, '(ART: 388) [LIBRO TERCERO] [SECCION III] [TITULO V]', '184494', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (914, 914, 'DECLARACIÓN DEL IMPUTADO: LA DILIGENCIA SE INICIARÁ REQUIRIENDO AL IMPUTADO DECLARAR RESPECTO A:', '["LUGAR DONDE SE COMETIÓ EL HECHO DELICTUOSO","UBICACIÓN DE LOS TATUAJES Y SEÑAS PARTICULARES","ESTADO DE SALUD FÍSICA Y MENTAL","NOMBRE, APELLIDOS, SOBRENOMBRE O APODO SI LO TUVIERE, LUGAR Y FECHA DE NACIMIENTO, PRINCIPALES SITIOS DE RESIDENCIA ANTERIOR","LAS ARMAS Y VEHÍCULOS UTILIZADOS EN EL HECHO PUNIBLE"]'::jsonb, 'NOMBRE, APELLIDOS, SOBRENOMBRE O APODO SI LO TUVIERE, LUGAR Y FECHA DE NACIMIENTO, PRINCIPALES SITIOS DE RESIDENCIA ANTERIOR', 3, '(ART: 88) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO III]', '184495', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (915, 915, 'EN EL ALEGATO ORAL DEL ACTOR CIVIL, EL ABOGADO PODRÁ:', '["NO ESCLARECER LOS HECHOS DELICTUOSOS","ESCLARECER CON TODA AMPLITUD LOS HECHOS DELICTUOSOS","ESCLARECER EN PARTE LOS HECHOS DELICTUOSOS","NO ESCLARECER LA AMPLITUD LOS HECHOS DELICTUOSOS","CON TODA AMBIGÜEDAD PROCURAR EL ESCLARECIMIENTO DE LOS HECHOS DELICTUOSOS"]'::jsonb, 'ESCLARECER CON TODA AMPLITUD LOS HECHOS DELICTUOSOS', 1, '(ART: 388) [LIBRO TERCERO] [SECCION III] [TITULO V]', '184496', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (916, 916, 'LA DILIGENCIA SE INICIARÁ REQUIRIENDO AL IMPUTADO DECLARAR RESPECTO A:', '["LUGAR DONDE SE COMETIÓ EL HECHO DELICTUOSO","ESTADO DE SALUD FÍSICA Y MENTAL","SI HA SIDO ENCAUSADO ANTERIORMENTE POR EL MISMO HECHO O POR OTROS","UBICACIÓN DE LOS TATUAJES Y SEÑAS PARTICULARES","LAS ARMAS Y VEHÍCULOS UTILIZADOS EN EL HECHO PUNIBLE"]'::jsonb, 'SI HA SIDO ENCAUSADO ANTERIORMENTE POR EL MISMO HECHO O POR OTROS', 2, '(ART: 88) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO III]', '184499', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (917, 917, 'EN EL ALEGATO ORAL DEL ABOGADO DEL TERCERO CIVIL, EL ABOGADO PODRÁ:', '["NO REFUTAR LA EXISTENCIA DE LA RESPONSABILIDAD PENAL SOLIDARIA QUE LE ATRIBUYE LA ACUSACIÓN","REFUTAR LA EXISTENCIA DE LA RESPONSABILIDAD CIVIL SOLIDARIA QUE LE ATRIBUYE LA ACUSACIÓN","ACEPTAR LA EXISTENCIA DE LA RESPONSABILIDAD CIVIL SOLIDARIA QUE LE ATRIBUYE LA ACUSACIÓN","NO REFUTAR LA EXISTENCIA DE LA RESPONSABILIDAD CIVIL SOLIDARIA QUE LE ATRIBUYE LA ACUSACIÓN","REFUTAR LA EXISTENCIA DE LA RESPONSABILIDAD ADMINISTRATIVA SOLIDARIA QUE LE ATRIBUYE LA ACUSACIÓN"]'::jsonb, 'REFUTAR LA EXISTENCIA DE LA RESPONSABILIDAD CIVIL SOLIDARIA QUE LE ATRIBUYE LA ACUSACIÓN', 1, '(ART: 389) [LIBRO TERCERO] [SECCION III] [TITULO V]', '184501', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (918, 918, 'EN EL ALEGATO ORAL DEL ABOGADO DEL TERCERO CIVIL, EL ABOGADO PODRÁ:', '["ADMITIR LA EXISTENCIA DE LOS CRITERIOS DE IMPUTACIÓN DE DERECHO CIVIL","RESALTAR LA EXISTENCIA DE LOS CRITERIOS DE IMPUTACIÓN DE DERECHO CIVIL","RESALTAR LA INEXISTENCIA DE LOS CRITERIOS DE IMPUTACIÓN DE DERECHO CIVIL","ACEPTAR LA INEXISTENCIA DE LOS CRITERIOS DE IMPUTACIÓN DE DERECHO CIVIL","ADMITIR LOS CRITERIOS DE IMPUTACIÓN DE DERECHO CIVIL"]'::jsonb, 'RESALTAR LA INEXISTENCIA DE LOS CRITERIOS DE IMPUTACIÓN DE DERECHO CIVIL', 2, '(ART: 389)** [LIBRO TERCERO] [SECCION III] [TITULO V]', '184502', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (919, 919, 'EN QUE CASO, SE DARÁ POR TERMINADA LA EXPOSICIÓN DEL ACUSADO:', '["SI INCUMPLE CON LAS REGLAS DE CONDUCTA","SI CUMPLE CON LA LIMITACIÓN IMPUESTA","SI INCUMPLE CON LA LIMITACIÓN IMPUESTA","SI INCUMPLE CON LOS PROCEDIMIENTOS ESTABLECIDOS","SI INCUMPLE CON LA LIMITACIÓN NO IMPUESTA"]'::jsonb, 'SI INCUMPLE CON LA LIMITACIÓN IMPUESTA', 2, '(ART: 391) [LIBRO TERCERO] [SECCION III] [TITULO V]', '184504', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (920, 920, 'EN EL DESARROLLO DE LA DECLARACIÓN, SE INTERROGARÁ AL IMPUTADO. EN EL JUICIO PARTICIPARÁN EN EL INTERROGATORIO TODAS LAS PARTES MEDIANTE:', '["RONDA DE PREGUNTAS A CARGO DEL ABOGADO DEFENSOR","UN INTERROGATORIO DIRECTO","UN CUESTIONARIO CON PREGUNTAS REFERENTES AL CASO","PREGUNTAS CAPCIOSAS O SUGESTIVAS","UNA ENTREVISTA DIRECTA"]'::jsonb, 'UN INTERROGATORIO DIRECTO', 1, '(ART: 88) [LIBRO PRIMERO] [SECCION IV] [TITULO II] [CAPITULO III]', '184505', '2026-07-14T01:12:29.113429+00:00');
