INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (939, 939, 'EL QUE, CON VIOLENCIA, OCASIONA UN ABORTO, SIN HABER TENIDO EL PROPÓSITO DE CAUSARLO, SIENDO NOTORIO O CONSTÁNDOLE EL EMBARAZO, COMETE DELITO DE:', '["ABORTO CONSENTIDO","ABORTO SIN CONSENTIMIENTO","AUTOABORTO","ABORTO PRETERINTENCIONAL","ABORTO TERAPÉUTICO"]'::jsonb, 'ABORTO PRETERINTENCIONAL', 3, '(ART: 118)** [LIBRO SEGUNDO] [TITULO I] [CAPITULO II]', '183966', '2026-07-14T01:12:29.113429+00:00');
