INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (924, 924, 'EL QUE, POR VIOLENCIA, AMENAZA O ASTUCIA, HACE EVADIR A UN PRESO, DETENIDO O INTERNO O LE PRESTA ASISTENCIA EN CUALQUIER FORMA PARA EVADIRSE, COMETE DELITO DE:', '["FAVORECIMIENTO A LA FUGA","FUGA MEDIANTE VIOLENCIA","FUGA MEDIANTE AMENAZA","FAVORECIMIENTO A LA EVASIÓN DE LA JUSTICIA","FUGA MEDIANTE VIOLENCIA O AMENAZA"]'::jsonb, 'FAVORECIMIENTO A LA FUGA', 0, '(ART: 414)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO III] [SECCION I]', '183942', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (925, 925, 'EL QUE OMITE COMUNICAR A LA AUTORIDAD LAS NOTICIAS QUE TENGA ACERCA DE LA COMISIÓN DE ALGÚN DELITO, CUANDO ESTÉ OBLIGADO A HACERLO POR SU PROFESIÓN O EMPLEO, COMETE DELITO DE:', '["OMISIÓN DE INFORMAR","OMISIÓN A LA JUSTICIA","OMISIÓN AGRAVADA","OMISIÓN DE DENUNCIA","OMISIÓN IMPROPIA"]'::jsonb, 'OMISIÓN DE DENUNCIA', 3, '(ART: 407)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO III] [SECCION I]', '183943', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (926, 926, 'TODA PERSONA QUE HAGA USO DE CUALQUIER TÉCNICA DE MANIPULACIÓN GENÉTICA CON LA FINALIDAD DE CLONAR SERES HUMANOS, COMETE DELITO DE:', '["MANIPULACIÓN DE ADN ILEGAL","MANIPULACIÓN GENÉTICA DE HUMANOS","FAVORECIMIENTO A LA CLONACIÓN","MANIPULACIÓN GENÉTICA","MANIPULACIÓN ILEGAL DE LA GENÉTICA"]'::jsonb, 'MANIPULACIÓN GENÉTICA', 3, '(ART: 324)** [LIBRO SEGUNDO] [TITULO XV] [CAPITULO V]', '183944', '2026-07-14T01:12:29.113429+00:00');
