INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (930, 930, 'EL QUE MATE A OTRO CONCURRIENDO CUALQUIERA DE LAS CIRCUNSTANCIAS SIGUIENTES: POR FEROCIDAD, CODICIA, LUCRO O PLACER, PARA FACILITAR U OCULTAR OTRO DELITO, CON GRAN CRUELDAD O ALEVOSÍA, POR FUEGO, EXPLOSIÓN U OTRO MEDIO CAPAZ DE PONER EN PELIGRO LA VIDA O SALUD DE OTRAS PERSONAS. ESTA CONSIDERADO COMO DELITO CONTRA LA VIDA, EL CUERPO Y LA SALUD EN LA MODALIDAD DE:', '["HOMICIDIO SIMPLE","HOMICIDIO GRAVE","HOMICIDIO PLANIFICADO","HOMICIDIO CRUEL","HOMICIDIO CALIFICADO"]'::jsonb, 'HOMICIDIO CALIFICADO', 4, '(ART: 108)** [LIBRO SEGUNDO] [TITULO I] [CAPITULO I]', '183952', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (931, 931, 'EL QUE MATA A UNO DE LOS ALTOS FUNCIONARIOS COMPRENDIDOS EN EL ARTÍCULO 39 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ, A UN MIEMBRO DE LA POLICÍA NACIONAL, DE LAS FUERZAS ARMADAS, A UN MAGISTRADO DEL PODER JUDICIAL, O DEL MINISTERIO PÚBLICO, O A UN MIEMBRO DEL TRIBUNAL CONSTITUCIONAL O A CUALQUIER AUTORIDAD ELEGIDA POR MANDATO POPULAR EN EL EJERCICIO DE SUS FUNCIONES O COMO CONSECUENCIA DE ELLAS.- COMETE DELITO CONTRA LA VIDA, EL CUERPO Y LA SALUD, EN LA MODALIDAD:', '["HOMICIDIO SIMPLE POR LA CONDICIÓN DE LA VÍCTIMA","HOMICIDIO PLANIFICADO POR LA CONDICIÓN DE LA VÍCTIMA","HOMICIDIO CALIFICADO POR LA CONDICIÓN DE LA VÍCTIMA","HOMICIDIO AGRAVADO POR LA CONDICIÓN DEL AUTOR","HOMICIDIO CALIFICADO POR LA RELACIÓN DEL AUTOR CON LA VÍCTIMA"]'::jsonb, 'HOMICIDIO CALIFICADO POR LA CONDICIÓN DE LA VÍCTIMA', 2, '(ART: 108-A)** [LIBRO SEGUNDO] [TITULO I] [CAPITULO I]', '183953', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (932, 932, 'EL QUE MATA A UNA MUJER POR SU CONDICIÓN DE TAL, EN CUALQUIERA DE LOS SIGUIENTES CONTEXTOS: VIOLENCIA FAMILIAR, COACCIÓN, HOSTIGAMIENTO O ACOSO SEXUAL, ABUSO DE PODER, CONFIANZA O DE CUALQUIER POSICIÓN O RELACIÓN QUE LE CONFIERE AUTORIDAD AL AGENTE, CUALQUIER FORMA DE DISCRIMINACIÓN CONTRA LA MUJER, INDEPENDIENTE DE QUE EXISTA O HAYA EXISTIDO UNA RELACIÓN CONYUGAL O DE CONVIVENCIA CON EL AGENTE, COMETE DELITO CONTRA LA VIDA, EL CUERPO Y LA SALUD, EN LA MODALIDAD DE:', '["PARRICIDIO","INFANTICIDIO","SUICIDIO","GENOCIDIO","FEMINICIDIO"]'::jsonb, 'FEMINICIDIO', 4, '(ART: 108-B)** [LIBRO SEGUNDO] [TITULO I] [CAPITULO I]', '183954', '2026-07-14T01:12:29.113429+00:00');
