INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (940, 940, 'NO ES PUNIBLE EL ABORTO PRACTICADO POR UN MÉDICO CON EL CONSENTIMIENTO DE LA MUJER EMBARAZADA O DE SU REPRESENTANTE LEGAL, SI LO TUVIERE, CUANDO ES EL ÚNICO MEDIO PARA SALVAR LA VIDA DE LA GESTANTE O PARA EVITAR EN SU SALUD UN MAL GRAVE Y PERMANENTE, ESTE ENUNCIADO CORRESPONDE A:', '["ABORTO SANITARIO","ABORTO CONSENTIDO","ABORTO SIN CONSENTIMIENTO","ABORTO PRETERINTENCIONAL","ABORTO TERAPÉUTICO"]'::jsonb, 'ABORTO TERAPÉUTICO', 4, '(ART: 119)** [LIBRO SEGUNDO] [TITULO I] [CAPITULO II]', '183967', '2026-07-14T01:12:29.113429+00:00');
