INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (954, 954, 'EL QUE PUBLICA, INDEBIDAMENTE, UNA CORRESPONDENCIA EPISTOLAR O TELEGRÁFICA, NO DESTINADA A LA PUBLICIDAD, AUNQUE LE HAYA SIDO DIRIGIDA, SERÁ REPRIMIDO, SI EL HECHO CAUSA ALGÚN PERJUICIO A OTRO, COMETE DELITO DE:', '["PUBLICACIÓN ILEGAL DE CORRESPONDENCIA EPISTOLAR O TELEGRÁFICA","PUBLICACIÓN INCORRECTA DE CORRESPONDENCIA EPISTOLAR","PUBLICACIÓN INDEBIDA DE CORRESPONDENCIA","PUBLICACIÓN AUTORIZADA DE CORRESPONDENCIA PRIVADA","PUBLICACIÓN NO AUTORIZADA DE CORRESPONDENCIA PÚBLICA"]'::jsonb, 'PUBLICACIÓN INDEBIDA DE CORRESPONDENCIA', 2, '(ART: 164)** [LIBRO SEGUNDO] [TITULO IV] [CAPITULO IV]', '183992', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (955, 955, 'EL QUE, TENIENDO INFORMACIÓN POR RAZÓN DE SU ESTADO, OFICIO, EMPLEO, PROFESIÓN O MINISTERIO, DE SECRETOS CUYA PUBLICACIÓN PUEDA CAUSAR DAÑO, LOS REVELA SIN CONSENTIMIENTO DEL INTERESADO, COMETE DELITO DE:', '["VIOLACIÓN DEL SECRETO PERSONAL","VIOLACIÓN DEL SECRETO PROFESIONAL","VIOLACIÓN DEL INFORME PROFESIONAL","VIOLACIÓN DEL SECRETO NO AUTORIZADO","VIOLACIÓN DEL SECRETO AUTORIZADO"]'::jsonb, 'VIOLACIÓN DEL SECRETO PROFESIONAL', 1, '(ART: 165)** [LIBRO SEGUNDO] [TITULO IV] [CAPITULO V]', '183993', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (956, 956, 'EN EL DELITO DE VIOLACIÓN DE LA LIBERTAD DE REUNIÓN, EL FUNCIONARIO PÚBLICO QUE ABUSANDO DE SU CARGO NO AUTORIZA, NO GARANTIZA, PROHÍBE O IMPIDE UNA REUNIÓN PÚBLICA, LÍCITAMENTE CONVOCADA, COMETE DELITO DE:', '["PROHIBICIÓN DE REUNIÓN PÚBLICA ILÍCITA POR FUNCIONARIO PARTICULAR","PROHIBICIÓN DE REUNIÓN SIN ARMAS ILÍCITA POR FUNCIONARIO PÚBLICO","PROHIBICIÓN DE REUNIÓN CON ARMAS LÍCITA POR FUNCIONARIO PARTICULAR","PROHIBICIÓN DE REUNIÓN ESCANDALOSA U OBSCENA POR FUNCIONARIO PÚBLICO","PROHIBICIÓN DE REUNIÓN PÚBLICA LÍCITA POR FUNCIONARIO PÚBLICO"]'::jsonb, 'PROHIBICIÓN DE REUNIÓN PÚBLICA LÍCITA POR FUNCIONARIO PÚBLICO', 4, '(ART: 167)** [LIBRO SEGUNDO] [TITULO IV] [CAPITULO VI]', '183995', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (957, 957, 'EL QUE, MEDIANTE VIOLENCIA O AMENAZA, OBLIGA O IMPIDE A OTRO A INTEGRAR UN SINDICATO. LA MISMA PENA SE APLICARÁ AL QUE INCUMPLE LAS RESOLUCIONE CONSENTIDAS O EJECUTORIADAS DICTADAS POR AL AUTORIDAD COMPETENTE; Y AL QUE DISMINUYE O DISTORSIONA LA PRODUCCIÓN, SIMULA CAUSALES PARA EL CIERRE DEL CENTRO DE TRABAJO O ABANDONA ÉSTE PARA EXTINGUIR LAS RELACIONES LABORALES, COMETE DELITO DE:', '["ATENTADO CONTRA LA LIBERTAD DE ASOCIACIÓN","ATENTADO CONTRA LA LIBERTAD DE NO SINDICALIZARSE","ATENTADO CONTRA LA LIBERTAD DE PERCIBIR HABERES POR TRABAJO","ATENTADO CONTRA LA LIBERTAD DE NO PERCIBIR HABERES POR TRABAJO","ATENTADO CONTRA LA LIBERTAD DE TRABAJO Y ASOCIACIÓN"]'::jsonb, 'ATENTADO CONTRA LA LIBERTAD DE TRABAJO Y ASOCIACIÓN', 4, '(ART: 168)** [LIBRO SEGUNDO] [TITULO IV] [CAPITULO VII]', '183996', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (984, 984, 'EL DELITO DE PELIGRO COMÚN, POR MEDIO DE INCENDIO, EXPLOSIÓN O LIBERANDO CUALQUIER CLASE DE ENERGÍA, CREA UN PELIGRO COMÚN PARA:', '["EL ORDEN SOCIAL","LAS PERSONAS O LOS BIENES","LOS OBJETOS","SOLO CONTRA LAS PERSONAS","CONTRA LOS ELEMENTOS MATERIALES"]'::jsonb, 'LAS PERSONAS O LOS BIENES', 1, '(ART: 273)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO I]', '184062', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (958, 958, 'EL FUNCIONARIO PÚBLICO QUE, ABUSANDO DE SU CARGO, SUSPENDE O CLAUSURA ALGÚN MEDIO DE COMUNICACIÓN SOCIAL O IMPIDE SU CIRCULACIÓN O DIFUSIÓN, COMETE DELITO DE:', '["VIOLACIÓN DE LA LIBERTAD DE EXPRESIÓN","VIOLACIÓN DE LA LIBERTAD DE CULTURA","VIOLACIÓN DE LA LIBERTAD DE PROGRAMACIÓN","PROHIBICIÓN DE LA LIBERTAD DE EXPRESIÓN","PROHIBICIÓN DE LA LIBERTAD DE CULTURA"]'::jsonb, 'VIOLACIÓN DE LA LIBERTAD DE EXPRESIÓN', 0, '(ART: 169)** [LIBRO SEGUNDO] [TITULO IV] [CAPITULO VIII]', '183997', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (959, 959, 'EL QUE CON VIOLENCIA, FÍSICA O PSICOLÓGICA, GRAVE AMENAZA O APROVECHÁNDOSE DE UN ENTORNO DE COACCIÓN O DE CUALQUIER OTRO ENTORNO QUE IMPIDA A LA PERSONA DAR SU LIBRE CONSENTIMIENTO, OBLIGA A ESTA A TENER ACCESO CARNAL POR VÍA VAGINAL, ANAL O BUCAL O REALIZA CUALQUIER OTRO ACTO ANÁLOGO CON LA INTRODUCCIÓN DE UN OBJETO O PARTE DEL CUERPO POR ALGUNA DE LAS DOS PRIMERAS VÍAS, COMETE DELITO DE:', '["VIOLACIÓN ÍNTIMA","VIOLACIÓN DE LA INTIMIDAD","VIOLACIÓN NO CONSENTIDA","VIOLACIÓN SEXUAL","VIOLACIÓN PERSONAL"]'::jsonb, 'VIOLACIÓN SEXUAL', 3, '(ART: 170)** [LIBRO SEGUNDO] [TITULO IV] [CAPITULO IX]', '183998', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (960, 960, 'EL QUE EMPLEE, DESARROLLE, PRODUZCA, ADQUIERA, ALMACENE, CONSERVE O TRANSFIERA A UNA PERSONA NATURAL O JURÍDICA, MINAS ANTIPERSONALES, COMETE DELITO DE:', '["SUSTRACCIÓN O ARREBATO DE ARMAS DE FUEGO","FABRICACIÓN, SUMINISTRO DE MATERIALES Y RESIDUOS PELIGROSOS","EMPLEO, PRODUCCIÓN Y TRANSFERENCIA DE MINAS ANTIPERSONALES","USO DE ARMA EN ESTADO DE EBRIEDAD O DROGADICCIÓN","EMPLEO Y TRANSFERENCIA DE EXPLOSIVOS ANTIPERSONALES"]'::jsonb, 'EMPLEO, PRODUCCIÓN Y TRANSFERENCIA DE MINAS ANTIPERSONALES', 2, '(ART: 279-D)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO I]', '184002', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (961, 961, 'EL QUE SIN CUMPLIR CON LA NORMATIVIDAD VIGENTE Y/O SIN CONTAR CON LA AUTORIZACIÓN EXPRESA, QUE PARA EL EFECTO EXPIDA LA AUTORIDAD COMPETENTE, REALICE U ORDENE REALIZAR A SUS SUBORDINADOS LA ACTIVIDAD DE ENSAMBLADO DE ÓMNIBUS SOBRE CHASIS ORIGINALMENTE DISEÑADO Y FABRICADO PARA EL TRANSPORTE DE MERCANCÍAS CON CORTE O ALARGAMIENTO DEL CHASIS; COMETE DELITO DE:', '["COMERCIALIZACIÓN Y UTILIZACIÓN, EN EL SERVICIO PÚBLICO DE TRANSPORTE CON ESTRUCTURAS PROHIBIDAS","ENSAMBLADO, COMERCIALIZACIÓN Y UTILIZACIÓN, EN EL SERVICIO PÚBLICO, DE TRANSPORTE DE OMNIBUSES SOBRE CHASIS DE CAMIÓN","ENSAMBLADO, COMERCIALIZACIÓN Y UTILIZACIÓN DE ÓMNIBUS SOBRE CHASIS DE SERVICIO PUBLICO","DISEÑO Y FABRICACIÓN PARA EL TRANSPORTE DE MERCADERÍAS SOBRE CHASIS DE CAMIÓN","AUTORIZACIÓN PARA EL ENSAMBLADO DE CHASIS DE CAMIÓN PARA TRANSPORTE PÚBLICO"]'::jsonb, 'ENSAMBLADO, COMERCIALIZACIÓN Y UTILIZACIÓN, EN EL SERVICIO PÚBLICO, DE TRANSPORTE DE OMNIBUSES SOBRE CHASIS DE CAMIÓN', 1, '(ART: 279-E)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO I]', '184003', '2026-07-14T01:12:29.113429+00:00');
