INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (977, 977, 'ES UNA MODALIDAD DE LOS DELITOS DE DESOBEDIENCIA O RESISTENCIA A LA AUTORIDAD:', '["INGRESO DEBIDO DE ARMAS, MUNICIONES O MATERIALES EXPLOSIVOS, INFLAMABLES, LACRIMÓGENOS O TÓXICOS EN ESTABLECIMIENTOS PENITENCIARIOS ESTATALES","INGRESO INDEBIDO DE ARMAS, MUNICIONES O MATERIALES EXPLOSIVOS, INFLAMABLES, PARALIZANTES O TÓXICOS EN ESTABLECIMIENTOS PREVENTIVOS","INGRESO INDEBIDO DE ARMAS, MUNICIONES O MATERIALES EXPLOSIVOS, INFLAMABLES, ASFIXIANTES O TÓXICOS EN ESTABLECIMIENTOS PENITENCIARIOS","INGRESO INDEBIDO DE ARMAS, MUNICIONES O MATERIALES NOCIVOS, INFLAMABLES, ASFIXIANTES O TÓXICOS EN LOCALES PENITENCIARIOS","INGRESO DEBIDO DE ARMAS, MUNICIONES O MATERIALES EXPLOSIVOS, INFLAMABLES, TÓXICOS EN ESTABLECIMIENTOS PENITENCIARIOS NACIONALES"]'::jsonb, 'INGRESO INDEBIDO DE ARMAS, MUNICIONES O MATERIALES EXPLOSIVOS, INFLAMABLES, ASFIXIANTES O TÓXICOS EN ESTABLECIMIENTOS PENITENCIARIOS', 2, '(ART: 368-E)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO I] [SECCION II]', '184051', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (978, 978, 'EL QUE, MEDIANTE VIOLENCIA O AMENAZA, IMPIDE A UNA AUTORIDAD ELEGIDA EN UN PROCESO ELECTORAL GENERAL, PARLAMENTARIO, REGIONAL O MUNICIPAL JURAMENTAR, ASUMIR O EJERCER SUS FUNCIONES, COMETE DELITO DE:', '["VIOLENCIA CONTRA AUTORIDADES PÚBLICAS","VIOLENCIA CONTRA AUTORIDADES ELEGIDAS","VIOLENCIA CONTRA AUTORIDADES CONSTITUCIONALES","VIOLENCIA CONTRA AUTORIDADES NOMBRADAS","VIOLENCIA CONTRA AUTORIDADES O SERVIDORES"]'::jsonb, 'VIOLENCIA CONTRA AUTORIDADES ELEGIDAS', 1, '(ART: 369)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO I] [SECCION II]', '184053', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1017, 1017, 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE, ABUSANDO DE SU CARGO, INCREMENTA ILÍCITAMENTE SU PATRIMONIO RESPECTO DE SUS INGRESOS LEGÍTIMOS, COMETE:', '["APROVECHAMIENTO INDEBIDO DEL CARGO","CORRUPCIÓN DE FUNCIONARIOS","APROPIACIÓN ILÍCITA","ENRIQUECIMIENTO ILÍCITO","PECULADO"]'::jsonb, 'ENRIQUECIMIENTO ILÍCITO', 3, '(ART: 401)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO II] [SECCION IV]', '184116', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (980, 980, 'EL QUE, POR SÍ O MEDIANTE TERCEROS, REALIZA ACTOS DE DISTINCIÓN, EXCLUSIÓN, RESTRICCIÓN O PREFERENCIA QUE ANULAN O MENOSCABAN EL RECONOCIMIENTO, GOCE O EJERCICIO DE CUALQUIER DERECHO DE UNA PERSONA O GRUPO DE PERSONAS RECONOCIDO EN LA LEY, LA CONSTITUCIÓN O EN LOS TRATADOS DE DERECHOS HUMANOS DE LOS CUALES EL PERÚ ES PARTE, BASADOS EN MOTIVOS DE ORIENTACIÓN SEXUAL, COMETE DELITO DE:', '["VIOLENCIA DE GÉNERO","DISCRIMINACIÓN Y SEGREGACIÓN","ABUSO DE GÉNERO","DISCRIMINACIÓN E INCITACIÓN A LA DISCRIMINACIÓN","CONTRA LA IDENTIDAD DE GÉNERO"]'::jsonb, 'DISCRIMINACIÓN E INCITACIÓN A LA DISCRIMINACIÓN', 3, '(ART: 323)** [LIBRO SEGUNDO] [TITULO XIV-A] [CAPITULO IV]', '184055', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (981, 981, 'EL DELITO DE DISCRIMINACIÓN SE AGRAVA, SI EL HECHO SE REALIZA MEDIANTE ACTOS DE VIOLENCIA FISICA O MENTAL:', '["A TRAVÉS DEL INTERNET U OTRO MEDIO ANALOGO","A TRAVÉS DE REUNIONES PÚBLICAS","HACIENDO USO DE LAS VÍAS DE COMUNICACIÓN PÚBLICAS","A TRAVÉS DE ORGANISMOS DEL ESTADO","A TRAVÉS E ORGANISMOS PRIVADAS"]'::jsonb, 'A TRAVÉS DEL INTERNET U OTRO MEDIO ANALOGO', 0, '(ART: 323)** [LIBRO SEGUNDO] [TITULO XIV-A] [CAPITULO IV]', '184059', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (982, 982, 'EL QUE CAUSA DESORDEN EN LA SALA DE SESIONES DEL CONGRESO O DE LAS CÁMARAS LEGISLATIVAS, DE LAS ASAMBLEAS REGIONALES, DE LOS CONSEJOS MUNICIPALES O DE LOS TRIBUNALES DE JUSTICIA U OTRO LUGAR DONDE LAS AUTORIDADES PÚBLICAS EJERCEN SUS FUNCIONES O EL QUE ENTRA ARMADO EN DICHOS LUGARES; COMETE DELITO DE:', '["PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD LEGISLA PARLAMENTARIAMENTE","PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD EJERCE SUS ATRIBUCIONES","PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD ADMINISTRA JUSTICIA","PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD EJERCE SU FUNCIÓN","PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD SANCIONA"]'::jsonb, 'PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD EJERCE SU FUNCIÓN', 3, '(ART: 375)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO I] [SECCION III]', '184060', '2026-07-14T01:12:29.113429+00:00');
