INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (985, 985, 'EL DELITO DE CONDUCCIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN, CUANDO EL AGENTE PRESTA SERVICIO DE TRANSPORTE PÚBLICO DE PASAJEROS, MERCANCÍAS O CARGA EN GENERAL, SE CONFIGURA EL DELITO, ENCONTRANDOSE EN ESTADO DE EBRIEDAD CUANDO HAY PRESENCIA DE ALCOHOL EN LA SANGRE EN PROPORCIÓN:', '["SUPERIOR A 0,50 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS,ESTUPEFACIENTES, SUSTANCIAS PSICOTRÓPICAS O SINTÉTICAS","IGUAL O MAYOR A 0,5 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS,ESTUPEFACIENTES, SUSTANCIAS PSICOTRÓPICAS O SINTÉTICAS","IGUAL O MAYOR DE 0,25 GRAMOS-LITRO O BAJO EFECTO DE DROGAS TÓXICAS,ESTUPEFACIENTES, SUSTANCIAS PSICOTRÓPICAS O SINTÉTICAS","SUPERIOR DE 0,25 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS, ESTUPEFACIENTES, SUSTANCIAS PSICOTRÓPICAS O SINTÉTICAS","SUPERIOR A 0,05 GRAMOS-LITRO O BAJO EFECTO DE DROGAS TÓXICAS,ESTUPEFACIENTES, SUSTANCIAS PSICOTRÓPICAS O SINTÉTICAS"]'::jsonb, 'SUPERIOR DE 0,25 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS, ESTUPEFACIENTES, SUSTANCIAS PSICOTRÓPICAS O SINTÉTICAS', 3, '(ART: 274)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO I]', '184063', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (986, 986, 'EL DELITO DE CONDUCCIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN, SE CONFIGURA CUANDO HAY PRESENCIA DE ALCOHOL EN LA SANGRE EN PROPORCIÓN:', '["MAYOR DE 0.5 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS","MENOR DE 0.5 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS","IGUAL O MAYOR DE 0.5 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS","IGUAL O MAYOR DE 0.3 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS","MAYOR DE 0.25 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS"]'::jsonb, 'MAYOR DE 0.5 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS', 0, '(ART: 274)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO I]', '184064', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (987, 987, 'EL DELITO DE MANIPULACIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN, SE CONFIGURA CUANDO EL AGENTE OPERA O MANIOBRA INSTRUMENTO, HERRAMIENTA, MÁQUINA U OTRO ANÁLOGO QUE REPRESENTE RIESGO O PELIGRO, CON PRESENCIA DE ALCOHOL EN LA SANGRE EN PROPORCIÓN:', '["MAYOR O IGUAL DE 0.5 GRAMOS-LITRO, O BAJO EL EFECTO DE ESTUPEFACIENTES","MAYOR DE 0.1 GRAMOS-LITRO, O BAJO EL EFECTO DE DROGAS TÓXICAS","MAYOR DE 0.5 GRAMOS-LITRO, O BAJO EL EFECTO DE DROGAS TÓXICAS","MAYOR O IGUAL DE 0.1 GRAMOS-LITRO, O BAJO EL EFECTO DE ESTUPEFACIENTES","MAYOR DE 1.5 GRAMOS-LITRO, O BAJO EL EFECTO DE ESTUPEFACIENTES, DROGAS TÓXICAS"]'::jsonb, 'MAYOR DE 0.5 GRAMOS-LITRO, O BAJO EL EFECTO DE DROGAS TÓXICAS', 2, '(ART: 274-A)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO I]', '184065', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (988, 988, 'EL QUE ENCONTRÁNDOSE EN ESTADO DE EBRIEDAD, CON PRESENCIA DE ALCOHOL EN LA SANGRE EN PROPORCIÓN MAYOR DE 0.5 GRAMOS-LITRO, O BAJO EL EFECTO DE ESTUPEFACIENTES, DROGAS TÓXICAS, SUSTANCIAS PSICOTRÓPICAS O SINTÉTICAS, OPERA O MANIOBRA INSTRUMENTO, HERRAMIENTA, MÁQUINA U OTRO ANÁLOGO QUE REPRESENTE RIESGO O PELIGRO; COMETE:', '["DELITO DE PELIGRO COMÚN - MANIPULACIÓN DE INSTRUMENTOS EN ESTADO DE EBRIEDAD O DROGADICCIÓN","DELITO DE RIESGO COMÚN - MANIPULACIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN","DELITO DE PELIGRO COMÚN - MANIPULACIÓN EN ESTADO DE INHABILITACIÓN","DELITO DE PELIGRO EMINENTE - MANIPULACIÓN EN ESTADO DE EBRIEDAD O INTERNACIÓN","DELITO DE PELIGRO INMINENTE - RIESGOS EN ESTADO DE EBRIEDAD O DROGADICCIÓN"]'::jsonb, 'DELITO DE RIESGO COMÚN - MANIPULACIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN', 1, '(ART: 274-A)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO I]', '184066', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (989, 989, 'EL QUE DAÑA O INUTILIZA DIQUES U OBRAS DESTINADAS A LA DEFENSA COMÚN CONTRA DESASTRES, PERJUDICANDO SU FUNCIÓN PREVENTIVA, COMETE DELITO DE PELIGRO COMÚN EN LA MODALIDAD DE:', '["PELIGRO DE OBRAS DESTINADAS A LA DEFENSA COMÚN","DAÑOS DE OBRAS PARA LA DEFENSA COMÚN","DAÑOS DE OBRAS DESTINADAS A LA DEFENSA PÚBLICA","PELIGRO DE OBRAS DESTINADAS A LA DEFENSA PÚBLICA","PELIGRO DE DEFENSA COMÚN"]'::jsonb, 'DAÑOS DE OBRAS PARA LA DEFENSA COMÚN', 1, '(ART: 277)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO I]', '184067', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (990, 990, 'EL QUE, SIN ESTAR DEBIDAMENTE AUTORIZADO, FABRICA, ENSAMBLA, MODIFICA, ALMACENA, SUMINISTRA, COMERCIALIZA, OFRECE O TIENE EN SU PODER BOMBAS, ARTEFACTOS O MATERIALES EXPLOSIVOS, INFLAMABLES, ASFIXIANTES O TÓXICOS O SUSTANCIAS O MATERIALES DESTINADOS PARA SU PREPARACIÓN; COMETE DELITO DE PELIGRO COMÚN EN LA MODALIDAD DE:', '["FABRICACIÓN, SUMINISTRO O TENENCIA Y ALMACENAMIENTO DE MATERIALES PELIGROSOS Y RESIDUOS","FABRICACIÓN, SUMINISTRO, ENSAMBLAJE O TENENCIA DE MATERIALES Y RESIDUOS PELIGROSOS","FABRICACIÓN O TENENCIA DE INSUMOS QUÍMICOS PELIGROSOS","FABRICACIÓN O TENENCIA DE MATERIALES QUÍMICOS PELIGROSOS","FABRICACIÓN, SUMINISTRO O TENENCIA DE MATERIALES PELIGROSOS Y RESIDUOS PELIGROSOS"]'::jsonb, 'FABRICACIÓN, SUMINISTRO O TENENCIA DE MATERIALES PELIGROSOS Y RESIDUOS PELIGROSOS', 4, '(ART: 279)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO I]', '184071', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1035, 1035, 'TODOS LOS DONATIVOS DADIVAS O PRESENTES RECIBIDOS POR FUNCIONARIOS Y/O SERVIDORES PÚBLICOS DE MANERA ILÍCITA SERÁN:', '["INCAUTADOS","DONADOS","DECOMISADOS","SUSTRAÍDOS","DEVUELTOS"]'::jsonb, 'DECOMISADOS', 2, '(ART: 401-A)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO II] [SECCION IV]', '184218', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (991, 991, 'EL QUE PRODUCE, DESARROLLA, COMERCIALIZA, ALMACENA, VENDE, ADQUIERE, USA O POSEE ARMAS QUÍMICAS, - CONTRAVINIENDO LAS PROHIBICIONES ESTABLECIDAS EN LA CONVENCIÓN SOBRE ARMAS QUÍMICAS ADOPTADA POR LAS NACIONES UNIDAS EN 1992- O LAS QUE TRANSFIERE A OTRO, O EL QUE PROMUEVE, FAVORECE O FACILITA QUE SE REALICEN DICHOS ACTOS, COMETE DELITO DE PELIGRO COMÚN EN LA MODALIDAD DE:', '["PRODUCCIÓN, DESARROLLO Y COMERCIALIZACIÓN ILEGAL DE ARMAS QUÍMICAS","CONTRA LA CONVENCIÓN SOBRE ARMAS QUÍMICAS","COMERCIALIZACIÓN ILEGAL DE ARMAS QUÍMICAS AUTORIZADAS POR LA CONVENCIÓN","PRODUCCIÓN, TRÁFICO LEGAL DE ARMAS, MUNICIONES Y EXPLOSIVOS","USO DE ARMAS QUÍMICAS SIN AUTORIZACIÓN DE LA CONVENCIÓN"]'::jsonb, 'PRODUCCIÓN, DESARROLLO Y COMERCIALIZACIÓN ILEGAL DE ARMAS QUÍMICAS', 0, '(ART: 279-A)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO I]', '184073', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (992, 992, 'QUE DELITO COMETE, EL QUE MEDIANTE VIOLENCIA, INTIMIDACIÓN O FRAUDE, SUSTITUYE O IMPIDE EL CUMPLIMIENTO DE SUS FUNCIONES AL CAPITÁN, COMANDANTE O PILOTO DE UN MEDIO DE TRANSPORTE:', '["SUSTITUCIÓN O IMPEDIMENTO DE FUNCIONES EN MEDIO DE TRANSPORTE","ABANDONO DE SERVICIO DE TRANSPORTE","ENTORPECIMIENTO AL FUNCIONAMIENTO DE SERVICIOS PÚBLICOS DE TRANSPORTE","SUSTITUCIÓN DE FUNCIONES EN MEDIO DE TRANSPORTE","IMPEDIMENTO DE FUNCIONES EN MEDIO DE TRANSPORTE"]'::jsonb, 'SUSTITUCIÓN O IMPEDIMENTO DE FUNCIONES EN MEDIO DE TRANSPORTE', 0, '(ART: 285)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO II]', '184074', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (993, 993, 'EL FUNCIONARIO PÚBLICO QUE, EN VIOLACIÓN DE SUS ATRIBUCIONES U OBLIGACIONES, OTORGA ILEGÍTIMAMENTE DERECHOS DE POSESIÓN O EMITE TÍTULOS DE PROPIEDAD SOBRE BIENES DE DOMINIO PÚBLICO O BIENES DE DOMINIO PRIVADO ESTATAL, O BIENES INMUEBLES DE PROPIEDAD PRIVADA, SIN CUMPLIR CON LOS REQUISITOS ESTABLECIDOS POR LA NORMATIVIDAD VIGENTE; COMETE DELITO DE:', '["ABUSO DE AUTORIDAD CONDICIONANDO ILEGALMENTE LA ENTREGA DE BIENES Y SERVICIOS","OTORGAMIENTO ILEGÍTIMO DE DERECHOS SOBRE MUEBLES","OTORGAMIENTO LEGÍTIMO DE DERECHOS SOBRE INMUEBLES","OTORGAMIENTO ILEGÍTIMO DE DERECHOS SOBRE INMUEBLES","OMISIÓN, REHUSAMIENTO O DEMORA DE ACTOS FUNCIONALES"]'::jsonb, 'OTORGAMIENTO ILEGÍTIMO DE DERECHOS SOBRE INMUEBLES', 3, '(ART: 376-B)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO II] [SECCION I]', '184078', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (994, 994, 'EL POLICÍA QUE REHÚSA, OMITE O RETARDA, SIN CAUSA JUSTIFICADA, LA PRESTACIÓN DE UN AUXILIO LEGALMENTE REQUERIDO POR LA AUTORIDAD CIVIL COMPETENTE; COMETE DELITO DE:', '["REQUERIMIENTO INDEBIDO DE LA FUERZA PÚBLICA","DENEGACIÓN O DEFICIENTE APOYO POLICIAL","OMISIÓN, REHUSAMIENTO O DEMORA DE APOYO POLICIAL","DENEGACIÓN O DEFICIENTE SERVICIO POLICIAL","OMISIÓN, REHUSAMIENTO O DEMORA DE ACTOS POLICIALES"]'::jsonb, 'DENEGACIÓN O DEFICIENTE APOYO POLICIAL', 1, '(ART: 378)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO II] [SECCION I]', '184080', '2026-07-14T01:12:29.113429+00:00');
