INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (999, 999, 'QUE DELITO COMETE, EL QUE A SABIENDAS PROPAGA UNA ENFERMEDAD PELIGROSA CONTAGIOSA PARA LA SALUD DE LAS PERSONAS:', '["PROPAGACIÓN DE ENFERMEDAD PELIGROSA CONTAGIOSA","DELITO CONTRA LA SALUD","PROPAGACIÓN DE ENFERMEDAD NO PELIGROSA CONTAGIOSA","PROPAGACIÓN DE ENFERMEDAD PELIGROSA","DELITO CONTRA LA SALUD MENTAL"]'::jsonb, 'PROPAGACIÓN DE ENFERMEDAD PELIGROSA CONTAGIOSA', 0, '(ART: 289)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO III] [SECCION I]', '184086', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1000, 1000, 'COMETE DELITO DE PROMOCIÓN, FAVORECIMIENTO O FACILITAMIENTO DEL CONSUMO ILEGAL DE DROGAS TÓXICAS; EL QUE PROMUEVE, FAVORECE O FACILITA EL CONSUMO ILEGAL DE DROGAS TÓXICAS, SEAN ESTUPEFACIENTES, SUSTANCIAS PSICOTRÓPICAS O:', '["NUEVAS SUSTANCIAS EXÓTICAS","SUSTANCIAS FISCALIZADAS","SUSTANCIAS PROHIBIDAS","SUSTANCIAS ALUCINÓGENAS","NUEVAS SUSTANCIAS PSICOACTIVAS"]'::jsonb, 'NUEVAS SUSTANCIAS PSICOACTIVAS', 4, '(ART: 296)** [LIBRO SEGUNDO] [TITULO XII] [CAPITULO III] [SECCION II]', '184087', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1001, 1001, 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE, PARA FINES AJENOS AL SERVICIO, USA O PERMITE QUE OTRO USE VEHÍCULOS, MÁQUINAS O CUALQUIER OTRO INSTRUMENTO DE TRABAJO PERTENECIENTES A LA ADMINISTRACIÓN PÚBLICA O QUE SE HALLAN BAJO SU GUARDA, COMETE DELITO DE:', '["COLUSIÓN","PECULADO","CONCUSIÓN DE USO","PECULADO DE USO","MALVERSACIÓN DE FONDOS"]'::jsonb, 'PECULADO DE USO', 3, '(ART: 388)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO II] [SECCION III]', '184089', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1002, 1002, 'EL DELITO DE PECULADO DE USO, ES APLICABLE AL CONTRATISTA DE UNA OBRA PÚBLICA O A SUS EMPLEADOS CUANDO LOS EFECTOS INDICADOS:', '["PERTENECEN AL ESTADO O A CUALQUIER EMPRESA","SON DE PROPIEDAD DEL JEFE DE LA ENTIDAD","HAN SIDO DECLARADOS EN ABANDONO LEGAL O CIVIL","ESTÁN SOMETIDOS A PROCESO JUDICIAL","PERTENECEN AL ESTADO O A CUALQUIER DEPENDENCIA PÚBLICA"]'::jsonb, 'PERTENECEN AL ESTADO O A CUALQUIER DEPENDENCIA PÚBLICA', 4, '(ART: 388)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO II] [SECCION III]', '184091', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1003, 1003, 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE DA AL DINERO O BIENES QUE ADMINISTRA UNA APLICACIÓN DEFINITIVA DIFERENTE DE AQUELLA A LOS QUE ESTÁN DESTINADOS, AFECTANDO EL SERVICIO O LA FUNCIÓN ENCOMENDADA, COMETE DELITO DE:', '["COLUSIÓN","CONCUSIÓN","PECULADO","COBRO INDEBIDO","MALVERSACIÓN"]'::jsonb, 'MALVERSACIÓN', 4, '(ART: 389)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO II] [SECCION III]', '184092', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1004, 1004, 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE, TENIENDO FONDOS EXPEDITOS, DEMORA INJUSTIFICADAMENTE UN PAGO ORDINARIO O DECRETADO POR LA AUTORIDAD COMPETENTE, COMETE:', '["COBRO INDEBIDO","MALVERSACIÓN","RETARDO INJUSTIFICADO DE PAGO","PECULADO DE USO","COLUSIÓN DOLOSA Y CULPOSA"]'::jsonb, 'RETARDO INJUSTIFICADO DE PAGO', 2, '(ART: 390)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO II] [SECCION III]', '184093', '2026-07-14T01:12:29.113429+00:00');
