INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1007, 1007, 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE ACEPTE O RECIBA DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO, PARA REALIZAR U OMITIR UN ACTO EN VIOLACIÓN DE SUS OBLIGACIONES O EL QUE LAS ACEPTA A CONSECUENCIA DE HABER FALTADO A ELLAS, COMETE:', '["COHECHO PASIVO PROPIO","COHECHO PASIVO PROPIO EN EL EJERCICIO DE LA FUNCIÓN","CORRUPCIÓN PASIVA DE AUXILIARES JURISDICCIONALES","COHECHO ACTIVO GENÉRICO","COHECHO PASIVO IMPROPIO EN EL EJERCICIO DE LA FUNCIÓN"]'::jsonb, 'COHECHO PASIVO PROPIO', 0, '(ART: 393)** [LIBRO SEGUNDO] [TITULO XVIII] [CAPITULO II] [SECCION IV]', '184099', '2026-07-14T01:12:29.113429+00:00');
