INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1013, 1013, 'ES UNA FORMA AGRAVADA DE DELITOS CONTRA LOS RECURSOS NATURALES Y EL MEDIO AMBIENTE, SI EL AGENTE:', '["ACTÚO CLANDESTINAMENTE EN EL EJERCICIO DE SU ACTIVIDAD","OBSTACULIZA O IMPIDE LA ACTIVIDAD PROCESAL ORDENADA POR LA AUTORIDAD ADMINISTRATIVA COMPETENTE","OBSTACULIZA O IMPIDE LA LABOR DE LA GERENCIA DE LA ENTIDAD PRIVADA","COMPROMETE LA ACTIVIDAD FISCALIZADORA DE RECURSOS ORDENADA POR LA AUTORIDAD ADMINISTRATIVA COMPETENTE","OBSTACULIZA O IMPIDE LA CONTAMINACIÓN DEL MEDIO AMBIENTE"]'::jsonb, 'ACTÚO CLANDESTINAMENTE EN EL EJERCICIO DE SU ACTIVIDAD', 0, '(ART: 305)** [LIBRO SEGUNDO] [TITULO XIII] [CAPITULO I]', '184111', '2026-07-14T01:12:29.113429+00:00');
