INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1015, 1015, 'ES UNA FORMA AGRAVADA DEL DELITO DE CONTAMINACIÓN, SI EL AGENTE:', '["OCULTA DATOS SOBRE EL HECHO AGRAVANTE","OBSTACULIZA O IMPIDE LA ACTIVIDAD FISCALIZADORA DE AUDITORÍA ORDENADA POR LA AUTORIDAD ADMINISTRATIVA COMPETENTE","FALSIFICA DOCUMENTACIÓN SOBRE LA ACCIÓN DESCONTAMINANTE","GUARDA INFORMACIÓN REFERIDA A FUNCIONARIOS A CARGO DE LA GESTIÓN DE RESIDUOS ORGÁNICOS","FALSEA U OCULTA INFORMACIÓN SOBRE EL HECHO CONSUMADO"]'::jsonb, 'OBSTACULIZA O IMPIDE LA ACTIVIDAD FISCALIZADORA DE AUDITORÍA ORDENADA POR LA AUTORIDAD ADMINISTRATIVA COMPETENTE', 1, '(ART: 305)** [LIBRO SEGUNDO] [TITULO XIII] [CAPITULO I]', '184113', '2026-07-14T01:12:29.113429+00:00');
