INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1021, 1021, 'EL QUE MEDIANTE VIOLENCIA O AMENAZA OBLIGA A UNA PERSONA O A UNA INSTITUCIÓN PÚBLICA O PRIVADA A OTORGAR AL AGENTE O A UN TERCERO UNA VENTAJA ECONÓMICA INDEBIDA U OTRA VENTAJA DE CUALQUIER OTRA ÍNDOLE; COMETE:', '["HURTO","EXTORSIÓN","ESTELIONATO","HURTO AGRAVADO","CHANTAJE"]'::jsonb, 'EXTORSIÓN', 1, '(ART: 200)** [LIBRO SEGUNDO] [TITULO V] [CAPITULO VII]', '184181', '2026-07-14T01:12:29.113429+00:00');
