INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1025, 1025, 'EL QUE, CON VIOLENCIA, AMENAZA, ENGAÑO O ABUSO DE CONFIANZA, DESPOJA A OTRO, TOTAL O PARCIALMENTE, DE LA POSESIÓN O TENENCIA DE UN INMUEBLE O DEL EJERCICIO DE UN DERECHO REAL, COMETE DELITO DE:', '["APROPIACIÓN ILÍCITA","DAÑOS","HURTO","ROBO","USURPACIÓN"]'::jsonb, 'USURPACIÓN', 4, '(ART: 202)** [LIBRO SEGUNDO] [TITULO V] [CAPITULO VIII]', '184187', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1026, 1026, 'ES UNA FORMA DE USURPACIÓN AGRAVADA, CUANDO LA USURPACIÓN SE COMETE:', '["SOBRE BIENES NO DESTINADOS A SERVICIOS BÁSICOS","SOBRE INMUEBLE RESERVADO PARA FINES HABITACIONALES","SOBRE BIENES DESTINADOS A SERVICIOS DE COMUNICACIÓN","CON CONOCIMIENTO DE LA AUTORIDAD JURISDICCIONAL","CON CONOCIMIENTO DE LA AUTORIDAD POLICIAL"]'::jsonb, 'SOBRE INMUEBLE RESERVADO PARA FINES HABITACIONALES', 1, '(ART: 204)** [LIBRO SEGUNDO] [TITULO V] [CAPITULO VIII]', '184189', '2026-07-14T01:12:29.113429+00:00');
