INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1079, 1079, 'EL QUE INSERTA O HACE INSERTAR EN INSTRUMENTO PÚBLICO, DECLARACIONES FALSAS, CONCERNIENTES A HECHOS QUE DEBAN PROBARSE CON EL DOCUMENTO, CON EL OBJETO DE EMPLEARLO COMO SI LA DECLARACIÓN FUERA CONFORME A LA VERDAD, SI DE SU USO PUEDE RESULTAR ALGÚN PERJUICIO, COMETE DELITO:', '["FALSIFICACIÓN DE DOCUMENTOS","FALSEDAD GENÉRICA","PREVARICATO","FALSEDAD IDEOLÓGICA","ENCUBRIMIENTO REAL"]'::jsonb, 'FALSEDAD IDEOLÓGICA', 3, '(ART: 428)** [LIBRO SEGUNDO] [TITULO XIX] [CAPITULO I]', '184272', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1080, 1080, 'EL QUE OBRA EN DEFENSA DE BIENES JURÍDICOS PROPIOS O DE TERCEROS, CON USO DE LA FUERZA, INCLUIDO EL USO DE LA FUERZA LETAL, SIEMPRE QUE CONCURRAN; SEÑALE LA ALTERNATIVA CORRECTA SEGÚN EL ARTÍCULO 20 DEL CÓDIGO PENAL:', '["SOLO ESTÁ PERMITIDO CUANDO HAY RIESGO INMINENTE DE MUERTE PARA EL DEFENSOR","AGRESIÓN ACTUAL, ILEGÍTIMA Y REAL; NECESIDAD RACIONAL DEL MEDIO EMPLEADO Y FALTA DE PROVOCACIÓN SUFICIENTE DE QUIEN HACE LA DEFENSA","AGRESION ILEGÍTIMA Y REAL; PROPORCIONALIAD ENTRE EL MEDIO DE DEFENSA Y FALTA DE PROVOCACIÓN SUFICIENTE","LA PROPORCIONALIDAD ENTRE EL MEDIO DE DEFENSA Y LA AGRESIÓN ES EL ÚNICO CRITERIO RELEVANTE","EL DEFENSOR DEBE ESPERAR A SER ATACADO FÍSICAMENTE ANTES DE REPELER LA AGRESIÓN"]'::jsonb, 'AGRESIÓN ACTUAL, ILEGÍTIMA Y REAL; NECESIDAD RACIONAL DEL MEDIO EMPLEADO Y FALTA DE PROVOCACIÓN SUFICIENTE DE QUIEN HACE LA DEFENSA', 1, '(ART: (ART: 20)** Articulo 20.-Inimputabilidad)**', '184274', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1081, 1081, '¿CUÁL ES EL CRITERIO QUE SE EXCLUYE PARA LA VALORARIZACIÓN DE LA NECESIDAD RACIONAL DEL MEDIO EMPLEADO, SEGÚN EL ARTÍCULO 20 DEL CÓDIGO PENAL:', '["EL CRITERIO DE NECESIDAD DE MEDIOS","EL CRITERIO DE PROPORCIONALIDAD DE MEDIOS","EL CRITERIO DE LA INMEDIATEZ DE LA AGRESIÓN","EL CRITERIO DE LA EXISTENCIA DE LESIONES RECÍPROCAS","EL CRITERIO DEL PELIGRO POTENCIAL DEL DEFENSOR"]'::jsonb, 'EL CRITERIO DE PROPORCIONALIDAD DE MEDIOS', 1, '(ART: (ART: 20)** Articulo 20.- Inimputabilidad)**', '184278', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1082, 1082, 'RESPECTO A LA FUERZA FÍSICA IRRESISTIBLE COMO CAUSA EXIMENTE PENAL, INDIQUE EL SUPUESTO CORRECTO:', '["SÓLO EXIME CUANDO LA FUERZA PROVIENE DE LA NATURALEZA, NUNCA DE UN TERCERO","EXIME DE RESPONSABILIDAD SIEMPRE QUE OBRA POR UNA FUERZA FÍSICA IRRESISTIBLE PROVENIENTE DE UN TERCERO O DE LA NATURALEZA","EXIME DE RESPONSABILIDAD LA FUERZA DEBE SER MORAL Y NO FÍSICA","LA FUERZA FÍSICA DEBE SER CONSENTIDA POR EL AGENTE","EXIME DE RESPONSABILIDAD SIEMPRE QUE EL AGENTE PUDO RESISTIR LA FUERZA PERO DECIDIÓ NO HACERLO"]'::jsonb, 'EXIME DE RESPONSABILIDAD SIEMPRE QUE OBRA POR UNA FUERZA FÍSICA IRRESISTIBLE PROVENIENTE DE UN TERCERO O DE LA NATURALEZA', 1, '(ART: (ART: 20)** Articulo 20.- Inimputabilidad)**', '184284', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1083, 1083, 'SEGÚN EL ARTÍCULO 22 DEL CÓDIGO PENAL, ¿EN QUÉ SUPUESTO NO PROCEDERÁ LA REDUCCIÓN DE LA PENA SEÑALADA PARA EL HECHO PUNIBLE COMETIDO POR UN AGENTE ENTRE DIECISÉIS Y MENOS DE VEINTIÚN AÑOS:', '["CUANDO EL AGENTE INTEGRA UNA ORGANIZACIÓN CRIMINAL AL MOMENTO DEL HECHO","CUANDO EL DELITO COMETIDO ES EL DE HOMICIDIO SIMPLE","CUANDO EL AGENTE HA COMETIDO EL DELITO DE APOLOGÍA DE DELITO","CUANDO EL AGENTE ES REINCIDENTE EN HURTO SIMPLE","CUANDO EL DELITO COMETIDO ES TRÁFICO ILÍCITO DE DROGAS"]'::jsonb, 'CUANDO EL AGENTE INTEGRA UNA ORGANIZACIÓN CRIMINAL AL MOMENTO DEL HECHO', 0, '(ART: (ART: 22)** Artículo 22.- Responsabilidad restringida por la edad)**', '184290', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1084, 1084, 'CONFORME AL ARTÍCULO 317, ¿QUÉ FINALIDAD DEBE PERSEGUIR UNA ORGANIZACIÓN CRIMINAL PARA SER CONSIDERADA COMO TAL BAJO EL TIPO PENAL:', '["DIFUNDIR IDEOLOGÍAS RELIGIOSAS O POLÍTICAS EXTREMISTAS","OBTENER, DIRECTA O INDIRECTAMENTE, UN BENEFICIO ECONÓMICO U OTRO DE ORDEN MATERIAL","ELIMINAR LA COMPETENCIA EN EL MERCADO LABORAL","CONSEGUIR INFLUENCIA EN ORGANIZACIONES SOCIALES SIN OBTENER BENEFICIOS MATERIALES","REALIZAR ACTIVIDADES ALTRUISTAS MEDIANTE EL USO DE VIOLENCIA"]'::jsonb, 'OBTENER, DIRECTA O INDIRECTAMENTE, UN BENEFICIO ECONÓMICO U OTRO DE ORDEN MATERIAL', 1, '(ART: (ART: 317)** Articulo 317.- Organizacion criminal)**', '184299', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1085, 1085, '¿CUÁL DE LAS SIGUIENTES CIRCUNSTANCIAS PUEDE SER CONSIDERADA COMO ATENUANTE SEGÚN EL ARTÍCULO 46 DEL CÓDIGO PENAL PERUANO, EN TANTO NO SEA ELEMENTO CONSTITUTIVO DEL HECHO PUNIBLE, NI ESTÉ PREVISTA ESPECÍFICAMENTE PARA SANCIONARLO:', '["EJECUTAR LA CONDUCTA PUNIBLE SOBRE RECURSOS PÚBLICOS","EL OBRAR POR MÓVILES NOBLES O ALTRUISTAS","REALIZAR LA CONDUCTA PUNIBLE ABUSANDO EL AGENTE DE SU CARGO","EJECUTAR LA CONDUCTA SOBRE BIENES DE UTILIDAD COMÚN","LA PLURALIDAD DE AGENTES QUE INTERVIENEN EN LA EJECUCIÓN"]'::jsonb, 'EL OBRAR POR MÓVILES NOBLES O ALTRUISTAS', 1, '(ART: (ART: 46)** Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184302', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1086, 1086, 'EL CÓDIGO PENAL, EN SU ARTÍCULO 46, DETERMINA UNA ATENUANTE SI EL IMPUTADO:', '["REPARA VOLUNTARIAMENTE EL DAÑO OCASIONADO O LAS CONSECUENCIAS DERIVADAS DEL PELIGRO GENERADO","REALIZA LA CONDUCTA PUNIBLE EMPLEANDO MEDIOS ESPECIALMENTE PELIGROSOS","INTERVIENE CON PLURALIDAD DE AGENTES","ACTÚA ABUSANDO DE SU POSICIÓN ECONÓMICA","EJECUTA EL DELITO COMO PARTE DE UN GRUPO CRIMINAL"]'::jsonb, 'REPARA VOLUNTARIAMENTE EL DAÑO OCASIONADO O LAS CONSECUENCIAS DERIVADAS DEL PELIGRO GENERADO', 0, '(ART: (ART: 46)** Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184305', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1087, 1087, 'SELECCIONE UNA CIRCUNSTANCIA AGRAVANTE RELACIONADA CON LA CONDICIÓN DE LA VÍCTIMA SEGÚN EL ARTÍCULO 46:', '["QUE LA VÍCTIMA SEA MENOR DE EDAD O ADULTO MAYOR EN SITUACIÓN DE ESPECIAL VULNERABILIDAD","QUE LA VÍCTIMA SE PRESENTE VOLUNTARIAMENTE ANTE LA AUTORIDAD","QUE LA VÍCTIMA PROCURE DISMINUIR LAS CONSECUENCIAS DEL DELITO","QUE LA VÍCTIMA TENGA ANTECEDENTES PENALES","QUE LA VÍCTIMA SEA FAMILIAR DEL IMPUTADO"]'::jsonb, 'QUE LA VÍCTIMA SEA MENOR DE EDAD O ADULTO MAYOR EN SITUACIÓN DE ESPECIAL VULNERABILIDAD', 0, '(ART: (ART: 46)** Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184306', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1101, 1101, 'EN EL PRINCIPIO DE NECESIDAD; PARA DETERMINAR EL NIVEL DE FUERZA A USAR, SE DEBE CONSIDERAR, RAZONABLEMENTE, ENTRE OTRAS CIRCUNSTANCIAS EL NIVEL DE:', '["PROPORCIONALIDAD","COOPERACIÓN","RESISTENCIA NO OFRECIDA","PELIGRO REPRESENTADO POR LA PERSONA A INTERVENIR","SITUACIÓN A CONTROLAR"]'::jsonb, 'COOPERACIÓN', 1, '(texto: 4) (item: 184)** [TITULO I] [CAPITULO II]', '184713', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1088, 1088, '¿CUÁL DE LAS SIGUIENTES CIRCUNSTANCIAS IMPLICA LA IMPOSICIÓN DE CADENA PERPETUA SEGÚN EL ARTÍCULO 129-Q DEL CÓDIGO PENAL PERUANO:', '["CUANDO EL AGENTE ACTÚA EN CONCURSO CON OTRAS PERSONAS MAYORES DE EDAD","CUANDO SE EMPLEA VIOLENCIA SIN MEDIACIÓN DE VÍNCULO FAMILIAR","CUANDO EL AGENTE SE VALE DE SU POSICIÓN, CARGO O VÍNCULO FAMILIAR QUE LE OTORGA PARTICULAR AUTORIDAD SOBRE EL MENOR DE EDAD","CUANDO EL MENOR COMETE UN DELITO DE HURTO SIMPLE POR INFLUENCIA DEL AGENTE","CUANDO EL AGENTE ES REINCIDENTE EN DELITOS COMUNES DISTINTOS A LOS SEÑALADOS EN EL ARTÍCULO"]'::jsonb, 'CUANDO EL AGENTE SE VALE DE SU POSICIÓN, CARGO O VÍNCULO FAMILIAR QUE LE OTORGA PARTICULAR AUTORIDAD SOBRE EL MENOR DE EDAD', 2, '(ART: (ART: 129-Q)** Artículo 129-Q.- Captacion de menores de edad para la comision de delitos)**', '184314', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1089, 1089, 'EL ARTÍCULO 129-Q DEL CÓDIGO PENAL SEÑALA QUE LA PENA AUMENTARÁ SI EL DELITO COMETIDO O INTENTADO POR EL MENOR ES:', '["LESIONES PERSONALES GRAVES","ROBO AGRAVADO, SICARIATO, TRÁFICO ILÍCITO DE DROGAS O INTEGRAR A UNA ORGANIZACIÓN CRIMINAL","ESTAFA AGRAVADA U HOMICIDIO CULPOSO","COACCIÓN AGRAVADA O SECUESTRO SIMPLE","DESOBEDIENCIA A LA AUTORIDAD O USURPACIÓN"]'::jsonb, 'ROBO AGRAVADO, SICARIATO, TRÁFICO ILÍCITO DE DROGAS O INTEGRAR A UNA ORGANIZACIÓN CRIMINAL', 1, '(ART: (ART: 129-Q)** Artículo 129-Q.- Captacion de menores de edad para la comision de delitos)**', '184317', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1090, 1090, 'RESPECTO AL ARTÍCULO 129-Q, ¿CUÁL DE LAS SIGUIENTES ALTERNATIVAS DESCRIBE CORRECTAMENTE UN SUPUESTO DE CAPTACIÓN EN SITUACIÓN DE VULNERABILIDAD:', '["CAPTAR A UN MENOR QUE PERTENECE A UNA FAMILIA ECONÓMICAMENTE ACOMODADA Y CON PLENO ACCESO A REDES DE PROTECCIÓN","INDUCIR A UN MENOR DE EDAD SIN QUE MEDIEN AMENAZAS NI ABUSO DE PODER","PERSUADIR A UN MENOR CUYA SITUACIÓN FAMILIAR LO COLOCA EN DESVENTAJA SOCIAL NOTABLE PARA QUE PARTICIPE EN LA COMISIÓN DE DELITOS","FAVORECER A MENORES MAYORES DE 17 AÑOS SIN DISTINCIÓN DE SITUACIÓN","UTILIZAR A UN MENOR DE EDAD ÚNICAMENTE COMO TESTIGO DE UN DELITO SIN SU PARTICIPACIÓN ACTIVA"]'::jsonb, 'PERSUADIR A UN MENOR CUYA SITUACIÓN FAMILIAR LO COLOCA EN DESVENTAJA SOCIAL NOTABLE PARA QUE PARTICIPE EN LA COMISIÓN DE DELITOS', 2, '(ART: (ART: 129-Q)** Artículo 129-Q.- Captacion de menores de edad para la comision de delitos)**', '184318', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1091, 1091, '¿QUÉ, MARCO LEGAL REGULA EL USO DE LA FUERZA POR PARTE DEL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ EN CUMPLIMIENTO DE SU FINALIDAD CONSTITUCIONAL:', '["DECRETO SUPREMO 1185","DECRETO LEGISLATIVO 8611","DECRETO SUPREMO 8611","DECRETO SUPREMO 1186","DECRETO LEGISLATIVO 1186"]'::jsonb, 'DECRETO LEGISLATIVO 1186', 4, '(texto: 1) (item: 184)** [TITULO I] [CAPITULO I]', '184701', '2026-07-14T01:12:29.113429+00:00');
