INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1102, 1102, 'DENTRO DE LOS NIVELES DEL USO DE LA FUERZA, EXISTEN DOS RESISTENCIAS EN LOS NIVELES DE COOPERACIÓN, RESISTENCIA O AGRESIVIDAD DEL CIUDADANO A INTERVENIR. MARQUE LO CORRECTO:', '["RESISTENCIA PASIVA Y AGENTE ACTIVO","RESISTENCIA DINÁMICA Y RESISTENCIA ACTIVA","RESISTENCIA PASIVA Y RESISTENCIA ACTIVA","RESISTENCIA LETAL Y NO LETAL","RESISTENCIA NO LETAL Y RESISTENCIA ACTIVA"]'::jsonb, 'RESISTENCIA PASIVA Y RESISTENCIA ACTIVA', 2, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184715', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1103, 1103, '¿CUÁLES SON LAS CLASES DE RESISTENCIA PASIVA:', '["RESISTENCIA FÍSICA, AGRESIÓN NO LETAL Y AGRESIÓN LETAL","RIESGO LATENTE, COOPERADOR Y RESISTENCIA FÍSICA","RIESGO LATENTE, EGRESIÓN NO LETAL Y NO COOPERADOR","RIESGO LATENTE, COOPERADOR Y NO COOPERADOR","RIESGO LATENTE Y NO COOPERADOR"]'::jsonb, 'RIESGO LATENTE, COOPERADOR Y NO COOPERADOR', 3, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184716', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1104, 1104, 'CUÁLES SON LAS CLASES DE RESISTENCIA ACTIVA:', '["RIESGO LATENTE, COOPERADOR Y NO COOPERADOR","RESISTENCIA PSICOLÓGICA, AGRESIÓN NO LETAL Y AGRESIÓN LETAL","RESISTENCIA FÍSICA, AGRESIÓN LETAL Y AGRESIÓN FÍSICA","RESISTENCIA FÍSICA, AGRESIÓN NO LETAL Y AGRESIÓN FÍSICA","RESISTENCIA FÍSICA, AGRESIÓN NO LETAL Y AGRESIÓN LETAL"]'::jsonb, 'RESISTENCIA FÍSICA, AGRESIÓN NO LETAL Y AGRESIÓN LETAL', 4, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184717', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1105, 1105, 'NO ACATA LAS INDICACIONES. NO REACCIONA NI AGREDE, CORRESPONDE A LA DEFINICIÓN DE:', '["COOPERADOR","NO COOPERADOR","NO CUMPLIDOR","PASIVO","NO COLABORADOR"]'::jsonb, 'NO COOPERADOR', 1, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184718', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1106, 1106, 'ES LA AMENAZA PERMANENTE NO VISIBLE PRESENTE EN TODA INTERVENCIÓN POLICIAL, CORRESPONDE A LA DEFINICIÓN DE:', '["RIESGO ENCUBIERTO","RIESGO OCULTO","RIESGO DE SEGURIDAD","RIESGO PERMANENTE","RIESGO LATENTE"]'::jsonb, 'RIESGO LATENTE', 4, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184719', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1107, 1107, 'SE OPONE A SU REDUCCIÓN, INMOVILIZACIÓN Y/O CONDUCCIÓN, LLEGANDO A UN NIVEL DE DESAFÍO FÍSICO, CORRESPONDE A LA DEFINICIÓN DE:', '["RESISTENCIA VIOLENTA","RESISTENCIA AGRESIVA","RESISTENCIA OBJETIVA","RESISTENCIA FÍSICA","RESISTENCIA MATERIAL"]'::jsonb, 'RESISTENCIA FÍSICA', 3, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184720', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1108, 1108, 'AGRESIÓN FÍSICA AL PERSONAL POLICIAL O PERSONAS INVOLUCRADAS EN LA INTERVENCIÓN, PUDIENDO UTILIZAR OBJETOS QUE ATENTEN CONTRA LA INTEGRIDAD FÍSICA, CORRESPONDE A LA DEFINICIÓN DE:', '["AGRESIÓN PELIGROSA","AGRESIÓN FÍSICA","AGRESIÓN NO LETAL","AGRESIÓN LETAL","AGRESIÓN TÁCTICA"]'::jsonb, 'AGRESIÓN NO LETAL', 2, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184721', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1109, 1109, 'CUÁL ES LA DEFINICIÓN DE AGRESIÓN LETAL:', '["ACCIÓN QUE NO PONE EN PELIGRO INMINENTE DE MUERTE O LESIONES GRAVES AL EFECTIVO POLICIAL O A PERSONAS INVOLUCRADAS EN LA INTERVENCIÓN","AGRESIÓN FÍSICA AL PERSONAL POLICIAL O PERSONAS INVOLUCRADAS EN LA INTERVENCIÓN, PUDIENDO UTILIZAR OBJETOS QUE ATENTEN CONTRA LA INTEGRIDAD FÍSICA","ACCIÓN QUE PONE EN PELIGRO INMINENTE DE DAÑO PSICOLÓGICO AL EFECTIVO POLICIAL O A PERSONAS INVOLUCRADAS EN LA INTERVENCIÓN","SE OPONE A SU REDUCCIÓN, INMOVILIZACIÓN Y/O CONDUCCIÓN, LLEGANDO A UN NIVEL DE DESAFIÓ FÍSICO LETAL","ACCIÓN QUE PONE EN PELIGRO INMINENTE DE MUERTE O LESIONES GRAVES AL EFECTIVO POLICIAL O A PERSONAS INVOLUCRADAS EN LA INTERVENCIÓN"]'::jsonb, 'ACCIÓN QUE PONE EN PELIGRO INMINENTE DE MUERTE O LESIONES GRAVES AL EFECTIVO POLICIAL O A PERSONAS INVOLUCRADAS EN LA INTERVENCIÓN', 4, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184722', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1110, 1110, 'LA ACCIÓN QUE PONE EN PELIGRO INMINENTE DE MUERTE O LESIONES GRAVES AL EFECTIVO POLICIAL O A PERSONAS INVOLUCRADAS EN LA INTERVENCIÓN. CORRESPONDE A LA DEFINICIÓN DE:', '["AGRESIÓN NO LETAL","AGRESIÓN LATENTE","RIESGO LATENTE","AGRESIÓN LETAL","PELIGRO LETAL"]'::jsonb, 'AGRESIÓN LETAL', 3, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184723', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1111, 1111, 'DENTRO DE LOS NIVELES DEL USO DE LA FUERZA, EXISTEN DOS NIVELES DE USO DE LA FUERZA POR EL PERSONAL DE LA POLICÍA NACIONAL. MARQUE LO CORRECTO:', '["NIVELES PREVENTIVOS Y NIVELES NO PREVENTIVOS","NIVELES PREVENTIVOS Y NIVELES DE ACCIÓN","NIVELES PREVENTIVOS Y NIVELES ACTIVOS","NIVELES PREVENTIVOS Y NIVELES REACTIVOS","NIVELES PSICOLÓGICOS Y NIVELES REACTIVOS"]'::jsonb, 'NIVELES PREVENTIVOS Y NIVELES REACTIVOS', 3, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184724', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1112, 1112, 'INDIQUE CUÁL DE LOS ENUNCIADOS CORRESPONDEN A LOS NIVELES PREVENTIVOS:', '["PRESENCIA POLICIAL, VERBALIZACIÓN Y CONTROL TOTAL","PRESENCIA POLICIAL, TÁCTICAS DEFENSIVAS NO LETALES Y FUERZA LETAL","PRESENCIA POLICIAL, ADVERTENCIA Y CONTROL DE CONTACTO","PRESENCIA POLICIAL, TÁCTICAS DEFENSIVAS Y FUERZA LETAL","PRESENCIA POLICIAL, VERBALIZACIÓN Y CONTROL DE CONTACTO"]'::jsonb, 'PRESENCIA POLICIAL, VERBALIZACIÓN Y CONTROL DE CONTACTO', 4, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184725', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1113, 1113, 'INDIQUE CUÁL DE LOS ENUNCIADOS CORRESPONDEN A LOS NIVELES REACTIVOS:', '["CONTROL PSICOLÓGICO, TÁCTICAS DEFENSIVAS NO LETALES Y FUERZA LETAL","CONTROL FÍSICO, VERBALIZACIÓN Y CONTROL DE CONTACTO","CONTROL FÍSICO, TÁCTICAS DEFENSIVAS NO LETALES Y FUERZA LETAL","PRESENCIA POLICIAL, VERBALIZACIÓN Y CONTROL TOTAL","CONTROL FÍSICO, TÁCTICAS DEFENSIVAS MORTALES Y FUERZA LETAL"]'::jsonb, 'CONTROL FÍSICO, TÁCTICAS DEFENSIVAS NO LETALES Y FUERZA LETAL', 2, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184726', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1114, 1114, 'ENTENDIDA COMO DEMOSTRACIÓN DE AUTORIDAD DEL PERSONAL DE LA POLICÍA NACIONAL UNIFORMADO, EQUIPADO, EN ACTITUD DE ALERTA Y REALIZANDO UN CONTROL VISUAL, QUE PREVIENE Y DISUADE LA COMISIÓN DE UNA INFRACCIÓN O UN DELITO, CORRESPONDE A LA DEFINICIÓN DE:', '["VERBALIZACIÓN","PRESENCIA POLICIAL","CONTROL DE CONTACTO","CONTROL FÍSICO","CONTROL POLICIAL"]'::jsonb, 'PRESENCIA POLICIAL', 1, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184727', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1115, 1115, 'INDIQUE LA DEFINICIÓN CORRECTA DE CONTROL DE CONTACTO:', '["ES EL USO DE LA COMUNICACIÓN ORAL CON LA ENERGÍA NECESARIA Y EL USO DE TÉRMINOS ADECUADOS QUE SEAN FÁCILMENTE ENTENDIDOS Y COMPRENDIDOS POR LAS PERSONAS A INTERVENIR, FACILITANDO SU CONTROL INDIVIDUAL O GRUPAL","ACCIÓN QUE PONE EN PELIGRO INMINENTE DE MUERTE O LESIONES GRAVES AL EFECTIVO POLICIAL O A PERSONAS INVOLUCRADAS EN LA INTERVENCIÓN","ES EL USO DE ACCIONES DE COMUNICACIÓN, NEGOCIACIÓN Y PROCEDIMIENTOS DESTINADOS A PERMITIR LA ACCIÓN O ACTITUD DE LA PERSONA O GRUPOS A SER INTERVENIDOS","ES EL USO DE LAS TÉCNICAS POLICIALES QUE PERMITEN CONTROLAR, REDUCIR, INMOVILIZAR Y CONDUCIR A LA PERSONA INTERVENIDA, EVITANDO EN LO POSIBLE CAUSAR LESIONES","ES EL USO DE TÉCNICAS DE COMUNICACIÓN, NEGOCIACIÓN Y PROCEDIMIENTOS DESTINADOS A GUIAR, CONTENER LA ACCIÓN O ACTITUD DE LA PERSONA O GRUPOS A SER INTERVENIDOS"]'::jsonb, 'ES EL USO DE TÉCNICAS DE COMUNICACIÓN, NEGOCIACIÓN Y PROCEDIMIENTOS DESTINADOS A GUIAR, CONTENER LA ACCIÓN O ACTITUD DE LA PERSONA O GRUPOS A SER INTERVENIDOS', 4, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184728', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1162, 1162, 'LAS DROGAS, LAS SUSTANCIAS QUÍMICAS Y LAS MATERIAS PRIMAS OBJETO MATERIAL DEL DELITO DE TRÁFICO ILÍCITO DE DROGAS EN TODAS SUS MANIFESTACIONES, SON:', '["DESTRUIDAS","INCAUTADAS","INMOVILIZADAS","DECOMISADAS","INDUSTRIALIZADAS"]'::jsonb, 'DECOMISADAS', 3, '(texto: 12)** [CAPITULO III]', '184978', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1116, 1116, '¿CUÁL ES LA DEFINICIÓN CORRECTA DE CONTROL FÍSICO, QUE SE ENCUENTRA DENTRO DE LOS NIVELES DEL USO DE LA FUERZA:', '["ES EL USO DE LAS TÉCNICAS OPERATIVAS QUE PERMITEN CONTROLAR, REDUCIR, INMOVILIZAR Y CONDUCIR A LA PERSONA INTERVENIDA, EVITANDO EN LO POSIBLE CAUSAR LESIONES","ES EL USO DE MEDIOS DE POLICÍA NO LETALES PARA CONTRARRESTAR Y/O SUPERAR EL NIVEL DE AGRESIÓN O RESISTENCIA","ES EL USO DE LAS TÉCNICAS POLICIALES QUE PERMITEN CONTROLAR, REDUCIR, INMOVILIZAR Y CONDUCIR A LA PERSONA INTERVENIDA, EVITANDO EN LO POSIBLE CAUSAR LESIONES","ES EL USO DE ARMAS DE FUEGO POR EL PERSONAL DE LA POLICÍA NACIONAL, CONTRA QUIEN REALIZA UNA ACCIÓN QUE REPRESENTA UN PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES","ES EL USO DE LAS TÉCNICAS POLICIALES QUE PERMITEN CONTROLAR, REDUCIR, INMOVILIZAR Y CONDUCIR A LA PERSONA INTERVENIDA, PROCURANDO CAUSAR LESIONES"]'::jsonb, 'ES EL USO DE LAS TÉCNICAS POLICIALES QUE PERMITEN CONTROLAR, REDUCIR, INMOVILIZAR Y CONDUCIR A LA PERSONA INTERVENIDA, EVITANDO EN LO POSIBLE CAUSAR LESIONES', 2, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184729', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1117, 1117, 'ES EL USO DE LAS TÉCNICAS POLICIALES QUE PERMITEN CONTROLAR, REDUCIR, INMOVILIZAR Y CONDUCIR A LA PERSONA INTERVENIDA, EVITANDO EN LO POSIBLE CAUSAR LESIONES. CORRESPONDE A LA DEFINICIÓN DE:', '["TÁCTICAS DEFENSIVAS NO LETALES","CONTROL FÍSICO","FUERZA LETAL","CONTROL TOTAL","CONTROL DE CONTACTO"]'::jsonb, 'CONTROL FÍSICO', 1, '(texto: 7) (item: 184)** [TITULO II] [CAPITULO I]', '184731', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1118, 1118, 'EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ PUEDE USAR LA FUERZA, DE CONFORMIDAD CON LOS ARTÍCULOS 4, 6 Y EL NUMERAL 7.2, EN LAS SIGUIENTES CIRCUNSTANCIAS:', '["NO PREVENIR LA COMISIÓN DE DELITOS Y FALTAS","CUMPLIR UN DEBER U ÓRDENES ILÍCITAS DICTADAS POR LAS AUTORIDADES COMPETENTES","CONTROLAR A QUIEN COLABORE CON LA AUTORIDAD","DETENER EN FLAGRANTE DELITO O POR MANDATO JUDICIAL CONFORME A LEY","PROTEGER O DEFENDER BIENES JURÍDICOS DEL POLICÍA"]'::jsonb, 'DETENER EN FLAGRANTE DELITO O POR MANDATO JUDICIAL CONFORME A LEY', 3, '(texto: 8) (item: 184)** [TITULO II] [CAPITULO II]', '184734', '2026-07-14T01:12:29.113429+00:00');
