INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1120, 1120, 'EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ PUEDE USAR LA FUERZA, DE CONFORMIDAD CON LOS ARTÍCULOS 4, 6 Y EL NUMERAL 7.2, EN LAS SIGUIENTES CIRCUNSTANCIAS:', '["PREVENIR LA COMISIÓN DE DELITOS Y FALTAS","CUMPLIR UN DEBER U ÓRDENES LÍCITAS DICTADAS POR LAS AUTORIDADES JUDICIALES","NO PREVENIR LA COMISIÓN DE DELITOS Y FALTAS","CONTROLAR A QUIEN NO COLABORE CON LA AUTORIDAD","PROPICIAR LA COMISIÓN DE DELITOS Y FALTAS"]'::jsonb, 'PREVENIR LA COMISIÓN DE DELITOS Y FALTAS', 0, '(texto: 8) (item: 184)** [TITULO II] [CAPITULO II]', '184736', '2026-07-14T01:12:29.113429+00:00');
