INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1141, 1141, 'LA POLICÍA NACIONAL DEL PERÚ A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS ANTIDROGAS REALIZAN OPERACIONES POLICIALES:', '["PREVENTIVAS, DISUASIVAS Y DE CONTROL","PREVENTIVAS, PERSUASIVAS Y DE CONTROL","REPRESIVAS Y DE CONTROL","PREVENTIVAS, DEFENSIVAS Y DE CONTROL","PREVENTIVAS, DISOLUTIVAS Y DE CONTROL"]'::jsonb, 'PREVENTIVAS, DISUASIVAS Y DE CONTROL', 0, '(texto: 3)** [CAPITULO II]', '184955', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1123, 1123, '¿EN QUÉ SITUACIÓN, EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ, EXCEPCIONALMENTE, PODRÁ HACER USO DEL ARMA DE FUEGO:', '["EN DEFENSA PROPIA O DE OTRAS PERSONAS EN CASO DE PELIGRO REAL E INMINENTE DE LESIONES","EN DEFENSA PROPIA O DE OTRAS PERSONAS EN CASO DE QUE NO EXISTA PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES","EN DEFENSA PROPIA O DE OTRAS PERSONAS EN CASO DE PELIGRO REAL E INMINENTE DE MUERTE O LESIONES LEVES","EN DEFENSA PROPIA O DE OTRAS PERSONAS EN CASO DE PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES","CUANDO NO SE GENERE UN PELIGRO REAL O INMINENTE DE MUERTE DEL PERSONAL POLICIAL U OTRA PERSONA"]'::jsonb, 'EN DEFENSA PROPIA O DE OTRAS PERSONAS EN CASO DE PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES', 3, '(texto: 8) (item: 184)** [TITULO II] [CAPITULO II]', '184739', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1124, 1124, '¿EN QUÉ SITUACIÓN, EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ, EXCEPCIONALMENTE, PODRÁ HACER USO DEL ARMA DE FUEGO:', '["EN DEFENSA PROPIA O DE OTRAS PERSONAS EN CASO DE QUE NO EXISTA PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES","CUANDO SE PRODUZCA UNA SITUACIÓN QUE IMPLIQUE UNA SERIA AMENAZA PARA LA VIDA DURANTE LA COMISIÓN DE UN DELITO PARTICULARMENTE GRAVE","CUANDO SE GENERE UNA SITUACIÓN DE PAZ Y TRANQUILIDAD COMO CONSECUENCIA DE LA COLABORACIÓN OFRECIDA POR LA PERSONA QUE VAYA A SER INTERVENIDA","CUANDO SE PRODUZCA UNA SITUACIÓN QUE IMPLIQUE UNA MÍNIMA AMENAZA PARA LA VIDA DURANTE LA COMISIÓN DE UN DELITO PARTICULARMENTE LEVE","CUANDO LA VIDA DE UNA PERSONA NO ES PUESTA EN RIESGO REAL, INMINENTE Y ACTUAL POR QUIEN SE ESTA FUGANDO"]'::jsonb, 'CUANDO SE PRODUZCA UNA SITUACIÓN QUE IMPLIQUE UNA SERIA AMENAZA PARA LA VIDA DURANTE LA COMISIÓN DE UN DELITO PARTICULARMENTE GRAVE', 1, '(texto: 8) (item: 184)** [TITULO II] [CAPITULO II]', '184740', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1125, 1125, '¿EN QUÉ SITUACIÓN, EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ, EXCEPCIONALMENTE, PODRÁ HACER USO DEL ARMA DE FUEGO:', '["CUANDO SE GENERE UN PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES COMO CONSECUENCIA DE LA RESISTENCIA OFRECIDA POR LA PERSONA QUE VAYA A SER DETENIDA","EN DEFENSA PROPIA O DE OTRAS PERSONAS EN CASO DE QUE NO EXISTA PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES","CUANDO SE GENERE UN PELIGRO REAL E INMINENTE DE MUERTE O LESIONES MUY GRAVES COMO CONSECUENCIA DE LA RESISTENCIA OFRECIDA POR LA PERSONA QUE VAYA A SER INTERVENIDA","CUANDO SE GENERE UNA SITUACIÓN DE PAZ Y TRANQUILIDAD COMO CONSECUENCIA DE LA COLABORACIÓN OFRECIDA POR LA PERSONA QUE VAYA A SER INTERVENIDA","CUANDO SE GENERE UNA SITUACIÓN REAL E INMINENTE DE LESIONES COMO CONSECUENCIA DE LA RESISTENCIA OFRECIDA POR LA PERSONA QUE VAYA A SER INTERVENIDA"]'::jsonb, 'CUANDO SE GENERE UN PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES COMO CONSECUENCIA DE LA RESISTENCIA OFRECIDA POR LA PERSONA QUE VAYA A SER DETENIDA', 0, '(texto: 8) (item: 184)** [TITULO II] [CAPITULO II]', '184741', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1126, 1126, '¿EN QUÉ SITUACIÓN, EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ, EXCEPCIONALMENTE, PODRÁ HACER USO DEL ARMA DE FUEGO:', '["CUANDO LA VIDA DE UNA PERSONA NO ES PUESTA EN RIESGO REAL Y ACTUAL POR QUIEN ESTA INTERVENIDO","CUANDO UNA PERSONA ES PUESTA EN RIESGO REAL E INMINENTE POR QUIEN VA A SER INTERVENIDO","EN DEFENSA PROPIA O DE OTRAS PERSONAS EN CASO DE QUE NO EXISTA PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES","CUANDO LA VIDA DE UNA PERSONA ES PUESTA EN RIESGO REAL, INMINENTE Y ACTUAL POR QUIEN SE ESTA FUGANDO","CUANDO LA VIDA DE UNA PERSONA ES PUESTA EN RIESGO REAL, INMINENTE Y ACTUAL"]'::jsonb, 'CUANDO LA VIDA DE UNA PERSONA ES PUESTA EN RIESGO REAL, INMINENTE Y ACTUAL POR QUIEN SE ESTA FUGANDO', 3, '(texto: 8) (item: 184)** [TITULO II] [CAPITULO II]', '184742', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1127, 1127, '¿EN QUÉ SITUACIÓN, EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ, EXCEPCIONALMENTE, PODRÁ HACER USO DEL ARMA DE FUEGO:', '["CUANDO SE GENERE UN PELIGRO REAL O INMINENTE DE MUERTE DEL PERSONAL POLICIAL U OTRA PERSONA, POR LA ACCIÓN DE QUIEN PARTICIPA DE UNA REUNIÓN TUMULTUARIA VIOLENTA","CUANDO LA VIDA DE UNA PERSONA ES PUESTA EN RIESGO REAL, INMINENTE Y ACTUAL POR QUIEN ESTA COLABORANDO","CUANDO SE GENERE UN PELIGRO REAL O INMINENTE DE MUERTE DEL PERSONAL POLICIAL U OTRA PERSONA, POR LA ACCIÓN DE QUIEN PARTICIPA DE UNA REUNIÓN TUMULTUARIA ACTIVA","CUANDO SE GENERE UNA SITUACIÓN DE PAZ Y TRANQUILIDAD COMO CONSECUENCIA DE LA COLABORACIÓN OFRECIDA POR LA PERSONA QUE VAYA A SER INTERVENIDA","CUANDO SE GENERE UN CLIMA DE PAZ Y TRANQUILIDAD DEL PERSONAL POLICIAL U OTRA PERSONA, POR LA ACCIÓN DE QUIEN PARTICIPA DE UNA REUNIÓN TUMULTUARIA PACÍFICA"]'::jsonb, 'CUANDO SE GENERE UN PELIGRO REAL O INMINENTE DE MUERTE DEL PERSONAL POLICIAL U OTRA PERSONA, POR LA ACCIÓN DE QUIEN PARTICIPA DE UNA REUNIÓN TUMULTUARIA VIOLENTA', 0, '(texto: 8) (item: 184)** [TITULO II] [CAPITULO II]', '184743', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1128, 1128, 'CON POSTERIORIDAD AL USO DE LA FUERZA EL PERSONAL DE LA POLICÍA NACIONAL DEBERÁ ADOPTAR LAS MEDIDAS NECESARIAS PARA COMUNICAR LO SUCEDIDO A LOS FAMILIARES DE LAS PERSONAS FALLECIDAS, HERIDAS O AFECTADAS O A AQUELLAS QUE ESTAS ÚLTIMAS INDIQUEN, SALVO QUE, SEÑALE LO CORRECTO:', '["EXISTAN CIRCUNSTANCIAS QUE NO IMPIDAN SU REALIZACIÓN","NO EXISTAN CIRCUNSTANCIAS QUE IMPIDAN SU REALIZACIÓN","SE ENCUENTREN EN UNA ZONA PELIGROSA","NO CUENTEN CON EQUIPOS DE COMUNICACIÓN","EXISTAN CIRCUNSTANCIAS QUE IMPIDAN SU REALIZACIÓN"]'::jsonb, 'EXISTAN CIRCUNSTANCIAS QUE IMPIDAN SU REALIZACIÓN', 4, '(texto: 9) (item: 184)** [TITULO II] [CAPITULO II]', '184745', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1129, 1129, 'CON POSTERIORIDAD AL USO DE LA FUERZA EL PERSONAL DE LA POLICÍA NACIONAL DEBERÁ PRESENTAR UN INFORME A LA UNIDAD POLICIAL CORRESPONDIENTE INDICANDO LAS CIRCUNSTANCIAS, LOS MEDIOS EMPLEADOS, EL PERSONAL INTERVINIENTE, EL TIPO DE ARMAS Y LAS MUNICIONES UTILIZADAS, EL NÚMERO DE IDENTIDAD DE LOS AFECTADOS, Y: SEÑALE LO CORRECTO:', '["LA CANTIDAD DE MUERTOS Y HERIDOS","LAS ASISTENCIAS Y EVACUACIONES REALIZADAS","LA CANTIDAD DE DETENIDOS","LA CANTIDAD DE INTERVENIDOS","LAS BAJAS DEL PERSONAL POLICIAL"]'::jsonb, 'LAS ASISTENCIAS Y EVACUACIONES REALIZADAS', 1, '(texto: 9) (item: 184)** [TITULO II] [CAPITULO II]', '184746', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1130, 1130, 'EN EL EJERCICIO DE SU FUNCIÓN RELACIONADA AL USO DE LA FUERZA, EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ TIENE DERECHO A:', '["LA PROTECCIÓN Y RESPETO DE SU VIDA, INTEGRIDAD PERSONAL, DIGNIDAD Y A LAS CONSIDERACIONES QUE SU AUTORIDAD LE OTORGA","QUE SE RESPETEN SUS DERECHO HUMANOS","LA PROTECCIÓN Y RESPETO DE SU VIDA, INTEGRIDAD FÍSICA, DIGNIDAD Y A LAS PRERROGATIVAS QUE SU AUTORIDAD LE OTORGA","A LA PROTECCIÓN Y EL RESPETO DE SU VIDA, A LA PRESTACIÓN DE SALUD, A SU INTEGRIDAD Y LAS CONSIDERACIONES QUE SU AUTORIDAD LE OTORGA","A QUE SE OTORGUE UNA INDEMNIZACIÓN A SUS FAMILIARES EN CASO DE FALLECIMIENTO"]'::jsonb, 'LA PROTECCIÓN Y RESPETO DE SU VIDA, INTEGRIDAD PERSONAL, DIGNIDAD Y A LAS CONSIDERACIONES QUE SU AUTORIDAD LE OTORGA', 0, '(texto: 10) (item: 184)** [TITULO III] [CAPITULO II]', '184747', '2026-07-14T01:12:29.113429+00:00');
