INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1138, 1138, '¿QUIÉN CONDUCE Y SUPERVISA LAS POLÍTICAS SECTORIALES EN MATERIA DE LUCHA CONTRA LAS DROGAS, INSUMOS QUÍMICOS Y PRODUCTOS FISCALIZADOS DECOMISADOS POR TRÁFICO ILÍCITO DE DROGAS, ERRADICACIÓN DE LOS CULTIVOS ILEGALES Y DESTRUCCIÓN DE DROGAS ILEGALES DECOMISADAS?', '["DEVIDA","POLICÍA NACIONAL DEL PERÚ","MINISTERIO DEL INTERIOR","MINISTERIO DE AGRICULTURA","EMPRESA NACIONAL DE LA COCA"]'::jsonb, 'MINISTERIO DEL INTERIOR', 2, '(texto: 2)** [CAPITULO I]', '184952', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1139, 1139, '¿QUIÉNES TIENEN LA OBLIGACIÓN DE COADYUVAR CON LAS AUTORIDADES COMPETENTES EN LA LUCHA CONTRA EL TRÁFICO ILÍCITO DE DROGAS - TID?', '["TODAS LAS PERSONAS NATURALES, JURÍDICAS E INSTITUCIONES PRIVADAS","ALGUNAS PERSONAS NATURALES, JURÍDICAS E INSTITUCIONES PÚBLICAS Y PRIVADAS","TODAS LAS PERSONAS NATURALES, JURÍDICAS E INSTITUCIONES PÚBLICAS Y PRIVADAS","TODAS LAS PERSONAS NATURALES, JURÍDICAS E INSTITUCIONES PÚBLICAS","TODAS LAS PERSONAS NATURALES, JURÍDICAS E INSTITUTOS PÚBLICOS Y PRIVADOS"]'::jsonb, 'TODAS LAS PERSONAS NATURALES, JURÍDICAS E INSTITUCIONES PÚBLICAS Y PRIVADAS', 2, '(texto: 2)** [CAPITULO I]', '184953', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1140, 1140, '¿QUÉ ACCIONES A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS, DESARROLLA LA POLICÍA NACIONAL DEL PERÚ?. MARQUE LA RESPUESTA CORRECTA:', '["APOYA A LA SUPERINTENDENCIA NACIONAL DE ADUANAS EN EL FORTALECIMIENTO DEL PROGRAMA DE REHABILITACIÓN","ADMINISTRA LA PLATAFORMA DE INTEROPERABILIDAD DE LUCHA CONTRA EL TRÁFICO ILÍCITO DE DROGAS - TID","APOYA A LA SUPERINTENDENCIA DE ADUANAS Y DE ADMINISTRACIÓN TRIBUTARIA - SUNAT EN LOS CONTROLES MÍNIMOS DE SEGURIDAD SOBRE LAS SUSTANCIAS QUÍMICAS FISCALIZADAS","RETENER DEFINITIVAMENTE SUSTANCIAS QUÍMICAS Y MEDIOS DE TRANSPORTE, CUANDO SE TRATE DE LA COMISIÓN DE INFRACCIONES A LAS LEYES DE CONTROL Y FISCALIZACIÓN SANCIONABLES CON INCAUTACIÓN, COMUNICANDO EN FORMA INMEDIATA A LA AUTORIDAD ADMINISTRATIVA COMPETENTE","APOYAR A LA SUPERINTENDENCIA NACIONAL DE ADUANAS Y DE ADMINISTRACIÓN TRIBUTARIA - SUNAT EN LA LABOR DE VERIFICACIÓN Y CERTIFICACIÓN DE LA EXISTENCIA DE CONDICIONES O CONTROLES MÍNIMOS DE SEGURIDAD SOBRE LAS SUSTANCIAS QUÍMICAS CONTROLADAS"]'::jsonb, 'APOYAR A LA SUPERINTENDENCIA NACIONAL DE ADUANAS Y DE ADMINISTRACIÓN TRIBUTARIA - SUNAT EN LA LABOR DE VERIFICACIÓN Y CERTIFICACIÓN DE LA EXISTENCIA DE CONDICIONES O CONTROLES MÍNIMOS DE SEGURIDAD SOBRE LAS SUSTANCIAS QUÍMICAS CONTROLADAS', 4, '(texto: 3)** [CAPITULO II]', '184954', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1143, 1143, 'A TRAVÉS DE SU DEPENDENCIA ESPECIALIZADA, ES LA AUTORIDAD ADMINISTRATIVA A CARGO DEL CONTROL Y FISCALIZACIÓN DE SUSTANCIAS QUÍMICAS EMPLEADAS LEGALMENTE EN LA INDUSTRIA FARMACÉUTICA Y QUE PUEDEN SER SUSCEPTIBLES DE UTILIZACIÓN EN LOS PROCESOS DE ELABORACIÓN ILEGAL DE ESTUPEFACIENTES Y SUSTANCIAS PSICOTRÓPICAS:', '["MINISTERIO DE LA PRODUCCIÓN","MINISTERIO DEL INTERIOR","MINISTERIO DE AMBIENTE","MINISTERIO DE DEFENSA","MINISTERIO DE SALUD"]'::jsonb, 'MINISTERIO DE SALUD', 4, '(texto: 11)** [CAPITULO III] [ART.11]', '184957', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1144, 1144, 'LAS ACCIONES DE PREVENCIÓN QUE REALIZA LA POLICÍA NACIONAL DEL PERÚ A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS, CON LA FINALIDAD DE EVITAR EL DESVIÓ DE SUSTANCIAS QUÍMICAS O EL TRÁFICO ILÍCITO DE INSUMOS QUÍMICOS Y PRODUCTOS FISCALIZADOS (IQPF) HACIA EL TRÁFICO ILÍCITO DE DROGAS - TID, TIENEN CARÁCTER:', '["GENERAL","FISCALIZADOR","REPRESIVO","SELECTIVO","INDIVIDUAL"]'::jsonb, 'SELECTIVO', 3, '(texto: 3)** [CAPITULO II] [ART.3]', '184958', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1145, 1145, '¿QUÉ SANCIÓN ES APLICABLE CUANDO LA POLICÍA NACIONAL DEL PERÚ A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS, RETIENE TEMPORALMENTE SUSTANCIAS QUÍMICAS Y MEDIOS DE TRANSPORTE, POR REPRESENTAR INFRACCIONES A LAS LEYES DE CONTROL Y FISCALIZACIÓN?:', '["DECOMISO","INCAUTACIÓN","MULTA","PERENNIZACIÓN","DESTRUCCIÓN"]'::jsonb, 'INCAUTACIÓN', 1, '(texto: 3)** [CAPITULO II] [ART3]', '184959', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1146, 1146, '¿CON QUÉ AUTORIDADES DEBERÁ DE COORDINAR LA POLICÍA NACIONAL, PARA LA DESTRUCCIÓN E INHABILITACIÓN DE PISTAS DE ATERRIZAJE CLANDESTINAS, UTILIZADAS PARA EL TRANSPORTE ILEGAL DE DROGAS TÓXICAS, ESTUPEFACIENTES O SUSTANCIAS PSICOTRÓPICAS?:', '["MINISTERIO DE LA PRODUCCIÓN O GOBIERNOS REGIONALES","MINISTERIO PÚBLICO","MINISTERIO DE TRANSPORTES Y COMUNICACIONES O GOBIERNOS REGIONALES","MINISTERIO DE TRANSPORTES Y COMUNICACIONES O GOBIERNOS LOCALES","PROCURADOR ANTIDROGAS"]'::jsonb, 'MINISTERIO DE TRANSPORTES Y COMUNICACIONES O GOBIERNOS REGIONALES', 2, '(texto: 3)** [CAPITULO II] [ART3]', '184960', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1163, 1163, 'INCAUTACIONES Y DECOMISOS.- SON OBJETO DE INCAUTACIÓN LOS SIGUIENTES BIENES:', '["LAS MATERIAS PRIMAS U OBJETOS DEL DELITO DE TRÁFICO ILÍCITO DE DROGAS","LOS ELEMENTOS, HERRAMIENTAS O INSTRUMENTOS DE USO INDIRECTO PARA EL CULTIVO Y EXPLOTACIÓN ILÍCITA DE LA COCA","LAS SUSTANCIAS QUÍMICAS","LAS ARMAS, MUNICIONES U OTROS ELEMENTOS DE ORIGEN ILÍCITO O EMPLEADAS EN LA COMISIÓN DEL DELITO","LAS SUSTANCIAS QUÍMICAS Y LAS MATERIAS PRIMAS"]'::jsonb, 'LAS ARMAS, MUNICIONES U OTROS ELEMENTOS DE ORIGEN ILÍCITO O EMPLEADAS EN LA COMISIÓN DEL DELITO', 3, '(texto: 12)** [CAPITULO III]', '184979', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1147, 1147, 'LA POLICÍA NACIONAL A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS, PARA LA DESTRUCCIÓN O NEUTRALIZACIÓN SEGÚN SEA EL CASO INSTALACIONES RÚSTICAS, FÁBRICAS O LABORATORIOS DE ELABORACIÓN ILEGAL DE DROGAS TÓXICAS COCAÍNITAS, ESTUPEFACIENTES O SUSTANCIAS PSICOTRÓPICAS, CULTIVOS DE PLANTAS DE AMAPOLA O ADORMIDERA DE LA ESPECIE PAPAVER SOMNÍFERUM O DE MARIHUANA DE LA ESPECIE CANNABIS SATIVA, SUSTANCIAS QUÍMICAS, MATERIA PRIMA, MATERIALES E IMPLEMENTOS QUE SE EMPLEAN EN LA ELABORACIÓN DE LAS INDICADAS DROGAS, ADOPTA LAS MEDIDAS ORIENTADAS A:', '["MINIMIZAR EL IMPACTO ECONÓMICO","MINIMIZAR EL IMPACTO EN LAS ZONAS ADYACENTES","MINIMIZAR EL IMPACTO EN EL ECOSISTEMA","MINIMIZAR EL IMPACTO SOCIOECONÓMICO","MINIMIZAR EL IMPACTO AMBIENTAL"]'::jsonb, 'MINIMIZAR EL IMPACTO AMBIENTAL', 4, '(texto: 3)** [CAPITULO II] [ART3]', '184961', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1148, 1148, '¿QUIÉN AUTORIZA LA DESTRUCCIÓN O INUTILIZACIÓN DE LOS MEDIOS DE TRANSPORTE TERRESTRE, ACUÁTICO O AÉREO QUE SE EMPLEEN O SE PRETENDA EMPLEAR PARA EL TRASLADO DE DROGAS TÓXICAS Y OTRAS SUSTANCIAS ILEGALES?. MARQUE LA RESPUESTA CORRECTA:', '["JUEZ ESPECIALIZADO","GOBIERNO REGIONAL","DEVIDA","PROCURADOR ANTIDROGAS","MINISTERIO PÚBLICO"]'::jsonb, 'MINISTERIO PÚBLICO', 4, '(texto: 3)** [CAPITULO II] [ART13]', '184962', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1149, 1149, '¿QUÉ ENTIDAD RECEPCIONA LA CONSOLIDACIÓN DE ESTADÍSTICA SOBRE CONTEO DE PLANTAS REMITIDA POR LA DIRANDRO DE LA POLICÍA NACIONAL DEL PERÚ?:', '["DEVIDA","MINISTERIO DEL INTERIOR","CORAH","MINISTERIO DE LA PRODUCCIÓN","MINISTERIO PÚBLICO"]'::jsonb, 'DEVIDA', 0, '(texto: 3)** [CAPITULO II] [ART3]', '184963', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1150, 1150, 'QUÉ SE PUEDE EVITAR EN LA DESACTIVACIÓN DE LABORATORIOS CLANDESTINOS DE ELABORACIÓN DE DROGAS SINTÉTICAS?, CUANDO SE ADOPTAN LAS MEDIDAS DE SEGURIDAD, EMPLEANDO MANUALES, PROTOCOLOS O GUÍAS DE TRABAJO DE NATURALEZA LOCAL O INTERNACIONAL:', '["LA RESIEMBRA DEL CULTIVO DE COCA","CONSECUENCIAS SOBRE LAS PERSONAS Y EL ECOSISTEMA","CONSECUENCIAS SOBRE LAS PERSONAS Y EL MEDIO AMBIENTE","CONSECUENCIAS SOBRE EL MEDIO AMBIENTE","AFECTAR EL ECOSISTEMA"]'::jsonb, 'CONSECUENCIAS SOBRE LAS PERSONAS Y EL MEDIO AMBIENTE', 2, '(texto: 3)** [CAPITULO II] [ART3]', '184964', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1151, 1151, '¿QUÉ DEBE DE CONSIGNAR LA POLICÍA NACIONAL A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS, EN EL LUGAR DE INTERVENCIÓN, AL LEVANTAR LAS ACTAS EN LAS DILIGENCIAS PARA LA DESTRUCCIÓN, INHABILITACIÓN, INUTILIZACIÓN, NEUTRALIZACIÓN, DESACTIVACIÓN U OTRAS?:', '["POSICIÓN TOPOGRÁFICA DEL LUGAR DE LA INTERVENCIÓN","POSICIÓN GEO-POLÍTICA DEL LUGAR DE LA INTERVENCIÓN","POSICIÓN GEO-SATELITAL DEL LUGAR DE LA INTERVENCIÓN","POSICIÓN GEO-REFERENCIAL DEL LUGAR DE LA INTERVENCIÓN","POSICIÓN GEO-TERRITORIAL DEL LUGAR DE LA INTERVENCIÓN"]'::jsonb, 'POSICIÓN GEO-REFERENCIAL DEL LUGAR DE LA INTERVENCIÓN', 3, '(texto: 3)** [CAPITULO II] [ART3]', '184965', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1152, 1152, '¿QUÉ IMPLICA PARA LA LUCHA CONTRA EL TRÁFICO ILÍCITO DE DROGAS - TID, LA CUANTIFICACIÓN DE LOS CULTIVOS?. MARQUE LA RESPUESTA CORRECTA:', '["LA MEDIDA DEL ÁREA NO EMPADRONADA","EL PESAJE DE LAS PLANTAS","LA MEDIDA DEL ÁREA CULTIVADA","LAS MEDIDAS DE LAS HECTÁREAS POR ERRADICAR","EL CONTEO DE PLANTAS"]'::jsonb, 'EL CONTEO DE PLANTAS', 4, '(texto: 3)** [CAPITULO II]', '184966', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1153, 1153, '¿DÓNDE SE PROHÍBE EL CULTIVO DE COCA Y ALMÁCIGOS?. MARQUE LA RESPUESTA CORRECTA:', '["EN ÁREAS EMPADRONADAS POR LA AUTORIDAD COMPETENTE","EN ÁREAS CONTROLADAS PARA EL CULTIVO ALTERNATIVO","EN ÁREAS NO EMPADRONADAS POR LA AUTORIDAD COMPETENTE","EN ÁREAS DE RÉGIMEN ESPECIAL","EN ÁREAS REGISTRADAS POR ENACO"]'::jsonb, 'EN ÁREAS NO EMPADRONADAS POR LA AUTORIDAD COMPETENTE', 2, '(texto: 4)** [CAPITULO III] {ART.4]', '184967', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1154, 1154, 'DE ACUERDO A LAS METAS PLANTEADAS ANUALMENTE, LAS PLANTACIONES DE COCA ILEGALMENTE CULTIVADAS SON:', '["OBJETO DE INTERDICCIÓN","OBJETO DE DECOMISO","OBJETO DE INMOVILIZACIÓN","OBJETO DE ERRADICACIÓN","OBJETO DE INCAUTACIÓN"]'::jsonb, 'OBJETO DE ERRADICACIÓN', 3, '(texto: 4)** [CAPITULO III] [ART.4]', '184968', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1155, 1155, 'LA INDUSTRIALIZACIÓN COMPRENDE LA ELABORACIÓN DE PASTA BÁSICA DE COCAÍNA, CLORHIDRATO DE COCAÍNA Y DEMÁS DERIVADOS DE LA HOJA DE COCA DE PRODUCCIÓN LÍCITA CON:', '["FINES CIENTÍFICOS","FINES DE LUCRO","FINES MEDICINALES","FINES COMERCIALES","FINES BENÉFICOS"]'::jsonb, 'FINES BENÉFICOS', 4, '(texto: 6)** [CAPITULO III] [ART.6]', '184970', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1156, 1156, 'LA POSESIÓN Y COMERCIALIZACIÓN ILEGAL DE HOJA DE COCA ES SANCIONADA CON:', '["EL DECOMISO DEL PRODUCTO","LA INCAUTACIÓN DEL PRODUCTO","LA INMOVILIZACIÓN DEL PRODUCTO","LA DESTRUCCIÓN DEL PRODUCTO","LA PROHIBICIÓN COMERCIAL DEL PRODUCTO"]'::jsonb, 'LA INCAUTACIÓN DEL PRODUCTO', 1, '(texto: 6)** [CAPITULO III] [ART.6]', '184971', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1157, 1157, 'LOS CULTIVOS DE PLANTAS DE AMAPOLA O ADORMIDERA DE LA ESPECIE PAPAVER SOMNÍFERUM O DE MARIHUANA DE LA ESPECIE CANNABIS SATIVA SON DESTRUIDOS IN SITU POR LA:', '["POLICÍA NACIONAL DEL PERÚ CON INTERVENCIÓN DE ENACO S.A","POLICÍA NACIONAL DEL PERÚ CON PARTICIPACIÓN DE DEVIDA","POLICÍA NACIONAL DEL PERÚ CON INTERVENCIÓN DEL MINISTERIO PÚBLICO","POLICÍA NACIONAL DEL PERÚ CON INTERVENCIÓN DEL JUZGADO ESPECIALIZADO","POLICÍA NACIONAL DEL PERÚ CON INTERVENCIÓN DEL CONABI"]'::jsonb, 'POLICÍA NACIONAL DEL PERÚ CON INTERVENCIÓN DEL MINISTERIO PÚBLICO', 2, '(texto: 7)** [CAPITULO III]', '184972', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1158, 1158, 'LOS CULTIVOS DE PLANTAS DE AMAPOLA O ADORMIDERA DE LA ESPECIE PAPAVER SOMNÍFERUM O DE MARIHUANA DE LA ESPECIE CANNABIS SATIVA SON DESTRUIDOS IN SITU, LEVANTÁNDOSE EL ACTA CORRESPONDIENTE, INDICANDO:', '["LA UBICACIÓN GEOPOLÍTICA REFERENCIAL A LA RED NACIONAL","LA UBICACIÓN GEOFÍSICA A LA RED GEODÉSICA INTERNACIONAL","LA UBICACIÓN GEOREFERENCIADA A LA RED GEODÉSICA LOCAL","LA UBICACIÓN GEOREFERENCIADA A LA RED GEODÉSICA INTERNACIONAL","LA UBICACIÓN GEOREFERENCIADA A LA RED GEODÉSICA NACIONAL"]'::jsonb, 'LA UBICACIÓN GEOREFERENCIADA A LA RED GEODÉSICA NACIONAL', 4, '(texto: 7)** [CAPITULO III]', '184973', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1159, 1159, '¿QUÉ REGISTROS LEVANTA LA AUTORIDAD COMPETENTE DEL GOBIERNO CENTRAL, REGIONAL O LOCAL, EN ÁREAS DE CULTIVO DE SU DEMARCACIÓN, QUE SIRVE PARA IDENTIFICAR A LOS PROPIETARIOS O POSESIONARIOS DE LOS TERRENOS DONDE SE PUEDAN DESCUBRIR CULTIVOS ILEGALES DE COCA EN RESIEMBRA, AMAPOLA O ADORMIDERA DE LA ESPECIE PAPAVER SOMNÍFERUM O DE MARIHUANA DE LA ESPECIE CANNABIS SATIVA? MARQUE LA RESPUESTA CORRECTA:', '["CATASTRALES Y GEOGRÁFICOS","DE UBICACIÓN GEOREFERENCIADA","CATASTRALES Y TOPOGRÁFICOS","UBICACIÓN GEOPOLÍTICA","DE CUANTIFICACIÓN Y CONTEO DE PLANTAS"]'::jsonb, 'CATASTRALES Y TOPOGRÁFICOS', 2, '(texto: 9)** [CAPITULO III]', '184974', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1160, 1160, 'EN EL USO INDEBIDO DEL PATRIMONIO DEL ESTADO, ¿QUIÉN COMUNICA LOS HECHOS AL MINISTERIO PÚBLICO PARA EL EJERCICIO DE SUS ATRIBUCIONES?', '["DEVIDA","LA UNIDAD DE INTELIGENCIA FINANCIERA","PROCURADOR ANTIDROGAS","LA POLICÍA NACIONAL DEL PERÚ","LA CONTRALORÍA GENERAL DE LA REPÚBLICA"]'::jsonb, 'LA POLICÍA NACIONAL DEL PERÚ', 3, '(texto: 10)** [CAPITULO III]', '184976', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1161, 1161, '¿QUIÉN ES LA AUTORIDAD ADMINISTRATIVA, QUE A TRAVÉS DE SU DEPENDENCIA ESPECIALIZADA ESTÁ A CARGO DEL CONTROL Y FISCALIZACIÓN DE INSUMOS QUÍMICOS, CONFORME A LA NORMATIVA DE LA MATERIA?', '["LA POLICÍA NACIONAL DEL PERÚ","EL MINISTERIO PÚBLICO","DEVIDA","LA SUNAT","EL MINISTERIO DE LA PRODUCCIÓN"]'::jsonb, 'LA SUNAT', 3, '(texto: 11)** [CAPITULO III]', '184977', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1164, 1164, 'INCAUTACIONES Y DECOMISOS.- SON OBJETO DE INCAUTACIÓN LOS SIGUIENTES BIENES:', '["LOS ELEMENTOS, HERRAMIENTAS O INSTRUMENTOS DE USO DIRECTO PARA EL CULTIVO Y EXPLOTACIÓN LÍCITA DE LA COCA","LAS DROGAS","LOS BIENES MUEBLES E INMUEBLES, TALES COMO VEHÍCULOS, NAVES, ARTEFACTOS NAVALES O AÉREOS, AERONAVES Y SEMOVIENTES O SOPORTES EMPLEADOS COMO MEDIOS O INSTRUMENTOS PARA FACILITAR LA COMISIÓN DEL DELITO","LAS SUSTANCIAS QUÍMICAS","LAS PROPIEDADES REGISTRADAS EN SUNARP"]'::jsonb, 'LOS BIENES MUEBLES E INMUEBLES, TALES COMO VEHÍCULOS, NAVES, ARTEFACTOS NAVALES O AÉREOS, AERONAVES Y SEMOVIENTES O SOPORTES EMPLEADOS COMO MEDIOS O INSTRUMENTOS PARA FACILITAR LA COMISIÓN DEL DELITO', 2, '(texto: 12)** [CAPITULO III]', '184980', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1165, 1165, '¿QUÉ SE EVALÚA PARA LA INCAUTACIÓN DE INMUEBLES, VEHÍCULOS, DINERO U OTROS VALORES?', '["EL GRADO DE CONSANGUINIDAD CON LOS AUTORES DEL DELITO","PERTENECER A LA FAMILIA DE LOS PRESUNTOS AUTORES O PARTÍCIPES","LA VINCULACIÓN CON LOS PRESUNTOS AUTORES O TESTIGOS","LA VINCULACIÓN CON LOS PRESUNTOS AUTORES O PARTÍCIPES","LA NO VINCULACIÓN CON LOS PRESUNTOS AUTORES O PARTÍCIPES"]'::jsonb, 'LA VINCULACIÓN CON LOS PRESUNTOS AUTORES O PARTÍCIPES', 3, '(texto: 12)** [CAPITULO III]', '184981', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1166, 1166, '¿QUÉ AUTORIDAD PUEDE DISPONER LA INMOVILIZACIÓN DE BIENES MUEBLES, COMO MEDIDA TRANSITORIA EN CASO DE FLAGRANCIA, CON LA FINALIDAD DE ASEGURAR LA PERMANENCIA Y CUSTODIA EN EL LUGAR QUE SE ENCUENTREN?', '["EL JUEZ PENAL ESPECIALIZADO EN EL TRÁFICO ILÍCITO DE DROGAS - TID","LA FISCALÍA ESPECIALIZADA EN EL TRÁFICO ILÍCITO DE DROGAS - TID","EL JUEZ EN LA ETAPA DE INVESTIGACIÓN PREPARATORIA","LA POLICÍA NACIONAL DEL PERÚ","EL PROCURADOR ANTIDROGAS"]'::jsonb, 'LA POLICÍA NACIONAL DEL PERÚ', 3, '(texto: 12)** [CAPITULO III]', '184982', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1167, 1167, 'LUEGO DE LOS EXÁMENES PRACTICADOS, ¿DÓNDE SON INTERNADAS LAS DROGAS DECOMISADAS?', '["EN LOS ALMACENES DE LA DIRECCIÓN GENERAL CONTRA EL CRIMEN ORGANIZADO O QUIEN HAGA SUS VECES","EN LOS ALMACENES DE LA FISCALÍA ESPECIALIZADA EN EL TRÁFICO ILÍCITO DE DROGAS - TID","EN LOS ALMACENES DE LA DIRANDRO PNP","DENTRO DE LAS VEINTICUATRO HORAS EN LOS ALMACENES DE LA CONABI","EN LOS ALMACENES DEL MINISTERIO DE LA PRODUCCIÓN"]'::jsonb, 'EN LOS ALMACENES DE LA DIRECCIÓN GENERAL CONTRA EL CRIMEN ORGANIZADO O QUIEN HAGA SUS VECES', 0, '(texto: 13)** [CAPITULO III]', '184983', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1168, 1168, '¿QUÉ PROCEDIMIENTO DEBE SER PRACTICADO EN ACTO PÚBLICO POR UN PROFESIONAL QUÍMICO CON LAS DROGAS DECOMISADAS, ANTES DE SU INCINERACIÓN?', '["PESAJE Y ANÁLISIS","EVALUACIÓN Y ANÁLISIS","PESAJE Y EVALUACIÓN","CALIFICACIÓN Y CUANTIFICACIÓN","DESCRIPCIÓN Y REGISTRO"]'::jsonb, 'PESAJE Y ANÁLISIS', 0, '(texto: 13)** [CAPITULO III]', '184984', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1169, 1169, '¿QUÉ DISPONE EL MINISTERIO PÚBLICO CON LOS OBJETOS EMPLEADOS, COMO ESCONDITE DE DROGAS (RECIPIENTES, MALETAS, ENTRE OTROS), LUEGO DEL EXAMEN O REGISTRO MATERIAL Y PERICIAL, ASÍ COMO DE LA DEBIDA PERENNIZACIÓN Y ELIMINACIÓN DE TODOS LOS RESTOS Y ADHERENCIAS DE DROGAS?:', '["EL INTERNAMIENTO O INCINERACIÓN","EL DECOMISO E INCINERACIÓN","SU DESTRUCCIÓN O INUTILIZACIÓN","SU ALMACENAMIENTO Y ANÁLISIS","SU INCAUTACIÓN O INCINERACIÓN"]'::jsonb, 'SU DESTRUCCIÓN O INUTILIZACIÓN', 2, '(texto: 13)** [CAPITULO III]', '184986', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1170, 1170, '¿DÓNDE SON PUESTOS A DISPOSICIÓN LOS BIENES MUEBLES E INMUEBLES SOBRE LOS CUALES HAYA RECAÍDO MEDIDA DE INCAUTACIÓN?', '["PRONABI","MINISTERIO DEL INTERIOR","POLICÍA NACIONAL DEL PERÚ","MINISTERIO PÚBLICO","ENACO"]'::jsonb, 'PRONABI', 0, '(texto: 13)** [CAPITULO III]', '184987', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1171, 1171, '¿DÓNDE SON DEPOSITADOS O INTERNADOS EL DINERO Y JOYAS SOBRE LOS CUALES HAYA RECAÍDO MEDIDA DE INCAUTACIÓN?', '["BANCO CENTRAL DE RESERVA DEL PERÚ","BANCO DE LA NACIÓN","CONABI","SUNAT","MINISTERIO DEL INTERIOR"]'::jsonb, 'BANCO DE LA NACIÓN', 1, '(texto: 13)** [CAPITULO III]', '184988', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1172, 1172, 'DESTINO DE LOS OBJETOS DECOMISADOS O INCAUTADOS.- LOS SEMOVIENTES SOBRE LOS CUALES HAYA RECAÍDO MEDIDA DE INCAUTACIÓN, QUEDAN EN PODER DE:', '["ENACO","AUTORIDAD REGIONAL","GOBERNADORES","POLICÍA NACIONAL DEL PERU","AUTORIDADES LOCALES"]'::jsonb, 'AUTORIDADES LOCALES', 4, '(texto: 13)** [CAPITULO III]', '184989', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1173, 1173, '¿DÓNDE SON INTERNADAS LAS ARMAS, MUNICIONES Y SIMILARES, SOBRE LAS QUE HAYA RECAÍDO LA MEDIDA DE INCAUTACIÓN?:', '["ALMACENES DEL MINISTERIO PÚBLICO","ALMACENES DEL MINISTERIO DEL INTERIOR","SUCAMEC","ALMACENES DE LA DIRANDRO DE LA POLICÍA NACIONAL DEL PERÚ","ARMERÍA DEL DEPARTAMENTO DE ARMAMENTO Y MUNICIÓN DE LA POLICÍA NACIONAL DEL PERÚ"]'::jsonb, 'SUCAMEC', 2, '(texto: 13)** [CAPITULO III]', '184990', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1174, 1174, '¿DÓNDE SON PUESTAS A DISPOSICIÓN LAS AERONAVES SOBRE LAS CUALES HAYA RECAÍDO MEDIDA DE INCAUTACIÓN?:', '["FUERZA AÉREA DEL PERÚ","CONABI","DIRECCIÓN AÉREA DE LA AVIACIÓN DE LA MARINA DE GUERRA DEL PERÚ","DIRECCIÓN AÉREA ESPECIALIZADA DE LA POLICÍA NACIONAL DEL PERÚ","DIRECCIÓN AÉREA ESPECIALIZADA DE LA AVIACIÓN DEL EJÉRCITO PERUANO"]'::jsonb, 'DIRECCIÓN AÉREA ESPECIALIZADA DE LA POLICÍA NACIONAL DEL PERÚ', 3, '(texto: 13)** [CAPITULO III]', '184991', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1176, 1176, '¿QUIÉN PUEDE PRIORIZAR LA AFECTACIÓN EN USO A LA UNIDAD ESPECIALIZADA QUE PRACTICÓ LA INCAUTACIÓN U OTRAS DEL SISTEMA ANTIDROGAS DE LA POLICÍA NACIONAL DEL PERÚ?', '["EL ESTADO","DEVIDA","MINISTERIO PÚBLICO","EL PODER JUDICIAL","PRONABI"]'::jsonb, 'PRONABI', 4, '(texto: 13)** [CAPITULO III]', '184993', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1177, 1177, '¿DÓNDE SE ESPECIFICA LA LISTA DE SUSTANCIAS QUÍMICAS?', '["EN EL REGLAMENTO DEL DECRETO LEGISLATIVO 1261","EN EL REGLAMENTO DEL DECRETO LEGISLATIVO 1251","EN LA PRIMERA DISPOSICIÓN COMPLEMENTARIA DEL DECRETO LEGISLATIVO 1126","EN EL DECRETO LEGISLATIVO 1271","EN EL REGLAMENTO DEL DECRETO LEGISLATIVO 1241"]'::jsonb, 'EN EL REGLAMENTO DEL DECRETO LEGISLATIVO 1241', 4, '(texto: 14)** [CAPITULO III]', '184994', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1178, 1178, 'EN EL DELITO DE TRÁFICO ILÍCITO DE DROGAS, ¿CUÁL ES LA FINALIDAD DE EJECUTAR ACCIONES DE OBSERVACIÓN, VIGILANCIA Y SEGUIMIENTO DE BLANCOS OBJETIVOS O EN TORNO A OBJETOS O INMUEBLES?', '["INTERPRETAR LOS ELEMENTOS DE CONVICCIÓN SUFICIENTES","COMPARAR LOS ELEMENTOS DE CONVICCIÓN SUFICIENTES","PROCESAR LOS ELEMENTOS DE CONVICCIÓN SUFICIENTES","REUNIR LOS ELEMENTOS DE CONVICCIÓN SUFICIENTES","ANALIZAR LOS ELEMENTOS DE CONVICCIÓN SUFICIENTES"]'::jsonb, 'REUNIR LOS ELEMENTOS DE CONVICCIÓN SUFICIENTES', 3, '(texto: 15)** [CAPITULO IV]', '184995', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1179, 1179, 'CON LA FINALIDAD DE PRACTICAR ANÁLISIS DE LA INFORMACIÓN PARA FINES DE PERFILACIÓN DE RIESGOS O PELIGRO INMINENTE DE DESVÍO DE INSUMOS O SUSTANCIAS QUÍMICAS DESTINADAS A LA ELABORACIÓN ILEGAL DE DROGAS, ¿QUIÉN TIENE ACCESO EN LÍNEA Y EN TIEMPO REAL, A LA INFORMACIÓN DEL REGISTRO DE BIENES FISCALIZADOS QUE ADMINISTRA SUNAT?', '["EL MINISTERIO PÚBLICO","EL INPE","LA POLICÍA NACIONAL DEL PERÚ","EL PODER JUDICIAL","EL MINISTERIO DE LA PRODUCCIÓN"]'::jsonb, 'LA POLICÍA NACIONAL DEL PERÚ', 2, '(texto: 3)** [CAPITULO II]', '184997', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1180, 1180, 'LAS PLANTACIONES DE COCA ILEGALMENTE CULTIVADAS SON OBJETO DE ERRADICACIÓN DE ACUERDO A LAS METAS PLANTEADAS:', '["ESTRATEGIA ALTERNATIVA DE LUCHA CONTRA LAS DROGAS","ANUALMENTE","ESTRATEGIA DE DESARROLLO DE LUCHA CONTRA LAS DROGAS","ESTRATEGIA ESPECIAL DE LUCHA CONTRA LAS DROGAS","ESTRATEGIA DE RECONVERSIÓN DE LUCHA CONTRA LAS DROGAS"]'::jsonb, 'ANUALMENTE', 1, '(texto: 4)** [CAPITULO III]', '184998', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1181, 1181, 'EL QUE CONVIERTE O TRANSFIERE DINERO, BIENES, EFECTOS O GANANCIAS CUYO ORIGEN ILÍCITO CONOCE O DEBÍA PRESUMIR, CON LA FINALIDAD DE EVITAR LA IDENTIFICACIÓN DE SU ORIGEN, SU INCAUTACIÓN O DECOMISO; ES CONSIDERADO COMO:', '["ACTOS DE TRANSFERENCIA DE BIEN","ACTOS DE OCULTAMIENTO Y TENENCIA","ACTOS DE CONVERSIÓN Y TRASLADO","CIRCUNSTANCIAS AGRAVANTES","ACTOS DE CONVERSIÓN Y TRANSFERENCIA"]'::jsonb, 'ACTOS DE CONVERSIÓN Y TRANSFERENCIA', 4, '(texto: 1)**', '185046', '2026-07-14T01:12:29.113429+00:00');
