INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1183, 1183, 'EL QUE TRANSPORTA O TRASLADA CONSIGO O POR CUALQUIER MEDIO DENTRO DEL TERRITORIO NACIONAL DINERO EN EFECTIVO O INSTRUMENTOS FINANCIEROS NEGOCIABLES EMITIDOS AL PORTADOR; CUYO ORIGEN ILÍCITO CONOCE O DEBÍA PRESUMIR, CON LA FINALIDAD DE EVITAR LA IDENTIFICACIÓN DE SU ORIGEN, SU INCAUTACIÓN O DECOMISO; O HACE INGRESAR O SALIR DEL PAÍS CONSIGO O POR CUALQUIER MEDIO TALES BIENES, CUYO ORIGEN ILÍCITO CONOCE O DEBÍA PRESUMIR, CON IGUAL FINALIDAD; ES CONSIDERADO COMO:', '["TRANSPORTE DE DINERO POR EL PAÍS","TRASLADO DE TÍTULOS VALORES DE ORIGEN ILÍCITO","TRANSPORTE, TRASLADO, INGRESO O SALIDA POR TERRITORIO NACIONAL DE DINERO O TÍTULOS VALORES DE ORIGEN ILÍCITO","TRANSPORTE DENTRO DE TERRITORIO NACIONAL DE DINERO","TRASLADO FUERA DEL TERRITORIO NACIONAL DE DINERO O TÍTULOS VALORES DE ORIGEN ILÍCITO"]'::jsonb, 'TRANSPORTE, TRASLADO, INGRESO O SALIDA POR TERRITORIO NACIONAL DE DINERO O TÍTULOS VALORES DE ORIGEN ILÍCITO', 2, '(texto: 3)**', '185048', '2026-07-14T01:12:29.113429+00:00');
