INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1199, 1199, 'ES FUNCIÓN Y FACULTAD DE LA UIF - PERÚ SUPERVISAR Y SANCIONAR EN MATERIA DE PREVENCIÓN DEL DELITO DE LAVADO DE ACTIVOS Y EL FINANCIAMIENTO DE TERRORISMO A:', '["A AQUELLOS SUJETOS OBLIGADOS QUE CARECEN DE ÓRGANO SUPERIOR","A AQUELLOS SUJETOS OBLIGADOS QUE DEPENDEN DE UN ORGANISMO SUPERVISOR","A AQUELLOS SUJETOS OBLIGADOS QUE DEPENDEN DEL ORGANO SUPERVISOR","A AQUELLOS SUJETOS OBLIGADOS QUE CARECEN DE ORGANISMO SUPERVISOR","A AQUELLOS SUJETOS OBLIGADOS QUE DEPENDEN DE UN ÓRGANO SUPERVISOR DEL ESTADO"]'::jsonb, 'A AQUELLOS SUJETOS OBLIGADOS QUE CARECEN DE ORGANISMO SUPERVISOR', 3, '(texto: DCM-PRIMERA)** [TITULO III]', '185091', '2026-07-14T01:12:29.113429+00:00');
