INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1188, 1188, 'CONSTITUYE OMISIÓN DE COMUNICACIÓN DE OPERACIONES O TRANSACCIONES SOSPECHOSAS; EL QUE:', '["CUMPLIENDO SUS OBLIGACIONES FUNCIONALES O PROFESIONALES, COMUNICA A LA AUTORIDAD POLICIAL LAS TRANSACCIONES U OPERACIONES SOSPECHOSAS QUE HUBIERE OMITIDO, SEGÚN LAS LEYES Y NORMAS REGLAMENTARIAS","CUMPLIENDO SUS OBLIGACIONES FUNCIONALES O PROFESIONALES, COMUNICA A LA AUTORIDAD COMPETENTE LAS TRANSACCIONES U OPERACIONES SOSPECHOSAS QUE HUBIERE DETECTADO, SEGÚN LAS LEYES Y NORMAS REGLAMENTARIAS","CUMPLIENDO SUS OBLIGACIONES FUNCIONALES O PROFESIONALES, OMITE COMUNICAR A LA AUTORIDAD JUDICIAL LAS TRANSACCIONES U OPERACIONES CLARAS QUE HUBIERE DETECTADO, SEGÚN LAS LEYES Y NORMAS REGLAMENTARIAS","CUMPLIENDO SUS OBLIGACIONES FUNCIONALES O PROFESIONALES, OMITE COMUNICAR A LA UNIDAD DE INTELIGENCIA FINANCIERA LAS TRANSACCIONES U OPERACIONES SOSPECHOSAS QUE HUBIERE DETECTADO, SEGÚN LAS LEYES Y NORMAS REGLAMENTARIAS","INCUMPLIENDO SUS OBLIGACIONES FUNCIONALES O PROFESIONALES, OMITE COMUNICAR A LA AUTORIDAD COMPETENTE, LAS TRANSACCIONES U OPERACIONES SOSPECHOSAS QUE HUBIERE DETECTADO, SEGÚN LAS LEYES Y NORMAS REGLAMENTARIAS"]'::jsonb, 'INCUMPLIENDO SUS OBLIGACIONES FUNCIONALES O PROFESIONALES, OMITE COMUNICAR A LA AUTORIDAD COMPETENTE, LAS TRANSACCIONES U OPERACIONES SOSPECHOSAS QUE HUBIERE DETECTADO, SEGÚN LAS LEYES Y NORMAS REGLAMENTARIAS', 4, '(texto: 5)**', '185060', '2026-07-14T01:12:29.113429+00:00');
