INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1228, 1228, 'LAS OPERACIONES MÚLTIPLES QUE EN CONJUNTO IGUALEN O SUPEREN DETERMINADO MONTO FIJADO POR LA UIF - PERÚ, SERÁN CONSIDERADAS COMO:', '["OPERACIONES SOSPECHOSAS SI SON REALIZADAS POR O EN BENEFICIO DE DETERMINADA PERSONA","DOS OPERACIONES IMPORTANTES SI SON REALIZADAS POR O EN BENEFICIO DE DETERMINADA PERSONA","MÚLTIPLES OPERACIONES SI SON REALIZADAS POR O EN BENEFICIO DE DETERMINADA PERSONA","UNA SOLA OPERACIÓN SI SON REALIZADAS POR O EN BENEFICIO DE DETERMINADA PERSONA","OPERACIONES PRINCIPALES SI SON REALIZADAS POR O EN BENEFICIO DE DETERMINADA PERSONA"]'::jsonb, 'UNA SOLA OPERACIÓN SI SON REALIZADAS POR O EN BENEFICIO DE DETERMINADA PERSONA', 3, '(texto: DCM-PRIMERA)** [TITULO III]', '185160', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1229, 1229, 'CUMPLIR CON TODAS LAS NORMAS PERTINENTES EN MATERIA DE PREVENCIÓN DEL LAVADO DE ACTIVOS Y DEL FINANCIAMIENTO DEL TERRORISMO, CONFORME A LA LEGISLACIÓN DE LA MATERIA.- CORRESPONDE A:', '["FUNCIONES DEL NOTARIO","PRERROGATIVAS DEL NOTARIO","OBLIGACIONES DEL NOTARIO","MISIONES DEL NOTARIO","FACULTADES DEL NOTARIO"]'::jsonb, 'OBLIGACIONES DEL NOTARIO', 2, '(texto: DCM-SEXTA)** [TITULO III]', '185161', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1230, 1230, 'ES OBLIGACIÓN DEL NOTARIO ACCEDER A LA BASE DE DATOS DEL RENIEC EN AQUELLOS LUGARES DONDE SE CUENTE CON ACCESO A INTERNET Y SEA POSIBLE PARA LA INDICADA ENTIDAD BRINDAR EL SERVICIO DE CONSULTAS EN LÍNEA PARA LA VERIFICACIÓN DE:', '["LA IDENTIDAD DE LOS INTERVINIENTES MEDIANTE LA VERIFICACIÓN DE LAS IMÁGENES, DATOS Y/O LA IDENTIFICACIÓN POR COMPARACIÓN BIOMÉTRICA","LA IDENTIDAD DE PERSONAS MEDIANTE LA VERIFICACIÓN DE LAS IMÁGENES, DATOS Y/O LA IDENTIFICACIÓN POR COMPARACIÓN BIOMÉTRICA","LA IDENTIDAD DE EMPRESAS FINANCIERAS MEDIANTE LA VERIFICACIÓN DE LAS IMÁGENES, DATOS Y/O LA IDENTIFICACIÓN POR COMPARACIÓN GEOMÉTRICA","LA ENTIDAD CREDITICIA MEDIANTE LA VERIFICACIÓN DE LAS IMÁGENES, DATOS Y/O LA IDENTIFICACIÓN POR COMPARACIÓN BIOELECTRÓNICA","LA ENTIDAD PRESTAMISTA MEDIANTE LA VERIFICACIÓN DE LAS IMÁGENES, DATOS Y/O LA IDENTIFICACIÓN POR COMPARACIÓN BIOMÉTRICA"]'::jsonb, 'LA IDENTIDAD DE LOS INTERVINIENTES MEDIANTE LA VERIFICACIÓN DE LAS IMÁGENES, DATOS Y/O LA IDENTIFICACIÓN POR COMPARACIÓN BIOMÉTRICA', 0, '(texto: DCM-SEPTIMA)** [TITULO III]', '185162', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1231, 1231, 'ES LA ACCIÓN O CONDUCTA, QUE CAUSA DAÑO A LA INTEGRIDAD CORPORAL O A LA SALUD. SE INCLUYE EL MALTRATO POR NEGLIGENCIA, DESCUIDO O POR PRIVACIÓN DE LAS NECESIDADES BÁSICAS, QUE HAYAN OCASIONADO DAÑO FÍSICO O QUE PUEDAN LLEGAR A OCASIONARLO, SIN IMPORTAR EL TIEMPO QUE SE REQUIERA PARA SU RECUPERACIÓN, ES UN TIPO DE:', '["VIOLENCIA FÍSICA","VIOLENCIA PSICOLÓGICA","VIOLENCIA SEXUAL","VIOLENCIA ECONÓMICA O PATRIMONIAL","VIOLENCIA DOMÉSTICA"]'::jsonb, 'VIOLENCIA FÍSICA', 0, '(texto: 8)** [TITULO I] [CAPITULO II]', '185163', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1232, 1232, 'ES LA ACCIÓN U OMISIÓN, TENDIENTE A CONTROLAR O AISLAR A LA PERSONA CONTRA SU VOLUNTAD, A HUMILLARLA, AVERGONZARLA, INSULTARLA, ESTIGMATIZARLA O ESTEREOTIPARLA, SIN IMPORTAR EL TIEMPO QUE SE REQUIERA PARA SU RECUPERACIÓN, ES UN TIPO DE:', '["VIOLENCIA FÍSICA","VIOLENCIA PSICOLÓGICA","VIOLENCIA SEXUAL","VIOLENCIA ECONÓMICA O PATRIMONIAL","VIOLENCIA DOMÉSTICA"]'::jsonb, 'VIOLENCIA PSICOLÓGICA', 1, '(texto: 8)** [TITULO I] [CAPITULO II]', '185164', '2026-07-14T01:12:29.113429+00:00');
