INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1235, 1235, 'A LA JUSTIFICACIÓN DE LAS INASISTENCIAS Y TARDANZAS AL CENTRO DE TRABAJO DERIVADAS DE DICHOS ACTOS DE VIOLENCIA, CONSTITUYE:', '["DERECHO A UNA VIDA LIBRE DE VIOLENCIA","DERECHO A LA ASISTENCIA Y PROTECCIÓN INTEGRALES","DERECHOS LABORALES","DERECHOS EN EL CAMPO DE LA EDUCACIÓN","DERECHOS EN EL CAMPO SOCIAL"]'::jsonb, 'DERECHOS LABORALES', 2, '(texto: 11)** [TITULO I] [CAPITULO III]', '185167', '2026-07-14T01:12:29.113429+00:00');
