INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1237, 1237, 'A QUE PRINCIPIO CONSTITUYE EL SIGUIENTE ANUNCIADO: "EN TODAS LAS MEDIDAS CONCERNIENTES A LAS NIÑAS Y NIÑOS ADOPTADAS POR INSTITUCIONES PÚBLICAS O PRIVADAS DE BIENESTAR SOCIAL, LOS TRIBUNALES, LAS AUTORIDADES ADMINISTRATIVAS O LOS ÓRGANOS LEGISLATIVOS SE DEBE TENER EN CONSIDERACIÓN PRIMORDIAL EL INTERÉS SUPERIOR DEL NIÑO":', '["PRINCIPIO DE INTERVENCIÓN INMEDIATA Y OPORTUNA","PRINCIPIO DE INTERÉS SUPERIOR DEL NIÑO","PRINCIPIO DE LA DEBIDA DILIGENCIA","PRINCIPIO DE IGUALDAD Y NO DISCRIMINACIÓN","PRINCIPIO DE SENCILLEZ Y ORALIDAD"]'::jsonb, 'PRINCIPIO DE INTERÉS SUPERIOR DEL NIÑO', 1, '(texto: 2)** [TITULO I] [CAPITULO I]', '185169', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1238, 1238, 'A QUE PRINCIPIO CONSTITUYE EL SIGUIENTE ENUNCIADO: "TODOS LOS PROCESOS POR VIOLENCIA CONTRA LAS MUJERES Y LOS INTEGRANTES DEL GRUPO FAMILIAR SE DESARROLLAN CONSIDERANDO EL MÍNIMO DE FORMALISMO, EN ESPACIOS AMIGABLES PARA LAS PRESUNTAS VÍCTIMAS, FAVORECIENDO QUE ESTAS CONFÍEN EN EL SISTEMA Y COLABOREN CON ÉL PARA UNA ADECUADA SANCIÓN AL AGRESOR Y LA RESTITUCIÓN DE SUS DERECHOS VULNERADOS":', '["PRINCIPIO DE INTERVENCIÓN MEDIATA Y OPORTUNA","PRINCIPIO DE LA DEBIDA DILIGENCIA","PRINCIPIO DE INTERÉS SUPERIOR DEL NIÑO","PRINCIPIO DE IGUALDAD Y DISCRIMINACIÓN","PRINCIPIO DE SENCILLEZ Y ORALIDAD"]'::jsonb, 'PRINCIPIO DE SENCILLEZ Y ORALIDAD', 4, '(texto: 2)** [TITULO I] [CAPITULO I]', '185170', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1240, 1240, 'LA POLICÍA NACIONAL DEL PERÚ U OTRAS ENTIDADES ENCARGADAS DE EJECUTAR LA MEDIDA DE PROTECCIÓN REMITEN AL JUZGADO DE FAMILIA UN INFORME SOBRE LA EJECUCIÓN DE LA MEDIDA, DENTRO DE LOS:', '["QUINCE (15) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE NOTIFICADA","DIEZ (10) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE NOTIFICADA","VEINTE (20) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE AGREDIDA","QUINCE (15) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE AGREDIDA","DOCE (12) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE NOTIFICADA"]'::jsonb, 'QUINCE (15) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE NOTIFICADA', 0, '(texto: 23-C)** [TITULO II] [CAPITULO II]', '185174', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1241, 1241, 'INFORME DE CUMPLIMIENTO DE LA MEDIDA DE PROTECCIÓN: EN CASOS DE RIESGO SEVERO, DICHO INFORME DEBE SER REMITIDO DENTRO DE LOS:', '["DIEZ (10) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE NOTIFICADA LA MEDIDA DE PROTECCIÓN","QUINCE (15) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE NOTIFICADA LA MEDIDA DE PROTECCIÓN","CINCO (5) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE REALIZADA LA AGRESIÓN","CINCO (5) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE NOTIFICADA LA MEDIDA DE PROTECCIÓN","TRES (3) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE NOTIFICADA LA MEDIDA DE PROTECCIÓN"]'::jsonb, 'CINCO (5) DÍAS CONTADOS DESDE LA FECHA EN QUE FUE NOTIFICADA LA MEDIDA DE PROTECCIÓN', 3, '(texto: 23-C)** [TITULO II] [CAPITULO II]', '185175', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1242, 1242, 'EL QUE DESOBEDECE, INCUMPLE O RESISTE UNA MEDIDA DE PROTECCIÓN DICTADA EN UN PROCESO ORIGINADO POR HECHOS QUE CONFIGURAN ACTOS DE VIOLENCIA CONTRA LAS MUJERES O CONTRA INTEGRANTES DEL GRUPO FAMILIAR, COMETE DELITO DE:', '["VIOLENCIA A LA AUTORIDAD","CUMPLIMIENTO DE MEDIDAS DE PROTECCIÓN","INCUMPLIMIENTO DE MEDIDAS SANITARIAS","PELIGRO COMÚN","RESISTENCIA O DESOBEDIENCIA A LA AUTORIDAD PREVISTO EN EL CÓDIGO PENAL"]'::jsonb, 'RESISTENCIA O DESOBEDIENCIA A LA AUTORIDAD PREVISTO EN EL CÓDIGO PENAL', 4, '(texto: 24)** [TITULO II] [CAPITULO II]', '185176', '2026-07-14T01:12:29.113429+00:00');
