INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1251, 1251, '¿QUÉ ENFOQUE HACE REFERENCIA EL TEXTO?. RECONOCE QUE ES NECESARIO IDENTIFICAR LAS RELACIONES DE PODER ENTRE DISTINTAS EDADES DE LA VIDA Y SUS VINCULACIONES PARA MEJORAR LAS CONDICIONES DE VIDA O EL DESARROLLO COMÚN', '["ENFOQUE DE INTERCULTURALIDAD","ENFOQUE DE INTEGRALIDAD","ENFOQUE DE INTERSECCIONALIDAD","ENFOQUE DE GÉNERO","ENFOQUE GENERACIONAL"]'::jsonb, 'ENFOQUE GENERACIONAL', 4, '(texto: 3)** [TITULO I] [CAPITULO I]', '185185', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1252, 1252, 'LAS DISPOSICIONES DE LA PRESENTE LEY SE APLICAN A TODOS LOS TIPOS DE VIOLENCIA CONTRA LAS MUJERES POR SU CONDICIÓN DE TALES Y CONTRA LOS:', '["ASOCIADOS DEL GRUPO FAMILIAR","INTEGRANTES DEL GRUPO FAMILIAR","PARTICIPANTES DEL GRUPO FAMILIAR","SOCIOS DEL GRUPO FAMILIAR","AYUDANTES DEL GRUPO FAMILIAR"]'::jsonb, 'INTEGRANTES DEL GRUPO FAMILIAR', 1, '(texto: 4)** [TITULO I] [CAPITULO I]', '185186', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1269, 1269, '¿CUÁLES SON LAS MEDIDAS DE PROTECCIÓN QUE PUEDEN DICTARSE EN LOS PROCESOS POR ACTOS DE VIOLENCIA CONTRA LAS MUJERES Y LOS INTEGRANTES DEL GRUPO FAMILIAR?', '["IMPEDIMENTO DE AISLAMIENTO O PROXIMIDAD A LA VÍCTIMA EN CUALQUIER FORMA","IMPEDIMENTO DE COMUNICACIÓN O ACERCAMIENTO A LA VÍCTIMA EN CUALQUIER FORMA","IMPEDIMENTO DE DECLARACIÓN O PROXIMIDAD A LA VÍCTIMA EN CUALQUIER FORMA","IMPEDIMENTO DE ACERCAMIENTO O PROXIMIDAD A LA VÍCTIMA EN CUALQUIER FORMA","IMPEDIMENTO DE AFIRMACIÓN O PROXIMIDAD A LA VÍCTIMA EN CUALQUIER FORMA"]'::jsonb, 'IMPEDIMENTO DE ACERCAMIENTO O PROXIMIDAD A LA VÍCTIMA EN CUALQUIER FORMA', 3, '(texto: 22)** [TITULO II] [CAPITULO II]', '185223', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1253, 1253, 'DEFINICION DE VIOLENCIA CONTRA LAS MUJERES: ES CUALQUIER ACCIÓN O....:', '["CONDUCTA QUE LES CAUSA MUERTE, DAÑO O SUFRIMIENTO FÍSICO, SEXUAL O PSICOLÓGICO POR SU CONDICIÓN DE TALES, TANTO EN EL ÁMBITO PÚBLICO COMO EN EL PRIVADO","PROCEDIMIENTO QUE LES CAUSA MUERTE, DAÑO O SUFRIMIENTO FÍSICO, SEXUAL O PSICOLÓGICO POR SU CONDICIÓN DE TALES, TANTO EN EL ÁMBITO PÚBLICO COMO EN EL PRIVADO","FORMA QUE LES CAUSA MUERTE, DAÑO O SUFRIMIENTO SEXUAL O PSICOLÓGICO POR SU CONDICIÓN DE TALES, TANTO EN EL ÁMBITO PÚBLICO COMO EN EL PRIVADO","ENGAÑO QUE LES CAUSA MUERTE, DAÑO O SUFRIMIENTO FÍSICO, SEXUAL O PSICOLÓGICO POR SU CONDICIÓN DE TALES, TANTO EN EL ÁMBITO PÚBLICO COMO EN EL PRIVADO","TRATAMIENTO QUE LES CAUSA MUERTE, DAÑO O SUFRIMIENTO FÍSICO, SEXUAL O PSICOLÓGICO POR SU CONDICIÓN DE TALES, TANTO EN EL ÁMBITO PÚBLICO COMO EN EL PRIVADO"]'::jsonb, 'CONDUCTA QUE LES CAUSA MUERTE, DAÑO O SUFRIMIENTO FÍSICO, SEXUAL O PSICOLÓGICO POR SU CONDICIÓN DE TALES, TANTO EN EL ÁMBITO PÚBLICO COMO EN EL PRIVADO', 0, '(texto: 5)** [TITULO I] [CAPITULO II]', '185187', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1254, 1254, 'LA VIOLENCIA CONTRA LAS MUJERES ES CUALQUIER ACCIÓN O CONDUCTA QUE LES CAUSA:', '["MUERTE","ILESO","RIESGO","QUEJA","AMENAZA"]'::jsonb, 'MUERTE', 0, '(texto: 5)** [TITULO I] [CAPITULO II]', '185188', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1255, 1255, 'LA VIOLENCIA CONTRA LAS MUJERES ES CUALQUIER ACCIÓN O CONDUCTA QUE LES CAUSA MUERTE, DAÑO O SUFRIMIENTO FÍSICO, SEXUAL O:', '["MORAL","PSICOLÓGICO","MENTAL","ECONÓMICO","ANÍMICO"]'::jsonb, 'PSICOLÓGICO', 1, '(texto: 5)** [TITULO I] [CAPITULO II]', '185189', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1256, 1256, 'SE ENTIENDE POR VIOLENCIA CONTRA LAS MUJERES:', '["LA QUE TENGA LUGAR FUERA DE LA FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACION INTERPERSONAL","LA QUE TENGA LUGAR AISLADO DE LA FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACION INTERPERSONAL","LA QUE TENGA LUGAR SITUADO DE LA FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACION INTERPERSONAL","LA QUE TENGA LUGAR DENTRO DE LA FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACION INTERPERSONAL","LA QUE TENGA LUGAR DISTANTE DE LA FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACION INTERPERSONAL"]'::jsonb, 'LA QUE TENGA LUGAR DENTRO DE LA FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACION INTERPERSONAL', 3, '(texto: 5)** [TITULO I] [CAPITULO II]', '185190', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1257, 1257, 'SE ENTIENDE POR VIOLENCIA CONTRA LAS MUJERES:', '["LA QUE TENGA LUGAR DENTRO DE LA FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACIÓN INTERPERSONAL, YA SEA QUE EL AGRESOR COMPARTA O HAYA COMPARTIDO EL MISMO DOMICILIO QUE LA MUJER","LA QUE TENGA LUGAR DENTRO DE LA FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACIÓN INTERPERSONAL","LA QUE TENGA LUGAR EN LA CASA DEL AGRESOR","LA QUE TENGA LUGAR DENTRO DE LA EX FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACIÓN INTERPERSONAL, YA SEA QUE EL AGRESOR NO HAYA COMPARTIDO EL MISMO DOMICILIO QUE LA MUJER","LA QUE TENGA LUGAR DENTRO DE LA FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACIÓN INTERPERSONAL, YA SEA QUE EL AGRESOR SE NIEGUE A COMPARTIR EL MISMO DOMICILIO QUE LA MUJER"]'::jsonb, 'LA QUE TENGA LUGAR DENTRO DE LA FAMILIA O UNIDAD DOMÉSTICA O EN CUALQUIER OTRA RELACIÓN INTERPERSONAL, YA SEA QUE EL AGRESOR COMPARTA O HAYA COMPARTIDO EL MISMO DOMICILIO QUE LA MUJER', 0, '(texto: 5)** [TITULO I] [CAPITULO II]', '185191', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1258, 1258, '¿QUÉ PERSONAS PUEDEN COMETER VIOLENCIA CONTRA LAS MUJERES?', '["CUALQUIER PERSONA","PERSONAS AUTORIZADAS","PERSONAS CALIFICADAS","PERSONAS CON REQUISITORIAS","PERSONAS CON ANTECEDENTES"]'::jsonb, 'CUALQUIER PERSONA', 0, '(texto: 5)** [TITULO I] [CAPITULO II]', '185193', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1259, 1259, 'LA VIOLENCIA CONTRA LAS MUJERES ES PERPETRADA POR CUALQUIER PERSONA Y COMPRENDE, ENTRE OTROS:', '["EL ACECHO","LA TORTURA","LA PERSECUCIÓN","EL SEGUIMIENTO","LA CACERÍA"]'::jsonb, 'LA TORTURA', 1, '(texto: 5)** [TITULO I] [CAPITULO II]', '185195', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1260, 1260, 'SE ENTIENDE POR VIOLENCIA CONTRA LAS MUJERES: LA QUE SEA PERPETRADA O TOLERADA POR LOS AGENTES DEL ESTADO:', '["EN UN SOLO LUGAR","EN EL TRABAJO","DONDE QUIERA QUE OCURRA","DONDE LA LEY LE PERMITE","EN EL EXTRANJERO"]'::jsonb, 'DONDE QUIERA QUE OCURRA', 2, '(texto: 5)** [TITULO I] [CAPITULO II]', '185200', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1261, 1261, 'LA VIOLENCIA CONTRA CUALQUIER INTEGRANTE DEL GRUPO FAMILIAR SE PRODUCE EN EL CONTEXTO DE UNA RELACIÓN DE:', '["AUSENCIA","ALEJAMIENTO","MARCACIÓN","SEPARACIÓN","CONFIANZA"]'::jsonb, 'CONFIANZA', 4, '(texto: 6)** [TITULO I] [CAPITULO II]', '185202', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1262, 1262, '¿A QUIÉN SE DEBERÁ TENER ESPECIAL CONSIDERACIÓN EN LA VIOLENCIA CONTRA LOS INTEGRANTES DEL GRUPO FAMILIAR:', '["CON LOS JOVENES","CON LOS VIEJOS","CON LOS JÓVENES MAYORES","CON LOS ADOLESCENTES MENORES","CON LOS ADULTOS MAYORES"]'::jsonb, 'CON LOS ADULTOS MAYORES', 4, '(texto: 6)** [TITULO I] [CAPITULO II]', '185203', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1265, 1265, 'SON SUJETOS DE PROTECCIÓN DE LA LEY, LOS MIEMBROS DEL GRUPO FAMILIAR, ENTIÉNDASE COMO TALES A:', '["LOS PARIENTES DE LOS EXCÓNYUGES Y CONVIVIENTES HASTA EL CUARTO GRADO DE CONSANGUINIDAD Y SEGUNDO DE AFINIDAD","LOS PARIENTES COLATERALES DE LOS CÓNYUGES Y CONVIVIENTES HASTA EL CUARTO GRADO DE CONSANGUINIDAD Y PRIMERO DE AFINIDAD","LOS PARIENTES COLATERALES DE LOS CÓNYUGES Y EXCONVIVIENTES HASTA EL CUARTO GRADO DE CONSANGUINIDAD Y SEGUNDO DE AFINIDAD","LOS PARIENTES COLATERALES DE LOS CÓNYUGES Y CONVIVIENTES HASTA EL TERCER GRADO DE CONSANGUINIDAD Y SEGUNDO DE AFINIDAD","LOS PARIENTES COLATERALES HASTA EL CUARTO GRADO DE CONSANGUINIDAD Y SEGUNDO DE AFINIDAD"]'::jsonb, 'LOS PARIENTES COLATERALES HASTA EL CUARTO GRADO DE CONSANGUINIDAD Y SEGUNDO DE AFINIDAD', 4, '(texto: 7)** [TITULO I] [CAPITULO II]', '185213', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1266, 1266, '¿CUÁLES SON LOS TIPOS DE VIOLENCIA CONTRA LAS MUJERES Y LOS INTEGRANTES DEL GRUPO FAMILIAR?', '["FÍSICA, PSICOLÓGICA Y SEXUAL","FÍSICA, PSICOLÓGICA, SEXUAL Y ECONÓMICA O PATRIMONIAL","PSÍQUICA, PSICOLÓGICA, SEXUAL Y ECONÓMICA O PATRIMONIAL","FÍSICA, PSICOLÓGICA, SEXUAL Y ECONÓMICA","FÍSICA, PSICOLÓGICA, ASEXUAL Y PATRIMONIAL"]'::jsonb, 'FÍSICA, PSICOLÓGICA, SEXUAL Y ECONÓMICA O PATRIMONIAL', 1, '(texto: 8)** [TITULO I] [CAPITULO II]', '185216', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1267, 1267, 'EN LA VIOLENCIA SEXUAL SE CONSIDERAN TALES LA EXPOSICIÓN A MATERIAL PORNOGRÁFICO Y QUE VULNERAN EL DERECHO DE LAS PERSONAS A DECIDIR VOLUNTARIAMENTE ACERCA DE SU VIDA SEXUAL O REPRODUCTIVA, A TRAVÉS DE AMENAZAS, COERCION, Y USO DE LA FUERZA O', '["INTIMIDACIÓN","POTENCIA","CONTROL","SATISFACCIÓN","REFUERZO"]'::jsonb, 'INTIMIDACIÓN', 0, '(texto: 8)** [TITULO I] [CAPITULO II]', '185217', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1268, 1268, 'LA VIOLENCIA ECONÓMICA O PATRIMONIAL ES LA ACCIÓN U OMISIÓN QUE OCASIONA UN MENOSCABO EN LOS RECURSOS ECONÓMICOS O PATRIMONIALES DE LAS MUJERES POR SU CONDICIÓN DE TALES O CONTRA CUALQUIER INTEGRANTE DEL GRUPO FAMILIAR, EN EL MARCO DE RELACIONES DE PODER, RESPONSABILIDAD O CONFIANZA, POR EJEMPLO, A TRAVÉS DE LA LIMITACIÓN O CONTROL DE SUS:', '["INGRESOS","LIQUIDACIONES","REMATES","PAGOS","ARBITRIOS"]'::jsonb, 'INGRESOS', 0, '(texto: 8)** [TITULO I] [CAPITULO II]', '185219', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1270, 1270, 'ES RESPONSABLE DE EJECUTAR LAS MEDIDAS DE PROTECCIÓN DICTADAS, PARA LO CUAL DEBE TENER UN MAPA GRÁFICO Y GEORREFERENCIAL DE REGISTRO DE TODAS LAS VÍCTIMAS CON LAS MEDIDAS DE PROTECCIÓN QUE LES HAYAN SIDO NOTIFICADAS:', '["PÚBLICO EL MINISTERIO","EL PODER JUDICIAL","EL DEFENSOR DEL PUEBLO","LA POLICÍA NACIONAL DEL PERÚ","EL PROCURADOR PÚBLICO"]'::jsonb, 'LA POLICÍA NACIONAL DEL PERÚ', 3, '(texto: 23-A)** [TITULO II] [CAPITULO II]', '185226', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1271, 1271, 'EL QUE DESOBEDECE, INCUMPLE O RESISTE A UNA MEDIDA DE PROTECCIÓN DICTADA EN UN PROCESO ORIGINADO POR HECHOS QUE CONFIGURAN ACTOS DE VIOLENCIA CONTRA LAS MUJERES O CONTRA INTEGRANTES DEL GRUPO FAMILIAR, COMETE DELITO DE RESISTENCIA O DESOBEDIENCIA A LA AUTORIDAD PREVISTO EN EL:', '["CÓDIGO PROCESAL PENAL","CÓDIGO CIVIL","CÓDIGO LABORAL","CÓDIGO PROCESAL CONSTITUCIONAL","CÓDIGO PENAL"]'::jsonb, 'CÓDIGO PENAL', 4, '(texto: 24)** [TITULO II] [CAPITULO II]', '185227', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1272, 1272, 'EN LOS PROCESOS POR DELITOS VINCULADOS A ACTOS DE VIOLENCIA CONTRA LAS MUJERES Y LOS INTEGRANTES DEL GRUPO FAMILIAR, LOS JUZGADOS PENALES DEBEN PRONUNCIARSE EN LA SENTENCIA CONDENATORIA ACERCA DEL TRATAMIENTO ESPECIALIZADO PARA EL AGRESOR QUE NO CUMPLA PENA:', '["PRIVATIVA DE LIBERTAD EFECTIVA","PENA RESTRICTIVA DE LA LIBERTAD","PENA LIMITATIVA DE DERECHOS","PRIVATIVA DE LIBERTAD INCONDICIONAL","PRIVATIVA DE LIBERTAD CONDICIONAL"]'::jsonb, 'PRIVATIVA DE LIBERTAD EFECTIVA', 0, '(texto: 32)** [TITULO III] [CAPITULO II]', '185230', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1273, 1273, 'LA SENTENCIA QUE PONGA FIN AL PROCESO POR DELITOS VINCULADOS A HECHOS QUE CONSTITUYEN ACTOS DE VIOLENCIA CONTRA LA MUJER Y LOS INTEGRANTES DEL GRUPO FAMILIAR PUEDE SER:', '["ABSOLUTORIA O CONDENATORIA","REPARADORA O REHABILITADORA","REPARADORA O CONDENATORIA","REHABILITADORA O ABSOLUTORIA","CONDENATORIA O REHABILITADORA"]'::jsonb, 'ABSOLUTORIA O CONDENATORIA', 0, '(texto: 20)** [TITULO II] [CAPITULO I]', '185235', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1274, 1274, 'LAS DENUNCIAS POR ACTOS DE VIOLENCIA CONTRA LAS MUJERES Y LOS INTEGRANTES DEL GRUPO FAMILIAR SE REGULAN POR LAS NORMAS PREVISTAS EN LA PRESENTE LEY 30364 Y, DE MANERA SUPLETORIA, POR EL:', '["CÓDIGO PROCESAL PENAL","CÓDIGO PENAL","CÓDIGO CIVIL","CÓDIGO LABORAL","CÓDIGO PROCESAL CONSTITUCIONAL"]'::jsonb, 'CÓDIGO PROCESAL PENAL', 0, '(texto: 13)** [TITULO II] [CAPITULO I]', '185237', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1275, 1275, 'EL FISCAL O JUEZ A CARGO DE CUALQUIER PROCESO DE VIOLENCIA, DEBE PONDERAR LA PROPORCIONALIDAD ENTRE LA EVENTUAL AFECTACIÓN CAUSADA Y LAS MEDIDAS DE PROTECCIÓN Y DE REHABILITACIÓN A ADOPTARSE. PARA ELLO, DEBE HACER UN JUICIO DE RAZONABILIDAD DE ACUERDO CON LAS CIRCUNSTANCIAS DEL CASO, EMITIENDO DECISIONES QUE PERMITAN PROTEGER EFECTIVAMENTE LA VIDA, LA SALUD Y LA INTEGRIDAD DE LAS VÍCTIMAS. LA ADOPCIÓN DE ESTAS MEDIDAS SE ADECÚA A LAS FASES DEL CICLO DE LA VIOLENCIA Y A LAS DIVERSAS TIPOLOGÍAS QUE PRESENTA LA VIOLENCIA CONTRA LAS MUJERES Y LOS INTEGRANTES DEL GRUPO FAMILIAR, CONSTITUYE EL:', '["PRINCIPIO DE RAZONABILIDAD Y PROPORCIONALIDAD","PRINCIPIO DEL INTERÉS SUPERIOR DEL NIÑO","PRINCIPIO DE LA DEBIDA DILIGENCIA","PRINCIPIO DE INTERVENCIÓN INMEDIATA Y OPORTUNA","PRINCIPIO DE SENCILLEZ Y ORALIDAD"]'::jsonb, 'PRINCIPIO DE RAZONABILIDAD Y PROPORCIONALIDAD', 0, '(texto: 2)** [TITULO I] [CAPITULO I]', '185239', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1276, 1276, 'LOS OPERADORES DE JUSTICIA Y LA POLICÍA NACIONAL DEL PERÚ, ANTE UN HECHO O AMENAZA DE VIOLENCIA, DEBEN ACTUAR EN FORMA OPORTUNA, SIN DILACIÓN POR RAZONES PROCEDIMENTALES,FORMALES O DE OTRA NATURALEZA, DISPONIENDO EL EJERCICIO DE LAS MEDIDAS DE PROTECCIÓN PREVISTAS EN LA LEY Y OTRAS NORMAS, CON LA FINALIDAD DE ATENDER EFECTIVAMENTE A LA VÍCTIMA, CONSTITUYE EL:', '["PRINCIPIO DE INTERVENCIÓN INMEDIATA Y OPORTUNA","PRINCIPIO DE IGUALDAD Y NO DISCRIMINACIÓN","PRINCIPIO DE INTERÉS SUPERIOR DEL NIÑO","PRINCIPIO DE LA DEBIDA DILIGENCIA","PRINCIPIO DE SENCILLEZ Y ORALIDAD"]'::jsonb, 'PRINCIPIO DE INTERVENCIÓN INMEDIATA Y OPORTUNA', 0, '(texto: 2)** [TITULO I] [CAPITULO I]', '185241', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1277, 1277, 'SON ACCIONES DE NATURALEZA SEXUAL QUE COMETEN CONTRA UNA PERSONA SIN SU CONSENTIMIENTO O BAJO COACCIÓN. INCLUYEN ACTOS QUE NO INVOLUCRAN PENETRACIÓN O CONTACTO FÍSICO, SE REFIERE A:', '["VIOLENCIA PSICOLÓGICA","VIOLENCIA SEXUAL","VIOLENCIA ECONÓMICA","VIOLENCIA FÍSICA","VIOLENCIA PATRIMONIAL"]'::jsonb, 'VIOLENCIA SEXUAL', 1, '(texto: 8)** [TITULO I] [CAPITULO II]', '185256', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1278, 1278, 'EN LA VIOLENCIA SEXUAL SE CONSIDERAN TALES, LA EXPOSICIÓN A MATERIAL:', '["PORNOGRÁFICO","PATRIMONIAL","REPRODUCTIVA","ESCABROSO","ECONÓMICA"]'::jsonb, 'PORNOGRÁFICO', 0, '(texto: 8)** [TITULO I] [CAPITULO II]', '185257', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1279, 1279, 'LA OBLIGACIÓN DE PROPORCIONAR INTÉRPRETES EN LENGUA DE SEÑAS PERUANA PARA LA ATENCIÓN DE DENUNCIAS DE PERSONAS CON DISCAPACIDAD AUDITIVA RECAE PRINCIPALMENTE EN:', '["EL MINISTERIO DE SALUD","EL MINISTERIO PÚBLICO","LA POLICÍA NACIONAL DEL PERÚ","EL COLEGIO DE ABOGADOS","EL PODER JUDICIAL"]'::jsonb, 'LA POLICÍA NACIONAL DEL PERÚ', 2, '(texto: (ART: 10)** Articulo 10.- Derecho a la asistencia y la proteccion integrales.)**', '185275', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1280, 1280, 'SI UNA VÍCTIMA DE VIOLENCIA REQUIERE HOSPITALIZACIÓN Y MEDICAMENTOS, ¿ESTOS SERVICIOS DEBEN SER CUBIERTOS POR EL ESTADO SEGÚN EL ARTÍCULO 10?', '["SOLO SI ES APROBADA PREVIAMENTE POR EL MINISTERIO PÚBLICO","SÍ, DE MANERA GRATUITA EN EL MARCO DE LA ATENCIÓN INTEGRAL","NO, ES RESPONSABILIDAD DE LA FAMILIA DE LA VÍCTIMA","SOLO EN CASOS CON DAÑO FÍSICO EXTREMO","SÍ, PERO ÚNICAMENTE MEDICAMENTOS NO PSIQUIÁTRICOS"]'::jsonb, 'SÍ, DE MANERA GRATUITA EN EL MARCO DE LA ATENCIÓN INTEGRAL', 1, '(texto: (ART: 10)** Articulo 10.- Derecho a la asistencia y la proteccion integrales.)**', '185280', '2026-07-14T01:12:29.113429+00:00');
