INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1290, 1290, 'LAS COMUNICACIONES QUE SON IRRELEVANTES PARA LA INVESTIGACIÓN SON ENTREGADAS A LAS PERSONAS AFECTADAS CON LA MEDIDA, ORDENÁNDOSE, BAJO RESPONSABILIDAD:', '["EL ALMACENAMIENTO DEBIDO POR EL AFECTADO","LA DESTRUCCIÓN O COPIA DE LAS MISMAS","LA DESTRUCCIÓN DE CUALQUIER TRANSCRIPCIÓN O COPIA DE LAS MISMAS","LA DESTRUCCIÓN DE CUALQUIER TRANSCRIPCIÓN O COPIA DE LOS ACTUADOS","LA INUTILIZACIÓN DE LOS MEDIOS ELECTRÓNICOS Y DE SOPORTE QUE LA CONTENGAN"]'::jsonb, 'LA DESTRUCCIÓN DE CUALQUIER TRANSCRIPCIÓN O COPIA DE LAS MISMAS', 2, '(texto: 10)** [TITULO II] [CAPITULO II]', '185318', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1291, 1291, 'TODAS LAS INSTITUCIONES Y ORGANISMOS DEL ESTADO, FUNCIONARIOS Y SERVIDORES PÚBLICOS, ASÍ COMO LAS PERSONAS NATURALES O JURÍDICAS DEL SECTOR PRIVADO, ESTÁN OBLIGADAS A PRESTAR SU COLABORACIÓN CUANDO:', '["LES SEA REQUERIDA PARA EL ESCLARECIMIENTO DE LOS DELITOS FLAGRANTES Y VIOLENTOS","LES SEA REQUERIDA PARA EL JUZGAMIENTO DE LOS DELITOS REGULADOS POR LA PRESENTE LEY","LES SEA REQUERIDA PARA LA INVESTIGACIÓN DE LOS DELITOS PENALES SOMETIDOS A SU JURISDICCIÓN","LES SEA REQUERIDA PARA EL ESCLARECIMIENTO DE LOS DELITOS REGULADOS POR LA PRESENTE LEY","LES SEA REQUERIDA PARA EL JUICIO DE LOS DELITOS REGULADOS POR LA PRESENTE LEY"]'::jsonb, 'LES SEA REQUERIDA PARA EL ESCLARECIMIENTO DE LOS DELITOS REGULADOS POR LA PRESENTE LEY', 3, '(texto: 15)** [TITULO II] [CAPITULO II]', '185322', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1292, 1292, 'EL INCUMPLIMIENTO DEL DEBER DE COLABORACIÓN Y DE CONFIDENCIALIDAD DE LAS INSTITUCIONES Y ENTIDADES PÚBLICAS Y PRIVADAS ACARREA:', '["RESPONSABILIDAD PENAL Y CIVIL, SEGÚN CORRESPONDA","RESPONSABILIDAD PENAL, CIVIL O ADMINISTRATIVA, SEGÚN CORRESPONDA","RESPONSABILIDAD PENAL Y FUNCIONAL, SEGÚN CORRESPONDA","RESPONSABILIDAD ANTE LA LEY Y LA SOCIEDAD, SEGÚN CORRESPONDA","RESPONSABILIDAD LEGAL, SOCIAL Y ECONÓMICA, SEGÚN CORRESPONDA"]'::jsonb, 'RESPONSABILIDAD PENAL, CIVIL O ADMINISTRATIVA, SEGÚN CORRESPONDA', 1, '(texto: 15)** [TITULO II] [CAPITULO II]', '185323', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1293, 1293, 'TODO PROCESO SEGUIDO CONTRA INTEGRANTES DE UNA ORGANIZACIÓN CRIMINAL, PERSONAS VINCULADAS A ELLA O QUE ACTÚAN POR ENCARGO DE LA MISMA, SE CONSIDERA:', '["ULTRASECRETO","CONFIDENCIAL","PÚBLICO","PRIVADO","COMPLEJO"]'::jsonb, 'COMPLEJO', 4, '(texto: 6)** [TITULO II] [CAPITULO I]', '185324', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1294, 1294, 'AGRAVANTES ESPECIALES.- EL JUEZ AUMENTA LA PENA HASTA EN UNA TERCERA PARTE POR ENCIMA DEL MÁXIMO LEGAL FIJADO POR EL DELITO COMETIDO, SIN QUE EN NINGÚN CASO PUEDA EXCEDER LOS TREINTA Y CINCO AÑOS, EN LOS SIGUIENTES SUPUESTOS:', '["SI EL AGENTE ES LÍDER, JEFE EJERCE FUNCIONES DE ADMINISTRACIÓN, SUPERVISIÓN, Y OPERATIVIZACIÓN DE LA ORGANIZACIÓN CRIMINAL","SI EL AGENTE ES LÍDER, JEFE O CABECILLA O EJERCE FUNCIONES DE ADMINISTRACIÓN, DIRECCIÓN Y SUPERVISIÓN DE LA ORGANIZACIÓN CRIMINAL","SI EL AGENTE ES LÍDER, JEFE O CABECILLA O EJERCE FUNCIONES DE ADMINISTRACIÓN, DIRECCIÓN DE LA ORGANIZACIÓN CRIMINAL","SI EL AGENTE ES LÍDER, CABECILLA O EJERCE FUNCIONES DE ADMINISTRACIÓN, DIRECCIÓN Y FISCALIZACIÓN DE LA ORGANIZACIÓN CRIMINAL","SI EL DETENIDO ES LÍDER O CABECILLA O EJERCE FUNCIONES DE DIRECCIÓN DE LA ORGANIZACIÓN DELINCUENCIAL"]'::jsonb, 'SI EL AGENTE ES LÍDER, JEFE O CABECILLA O EJERCE FUNCIONES DE ADMINISTRACIÓN, DIRECCIÓN Y SUPERVISIÓN DE LA ORGANIZACIÓN CRIMINAL', 1, '(texto: 22)** [TITULO II] [CAPITULO VI]', '185328', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1295, 1295, 'AGRAVANTES ESPECIALES.- EL JUEZ AUMENTA LA PENA HASTA EN UNA TERCERA PARTE POR ENCIMA DEL MÁXIMO LEGAL FIJADO POR EL DELITO COMETIDO, SIN QUE EN NINGÚN CASO PUEDA EXCEDER LOS TREINTA Y CINCO AÑOS, EN LOS SIGUIENTES SUPUESTOS:', '["SI EL AGENTE, EN CONDICIÓN DE INTEGRANTE DE LA ORGANIZACIÓN CRIMINAL O PERSONA VINCULADA A ELLA O QUE ACTÚA POR ENCARGO DE LA MISMA, ES FUNCIONARIO O SERVIDOR PÚBLICO","SI EL AGENTE, EN CONDICIÓN DE EX INTEGRANTE DE LA ORGANIZACIÓN CRIMINAL O PERSONA VINCULADA A ELLA, ES SERVIDOR PÚBLICO O AUTORIDAD ELEGIDA","SI EL AGENTE, EN CONDICIÓN DE INTEGRANTE DE LA ORGANIZACIÓN CRIMINAL O PERSONA VINCULADA A ELLA, ES FUNCIONARIO PÚBLICO","SI EL AGENTE, EN CONDICIÓN DE INTEGRANTE DE LA ORGANIZACIÓN CRIMINAL O PERSONA VINCULADA A ELLA, ES SERVIDOR","SI EL AGENTE, EN CONDICIÓN DE INTEGRANTE DE LA ORGANIZACIÓN CRIMINAL O PERSONA NO VINCULADA A ELLA, ES AUTORIDAD ELEGIDA POR MANDATO POPULAR"]'::jsonb, 'SI EL AGENTE, EN CONDICIÓN DE INTEGRANTE DE LA ORGANIZACIÓN CRIMINAL O PERSONA VINCULADA A ELLA O QUE ACTÚA POR ENCARGO DE LA MISMA, ES FUNCIONARIO O SERVIDOR PÚBLICO', 0, '(texto: 22)** [TITULO II] [CAPITULO VI]', '185330', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1319, 1319, 'SI EL PERSONAL POLICIAL CONSTATA QUE EL/LA RETENIDO/A REGISTRA ALGUNA REQUISITORIA PENDIENTE, LO PONDRÁ A DISPOSICIÓN DE LA OFICINA DE REQUISITORIAS DE LA PNP MEDIANTE EL DOCUMENTO RESPECTIVO, SIN PERJUICIO DE COMUNICAR TAL SITUACIÓN A:', '["EL/LA FISCAL","AL JEFE DE UNIDAD","EL JUEZ","EL JEFE INMEDIATO SUPERIOR","AL COMANDO POLICIAL"]'::jsonb, 'EL/LA FISCAL', 0, 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL ESPECÍFICO DE CONTROL DE IDENTIDAD. DILIGENCIAS EN LA DEPENDENCIA POLICIAL', '185704', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1296, 1296, 'SI CUALQUIERA DE LOS DELITOS PREVISTOS EN LA PRESENTE LEY HAN SIDO COMETIDOS EN EJERCICIO DE LA ACTIVIDAD DE UNA PERSONA JURÍDICA O VALIÉNDOSE DE SU ESTRUCTURA ORGANIZATIVA PARA FAVORECERLO, FACILITARLO O ENCUBRIRLO, EL JUEZ DEBE IMPONER, ATENDIENDO A LA GRAVEDAD Y NATURALEZA DE LOS HECHOS, LA RELEVANCIA DE LA INTERVENCIÓN DE LA PERSONA JURÍDICA EN EL DELITO Y LAS CARACTERÍSTICAS PARTICULARES DE LA ORGANIZACIÓN CRIMINAL, CUALQUIERA DE LAS SIGUIENTES CONSECUENCIAS ACCESORIAS DE FORMA ALTERNATIVA O CONJUNTA:', '["CLAUSURA TEMPORAL DE LOCALES O ESTABLECIMIENTOS","CLAUSURA INMEDIATA DE LOCALES O ESTABLECIMIENTOS","CLAUSURA DEFINITIVA DE LOCALES O ESTABLECIMIENTOS","CLAUSURA PROLONGADA DE LOCALES O ESTABLECIMIENTOS","CLAUSURA MUNICIPAL DE LOCALES O ESTABLECIMIENTOS"]'::jsonb, 'CLAUSURA DEFINITIVA DE LOCALES O ESTABLECIMIENTOS', 2, '(texto: 23)** [TITULO II] [CAPITULO VI]', '185337', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1297, 1297, 'SI CUALQUIERA DE LOS DELITOS PREVISTOS EN LA PRESENTE LEY HAN SIDO COMETIDOS EN EJERCICIO DE LA ACTIVIDAD DE UNA PERSONA JURÍDICA O VALIÉNDOSE DE SU ESTRUCTURA ORGANIZATIVA PARA FAVORECERLO, FACILITARLO O ENCUBRIRLO, EL JUEZ DEBE IMPONER, ATENDIENDO A LA GRAVEDAD Y NATURALEZA DE LOS HECHOS, LA RELEVANCIA DE LA INTERVENCIÓN DE LA PERSONA JURÍDICA EN EL DELITO Y LAS CARACTERÍSTICAS PARTICULARES DE LA ORGANIZACIÓN CRIMINAL, CUALQUIERA DE LAS SIGUIENTES CONSECUENCIAS ACCESORIAS DE FORMA ALTERNATIVA O CONJUNTA:', '["DISOLUCIÓN DE LA PERSONA JURÍDICA","DISOLUCIÓN DE LA PERSONA NATURAL","CANCELACIÓN DE LA PERSONA NATURAL","TERMINACIÓN DE LA PERSONA JURÍDICA","DESACTIVACIÓN DE LA PERSONA NATURAL"]'::jsonb, 'DISOLUCIÓN DE LA PERSONA JURÍDICA', 0, '(texto: 23)** [TITULO II] [CAPITULO VI]', '185341', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1298, 1298, 'ACTOS DE COOPERACIÓN O ASISTENCIA INTERNACIONAL.- EN ESPECIAL LOS ACTOS DE COOPERACION Y ASISTENCIA SON LOS SIGUIENTES:', '["CUALQUIER OTRA FORMA DE COOPERACION O ASISTENCIA JUDICIAL AUTORIZADA POR EL DERECHO INTERNO","ASISTENCIA A OTROS ESTADOS EN ACTUACIONES JUDICIALES, ACTOS DE INVESTIGACIÓN Y PROCESOS JUDICIALES","CUALQUIER OTRA FROMA DE COOPERACION O ASISTENCIA EXTRA JUDICIAL AUTORIZADA POR EL DERECHO INTERNO","APOYO LOGÍSTICO A OTROS ESTADOS EN ACTUACIONES OPERATIVAS, ACTOS DE INVESTIGACIÓN Y PROCESOS JUDICIALES","CUALQUIER OTRA FORMA DE COOPERACION O ASISTENCIA JUDICIAL AUTORIZADA POR EL DERECHO EXTERNO"]'::jsonb, 'CUALQUIER OTRA FORMA DE COOPERACION O ASISTENCIA JUDICIAL AUTORIZADA POR EL DERECHO INTERNO', 0, '(texto: 28)** [TITULO III]', '185343', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1299, 1299, 'ACTOS DE COOPERACIÓN O ASISTENCIA INTERNACIONAL.- EN ESPECIAL, LOS ACTOS DE COOPERACIÓN Y ASISTENCIA, SON LOS SIGUIENTES:', '["RECIBIR DONACIONES MATERIALES","ACEPTAR FINANCIAMIENTO ECONÓMICO","EMITIR COPIA CERTIFICADA DE DOCUMENTOS","INTERCAMBIO CULTURAL PERMANENTE","PROTOCOLOS UNIFICADOS DE ACTUACIÓN"]'::jsonb, 'EMITIR COPIA CERTIFICADA DE DOCUMENTOS', 2, '(texto: 28)** [TITULO III]', '185344', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1302, 1302, 'RESPECTO AL CONCEPTO DE CAPACIDAD OPERATIVA EN LA ORGANIZACIÓN CRIMINAL, LA LEY 30077 ESTABLECE QUE:', '["SE REFIERE ÚNICAMENTE AL EQUIPAMIENTO TECNOLOGICO DEL GRUPO","CONSISTE EN LA SUMA DE MEDIOS Y RECURSOS IDONEOS, DE HECHO O DE DERECHO, IDÓNEOS PARA DESARROLLAR EL PROGRAMA CRIMINAL","INVOLUCRA SOLO A DOS MIEMBROS INVOLUCRADOS EN EL GRUPO","ESTÁ LIMITADA A LOS RECURSOS OBTENIDOS DE ACTIVIDADES LÍCITAS","SE LIMITA A MEDIOS TECNOLÓGICOS DE COMUNICACIÓN EXTERNA"]'::jsonb, 'CONSISTE EN LA SUMA DE MEDIOS Y RECURSOS IDONEOS, DE HECHO O DE DERECHO, IDÓNEOS PARA DESARROLLAR EL PROGRAMA CRIMINAL', 1, '(texto: (ART: 2)** Artículo 2.- Definición y criterios para determinar la existencia de una organización criminal.)**', '185351', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1303, 1303, 'DE ACUERDO A LA LEY 30077, ¿CUÁL DE LOS SIGUIENTES DELITOS NO FORMARÍA PARTE DE LA DEFINICIÓN DE ORGANIZACIÓN CRIMINAL SI SU PENALIDAD MÍNIMA FUERA INFERIOR A CINCO AÑOS DE PRISIÓN?', '["SICARIATO Y MUERTE VIOLENTA ESTABLECIDO CON UNA PENA MÍNIMA DE SEIS AÑOS","EXTORSIÓN CON UNA PENA MÍNIMA DE SIETE AÑOS","ROBO AGRAVADO CON PENA MÍNIMA DE CINCO AÑOS","DELITO DE INJURIA SIMPLE CON PENA MENOR A DOS AÑOS","SECUESTRO SIMPLE CON PENA MÍNIMA DE OCHO AÑOS"]'::jsonb, 'DELITO DE INJURIA SIMPLE CON PENA MENOR A DOS AÑOS', 3, '(texto: (ART: 2)** Artículo 2.- Definición y criterios para determinar la existencia de una organización criminal.)**', '185352', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1304, 1304, '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS REFLEJA EL CRITERIO LEGAL SOBRE LA PERMANENCIA TEMPORAL DE UNA ORGANIZACIÓN CRIMINAL SEGÚN LA LEY 30077?', '["EL GRUPO DEBE OPERAR ÚNICAMENTE DURANTE LA COMISIÓN DEL DELITO Y LUEGO DISOLVERSE","LA TEMPORALIDAD ES IRRELEVANTE MIENTRAS EXISTA UN BENEFICIO ECONÓMICO","DEBE SER UN GRUPO DE CARÁCTER PERMANENTE O POR TIEMPO INDEFINIDO, NO FORTUITO","LOS MIEMBROS PUEDEN REUNIRSE FORTUITAMENTE PARA CALIFICAR COMO ORGANIZACIÓN CRIMINAL","LA PERMANENCIA SE DETERMINA POR LA NOTORIEDAD PÚBLICA DEL GRUPO"]'::jsonb, 'DEBE SER UN GRUPO DE CARÁCTER PERMANENTE O POR TIEMPO INDEFINIDO, NO FORTUITO', 2, '(texto: (ART: 2)** Artículo 2.- Definición y criterios para determinar la existencia de una organización criminal.)**', '185353', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1305, 1305, '¿EN QUÉ CASOS UNA ORGANIZACIÓN CRIMINAL PODRÍA PERSEGUIR UNA FINALIDAD DISTINTA A LA OBTENCIÓN DE UN BENEFICIO ECONÓMICO SEGÚN LA LEY 30077?', '["CUANDO SU FINALIDAD ES ÚNICAMENTE POLÍTICA O IDEOLÓGICA","CUANDO OBTENGA BENEFICIO INDIRECTO DE ORDEN MATERIAL, ADEMÁS DEL ECONÓMICO","CUANDO SUS ACTIVIDADES SEAN EXCLUSIVAMENTE FILANTRÓPICAS","CUANDO OBTIENE ÚNICAMENTE NOTORIEDAD SOCIAL","EN NINGÚN CASO, SÓLO PROCEDE EL BENEFICIO ECONÓMICO"]'::jsonb, 'CUANDO OBTENGA BENEFICIO INDIRECTO DE ORDEN MATERIAL, ADEMÁS DEL ECONÓMICO', 1, '(texto: (ART: 2)** Artículo 2.- Definición y criterios para determinar la existencia de una organización criminal.)**', '185356', '2026-07-14T01:12:29.113429+00:00');
