INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1327, 1327, 'ES TODO ESPACIO FÍSICO, INCLUIDAS LAS ZONAS ADYACENTES, DONDE PRESUNTAMENTE SE HA PERPETRADO O SE HA DEJADO RASTROS DE UNO O MÁS HECHOS PUNIBLES, Y DONDE SE HALLAN INDICIOS Y EVIDENCIAS RELACIONADAS CON EL HECHO A INVESTIGAR. EL PRESENTE CONCEPTO CORRESPONDE A:', '["LUGAR DE INTERVENCIÓN","ESCENA ABIERTA","ESCENA DEL CRIMEN","ESCENA CERRADA","ESCENA MIXTA"]'::jsonb, 'ESCENA DEL CRIMEN', 2, 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL DE PROTECCIÓN E INVESTIGACIÓN DE LA ESCENA DEL CRIMEN. CONCEPTO DE ESCENA DEL CRIMEN', '185712', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1328, 1328, 'PARA EL AISLAMIENTO DEBERÁN EMPLEAR UN MECANISMO IDÓNEO PARA SU DEMARCACIÓN Y ACORDONAMIENTO (CINTA PLÁSTICA, CORDELES, ETC.), DEFINIENDO ADECUADAMENTE SUS LÍMITES Y… (MARQUE LA ALTERNATIVA CORRECTA)', '["SE REALIZA LA INSPECCIÓN TÉCNICO POLICIAL","SE REALIZA IMÁGENES FOTOGRÁFICAS","ESTABLECIENDO LAS VÍAS DE ENTRADA Y SALIDA DE LA ESCENA AISLADA","SE COMUNICA AL JEFE DE UNIDAD","SE COMUNICA AL JUEZ"]'::jsonb, 'ESTABLECIENDO LAS VÍAS DE ENTRADA Y SALIDA DE LA ESCENA AISLADA', 2, 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL DE PROTECCIÓN E INVESTIGACIÓN DE LA ESCENA DEL CRIMEN. PROTECCIÓN DE LA ESCENA', '185714', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1329, 1329, 'EL EQUIPO QUE TENDRÁ A SU CARGO EL PROCESAMIENTO DE LA ESCENA, ESTARÁ CONFORMADO POR: (MARQUE LA ALTERNATIVA CORRECTA)', '["EL REPRESENTANTE DEL MINISTERIO PÚBLICO","EL REPRESENTANTE DEL PODER JUDICIAL","LOS EFECTIVOS POLICIALES DEL SISTEMA DE INTELIGENCIA POLICIAL","EL PRESENTANTE DE LOS AGRAVIADOS","EFECTIVOS POLICIALES DEL SISTEMA CRIMINALÍSTICO POLICIAL"]'::jsonb, 'EFECTIVOS POLICIALES DEL SISTEMA CRIMINALÍSTICO POLICIAL', 4, 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL DE PROTECCIÓN E INVESTIGACIÓN DE LA ESCENA DEL CRIMEN. PROCESAMIENTO E INVESTIGACIÓN DE LA ESCENA DEL CRIMEN', '185716', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1330, 1330, 'EN CASO DE EXISTIR UN SOSPECHOSO, EL PERSONAL POLICIAL POLICÍA TOMARÁ EL CONTROL DE DICHA PERSONA TOMANDO LAS MEDIDAS DE SEGURIDAD CORRESPONDIENTES, A FIN DE EVITAR SU FUGA; DE SER EL CASO, … (MARQUE LA ALTERNATIVA CORRECTA)', '["PROCEDERÁ A DETENERLO","INDAGAR SUS ANTECEDENTES","LO PONDRÁ A DISPOSICIÓN DEL FISCAL DE TURNO","LO PONDRÁ A DISPOSICIÓN DE LA UNIDAD POLICIAL MÁS CERCANA","LO IDENTIFICARÁ PLENAMENTE"]'::jsonb, 'PROCEDERÁ A DETENERLO', 0, 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL DE PROTECCIÓN E INVESTIGACIÓN DE LA ESCENA DEL CRIMEN. PROCESAMIENTO E INVESTIGACIÓN DE LA ESCENA DEL CRIMEN', '185718', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1331, 1331, '¿CUÁL ES EL ÁMBITO DE ACTUACIÓN JURISDICCIONAL DE LA INVESTIGACIÓN REALIZADA POR LA POLICÍA NACIONAL DEL PERÚ BAJO LA CONDUCCIÓN JURÍDICA DEL MINISTERIO PÚBLICO SEGÚN LA MODIFICACIÓN DE LA LEY 32130:', '["LA INVESTIGACIÓN POLICIAL TIENE CARÁCTER JURISDICCIONAL PLENO DESDE SU INICIO, PERMITIENDO A LA POLICÍA NACIONAL RESOLVER ASPECTOS SUSTANTIVOS DEL PROCESO PENAL","LA INVESTIGACIÓN POLICIAL, BAJO LA CONDUCCIÓN DEL MINISTERIO DEL INTERIOR, ADQUIERE CARÁCTER JURISDICCIONAL ÚNICAMENTE EN CASOS DE FLAGRANCIA DELICTIVA","LA INVESTIGACIÓN POLICIAL, BAJO CONDUCCIÓN DEL MINISTERIO PÚBLICO, NO TIENE CARÁCTER JURISDICCIONAL, DEBIENDO REQUERIRSE DECISIÓN JURISDICCIONAL AL ÓRGANO COMPETENTE CUANDO SEA INDISPENSABLE","LA INVESTIGACIÓN POLICIAL ES DE NATURALEZA JURISDICCIONAL SOLO CUANDO INTERVIENEN PERITOS EXTERNOS DESIGNADOS POR EL JUEZ PENAL","LA INVESTIGACIÓN POLICIAL Y LA FISCALÍA COMPARTEN COMPETENCIA JURISDICCIONAL EN IGUALDAD DE CONDICIONES DURANTE TODA LA ETAPA DE INVESTIGACIÓN PRELIMINAR"]'::jsonb, 'LA INVESTIGACIÓN POLICIAL, BAJO CONDUCCIÓN DEL MINISTERIO PÚBLICO, NO TIENE CARÁCTER JURISDICCIONAL, DEBIENDO REQUERIRSE DECISIÓN JURISDICCIONAL AL ÓRGANO COMPETENTE CUANDO SEA INDISPENSABLE', 2, '(texto: (ART: UNICO)**Articulo IV. Titular de la accion Penal)**', '184850', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1342, 1342, '¿QUÉ OCURRE SI DURANTE LA INVESTIGACIÓN PRELIMINAR, LA POLICÍA NACIONAL DEL PERÚ REALIZA ACTOS DE INVESTIGACIÓN SIN CUMPLIR LAS FORMALIDADES PRECISADAS POR EL FISCAL?', '["ESOS ACTOS PODRÍAN CARECER DE VALIDEZ CONFORME A LO DISPUESTO POR LA NORMA","SE DEBEN REMITIR DE INMEDIATO A LA FISCALÍA DE LA NACIÓN","DEBEN SER CORREGIDOS POR LA DEFENSA DEL IMPUTADO","SON AUTOMÁTICAMENTE VÁLIDOS Y NO REQUIEREN REVISIÓN","PUEDEN SER SUBSANADOS POR LA CORTE SUPERIOR PENAL"]'::jsonb, 'ESOS ACTOS PODRÍAN CARECER DE VALIDEZ CONFORME A LO DISPUESTO POR LA NORMA', 0, '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184874', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1332, 1332, 'SEGÚN LA LEY 32130, ¿CUÁL ES LA FUNCIÓN PRIMORDIAL DEL MINISTERIO PÚBLICO EN RELACIÓN CON LA POLICÍA NACIONAL DURANTE LA INVESTIGACIÓN PRELIMINAR DE UN DELITO:', '["EMITIR RESOLUCIONES JURISDICCIONALES REEMPLAZANDO AL JUEZ PENAL EN ACTOS DE URGENCIA","DIRIGIR JURÍDICAMENTE LA INVESTIGACIÓN ORIENTANDO LEGALMENTE LAS ACCIONES DE LA POLICÍA NACIONAL DEL PERÚ DENTRO DE LOS PARÁMETROS DE LA LEY","REALIZAR DE MANERA INDEPENDIENTE LA INTERVENCIÓN POLICIAL SIN COORDINACIÓN INTERINSTITUCIONAL","SUPERVISAR ÚNICAMENTE LA RECOLECCIÓN DE PRUEBAS FÍSICAS Y DOCUMENTALES SIN INDAGAR SOBRE LA INOCENCIA DEL IMPUTADO","DESIGNAR A LOS ABOGADOS DEFENSORES PÚBLICOS EN TODOS LOS CASOS QUE INVESTIGUE LA POLICÍA"]'::jsonb, 'DIRIGIR JURÍDICAMENTE LA INVESTIGACIÓN ORIENTANDO LEGALMENTE LAS ACCIONES DE LA POLICÍA NACIONAL DEL PERÚ DENTRO DE LOS PARÁMETROS DE LA LEY', 1, '(texto: (ART: UNICO)**Articulo IV. Titular de la accion Penal)**', '184851', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1333, 1333, 'DE ACUERDO CON LA LEY 32130, ¿CUÁL ES LA RELACIÓN JERÁRQUICA Y FUNCIONAL ENTRE EL MINISTERIO PÚBLICO Y LA POLICÍA NACIONAL EN EL MARCO DE LA INVESTIGACIÓN DEL DELITO:', '["LA POLICÍA NACIONAL DIRIGE AUTÓNOMAMENTE LA INVESTIGACIÓN Y EL MINISTERIO PÚBLICO SOLO REVISA EL INFORME FINAL","LA POLICÍA NACIONAL EJERCE INICIATIVA PLENA EN LA PRODUCCIÓN DE PRUEBAS Y EL MINISTERIO PÚBLICO SE LIMITA A AUTORIZARLAS RETROACTIVAMENTE","EL MINISTERIO PÚBLICO ASUME LA CONDUCCIÓN JURÍDICA DE LA INVESTIGACIÓN Y LA POLICÍA NACIONAL REALIZA LA INVESTIGACIÓN PRELIMINAR CONFORME A SU LEYES Y REGLAMENTOS","AMBOS ÓRGANOS ACTÚAN EN PIE DE IGUALDAD EN LA TOMA DE DECISIONES JURÍDICAS DURANTE LA INVESTIGACIÓN PRELIMINAR","LA POLICÍA NACIONAL SOLO INTERVIENE CUANDO EL JUEZ PENAL LO AUTORIZA, ACTUANDO BAJO CONTROL JUDICIAL DIRECTO"]'::jsonb, 'EL MINISTERIO PÚBLICO ASUME LA CONDUCCIÓN JURÍDICA DE LA INVESTIGACIÓN Y LA POLICÍA NACIONAL REALIZA LA INVESTIGACIÓN PRELIMINAR CONFORME A SU LEYES Y REGLAMENTOS', 2, '(texto: (ART: UNICO)**Articulo IV. Titular de la accion Penal)**', '184854', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1334, 1334, 'CONFORME AL ARTÍCULO 60 DEL CÓDIGO PROCESAL PENAL TRAS LA MODIFICACIÓN POR LA LEY 32130, ¿BAJO QUÉ PRINCIPIO DEBE EL FISCAL CONDUCIR LA INVESTIGACIÓN PREPARATORIA DEL DELITO:', '["BAJO EL PRINCIPIO DE OPORTUNIDAD, PROMOVIENDO LA CONCILIACIÓN ENTRE LAS PARTES","BAJO EL PRINCIPIO DE LEGALIDAD, ASEGURANDO LA CORRECTA APLICACIÓN DE LA NORMA","BAJO EL PRINCIPIO DE ARBITRARIEDAD, ACTUANDO SEGÚN SU PROPIO CRITERIO","BAJO EL PRINCIPIO DE EJECUCIÓN DIRECTA Y MATERIAL DE LAS ACCIONES POLICIALES","BAJO EL PRINCIPIO DE AUTONOMÍA ABSOLUTA DE LA POLICÍA NACIONAL DEL PERÚ SIN INTERVENCIÓN DEL MINISTERIO PÚBLICO"]'::jsonb, 'BAJO EL PRINCIPIO DE LEGALIDAD, ASEGURANDO LA CORRECTA APLICACIÓN DE LA NORMA', 1, '(texto: (ART: UNICO)**Articulo 60. Funciones)**', '184860', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1335, 1335, '¿CUÁL ES EL PLAZO MÁXIMO QUE TIENE EL FISCAL PARA DISPONER EL INICIO DE LA INVESTIGACIÓN PRELIMINAR EN CASO DE DELITOS DE TRÁFICO ILÍCITO DE DROGAS, TERRORISMO, SICARIATO, EXTORSIÓN, SECUESTRO, FEMINICIDIO Y CRIMINALIDAD ORGANIZADA:', '["DOCE HORAS","TREINTA Y SEIS HORAS","CUARENTA Y OCHO HORAS","VEINTICUATRO HORAS","SETENTA Y DOS HORAS"]'::jsonb, 'VEINTICUATRO HORAS', 3, '(texto: (ART: UNICO)**Articulo 61. Atribuciones y obligaciones)**', '184861', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1336, 1336, '¿CUÁL DE LAS SIGUIENTES ACCIONES ES UNA ATRIBUCIÓN Y/O OBLIGACION DIRECTA DEL FISCAL, CONFORME AL ARTÍCULO 61 DE LA PRESENTE LEY:', '["EMITIR SENTENCIAS DE PRIMERA INSTANCIA","SOLICITAR AL JUEZ LAS MEDIDAS QUE CONSIDERE NECESARIAS CUANDO CORRESPONDA HACERLO","ORDENAR LA DETENCIÓN SIN INTERVENCIÓN JUDICIAL","OTORGAR PERMISOS DE LIBERTAD PROVISORIA","EJERCER FUNCIONES DE DEFENSOR PÚBLICO"]'::jsonb, 'SOLICITAR AL JUEZ LAS MEDIDAS QUE CONSIDERE NECESARIAS CUANDO CORRESPONDA HACERLO', 1, '(texto: (ART: UNICO)**Articulo 61. Atribuciones y obligaciones)**', '184864', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1337, 1337, 'DE ACUERDO CON EL ARTÍCULO 65, CUANDO EL FISCAL DISPONE EL INICIO DE LA INVESTIGACIÓN PRELIMINAR, ¿QUÉ DEBE PRECISARSE NECESARIAMENTE?:', '["EL OBJETO, LOS PLAZOS Y LAS FORMALIDADES ESPECÍFICAS APLICABLES","LA DESIGNACIÓN DE UN PERITO OFICIAL","EL MONTO DE LAS REPARACIONES CIVILES","EL JUEZ QUE SUPERVISARÁ LA INVESTIGACIÓN","EL PRONUNCIAMIENTO SOBRE LA CULPABILIDAD DEL IMPUTADO"]'::jsonb, 'EL OBJETO, LOS PLAZOS Y LAS FORMALIDADES ESPECÍFICAS APLICABLES', 0, '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184867', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1338, 1338, 'SEGÚN LA MODIFICACIÓN INTRODUCIDA POR LA LEY 32130, ¿A QUIÉN CORRESPONDE DEFINIR LA ESTRATEGIA OPERATIVA EN LA INVESTIGACIÓN DEL DELITO?:', '["AL JUEZ DE GARANTÍAS","AL FISCAL EN TODO MOMENTO Y SIN EXCEPCIÓN","A LA POLICÍA NACIONAL DEL PERÚ","A LA CORTE SUPERIOR DE JUSTICIA","A LA DEFENSA TÉCNICA DEL IMPUTADO"]'::jsonb, 'A LA POLICÍA NACIONAL DEL PERÚ', 2, '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184868', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1339, 1339, '¿QUÉ ASPECTO DEBEN GARANTIZAR TANTO EL FISCAL COMO LA POLICÍA NACIONAL DEL PERÚ DURANTE LA INVESTIGACIÓN DEL DELITO, SEGÚN EL ARTÍCULO 65 DE LA LEY N°32130?:', '["EL RESARCIMIENTO ECONÓMICO DE LA VÍCTIMA","EL DERECHO DE DEFENSA DEL IMPUTADO Y SUS DEMAS DERECHOS FUNDAMENTALES","LA OBTENCIÓN DE PRUEBAS SIN LÍMITES LEGALES CUANDO SE TRATE DE DELITOS GRAVES","LA PARTICIPACIÓN DE LA PRENSA EN TODAS LAS DILIGENCIAS","EL SECRETO ABSOLUTO DE LAS ACTUACIONES"]'::jsonb, 'EL DERECHO DE DEFENSA DEL IMPUTADO Y SUS DEMAS DERECHOS FUNDAMENTALES', 1, '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184869', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1340, 1340, '¿CUÁL ES LA RELACIÓN ENTRE LA ESTRATEGIA JURÍDICA Y LA ESTRATEGIA OPERATIVA SEGÚN LA LEY 32130?:', '["AMBAS ESTRATEGIAS SON DIRIGIDAS POR LA POLICÍA NACIONAL DEL PERÚ","LA ESTRATEGIA JURÍDICA ES COMPETENCIA DEL FISCAL Y LA OPERATIVA DE LA POLICÍA, PERO DEBEN SER PROGRAMADAS Y COORDINADAS EN CONJUNTO","LA ESTRATEGIA JURÍDICA Y LA OPERATIVA SÓLO LAS DEFINE EL JUEZ PENAL","EL FISCAL DEFINE LA OPERATIVA Y LA POLICÍA LA JURÍDICA","AMBAS ESTRATEGIAS NO REQUIEREN COORDINACIÓN"]'::jsonb, 'LA ESTRATEGIA JURÍDICA ES COMPETENCIA DEL FISCAL Y LA OPERATIVA DE LA POLICÍA, PERO DEBEN SER PROGRAMADAS Y COORDINADAS EN CONJUNTO', 1, '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184870', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1341, 1341, 'EN LA INVESTIGACIÓN DEL DELITO CONFORME AL ARTÍCULO 65, ¿QUÉ DEBE HACER EL FISCAL RESPECTO A LAS DILIGENCIAS PRACTICADAS POR LA POLICÍA NACIONAL DEL PERÚ?:', '["REGISTRAR EN AUDIO Y VIDEO TODAS LAS DILIGENCIAS","REALIZAR LAS FORMALIDADES ESPECIFICAS QUE DEBEN REUNIR LOS ACTOS DE INVESTIGACION PARA GARANTIZAR SU VALIDEZ","NO INTERVENIR BAJO NINGUNA CIRCUNSTANCIA","SOLICITAR LA APROBACIÓN DE LA CORTE SUPREMA ANTES DE CADA DILIGENCIA","ADMINISTRAR LOS FONDOS PARA QUE SE REALICEN LAS DILIGENCIAS"]'::jsonb, 'REALIZAR LAS FORMALIDADES ESPECIFICAS QUE DEBEN REUNIR LOS ACTOS DE INVESTIGACION PARA GARANTIZAR SU VALIDEZ', 1, '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184871', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1436, 1436, 'LAS EMOCIONES COMO LA CÓLERA, LA IRA, LA COMPASIÓN, EL MIEDO, ENTRE OTRAS, SON ESTADOS DE ÁNIMO QUE INFLUYEN DIRECTAMENTE EN EL ACCIONAR DEL PERSONAL POLICIAL. ESTE ENUNCIADO ESTÁ RELACIONADO A:', '["VERBALIZACIÓN","USO DE LA FUERZA","MANEJO DE EQUIPO","CONTROL DE EMOCIONES E INTELIGENCIA EMOCIONAL","ENTRENAMIENTO FÍSICO"]'::jsonb, 'CONTROL DE EMOCIONES E INTELIGENCIA EMOCIONAL', 3, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186023', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1343, 1343, 'DE TODAS LAS DILIGENCIAS DE INVESTIGACIÓN REALIZADAS POR LA POLICÍA NACIONAL DEL PERÚ BAJO CONDUCCIÓN FISCAL, ¿QUE DOCUMENTOS FORMULARAN RESPETANDO LAS FORMALIDADES PREVISTAS PARA LA INVESTIGACION?:', '["SÓLO DEBEN ENVIARSE RESÚMENES EJECUTIVOS AL FISCAL","LAS ACTAS DETALLADAS LAS QUE ENTREGARA AL FISCAL Y EMITIRA EL INFORME POLICIAL","LAS ACTAS SÓLO SON REQUERIDAS CUANDO SE TRATA DE DELITOS GRAVES O COMPLEJOS, NO EN DELITOS SIMPLES","LAS ACTAS E INFORMES DEBEN REMITIRSE EXCLUSIVAMENTE AL JUEZ DE INVESTIGACIÓN PREPARATORIA","ELABORAR ACTAS DETALLADAS ES OPTATIVO, DEPENDIENDO DEL CRITERIO DEL COMISARIO RESPONSABLE"]'::jsonb, 'LAS ACTAS DETALLADAS LAS QUE ENTREGARA AL FISCAL Y EMITIRA EL INFORME POLICIAL', 1, '(texto: (ART: UNICO)** Articulo 68. Funcion de investigacion de la Policia Nacional del Peru)**', '184879', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1344, 1344, 'DURANTE LA INVESTIGACIÓN PREPARATORIA, ¿QUÉ FUNCIÓN PUEDE EJERCER EL FISCAL RESPECTO A LA ACTUACIÓN DE LA POLICÍA NACIONAL DEL PERÚ SEGÚN LA MODIFICACIÓN LEGAL?', '["EL FISCAL PUEDE PRESCINDIR COMPLETAMENTE DE LA POLICÍA DURANTE TODA LA INVESTIGACIÓN PREPARATORIA","EL FISCAL PUEDE REQUERIR LA ACTUACIÓN POLICIAL DENTRO DEL MARCO DE LAS ATRIBUCIONES RECONOCIDAS EN LA LEY","EL FISCAL SOLO PUEDE RECURRIR A LA POLICÍA CUANDO HAYAN TERMINADO LOS ACTOS DE INVESTIGACIÓN INICIALES","EL FISCAL SÓLO PUEDE SOLICITAR APOYO POLICIAL SI EXISTE UNA ORDEN DEL JUEZ DE GARANTÍAS","LA INSTRUCCIÓN DEL FISCAL A LA POLICÍA DEBE CONSTAR EN RESOLUCIÓN JUDICIAL PARA SER VÁLIDA"]'::jsonb, 'EL FISCAL PUEDE REQUERIR LA ACTUACIÓN POLICIAL DENTRO DEL MARCO DE LAS ATRIBUCIONES RECONOCIDAS EN LA LEY', 1, '(texto: (ART: UNICO)** Articulo 67. Funcion de investigacion de la Policia Nacional del Peru)**', '184880', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1345, 1345, 'EN EL EJERCICIO DE LA FUNCIÓN DE INVESTIGACIÓN, ¿CUÁL ES EL LÍMITE LEGAL DE LA INTERVENCIÓN DE LA POLICÍA NACIONAL DEL PERÚ SEGÚN LA NORMA CITADA?', '["PUEDE INVESTIGAR DE FORMA AUTÓNOMA SIN NINGUNA INJERENCIA DEL MINISTERIO PÚBLICO","PUEDE REALIZAR ACTOS DE INVESTIGACIÓN BAJO LA CONDUCCIÓN DEL FISCAL Y RESPETANDO LAS FORMALIDADES LEGALES","SU PARTICIPACIÓN SE LIMITA A LA CUSTODIA DE EVIDENCIA SIN FACULTAD PARA PRACTICAR DILIGENCIAS","SOLO INTERVIENE COMO APOYO LOGÍSTICO Y TÉCNICO SIN PODERES DE INVESTIGACIÓN","ACTÚA ÚNICAMENTE BAJO INSTRUCCIONES ORALES DE LOS JUECES PENALES"]'::jsonb, 'PUEDE REALIZAR ACTOS DE INVESTIGACIÓN BAJO LA CONDUCCIÓN DEL FISCAL Y RESPETANDO LAS FORMALIDADES LEGALES', 1, '(texto: (ART: UNICO)** Articulo 67. Funcion de investigacion de la Policia Nacional del Peru)**', '184881', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1346, 1346, '¿CUÁL ES EL DESTINO OBLIGATORIO DE LAS ACTAS DETALLADAS DE LAS DILIGENCIAS ESPECÍFICAS REALIZADAS POR LA POLICÍA NACIONAL DEL PERÚ, SEGÚN LA LEY MODIFICADA?:', '["DEBEN SER REMITIDAS AL MINISTERIO DEL INTERIOR PARA CONSTANCIA INTERNA","SE CONSERVAN EN LA COMISARÍA HASTA FINALIZADO EL JUICIO ORAL","SE ENTREGAN AL FISCAL A CARGO Y SE EMITE INFORME POLICIAL CORRESPONDIENTE","SON ENTREGADAS ÚNICAMENTE AL ÓRGANO JURISDICCIONAL PENAL","SE PUBLICAN EN EL PORTAL DE TRANSPARENCIA POLICIAL PARA CONTROL CIUDADANO"]'::jsonb, 'SE ENTREGAN AL FISCAL A CARGO Y SE EMITE INFORME POLICIAL CORRESPONDIENTE', 2, '(texto: (ART: UNICO)** Articulo 67. Funcion de investigacion de la Policia Nacional del Peru)**', '184882', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1347, 1347, 'RESPECTO A LA MODIFICACIÓN INTRODUCIDA EN EL CÓDIGO PROCESAL PENAL, ¿QUÉ SUCEDE SI EL DECLARANTE NO CUENTA CON ABOGADO DEFENSOR DE ELECCIÓN O DEFENSOR PÚBLICO EN SU MANIFESTACIÓN ANTE LA POLICÍA NACIONAL DEL PERÚ?:', '["SE SUSPENDE LA DILIGENCIA Y SE REPROGRAMA","EL ACTO PUEDE SER SUBSANADO SI EL FISCAL RATIFICA LA ACTUACIÓN POLICIAL A POSTERIORI","LA MANIFESTACIÓN ES VÁLIDA SIEMPRE QUE SEA VOLUNTARIA, AUN SIN DEFENSA TÉCNICA","EL DEFECTO SOLO AFECTA EL VALOR PROBATORIO Y NO LA EXISTENCIA DE LA MANIFESTACIÓN","LA ACTUACIÓN POLICIAL QUEDA SUSPENDIDA AUTOMÁTICAMENTE Y DEBE INFORMARSE AL JUEZ"]'::jsonb, 'SE SUSPENDE LA DILIGENCIA Y SE REPROGRAMA', 0, '(texto: (ART: UNICO)** Articulo 68. Funcion de investigacion de la Policia Nacional del Peru)**', '184883', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1348, 1348, 'SEGÚN EL ARTÍCULO 84 DEL CÓDIGO PROCESAL PENAL, MODIFICADO POR LA LEY 32130, RESPECTO AL ACCESO DEL ABOGADO DEFENSOR A LA INFORMACIÓN DEL PROCESO, SEÑALE LA RESPUESTA CORRECTA:', '["EL ABOGADO DEFENSOR PUEDE ACCEDER SOLO A LOS DOCUMENTOS DEL ÁMBITO JUDICIAL DESPUÉS DE LA ETAPA DE JUICIO ORAL, POR RESPETO AL PRINCIPIO DE SEGURIDAD PROCESAL","EL DERECHO DEL ABOGADO DEFENSOR A ACCEDER A LOS DOCUMENTOS ESTÁ RESTRINGIDO ÚNICAMENTE A LAS ETAPAS PREVIAS A LA ACUSACIÓN FISCAL","EL ACCESO A LOS DOCUMENTOS POR PARTE DEL ABOGADO DEFENSOR DEPENDE DE LA AUTORIZACIÓN EXPRESA DEL MINISTERIO PÚBLICO EN CADA ETAPA PROCESAL","EL ABOGADO DEFENSOR TIENE DERECHO A ACCEDER A LOS DOCUMENTOS DE ÁMBITO POLICIAL, FISCAL Y JUDICIAL EN TODO EL DESARROLLO DEL PROCESO, SIN MÁS LIMITACIÓN QUE LA PREVISTA EN LA LEY","EL ABOGADO DEFENSOR PUEDE SOLICITAR LA RESTRICCIÓN DE SU PROPIO ACCESO A LOS DOCUMENTOS COMO ESTRATEGIA DE DEFENSA, DE ACUERDO AL PRINCIPIO DE AUTONOMÍA DE LA VOLUNTAD"]'::jsonb, 'EL ABOGADO DEFENSOR TIENE DERECHO A ACCEDER A LOS DOCUMENTOS DE ÁMBITO POLICIAL, FISCAL Y JUDICIAL EN TODO EL DESARROLLO DEL PROCESO, SIN MÁS LIMITACIÓN QUE LA PREVISTA EN LA LEY', 3, '(texto: (ART: UNICO)** Articulo 84. Derechos y deberes del abogado defensor)**', '184884', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1349, 1349, 'SEGÚN LA MODIFICACIÓN DEL ARTÍCULO 160 DEL CÓDIGO PROCESAL PENAL INTRODUCIDA POR LA LEY 32130 (ARTÍCULO ÚNICO), ¿EN CUÁL DE LAS SIGUIENTES SITUACIONES LA CONFESIÓN DE UN IMPUTADO TIENE VALOR PROBATORIO EN EL PROCESO PENAL?:', '["CUANDO EL IMPUTADO CONFIESA ANTE EL FISCAL O JUEZ, CON PRESENCIA DE SU ABOGADO DEFENSOR, Y DICHA DILIGENCIA ES REGISTRADA EN EQUIPOS AUDIOVISUALES","CUANDO EL IMPUTADO CONFIESA ANTE LA POLICÍA NACIONAL DURANTE LA INVESTIGACIÓN PRELIMINAR, SIN NECESIDAD DE ABOGADO DEFENSOR NI REGISTRO AUDIOVISUAL","CUANDO LA CONFESIÓN ES PRESTADA ANTE CUALQUIER SERVIDOR PÚBLICO Y EN CUALQUIER ETAPA DEL PROCESO, SIEMPRE QUE EL IMPUTADO NO LA IMPUGNE POSTERIORMENTE","CUANDO EL IMPUTADO FIRMA UN ACTA DE CONFESIÓN EXTRAJUDICIAL, AUNQUE NO HAYA REGISTRO AUDIOVISUAL NI PRESENCIA DE DEFENSOR, SIEMPRE QUE EL DOCUMENTO SEA LEGALIZADO","CUANDO LA CONFESIÓN ES OBTENIDA MEDIANTE ACTA POLICIAL EN CUALQUIER ETAPA DEL PROCESO Y NO SE ALEGUE COACCIÓN"]'::jsonb, 'CUANDO EL IMPUTADO CONFIESA ANTE EL FISCAL O JUEZ, CON PRESENCIA DE SU ABOGADO DEFENSOR, Y DICHA DILIGENCIA ES REGISTRADA EN EQUIPOS AUDIOVISUALES', 0, '(texto: (ART: UNICO)**Articulo 160. Valor de prueba de la confesion)**', '184887', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1350, 1350, '¿BAJO QUÉ CIRCUNSTANCIAS PROCEDERÁ LA CESACIÓN DE LA PRISIÓN PREVENTIVA O DE LAS MEDIDAS DE COMPARECENCIA SEGÚN EL ARTÍCULO 83 DE LA LEY N°32130?:', '["CUANDO EL IMPUTADO SOLICITE POR PRIMERA VEZ LA CESACIÓN, SIN NECESIDAD DE MÁS REQUISITOS","CUANDO SE HAYAN CUMPLIDO LOS REQUISITOS DE INVESTIGACIÓN PRELIMINAR","CUANDO NUEVOS ELEMENTOS DE CONVICCIÓN DEMUESTREN QUE NO CONCURREN O NO SUBSISTEN LOS MOTIVOS QUE ORIGINARON LA MEDIDA Y RESULTE NECESARIO SUSTITUIRLA POR COMPARECENCIA","SOLO CUANDO EL PROCESO PENAL HAYA SUPERADO LA ETAPA INTERMEDIA","CUANDO EL MINISTERIO PÚBLICO DECLARE LA INOCENCIA DEL IMPUTADO"]'::jsonb, 'CUANDO NUEVOS ELEMENTOS DE CONVICCIÓN DEMUESTREN QUE NO CONCURREN O NO SUBSISTEN LOS MOTIVOS QUE ORIGINARON LA MEDIDA Y RESULTE NECESARIO SUSTITUIRLA POR COMPARECENCIA', 2, '(texto: (ART: UNICO)** Articulo 283. Cesacion de la prision preventiva o de la comparecencia)**', '184910', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1351, 1351, 'PARA LA DETERMINACION DE LA MEDIDA SUSTITUTIVA EL JUEZ TENDRA EN CONSIDERACION ADICIONALMENTE, SEÑALE LA CORRECTA:', '["LA GRAVEDAD DEL DELITO INVESTIGADO EXCLUSIVAMENTE","EL MONTO DEL DAÑO CIVIL CAUSADO POR EL IMPUTADO","LAS CARACTERÍSTICAS PERSONALES DEL IMPUTADO, EL TIEMPO TRANSCURRIDO DESDE LA PRIVACIÓN DE LIBERTAD Y EL ESTADO DE LA CAUSA","EL OBJETIVO DE IMPONER LA MAYOR RESTRICCIÓN POSIBLE PARA EVITAR LA FUGA","LA OPINIÓN DEL AGRAVIADO COMO FACTOR DETERMINANTE"]'::jsonb, 'LAS CARACTERÍSTICAS PERSONALES DEL IMPUTADO, EL TIEMPO TRANSCURRIDO DESDE LA PRIVACIÓN DE LIBERTAD Y EL ESTADO DE LA CAUSA', 2, '(texto: (ART: UNICO)** Articulo 283. Cesacion de la prision preventiva o de la comparecencia)**', '184911', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1352, 1352, '¿QUÉ DERECHO LE ASISTE AL IMPUTADO RESPECTO A LA SOLICITUD DE CESACIÓN DE PRISIÓN PREVENTIVA O COMPARECENCIA RESTRICTIVA?:', '["PUEDE SOLICITAR LA CESACIÓN SÓLO UNA VEZ DURANTE LA INVESTIGACIÓN PREPARATORIA","PUEDE SOLICITAR LA CESACIÓN TANTAS VECES COMO LO CONSIDERE PERTINENTE","SOLO PUEDE SOLICITAR LA CESACIÓN SI HAN TRANSCURRIDO DOCE MESES DESDE LA IMPOSICIÓN DE LA MEDIDA","DEBE PRESENTAR LA SOLICITUD ÚNICAMENTE A TRAVÉS DE SU ABOGADO DEFENSOR","PUEDE SOLICITAR CESACIÓN ÚNICAMENTE PREVIA AUTORIZACIÓN DEL MINISTERIO PÚBLICO"]'::jsonb, 'PUEDE SOLICITAR LA CESACIÓN TANTAS VECES COMO LO CONSIDERE PERTINENTE', 1, '(texto: (ART: UNICO)** Articulo 283. Cesacion de la prision preventiva o de la comparecencia)**', '184913', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1353, 1353, '¿CUÁL ES LA FINALIDAD PRINCIPAL DE LA INVESTIGACIÓN PREPARATORIA SEGÚN EL ARTÍCULO 321?:', '["FORMULAR ACUSACIÓN DE INMEDIATO CONTRA EL IMPUTADO SIN MAYOR ANÁLISIS","PROTEGER EXCLUSIVAMENTE LOS DERECHOS DE LA VÍCTIMA","REUNIR ELEMENTOS DE CONVICCIÓN PARA QUE EL FISCAL DECIDA SI FORMULA O NO ACUSACIÓN Y PERMITIR AL IMPUTADO PREPARAR SU DEFENSA","SANCIONAR ANTICIPADAMENTE A LOS RESPONSABLES DEL DELITO","IMPULSAR ACCIONES ADMINISTRATIVAS EN CASO DE DELITOS MENORES"]'::jsonb, 'REUNIR ELEMENTOS DE CONVICCIÓN PARA QUE EL FISCAL DECIDA SI FORMULA O NO ACUSACIÓN Y PERMITIR AL IMPUTADO PREPARAR SU DEFENSA', 2, '(texto: (ART: UNICO)** Articulo 321. Finalidad)**', '184914', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1364, 1364, 'SOBRE LA FACULTAD DE CONSTITUIRSE EN EL LUGAR DE LOS HECHOS, ¿EN QUÉ CASOS PUEDEN HACERLO EL FISCAL O LA POLICÍA NACIONAL?:', '["SOLAMENTE SI EXISTE FLAGRANCIA DELICTIVA GRAVE","AL TENER CONOCIMIENTO DE CUALQUIER DELITO PERSEGUIBLE POR ACCIÓN PRIVADA","AL TENER CONOCIMIENTO DE UN DELITO DE EJERCICIO PÚBLICO DE LA ACCIÓN PENAL","DESPUÉS DE LA FORMALIZACIÓN DE LA ACUSACIÓN PENAL","SOLO AL RECIBIR DENUNCIA ESCRITA DEL AGRAVIADO"]'::jsonb, 'AL TENER CONOCIMIENTO DE UN DELITO DE EJERCICIO PÚBLICO DE LA ACCIÓN PENAL', 2, '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184931', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1354, 1354, 'SEGÚN EL ARTÍCULO 321 MODIFICADO, ¿QUÉ ROL CORRESPONDE A LA POLICÍA NACIONAL DEL PERÚ EN LA ETAPA PRELIMINAR DE INVESTIGACIÓN?', '["ES ÚNICAMENTE UNA FUNCIÓN DE APOYO EN EJECUCIÓN DE MANDATOS JUDICIALES","ACTÚA DIRECTAMENTE EN LA INVESTIGACIÓN PRELIMINAR BAJO LA CONDUCCIÓN JURÍDICA DEL MINISTERIO PÚBLICO","TIENE COMPETENCIA AUTÓNOMA EN LA DISPOSICIÓN DE DILIGENCIAS FISCALES Y JUDICIALES","SOLO PUEDE INTERVENIR EN DETENCIONES IN FRAGANTI","ASUME LA DIRECCIÓN EXCLUSIVA EN TODO EL PROCESO PENAL"]'::jsonb, 'ACTÚA DIRECTAMENTE EN LA INVESTIGACIÓN PRELIMINAR BAJO LA CONDUCCIÓN JURÍDICA DEL MINISTERIO PÚBLICO', 1, '(texto: (ART: UNICO)** Articulo 321. Finalidad)**', '184916', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1355, 1355, '¿CUÁL DE LOS SIGUIENTES ASPECTOS, NO ES UNA FINALIDAD DE LA INVESTIGACIÓN PREPARATORIA SEGÚN EL ART 321 DE LA LEY N°32130?:', '["DETERMINAR LA EXISTENCIA DEL DAÑO CAUSADO","IDENTIFICAR LA IDENTIDAD DEL AUTOR O PARTÍCIPE DEL DELITO","DETERMINAR SI LA CONDUCTA INCRIMINADA ES DELICTUOSA","EJECUTAR SANCIONES PENALES DE MANERA ANTICIPADA","CONOCER LOS MÓVILES DE LA PERPETRACIÓN DEL DELITO"]'::jsonb, 'EJECUTAR SANCIONES PENALES DE MANERA ANTICIPADA', 3, '(texto: (ART: UNICO)** Articulo 321. Finalidad)**', '184917', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1356, 1356, '¿A QUIÉN CORRESPONDE LA DIRECCIÓN PRINCIPAL DE LA INVESTIGACIÓN PREPARATORIA FORMALIZADA, DE ACUERDO CON LA MODIFICACIÓN AL CÓDIGO PROCESAL PENAL?:', '["EXCLUSIVAMENTE AL PODER JUDICIAL, CON INTERVENCIÓN PUNTUAL DEL MINISTERIO PÚBLICO","A LA POLICÍA NACIONAL DEL PERÚ, SIN INJERENCIA DE OTRAS ENTIDADES","AL MINISTERIO PÚBLICO, CON APOYO EN LAS DILIGENCIAS DE LA POLICÍA NACIONAL DEL PERÚ","A LOS ABOGADOS DEFENSORES DE LAS PARTES, PARA GARANTIZAR EL CONTRADICTORIO","A LA DEFENSORÍA DEL PUEBLO, COMO GARANTE DE DERECHOS FUNDAMENTALES"]'::jsonb, 'AL MINISTERIO PÚBLICO, CON APOYO EN LAS DILIGENCIAS DE LA POLICÍA NACIONAL DEL PERÚ', 2, '(texto: (ART: UNICO)** Articulo 321. Finalidad)**', '184918', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1357, 1357, 'SEGÚN EL ARTÍCULO 322 DEL CÓDIGO PROCESAL PENAL TRAS SU MODIFICACIÓN, ¿EN QUÉ SUPUESTO EL MINISTERIO PÚBLICO PUEDE SOLICITAR EL APOYO DE LA POLICÍA NACIONAL DEL PERÚ UNA VEZ FORMALIZADA LA INVESTIGACIÓN PREPARATORIA?:', '["CUANDO CONSTITUYE UNA GARANTÍA PERSONAL DEL INVESTIGADO","CUANDO LA INVESTIGACIÓN REQUIERA DILIGENCIAS QUE TENGAN CONTENIDO JURISDICCIONAL, ESPECIALMENTE LAS QUE RESTRINJAN DERECHOS FUNDAMENTALES","PARA QUE LA POLICÍA REALICE INVESTIGACIONES COMPLEMENTARIAS BAJO LA DIRECCIÓN DEL MINISTERIO PÚBLICO","SÓLO CUANDO EL CASO HA SIDO ELEVADO A JUICIO ORAL POR EL JUEZ PENAL","EN CASOS DE FLAGRANCIA DELICTIVA, SIN IMPORTAR ETAPA PROCESAL"]'::jsonb, 'PARA QUE LA POLICÍA REALICE INVESTIGACIONES COMPLEMENTARIAS BAJO LA DIRECCIÓN DEL MINISTERIO PÚBLICO', 2, '(texto: (ART: UNICO)** Articulo 322. Direccion de la investigacion)**', '184920', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1358, 1358, '¿CUÁL ES LA FINALIDAD INMEDIATA DE LA INVESTIGACIÓN PRELIMINAR, SEGÚN EL ARTÍCULO 330 MODIFICADO POR LA LEY 32130?:', '["INDIVIDUALIZAR ÚNICAMENTE A LOS PRESUNTOS AUTORES DEL DELITO PARA SU DETENCIÓN","GARANTIZAR LOS DERECHOS FUNDAMENTALES DE LOS DETENIDOS EN LA ETAPA INTERMEDIA","REALIZAR ACTOS URGENTES O INAPLAZABLES PARA DETERMINAR LA EXISTENCIA DE LOS HECHOS, SU DELICTUOSIDAD Y ASEGURAR LOS ELEMENTOS MATERIALES, ASÍ COMO INDIVIDUALIZAR A TODOS LOS INVOLUCRADOS","DEFINIR EL GRADO DE RESPONSABILIDAD DE LOS PARTÍCIPES DURANTE LA INVESTIGACIÓN PREPARATORIA","PREPARAR LA ACUSACIÓN FISCAL PARA EL REQUERIMIENTO DE PRISIÓN PREVENTIVA"]'::jsonb, 'REALIZAR ACTOS URGENTES O INAPLAZABLES PARA DETERMINAR LA EXISTENCIA DE LOS HECHOS, SU DELICTUOSIDAD Y ASEGURAR LOS ELEMENTOS MATERIALES, ASÍ COMO INDIVIDUALIZAR A TODOS LOS INVOLUCRADOS', 2, '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184923', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1359, 1359, '¿QUIÉN ESTÁ ENCARGADO DE LA INVESTIGACIÓN PRELIMINAR DEL DELITO, CONFORME AL ARTÍCULO 330 DE LA LEY N°32130, MARQUE LA RESPUESTA CORRECTA?:', '["ÚNICAMENTE EL FISCAL, CON AUXILIO DE LA POLICÍA NACIONAL DEL PERÚ","EL PODER JUDICIAL, CON APOYO DEL MINISTERIO PÚBLICO","LA POLICÍA NACIONAL DEL PERÚ, CON LA CONDUCCIÓN JURÍDICA DEL FISCAL","EL MINISTERIO PÚBLICO, DE MANERA AUTÓNOMA E INDEPENDIENTE","EL PROCURADOR PÚBLICO, CON INTERVENCIÓN SUBSIDIARIA DEL FISCAL"]'::jsonb, 'LA POLICÍA NACIONAL DEL PERÚ, CON LA CONDUCCIÓN JURÍDICA DEL FISCAL', 2, '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184924', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1360, 1360, '¿CUÁL DE LOS ENUNCIADOS, NO ES UN PROPÓSITO INMEDIATO DE LA INVESTIGACIÓN PRELIMINAR, SEGÚN EL ART 330 DE LA LEY N°32130?:', '["IDENTIFICAR Y UBICAR A LOS PRESUNTOS AUTORES Y PARTÍCIPES DEL HECHO DELICTIVO","ASEGURAR DEBIDAMENTE A LAS PERSONAS INVOLUCRADAS, DENTRO DE LOS LÍMITES DE LA LEY","IMPEDIR QUE EL DELITO PRODUZCA CONSECUENCIAS ULTERIORES","ASEGURAR LOS ELEMENTOS MATERIALES DE LA COMISIÓN DEL HECHO","FORMALIZAR LA ACUSACIÓN ANTE EL ÓRGANO JURISDICCIONAL COMPETENTE"]'::jsonb, 'FORMALIZAR LA ACUSACIÓN ANTE EL ÓRGANO JURISDICCIONAL COMPETENTE', 4, '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184925', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1361, 1361, 'DENTRO DEL MARCO DEL ARTÍCULO 330 REFORMADO, ¿CUÁL ES EL PAPEL DE LA POLICÍA NACIONAL AL TENER CONOCIMIENTO DE UN DELITO DE EJERCICIO PÚBLICO DE LA ACCIÓN PENAL?:', '["CONDUCIR LA INVESTIGACIÓN PRELIMINAR DE MANERA AUTÓNOMA Y SIN SUPERVISIÓN FISCAL","PODRA CONSTITUIRSE INMEDIATAMENTE EN EL LUGAR DE LOS HECHOS CON PERSONAL POLICIAL ESPECIALIZADO Y EFECTUAR UN EXAMEN PARA ESTABLECER LA REALIDAD DE LOS HECHOS","SOLICITAR A LA FISCALÍA LA AUTORIZACIÓN PARA INTERVENIR EN EL LUGAR DEL DELITO","EMITIR PRONTAMENTE LA ACUSACIÓN PENAL FORMAL SIN INTERVENCIÓN DEL MINISTERIO PÚBLICO","COORDINAR CON EL PODER JUDICIAL PARA DETERMINAR LAS MEDIDAS CAUTELARES PROVISIONALES"]'::jsonb, 'PODRA CONSTITUIRSE INMEDIATAMENTE EN EL LUGAR DE LOS HECHOS CON PERSONAL POLICIAL ESPECIALIZADO Y EFECTUAR UN EXAMEN PARA ESTABLECER LA REALIDAD DE LOS HECHOS', 1, '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184926', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1362, 1362, 'DENTRO DE LA INVESTIGACIÓN PRELIMINAR BAJO LA LEY 32130, ¿QUÉ ACTO ESTÁ JUSTIFICADO COMO FUNCIÓN AUTÓNOMA POLICIAL?:', '["CONDUCIR TODAS LAS DILIGENCIAS SIN CONTROL DEL FISCAL","REALIZAR ACTOS URGENTES O INAPLAZABLES NECESARIOS PARA IMPEDIR CONSECUENCIAS ULTERIORES DEL DELITO","DICTO DE MEDIDAS COERCITIVAS PERSONALES SIN INTERVENCIÓN DEL MINISTERIO PÚBLICO","INICIAR FORMALMENTE EL PROCESO PENAL ANTE EL JUEZ","EMITIR SENTENCIA CONDENATORIA LUEGO DE LA INVESTIGACIÓN POLICIAL"]'::jsonb, 'REALIZAR ACTOS URGENTES O INAPLAZABLES NECESARIOS PARA IMPEDIR CONSECUENCIAS ULTERIORES DEL DELITO', 1, '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184928', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1363, 1363, 'SEGÚN EL ARTÍCULO 330, ¿QUÉ FUNCIÓN CUMPLE EL INFORME POLICIAL EMITIDO AL FISCAL AL CONCLUIR LA INVESTIGACIÓN PRELIMINAR?', '["PERMITE DECIDIR SOBRE LA FORMALIZACIÓN DE LA INVESTIGACIÓN PREPARATORIA","SUSTITUYE LA IMPUTACIÓN FORMAL ANTE EL PODER JUDICIAL","DEFINE LA CULPABILIDAD DEL INVESTIGADO","PRESENTA LOS ALEGATOS DE CIERRE PARA LA SENTENCIA","ORDENA LA DETENCIÓN JUDICIAL DIRECTA DEL IMPUTADO"]'::jsonb, 'PERMITE DECIDIR SOBRE LA FORMALIZACIÓN DE LA INVESTIGACIÓN PREPARATORIA', 0, '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184930', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1365, 1365, 'CONFORME AL ART 330 DE LA LEY N°32130, ¿QUÉ ELEMENTO NO ES DESTACADO COMO COMPETENCIA DE LA INVESTIGACIÓN PRELIMINAR DE LA PNP BAJO CONDUCCIÓN FISCAL?:', '["IMPEDIR QUE EL DELITO PRODUZCA CONSECUENCIAS ULTERIORES","ASEGURAR LOS ELEMENTOS MATERIALES DEL DELITO","INDIVIDUALIZAR A LOS AGRAVIADOS","ASEGURAR DEBIDAMENTE A LAS PERSONAS INVOLUCRADAS","EMITIR AUTO DE PRISIÓN PREVENTIVA"]'::jsonb, 'EMITIR AUTO DE PRISIÓN PREVENTIVA', 4, '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184932', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1366, 1366, 'SEGÚN LA MODIFICACIÓN DEL ARTÍCULO 331, ¿CUÁNDO DEBE LA POLICÍA PONER A DISPOSICIÓN DEL FISCAL TODO LO ACTUADO DURANTE LA INVESTIGACIÓN PRELIMINAR?:', '["UNA VEZ QUE EL MINISTERIO PÚBLICO LE COMUNIQUE FORMALMENTE UNA ORDEN EXPRESA","AL FINALIZAR LA INVESTIGACIÓN PRELIMINAR, MEDIANTE EL CORRESPONDIENTE INFORME POLICIAL","ÚNICAMENTE CUANDO SE HAYA DICTADO PRISIÓN PREVENTIVA PARA EL INVESTIGADO","SIEMPRE QUE EXISTAN PRUEBAS INCRIMINATORIAS SUFICIENTES, SIN IMPORTAR EL ESTADO DEL PROCEDIMIENTO","AL MOMENTO EN QUE SE REMITA EL EXPEDIENTE AL PODER JUDICIAL PARA JUZGAMIENTO"]'::jsonb, 'AL FINALIZAR LA INVESTIGACIÓN PRELIMINAR, MEDIANTE EL CORRESPONDIENTE INFORME POLICIAL', 1, '(texto: (ART: UNICO)** Articulo 331. Actuacion policial)**', '184934', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1367, 1367, '¿QUÉ INFORMACIÓN ADICIONAL DEBE REMITIR LA POLICÍA AL MINISTERIO PÚBLICO, SEGÚN EL ARTÍCULO 331, SIN PERJUICIO DE LA COMUNICACIÓN INMEDIATA?:', '["SOLO EL ACTA POLICIAL Y LA RELACIÓN DE LOS PRESUNTOS RESPONSABLES","TODA LA DOCUMENTACIÓN QUE PUDIERA EXISTIR RELACIONADA AL HECHO INVESTIGADO","ÚNICAMENTE LA DECLARACIÓN DE LOS TESTIGOS PRESENCIALES Y LA EVIDENCIA MATERIAL","LA PETICIÓN FORMAL DE INICIO DE PROCESO PENAL","LA SOLICITUD DE AUTORIZACIÓN PARA REALIZAR DILIGENCIAS ADICIONALES"]'::jsonb, 'TODA LA DOCUMENTACIÓN QUE PUDIERA EXISTIR RELACIONADA AL HECHO INVESTIGADO', 1, '(texto: (ART: UNICO)** Articulo 331. Actuacion policial)**', '184935', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1368, 1368, 'RESPECTO AL INFORME POLICIAL REGULADO EN EL ARTÍCULO 332, ¿CUÁL DE LOS SIGUIENTES ENUNCIADOS ES CORRECTO EN CUANTO A SU NATURALEZA Y EFECTOS JURÍDICOS ANTE EL FISCAL?:', '["EL INFORME POLICIAL ES VINCULANTE Y OBLIGA AL FISCAL A ADECUAR SU DECISIÓN CONFORME AL MISMO","EL INFORME POLICIAL NO ES VINCULANTE","EL INFORME POLICIAL TIENE CARÁCTER RESOLUTIVO Y PUEDE SUSTITUIR LA ACUSACIÓN FISCAL","EL INFORME POLICIAL ES OBLIGATORIO TANTO EN SU CONTENIDO COMO EN SUS RECOMENDACIONES PARA EL FISCAL","EL INFORME POLICIAL DEBE SER CALIFICADO POR EL FISCAL COMO MÉRITO SUFICIENTE PARA ABRIR JUICIO ORAL"]'::jsonb, 'EL INFORME POLICIAL NO ES VINCULANTE', 1, '(texto: (ART: UNICO)** Articulo 332. Informe policial)**', '184936', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1369, 1369, 'CONFORME A LO DISPUESTO EN EL ARTÍCULO 332, ¿CUÁLES DE LOS SIGUIENTES ELEMENTOS NO DEBE NECESARIAMENTE CONTENER EL INFORME POLICIAL REMITIDO AL FISCAL?:', '["LOS ANTECEDENTES QUE MOTIVARON LA INTERVENCIÓN POLICIAL","LA RELACIÓN DETALLADA DE LAS DILIGENCIAS EFECTUADAS DURANTE LA INVESTIGACIÓN","UNA VALORACIÓN DEFINITIVA SOBRE LA CULPABILIDAD DEL INVESTIGADO","LAS PRECALIFICACIONES DE LOS DELITOS PRESUNTAMENTE COMETIDOS","EL ANÁLISIS DE LOS HECHOS INVESTIGADOS Y LAS CONCLUSIONES RESPECTIVAS"]'::jsonb, 'UNA VALORACIÓN DEFINITIVA SOBRE LA CULPABILIDAD DEL INVESTIGADO', 2, '(texto: (ART: UNICO)** Articulo 332. Informe policial)**', '184938', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1370, 1370, 'EN EL MARCO DE LA LEY 32130, ¿EN QUÉ MOMENTO PROCESAL LA POLICÍA NACIONAL DEBE ELEVAR EL INFORME POLICIAL AL FISCAL?', '["ÚNICAMENTE AL FINALIZAR LA INVESTIGACIÓN PREPARATORIA","DENTRO DEL PLAZO OTORGADO POR EL REPRESENTANTE DEL MINISTERIO PÚBLICO DURANTE LA INVESTIGACIÓN PRELIMINAR","SOLO CUANDO EXISTA DENUNCIA FORMAL DEL AGRAVIADO","DESPUÉS DE EMITIDA LA SENTENCIA ABSOLUTORIA O CONDENATORIA","AL MOMENTO DE LA DETENCIÓN EN FLAGRANCIA DEL PRESUNTO AUTOR DEL DELITO"]'::jsonb, 'DENTRO DEL PLAZO OTORGADO POR EL REPRESENTANTE DEL MINISTERIO PÚBLICO DURANTE LA INVESTIGACIÓN PRELIMINAR', 1, '(texto: (ART: UNICO)** Articulo 332. Informe policial)**', '184939', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1388, 1388, 'EN EL INTERCAMBIO DE INFORMACIÓN DENTRO DEL MECANISMO PÚBLICO-PRIVADO, ¿QUÉ RESTRICCIÓN SE IMPONE RESPECTO AL USO DE LA MISMA?', '["PUEDE SER UTILIZADA PARA FUTURAS INVESTIGACIONES DISTINTAS","SOLO PUEDE UTILIZARSE PARA LOS HECHOS QUE MOTIVARON LA INVESTIGACIÓN ORIGINAL","DEBE SER DIFUNDIDA PÚBLICAMENTE SI SE CONSIDERA DE INTERÉS SOCIAL","LA RESTRICCIÓN SOLO APLICA A INFORMACIÓN FINANCIERA","LA INFORMACIÓN CARECE DE CUALQUIER RESTRICCIÓN SI PROVIENE DEL MINISTERIO PÚBLICO"]'::jsonb, 'SOLO PUEDE UTILIZARSE PARA LOS HECHOS QUE MOTIVARON LA INVESTIGACIÓN ORIGINAL', 1, '(texto: (ART: 9)** Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185404', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1371, 1371, '¿CUÁL ES LA FUNCIÓN PRINCIPAL DEL INFORME POLICIAL EN EL PROCEDIMIENTO PENAL PERUANO, CONFORME AL ARTÍCULO 332 MODIFICADO POR LA LEY 32130?', '["SERVIR COMO DICTAMEN PERICIAL PARA RESOLUCIONES JUDICIALES","CONSTITUIR LA BASE ESENCIAL PARA LA ACUSACIÓN FISCAL EN JUICIO ORAL","PROPORCIONAR ANTECEDENTES, DILIGENCIAS REALIZADAS, PRECALIFICACIONES Y CONCLUSIONES PARA FUNDAMENTAR LA CONTINUACIÓN O NO DE LA INVESTIGACIÓN PREPARATORIA","DETERMINAR LA RESPONSABILIDAD PENAL DEL IMPUTADO DIRECTA E IRREVOCABLEMENTE","VALIDAR ADMINISTRATIVAMENTE LA ACTUACIÓN POLICIAL ANTE EL FISCAL SUPERIOR"]'::jsonb, 'PROPORCIONAR ANTECEDENTES, DILIGENCIAS REALIZADAS, PRECALIFICACIONES Y CONCLUSIONES PARA FUNDAMENTAR LA CONTINUACIÓN O NO DE LA INVESTIGACIÓN PREPARATORIA', 2, '(texto: (ART: UNICO)** Articulo 332. Informe policial)**', '184940', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1372, 1372, 'SEGÚN EL ARTÍCULO 337, ¿EN QUÉ SUPUESTO ESPECÍFICO LA INVESTIGACIÓN PRELIMINAR PUEDE SER AMPLIADA UNA VEZ FORMALIZADA LA INVESTIGACIÓN PREPARATORIA?:', '["CUANDO LO SOLICITA LA DEFENSA TÉCNICA DEL IMPUTADO, ALEGANDO VULNERACIÓN DE SUS DERECHOS PROCESALES","SI LA VÍCTIMA PRESENTA UNA NUEVA DENUNCIA SOBRE LOS MISMOS HECHOS","CUANDO EL FISCAL ADVIERTA UN GRAVE DEFECTO EN LA ACTUACIÓN DE LA DILIGENCIA O SE DEBA COMPLETAR INELUDIBLEMENTE POR LA INCORPORACIÓN DE NUEVOS ELEMENTOS DE CONVICCIÓN","CADA VEZ QUE LA POLICÍA NACIONAL LO CONSIDERE NECESARIO EN CUMPLIMIENTO DE SU FUNCIÓN INVESTIGADORA","ANTE LA EXISTENCIA DE CONTRADICCIONES ENTRE TESTIMONIOS RECABADOS DURANTE LA INVESTIGACIÓN PRELIMINAR"]'::jsonb, 'CUANDO EL FISCAL ADVIERTA UN GRAVE DEFECTO EN LA ACTUACIÓN DE LA DILIGENCIA O SE DEBA COMPLETAR INELUDIBLEMENTE POR LA INCORPORACIÓN DE NUEVOS ELEMENTOS DE CONVICCIÓN', 2, '(texto: (ART: UNICO)** Articulo 337. Diligencias de la Investigacion Preparatoria)**', '184942', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1373, 1373, 'EN VIRTUD DEL ARTÍCULO 337 DEL CÓDIGO PROCESAL PENAL PERUANO, TRAS LA FORMALIZACIÓN DE LA INVESTIGACIÓN PREPARATORIA:', '["LAS DILIGENCIAS PRELIMINARES PUEDEN REPETIRSE ILIMITADAMENTE POR DISPOSICIÓN FISCAL","SOLO PUEDEN REPETIRSE SI LO ORDENA UN JUEZ CONSTITUCIONAL EN VÍA DE TUTELA DE DERECHOS","NO PODRÁN REPETIRSE, SALVO QUE ESTÉN JUSTIFICADAS POR LA APARICIÓN DE NUEVA PRUEBA, PERO SOLO BAJO ESTRICTA AUTORIZACIÓN JUDICIAL","NO PODRÁN REPETIRSE BAJO NINGÚN CONCEPTO, SALVO EN LAS EXCEPCIONES SEÑALADAS EN LA PROPIA NORMA POR DEFECTOS GRAVES O NUEVOS ELEMENTOS DE CONVICCIÓN","PUEDEN REPETIRSE COMO PARTE DE LA ESTRATEGIA PROCESAL DE ALGUNA DE LAS PARTES EN EL PROCESO"]'::jsonb, 'NO PODRÁN REPETIRSE BAJO NINGÚN CONCEPTO, SALVO EN LAS EXCEPCIONES SEÑALADAS EN LA PROPIA NORMA POR DEFECTOS GRAVES O NUEVOS ELEMENTOS DE CONVICCIÓN', 3, '(texto: (ART: UNICO)** Articulo 337. Diligencias de la Investigacion Preparatoria)**', '184943', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1382, 1382, '¿QUIÉNES ESTÁN OBLIGADOS A OTORGAR PRIORIDAD AL REQUERIMIENTO DE LOCALIZACIÓN Y GEOLOCALIZACIÓN EN LAS INVESTIGACIONES DE EXTORSIÓN Y DELITOS CONEXOS, SEGÚN EL ARTÍCULO 7?', '["ÚNICAMENTE LA POLICÍA NACIONAL DEL PERÚ","LAS AUTORIDADES POLICIALES, FISCALES Y JUDICIALES, ASÍ COMO LOS CONCESIONARIOS DE SERVICIOS PÚBLICOS DE TELECOMUNICACIONES","EL MINISTERIO DE DEFENSA Y LA FISCALÍA DE LA NACIÓN","SOLO LAS AUTORIDADES JUDICIALES CON COMPETENCIA EN MATERIA PENAL","LAS EMPRESAS DE TRANSPORTE PÚBLICO Y TAXISTAS REGISTRADOS"]'::jsonb, 'LAS AUTORIDADES POLICIALES, FISCALES Y JUDICIALES, ASÍ COMO LOS CONCESIONARIOS DE SERVICIOS PÚBLICOS DE TELECOMUNICACIONES', 1, '(texto: (ART: 7)** Articulo 7.- Identificacion y localizacion de presuntos autores y participes)**', '185393', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1374, 1374, 'CONFORME AL ARTÍCULO 337, ¿CUÁL DE LOS SIGUIENTES ENUNCIADOS REFLEJA CORRECTAMENTE LA RELACIÓN ENTRE LA ACTUACIÓN FISCAL Y POLICIAL EN LA INVESTIGACIÓN DE DELITOS?:', '["EL FISCAL ESTÁ AUTORIZADO A DELEGAR EN LA POLICÍA ÚNICAMENTE LA BÚSQUEDA DE ELEMENTOS MATERIALES DE PRUEBA","LA POLICÍA INVESTIGA SOLO BAJO LA SUPERVISIÓN DEL JUEZ DE LA INVESTIGACIÓN PREPARATORIA","LA POLICÍA REALIZA DILIGENCIAS QUE CONSIDERE PERTINENTES Y ÚTILES, PERO SIEMPRE DENTRO DE LOS LÍMITES FIJADOS POR LA LEY Y BAJO LAS DISPOSICIONES DEL FISCAL","LA POLICÍA TIENE FACULTAD AUTÓNOMA DE DECIDIR EL INICIO, EL CONTENIDO Y LA CULMINACIÓN DE LAS DILIGENCIAS DE INVESTIGACIÓN","EL FISCAL SOLO INTERVIENE SI EXISTE UNA SOLICITUD EXPRESA DE LA VÍCTIMA"]'::jsonb, 'LA POLICÍA REALIZA DILIGENCIAS QUE CONSIDERE PERTINENTES Y ÚTILES, PERO SIEMPRE DENTRO DE LOS LÍMITES FIJADOS POR LA LEY Y BAJO LAS DISPOSICIONES DEL FISCAL', 2, '(texto: (ART: UNICO)** Articulo 337. Diligencias de la Investigacion Preparatoria)**', '184946', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1375, 1375, 'SEGÚN EL ARTÍCULO 353 MODIFICADO POR LA LEY 32130, ¿CUÁL ES LA CONDICIÓN ESENCIAL PARA QUE EL AUTO DE ENJUICIAMIENTO PUEDA SER RECURRIDO POR LAS PARTES PROCESALES?:', '["SI EN EL AUTO DE ENJUICIAMIENTO NO SE CITA EXPRESAMENTE LA LEY QUE SUSTENTA LA ACUSACIÓN FISCAL","CUANDO EL AUTO DE ENJUICIAMIENTO OMITE IDENTIFICAR A LOS SUJETOS PASIVOS DEL PROCESO PENAL","SI LA IMPUTACIÓN NECESARIA NO ESTÁ DEBIDAMENTE FORMULADA, ES DECIR, NO SE IDENTIFICAN CORRECTAMENTE LOS HECHOS Y LOS ELEMENTOS PROBATORIOS QUE TIENDEN A ACREDITARLA O LAS OBSERVACIONES ASUMIDAS EN ETAPA INTERMEDIA","EN TODOS LOS CASOS EN LOS QUE SE DICTE UN AUTO DE ENJUICIAMIENTO, INDEPENDIENTEMENTE DE SU CONTENIDO","CUANDO EL JUEZ DICTA EL AUTO DE ENJUICIAMIENTO SIN HABER INTERVENIDO EL FISCAL PRINCIPAL EN LA AUDIENCIA PRELIMINAR"]'::jsonb, 'SI LA IMPUTACIÓN NECESARIA NO ESTÁ DEBIDAMENTE FORMULADA, ES DECIR, NO SE IDENTIFICAN CORRECTAMENTE LOS HECHOS Y LOS ELEMENTOS PROBATORIOS QUE TIENDEN A ACREDITARLA O LAS OBSERVACIONES ASUMIDAS EN ETAPA INTERMEDIA', 2, '(texto: (ART: UNICO)** Articulo 353. Contenido del auto de enjuiciamiento)**', '184947', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1376, 1376, '¿CUÁL ES EL ÁMBITO DE APLICACIÓN TERRITORIAL DEL DECRETO LEGISLATIVO 1611 RESPECTO A LA PREVENCIÓN E INVESTIGACIÓN DEL DELITO DE EXTORSIÓN Y SUS DELITOS CONEXOS, SEGÚN EL ARTÍCULO 2?', '["SE APLICA ÚNICAMENTE EN ZONAS URBANAS DEL TERRITORIO NACIONAL, EXCLUYENDO ÁREAS RURALES Y ZONAS DE FRONTERA","SE APLICA EN TODO EL TERRITORIO DE LA REPÚBLICA, INCLUYENDO ÁREAS DE EXCLUSIÓN, RÉGIMEN ESPECIAL ADMINISTRATIVO Y EL CIBERESPACIO, SALVO LAS EXCEPCIONES EXPRESAMENTE PREVISTAS","SE LIMITA EXCLUSIVAMENTE A LOS ESPACIOS GEOGRÁFICOS SUJETOS A ESTADO DE EMERGENCIA DECRETADO POR EL EJECUTIVO","ALCANZA SOLO PROPIEDAD PÚBLICA, EXCLUYENDO DE MANERA PERMANENTE LA INVESTIGACIÓN EN ESPACIOS PRIVADOS SIN EXCEPCIÓN ALGUNA","OPERA SOLAMENTE EN CIRCUNSCRIPCIONES DONDE EXISTAN ANTECEDENTES DE DELITOS DE EXTORSIÓN VERIFICADOS EN LOS ÚLTIMOS CINCO AÑOS"]'::jsonb, 'SE APLICA EN TODO EL TERRITORIO DE LA REPÚBLICA, INCLUYENDO ÁREAS DE EXCLUSIÓN, RÉGIMEN ESPECIAL ADMINISTRATIVO Y EL CIBERESPACIO, SALVO LAS EXCEPCIONES EXPRESAMENTE PREVISTAS', 1, '(texto: (ART: 2)** Articulo 2.- Ambito de Aplicacion)**', '185359', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1377, 1377, 'DE ACUERDO AL TEXTO ANALIZADO, ¿QUÉ FUNCIÓN CUMPLE LA POLICÍA NACIONAL DEL PERÚ RESPECTO AL DELITO DE EXTORSIÓN Y SUS DELITOS CONEXOS?', '["DIRIGE LA INVESTIGACIÓN JUDICIAL A CARGO DEL PODER JUDICIAL","PREVIENE, INVESTIGA Y COMBATE LA DELINCUENCIA EN GENERAL, Y REALIZA LA INVESTIGACIÓN DEL DELITO DE EXTORSIÓN EN MATERIA PROCESAL PENAL","SOLICITA DE MANERA EXCLUSIVA ÓRDENES DE ALLANAMIENTO EN INVESTIGACIONES DE EXTORSIÓN","ELABORA Y EJECUTA SENTENCIAS EN CASOS DE EXTORSIÓN","SUSTITUYE AL MINISTERIO PÚBLICO CUANDO ESTE SE DECLARE IMPEDIDO"]'::jsonb, 'PREVIENE, INVESTIGA Y COMBATE LA DELINCUENCIA EN GENERAL, Y REALIZA LA INVESTIGACIÓN DEL DELITO DE EXTORSIÓN EN MATERIA PROCESAL PENAL', 1, '(texto: (ART: 3)** Articulo 3.- Alcance)**', '185365', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1378, 1378, '¿QUÉ REQUISITO DEBEN CUMPLIR LAS VERSIONES EXPUSTAS POR LOS INTERVENIDOS PARA QUE MOTIVEN DILIGENCIAS INMEDIATAS DE CORROBORACIÓN?', '["SER MANIFESTADAS EN PRESENCIA OBLIGATORIA DEL FISCAL SUPERIOR","HABER SIDO PRESTADAS LIBREMENTE, EN ESTADO NORMAL DE LAS FACULTADES PSÍQUICAS, Y HABIENDO SIDO ADVERTIDO EL DERECHO A GUARDAR SILENCIO","ESTAR GRABADAS EN AUDIO Y VIDEO CON FIRMA LEGALIZADA","EXPRESARSE POR ESCRITO Y EN PRESENCIA DE TESTIGOS CIVILES","CONTENER INFORMACIÓN SOBRE TODAS LAS ETAPAS DEL ILÍCITO PENAL"]'::jsonb, 'HABER SIDO PRESTADAS LIBREMENTE, EN ESTADO NORMAL DE LAS FACULTADES PSÍQUICAS, Y HABIENDO SIDO ADVERTIDO EL DERECHO A GUARDAR SILENCIO', 1, '(texto: (ART: 6)** Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos conexos)**', '185384', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1379, 1379, '¿EL LEVANTAMIENTO DE LAS ACTAS EN FORMA CRONOLOGICAS Y DE MANERA COHERENTE, SUSCRIBIENDOLA QUIENES PARTICIPARON EN LAS RESPECTIVAS DILIGENCIAS, EN EL MISMO LUGAR DE LOS HECHOS SALVO IMPEDIMENTO DEBIDAMENTE ACREDITADO Y EXPRESADO?', '["SI POR RAZONES DE SEGURIDAD O CAUSAS AJENAS A LA VOLUNTAD DEL PERSONAL POLICIAL, NO ES POSIBLE LEVANTAR LAS ACTAS EN EL LUGAR DE LOS HECHOS","LA DILIGENCIA SE ANULA AUTOMÁTICAMENTE POR INCUMPLIMIENTO DE FORMALIDAD","SE TOMA COMO VÁLIDA CUALQUIER VERSIÓN ORAL DE LOS INTERVINIENTES, SIN NECESIDAD DE ACTA ESCRITA","EL FISCAL COMPETENTE DEBE ASUMIR LA REDACCIÓN DE LAS ACTAS EN SU DESPACHO SIN INFORMACIÓN POLICIAL","NO EXISTE SOLUCIÓN LEGALMENTE PREVISTA Y DEBE REPETIRSE LA DILIGENCIA EN OTRO MOMENTO"]'::jsonb, 'SI POR RAZONES DE SEGURIDAD O CAUSAS AJENAS A LA VOLUNTAD DEL PERSONAL POLICIAL, NO ES POSIBLE LEVANTAR LAS ACTAS EN EL LUGAR DE LOS HECHOS', 0, '(texto: (ART: 6)** Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos conexos)**', '185389', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1380, 1380, '¿CUÁL ES LA COMPETENCIA DE LA POLICÍA EN LAS PESQUISAS E INDAGACIONES URGENTES, CONFORME EL ARTÍCULO 6?', '["REALIZAR SOLO INDAGACIONES PRELIMINARES SIN ACTUACIÓN ALGUNA EN EL LUGAR DE LOS HECHOS","LLEVAR A CABO PESQUISAS PARA IDENTIFICAR Y LOCALIZAR AUTORES, VÍCTIMAS, MEDIOS E INSTRUMENTOS DEL DELITO, ASÍ COMO OTROS ELEMENTOS DE CONVICCIÓN","EXCLUSIVAMENTE PROTEGER LOS DERECHOS HUMANOS DE LOS IMPUTADOS DURANTE LA DILIGENCIA","DEDICAR SUS FUNCIONES A LA ORGANIZACIÓN DE OPERATIVOS PREVENTIVOS FUERA DE LA ESCENA DEL DELITO","REMITIR TODA SOSPECHA DIRECTAMENTE AL PODER JUDICIAL SIN DILIGENCIA PREVIA"]'::jsonb, 'LLEVAR A CABO PESQUISAS PARA IDENTIFICAR Y LOCALIZAR AUTORES, VÍCTIMAS, MEDIOS E INSTRUMENTOS DEL DELITO, ASÍ COMO OTROS ELEMENTOS DE CONVICCIÓN', 1, '(texto: (ART: 6)** Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos conexos)**', '185390', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1381, 1381, '¿CUÁL DE LOS SIGUIENTES MÉTODOS UTILIZADOS PARA LA IDENTIFICACIÓN DE PRESUNTOS AUTORES Y PARTÍCIPES DE DELITOS DE EXTORSIÓN Y CONEXOS ES EXPRESAMENTE MENCIONADO EN EL ARTÍCULO 7 DEL D.LEG 1611?', '["RECONOCIMIENTO DE HUELLAS DACTILARES A TRAVÉS DE INTELIGENCIA ARTIFICIAL","EXÁMENES PERICIALES PAPILOSCÓPICOS, MORFOLÓGICOS, FACIALES, CINÉTICOS (GAIT), BIOMÉTRICOS O ANTROPOMÉTRICOS","ENTREVISTAS PSICOLÓGICAS A FAMILIARES DEL IMPUTADO","INTERCEPTACIÓN DE LLAMADAS TELEFÓNICAS SIN AUTORIZACIÓN JUDICIAL","ANÁLISIS DE SOLVENCIA ECONÓMICA DEL IMPUTADO"]'::jsonb, 'EXÁMENES PERICIALES PAPILOSCÓPICOS, MORFOLÓGICOS, FACIALES, CINÉTICOS (GAIT), BIOMÉTRICOS O ANTROPOMÉTRICOS', 1, '(texto: (ART: 7)** Articulo 7.- Identificacion y localizacion de presuntos autores y participes)**', '185391', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1383, 1383, 'SEGÚN EL TEXTO DEL ARTÍCULO 7, ¿QUÉ ELEMENTO ES OBJETO DE LOCALIZACIÓN O UBICACIÓN MEDIANTE MEDIOS TECNOLÓGICOS EN PROCESOS DE EXTORSIÓN Y DELITOS CONEXOS?', '["SOLO LOS PRESUNTOS AUTORES Y PARTÍCIPES","PRESUNTOS AUTORES O PARTÍCIPES, VÍCTIMAS E INSTRUMENTOS, MEDIOS, EFECTOS U OBJETO MATERIAL DEL DELITO","TESTIGOS PROTEGIDOS Y ABOGADOS DEFENSORES","FUNCIONARIO PÚBLICO QUE NO COLABORA CON LA INVESTIGACIÓN","TODA PERSONA VINCULADA ADMINISTRATIVA O CONTRACTUALMENTE A LA VÍCTIMA"]'::jsonb, 'PRESUNTOS AUTORES O PARTÍCIPES, VÍCTIMAS E INSTRUMENTOS, MEDIOS, EFECTOS U OBJETO MATERIAL DEL DELITO', 1, '(texto: (ART: 7)** Articulo 7.- Identificacion y localizacion de presuntos autores y participes)**', '185395', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1384, 1384, '¿EN CUÁL DE LOS SIGUIENTES SUPUESTOS LAS ENTIDADES PÚBLICAS Y PRIVADAS ESTÁN OBLIGADAS A COOPERAR CON LA AUTORIDAD POLICIAL EN INVESTIGACIONES SOBRE EXTORSIÓN, SEGÚN EL ARTÍCULO 9 DEL D. LEG. 1611?', '["SOLO EN PRESENCIA DE ORDEN JUDICIAL DEBIDAMENTE MOTIVADA","ÚNICAMENTE CUANDO EXISTA FLAGRANCIA DELICTIVA RELACIONADA CON EXTORSIÓN O DELITOS CONEXOS","SIEMPRE QUE LA AUTORIDAD POLICIAL LO SOLICITE, SIN NECESIDAD DE NINGÚN TIPO DE ACTO PROCESAL","SOLO CUANDO LA FISCALÍA ASÍ LO REQUIERA, CON INDEPENDENCIA DE LA FLAGRANCIA","EN CUALQUIER INVESTIGACIÓN CRIMINAL, INDEPENDIENTEMENTE DEL TIPO DELICTIVO"]'::jsonb, 'ÚNICAMENTE CUANDO EXISTA FLAGRANCIA DELICTIVA RELACIONADA CON EXTORSIÓN O DELITOS CONEXOS', 1, '(texto: (ART: 9)** Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185400', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1385, 1385, '¿QUÉ PROCEDIMIENTO DEBE OBSERVARSE PARA OBTENER INFORMACIÓN DE ABONADOS DE TELEFONÍA MÓVIL UTILIZADOS EN LA COMISIÓN DE DELITOS DE EXTORSIÓN SEGÚN EL CITADO ARTÍCULO?', '["LA ENTREGA DEBE REALIZARSE EXTRAJUDICIALMENTE SIN PROCEDIMIENTO ESTABLECIDO","LA INFORMACIÓN SE PROPORCIONA MEDIANTE UN PROCEDIMIENTO DEBIDAMENTE ESTABLECIDO EN EL CÓDIGO PROCESAL PENAL","SE REQUIERE APROBACIÓN DEL MINISTERIO DEL INTERIOR","SOLO PUEDE SOLICITARSE BAJO SUPERVISIÓN DE LA CONTRALORÍA GENERAL DE LA REPÚBLICA","ES SUFICIENTE UNA SOLICITUD INFORMAL POR PARTE DE LA POLICÍA NACIONAL"]'::jsonb, 'LA INFORMACIÓN SE PROPORCIONA MEDIANTE UN PROCEDIMIENTO DEBIDAMENTE ESTABLECIDO EN EL CÓDIGO PROCESAL PENAL', 1, '(texto: (ART: 9)** Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185401', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1386, 1386, 'RESPECTO AL ACCESO A DATOS MIGRATORIOS DE EXTRANJEROS EN EL CONTEXTO DE INVESTIGACIONES POR EXTORSIÓN, ¿CUÁL ES UNA OBLIGACIÓN DE LA AUTORIDAD DE MIGRACIONES SEGÚN LO DISPUESTO?', '["NEGAR EL ACCESO A LA INFORMACIÓN MIGRATORIA SI NO HAY SENTENCIA FIRME","FACILITAR EL ACCESO O ENTREGAR DATOS SOBRE MOVIMIENTOS MIGRATORIOS Y SITUACIÓN LEGAL EN EL PAÍS A LA AUTORIDAD POLICIAL, PARA EL ESCLARECIMIENTO DEL DELITO EXCLUSIVAMENTE","SOLICITAR AUTORIZACIÓN PREVIA DEL MINISTERIO DEL EXTERIOR","PROVEER INFORMACIÓN SOLO AL PODER JUDICIAL","REMITIR LA INFORMACIÓN EXCLUSIVAMENTE A LA UIF-PERÚ"]'::jsonb, 'FACILITAR EL ACCESO O ENTREGAR DATOS SOBRE MOVIMIENTOS MIGRATORIOS Y SITUACIÓN LEGAL EN EL PAÍS A LA AUTORIDAD POLICIAL, PARA EL ESCLARECIMIENTO DEL DELITO EXCLUSIVAMENTE', 1, '(texto: (ART: 9)** Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185402', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1387, 1387, '¿CUÁL DE LAS SIGUIENTES ENTIDADES NO SE MENCIONA EXPRESAMENTE EN EL ARTÍCULO 9 COMO HABILITADA PARA INTEGRAR EL MECANISMO PÚBLICO-PRIVADO DE INTERCAMBIO DE INFORMACIÓN?', '["SUPERINTENDENCIA DE BANCA, SEGUROS Y AFP","MINISTERIO PÚBLICO","CONTRALORÍA GENERAL DE LA REPÚBLICA","MINISTERIO DE JUSTICIA Y DERECHOS HUMANOS","SUPERINTENDENCIA NACIONAL DE ADUANAS Y DE ADMINISTRACIÓN TRIBUTARIA"]'::jsonb, 'MINISTERIO DE JUSTICIA Y DERECHOS HUMANOS', 3, '(texto: (ART: 9)** Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185403', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1389, 1389, '¿CUÁL ES EL ROL DE LA UIF-PERÚ RESPECTO AL MECANISMO PÚBLICO-PRIVADO DE LUCHA CONTRA LA EXTORSIÓN Y DELITOS CONEXOS SEGÚN EL ARTÍCULO 9?', '["SUPERVISAR A LAS ENTIDADES BANCARIAS EXCLUSIVAMENTE","EJERCER LA ARTICULACIÓN DEL MECANISMO Y ESTABLECER MEDIANTE RESOLUCIÓN LOS ALCANCES Y PROCEDIMIENTOS","EMITIR SENTENCIAS VINCULANTES","LIDERAR LAS INVESTIGACIONES JUDICIALES DE EXTORSIÓN","DETERMINAR LA SANCIÓN PENAL DE LOS INVESTIGADOS"]'::jsonb, 'EJERCER LA ARTICULACIÓN DEL MECANISMO Y ESTABLECER MEDIANTE RESOLUCIÓN LOS ALCANCES Y PROCEDIMIENTOS', 1, '(texto: (ART: 9)** Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185407', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1390, 1390, 'DE ACUERDO CON EL ARTÍCULO ANALIZADO, ¿QUÉ FINALIDAD TIENE EL INTERCAMBIO DE INFORMACIÓN ENTRE ENTIDADES PÚBLICAS Y PRIVADAS?', '["GARANTIZAR LA CONFIDENCIALIDAD TOTAL DE LAS OPERACIONES FINANCIERAS","OBSTRUIR LA LABOR INVESTIGATIVA DEL MINISTERIO PÚBLICO","FORTALECER LA LUCHA CONTRA LA EXTORSIÓN Y DELITOS CONEXOS","PERMITIR LA COOPERACIÓN INTERNACIONAL EN CUALQUIER DELITO","CREAR UNA BASE DE DATOS PÚBLICA SOBRE LOS INVESTIGADOS"]'::jsonb, 'FORTALECER LA LUCHA CONTRA LA EXTORSIÓN Y DELITOS CONEXOS', 2, '(texto: (ART: 9)** Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185408', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1391, 1391, 'SEGÚN EL ARTÍCULO 9, ¿CUÁLES SUJETOS PRIVADOS PUEDEN INTEGRARSE AL MECANISMO PÚBLICO-PRIVADO DE INTERCAMBIO DE INFORMACIÓN?', '["ÚNICAMENTE BANCOS NACIONALES","ÚNICAMENTE LAS PERSONAS JURÍDICAS INSCRITAS ANTE SUNAT","LOS SUJETOS OBLIGADOS A INFORMAR A LA UIF-PERÚ EN MATERIA DE PREVENCIÓN DEL LAVADO DE ACTIVOS Y FINANCIAMIENTO DEL TERRORISMO","CUALQUIER CIUDADANO INTERESADO EN LA PREVENCIÓN DEL DELITO","SOLAMENTE EMPRESAS DE TELECOMUNICACIONES"]'::jsonb, 'LOS SUJETOS OBLIGADOS A INFORMAR A LA UIF-PERÚ EN MATERIA DE PREVENCIÓN DEL LAVADO DE ACTIVOS Y FINANCIAMIENTO DEL TERRORISMO', 2, '(texto: (ART: 9)** Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185409', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1392, 1392, '¿CUÁL ES LA FUNCIÓN PRINCIPAL DE LA POLICÍA NACIONAL DEL PERÚ EN LA INVESTIGACIÓN DEL DELITO DE EXTORSIÓN Y SUS DELITOS CONEXOS SEGÚN EL ARTÍCULO 10 DEL D.LEG 1611?', '["TOMAR DECISIONES AUTÓNOMAS SOBRE MEDIDAS RESTRICTIVAS DE DERECHOS DURANTE LA INVESTIGACIÓN","DIRIGIR Y CONDUCIR ÍNTEGRAMENTE LA INVESTIGACIÓN FISCAL Y POLICIAL","RECOMENDAR LA ESTRATEGIA DE LA INVESTIGACIÓN AL FISCAL Y EJECUTAR ACCIONES TÉCNICAS NECESARIAS BAJO CONDUCCIÓN FISCAL","EMITIR RESOLUCIONES JUDICIALES FRENTE A HALLAZGOS RELEVANTES","DICTAR MEDIDAS CAUTELARES ADMINISTRATIVAS SOBRE BIENES INCAUTADOS"]'::jsonb, 'RECOMENDAR LA ESTRATEGIA DE LA INVESTIGACIÓN AL FISCAL Y EJECUTAR ACCIONES TÉCNICAS NECESARIAS BAJO CONDUCCIÓN FISCAL', 2, '(texto: (ART: 10)** Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185410', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1393, 1393, 'FRENTE A LA INCAUTACIÓN DE VEHÍCULOS O BIENES INMUEBLES VINCULADOS A DELITOS DE EXTORSIÓN Y CONEXOS, ¿QUÉ PROCEDIMIENTO SE DEBE SEGUIR SEGÚN EL ARTÍCULO 10?', '["REMITIR EL BIEN DE MANERA INMEDIATA A LA MUNICIPALIDAD CORRESPONDIENTE","LA INCAUTACIÓN DEBE SER CONFIRMADA POR UN JUEZ A SOLICITUD DEL FISCAL EN UN PLAZO DE 48 HORAS DESDE LA INCAUTACIÓN","ESPERAR AUTORIZACIÓN EXPRESA DEL PROPIETARIO LEGÍTIMO ANTES DE INCAUTAR EL BIEN","ORDENAR LA DESTRUCCIÓN DEL BIEN INCAUTADO EN LAS PRIMERAS 24 HORAS","DISPONER LA INMEDIATA VENTA PÚBLICA DEL BIEN INCAUTADO PARA EVITAR SU DETERIORO"]'::jsonb, 'LA INCAUTACIÓN DEBE SER CONFIRMADA POR UN JUEZ A SOLICITUD DEL FISCAL EN UN PLAZO DE 48 HORAS DESDE LA INCAUTACIÓN', 1, '(texto: (ART: 10)** Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185411', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1394, 1394, '¿CUÁL DE LOS SIGUIENTES PRESUPUESTOS NO ES REQUISITO PARA LA INCAUTACIÓN DE VEHÍCULOS O INMUEBLES SEGÚN EL ARTÍCULO 10 DEL D.LEG 1611?', '["EXISTENCIA DE VINCULACIÓN ENTRE EL HECHO INDICADOR Y EL BIEN","TITULARIDAD DE LA PROPIEDAD DEL BIEN RECAYENDO EN PRESUNTOS AUTORES O PARTÍCIPES","CAPACIDAD ECONÓMICA DEL TITULAR PARA ADQUIRIR EL BIEN","POSIBILIDAD DE CONOCIMIENTO DEL USO ILÍCITO DEL BIEN POR PARTE DEL TITULAR AJENO Y SU OMISIÓN EN DENUNCIAR O RESOLVER EL CONTRATO","EL BIEN HAYA SIDO UTILIZADO COMO CENTRO DE OPERACIONES CRIMINALES O REFUGIO DE DELINCUENTES"]'::jsonb, 'CAPACIDAD ECONÓMICA DEL TITULAR PARA ADQUIRIR EL BIEN', 2, '(texto: (ART: 10)** Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185412', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1395, 1395, '¿CUÁL DE LAS SIGUIENTES TÉCNICAS ESPECIALES DE INVESTIGACIÓN MENCIONADAS NO REQUIERE NECESARIAMENTE AUTORIZACIÓN JUDICIAL SEGÚN EL ARTÍCULO 10 DEL D.LEG 1611?', '["INTERVENCIÓN LEGAL DE LAS COMUNICACIONES MEDIANTE LEVANTAMIENTO JUDICIAL DEL SECRETO","OBSERVACIÓN, VIGILANCIA Y SEGUIMIENTO","LEVANTAMIENTO DEL SECRETO BANCARIO","LEVANTAMIENTO DE LA RESERVA TRIBUTARIA","GEOLOCALIZACIÓN Y RASTREO VINCULADOS A ACTIVIDADES INTERNACIONALES"]'::jsonb, 'OBSERVACIÓN, VIGILANCIA Y SEGUIMIENTO', 1, '(texto: (ART: 10)** Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185413', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1396, 1396, '¿EN QUÉ SUPUESTO EL TITULAR DE UN BIEN INMUEBLE PODRÍA VERSE COMPROMETIDO EN LA INVESTIGACIÓN DE EXTORSIÓN SIN SER AUTOR DIRECTO, DE ACUERDO AL ARTÍCULO 10 DEL D.LEG 1611?', '["CUANDO NO REALIZA EL PAGO OPORTUNO DE IMPUESTOS PREDIALES","CUANDO FACILITA EL USO DEL BIEN CON FINES LÍCITOS DOCUMENTADOS","CUANDO, AUN SIN SER AUTOR, TENÍA POSIBILIDAD DE CONOCER EL USO ILÍCITO Y NO DENUNCIÓ NI ACTUÓ PARA RESOLVER EL CONTRATO O DESALOJAR","CUANDO ALQUILA EL BIEN A UNA EMPRESA RECONOCIDA LEGALMENTE","CUANDO TRANSFIERE LA PROPIEDAD MEDIANTE ESCRITURA PÚBLICA Y YA NO TIENE POSESIÓN"]'::jsonb, 'CUANDO, AUN SIN SER AUTOR, TENÍA POSIBILIDAD DE CONOCER EL USO ILÍCITO Y NO DENUNCIÓ NI ACTUÓ PARA RESOLVER EL CONTRATO O DESALOJAR', 2, '(texto: (ART: 10)** Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185415', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1397, 1397, 'RESPECTO A LOS BIENES INCAUTADOS POR LA POLICÍA NACIONAL DEL PERÚ, ¿QUÉ CARACTERÍSTICA DEBEN CUMPLIR PARA SER INCAUTADOS SEGÚN EL ARTÍCULO 10 DEL D.LEG 1611?', '["SOLO PUEDEN INCAUTARSE SI HAN SIDO ROBADOS DE UNA DEPENDENCIA ESTATAL","DEBEN SER BIENES AUTOMOTORES Y, EN CASO DE COMPUTADORAS, SÓLO SI SON NUEVAS","PUEDEN SER INCAUTADOS SI SE DUDA DE LA LEGALIDAD DE SU ORIGEN Y SE ENCUENTRAN VINCULADOS A DELITOS INVESTIGADOS","ES IRRELEVANTE LA DOCUMENTACIÓN DEL BIEN A INCAUTAR","PUEDEN SER DECOMISADOS POR CUALQUIER AGENTE PÚBLICO SIN REQUISITOS ADICIONALES"]'::jsonb, 'PUEDEN SER INCAUTADOS SI SE DUDA DE LA LEGALIDAD DE SU ORIGEN Y SE ENCUENTRAN VINCULADOS A DELITOS INVESTIGADOS', 2, '(texto: (ART: 10)** Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185416', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1398, 1398, '¿QUÉ ACCIÓN PUEDE TOMAR LA POLICÍA NACIONAL DEL PERÚ RESPECTO A CENTROS DE OPERACIONES ILÍCITAS CONFORME AL ARTÍCULO 10 DEL D.LEG 1611?', '["SOLICITAR SU CLAUSURA ADMINISTRATIVA POR PARTE DE LA MUNICIPALIDAD","EJECUTAR VIGILANCIA Y SEGUIMIENTO PARA IDENTIFICACIÓN, INDIVIDUALIZACIÓN Y DOCUMENTACIÓN DE LAS ACTIVIDADES CRIMINALES","REMITIR UN INFORME PRO FORMA SIN INTERVENCIÓN DIRECTA","ORDENAR JUDICIALMENTE EL DESALOJO INMEDIATO","APROPIAR TEMPORALMENTE LOS BIENES DEL LUGAR CON FINES RECAUDATORIOS"]'::jsonb, 'EJECUTAR VIGILANCIA Y SEGUIMIENTO PARA IDENTIFICACIÓN, INDIVIDUALIZACIÓN Y DOCUMENTACIÓN DE LAS ACTIVIDADES CRIMINALES', 1, '(texto: (ART: 10)** Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185417', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1399, 1399, '¿QUÉ TÉCNICA ESPECIAL DE INVESTIGACIÓN PERMITE A LA POLICÍA NACIONAL DEL PERÚ CONOCER INTERNAMENTE LAS OPERACIONES ILÍCITAS DE UNA ORGANIZACIÓN, SEGÚN EL ARTÍCULO 10 DEL D.LEG 1611?', '["OBSERVACIÓN INDIRECTA MEDIANTE CIRCUITOS CERRADOS DE TERCEROS","USO DE AGENTES ENCUBIERTOS O AGENTES ESPECIALES","LEVANTAMIENTO DEL SECRETO BANCARIO SIN ORDEN JUDICIAL","EMISIÓN DE ALERTAS PREVENTIVAS EN MEDIOS MASIVOS","RECOLECCIÓN DE TESTIMONIOS ANÓNIMOS EXCLUSIVAMENTE"]'::jsonb, 'USO DE AGENTES ENCUBIERTOS O AGENTES ESPECIALES', 1, '(texto: (ART: 10)** Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185418', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1400, 1400, 'CUANDO LA POLICÍA REQUIERE INFORMACIÓN DE REGISTROS OFICIALES O PRIVADOS DURANTE LA INVESTIGACIÓN, ¿CUÁL ES EL PROCEDIMIENTO CORRECTO SEGÚN EL ARTÍCULO 10 DEL D.LEG 1611?', '["SOLICITAR SIEMPRE INFORMACIÓN EN DOCUMENTOS EN PAPEL FIRMADOS ANTE NOTARIO","LOS REQUERIDOS DEBEN SUMINISTRAR DATOS SIN DILACIÓN A TRAVÉS DE SOPORTES MAGNÉTICOS O ELECTRÓNICOS, SALVO EXCEPCIONES LEGALES","EXIGIR LA PRESENCIA FÍSICA DE TODOS LOS TITULARES EN LA ENTREGA DE INFORMACIÓN","COORDINAR LA ENTREGA CON LA DEFENSORÍA DEL PUEBLO","PERMITIR QUE LA ENTIDAD REQUERIDA ENTREGUE LOS DATOS EN UN PLAZO NO MENOR A 30 DÍAS HÁBILES"]'::jsonb, 'LOS REQUERIDOS DEBEN SUMINISTRAR DATOS SIN DILACIÓN A TRAVÉS DE SOPORTES MAGNÉTICOS O ELECTRÓNICOS, SALVO EXCEPCIONES LEGALES', 1, '(texto: (ART: 10)** Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185419', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1401, 1401, 'EL NIVEL DE FUERZA A EMPLEAR ES UNO DE LOS ASPECTOS IMPORTANTES QUE SE TIENEN QUE TENER EN CUENTA EN LAS TECNICAS DE INTERVENCION, Y SE REFIERE A:', '["SE DEBE CONSIDERAR LAS CARACTERÍSTICAS DEL LUGAR DE LA INTERVENCIÓN (UBICACIÓN, ESTRUCTURAS DESCONOCIDAS, CALLEJONES, EDIFICACIONES, ILUMINACIÓN, ENTRE OTROS) QUE PUEDAN REPRESENTAR UN RIESGO PARA LA INTEGRIDAD DEL EFECTIVO POLICIAL O DE TERCEROS, ASÍ COMO EL POSIBLE APOYO DE OTRAS PERSONAS AL INFRACTOR","EL EFECTIVO POLICIAL DEBE TENER EN CUENTA EL COMPORTAMIENTO DE LA PERSONA A INTERVENIR, QUE PUEDE SER DE COLABORACIÓN, RESISTENCIA PASIVA O ACTIVA, LLEGANDO INCLUSIVE A LA AGRESIÓN LETAL","ESTA INTERVENCIÓN SE DEBE INICIAR CON LA VERBALIZACIÓN","LUEGO DE UNA APRECIACIÓN DE LA SITUACIÓN Y LAS CIRCUNSTANCIAS QUE SE PRESENTAN EN LA INTERVENCIÓN, EL EFECTIVO POLICIAL EMPLEARÁ LA FUERZA, DE ACUERDO AL NIVEL DE RESISTENCIA DE LA PERSONA A INTERVENIR","FORMAR EL CONO DE SEGURIDAD, TOMANDO UNA DISTANCIA APROXIMADA DE DOS BRAZOS EXTENDIDOS, QUE IMPIDA AL INTERVENIDO ATENTAR CONTRA LA INTEGRIDAD FÍSICA DEL O LOS EFECTIVOS POLICIALES; DE EXISTIR UNA PARED (INMUEBLE), EL EFECTIVO QUE DA LA SEGURIDAD DEBE UBICARSE DE ESPALDAS A ÉSTA"]'::jsonb, 'LUEGO DE UNA APRECIACIÓN DE LA SITUACIÓN Y LAS CIRCUNSTANCIAS QUE SE PRESENTAN EN LA INTERVENCIÓN, EL EFECTIVO POLICIAL EMPLEARÁ LA FUERZA, DE ACUERDO AL NIVEL DE RESISTENCIA DE LA PERSONA A INTERVENIR', 3, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185988', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1402, 1402, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- SE HAN CONSIDERADO DOS SITUACIONES QUE SE PRESENTAN EN FORMA COTIDIANA EN EL SERVICIO POLICIAL: LA PRIMERA, CON FINES DE IDENTIFICACIÓN, Y LA SEGUNDA, CUANDO SE TRATE DE UN PRESUNTO INFRACTOR. SIN EMBARGO ...:', '["UNA NO ES EXCLUYENTE DE LA OTRA","UNA ES EXCLUYENTE DE LA OTRA","UNA NO ES INCLUYENTE DE LA OTRA","UNA ES INCLUYENTE DE LA OTRA","EN OCASIONES AMBAS SITUACIONES NO SE CUMPLEN"]'::jsonb, 'UNA NO ES EXCLUYENTE DE LA OTRA', 0, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185989', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1403, 1403, 'LA PERCEPCIÓN DEL RIESGO ES UNO DE LOS ASPECTOS IMPORTANTES QUE SE TIENEN QUE TENER EN CUENTA EN LAS TÉCNICAS DE INTERVENCIÓN, DONDE SE DEBE CONSIDERAR LAS CARACTERÍSTICAS DEL LUGAR DE LA INTERVENCIÓN (UBICACIÓN, ESTRUCTURAS DESCONOCIDAS, CALLEJONES, EDIFICACIONES, ILUMINACIÓN, ENTRE OTROS) QUE PUEDAN REPRESENTAR UN RIESGO PARA LA INTEGRIDAD DEL PERSONAL POLICIAL O DE TERCEROS, ASÍ COMO EL POSIBLE....:', '["APOYO POLICIAL","INCREMENTO DE LAS FUERZAS AMIGAS","EVENTO DE FUGA DE LA PERSONA INTERVENIDA","APOYO DE OTRAS PERSONAS AL INFRACTOR","ATAQUE TERRORISTA"]'::jsonb, 'APOYO DE OTRAS PERSONAS AL INFRACTOR', 3, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185990', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1404, 1404, 'EL NIVEL DE FUERZA A EMPLEAR ES UNO DE LOS ASPECTOS IMPORTANTES QUE SE TIENEN QUE TENER EN CUENTA EN LAS TECNICAS DE INTERVENCION, EN LA CUAL, LUEGO DE UNA APRECIACIÓN DE LA SITUACIÓN Y LAS CIRCUNSTANCIAS QUE SE PRESENTAN EN LA INTERVENCIÓN, EL PERSONAL POLICIAL EMPLEARÁ LA FUERZA, DE ACUERDO.....:', '["A LA FUERZA QUE SE PUEDA EJERCER SOBRE LA PERSONA A INTERVENIR","A LA EDAD DEL EFECTIVO POLICIAL","A LA CONDICIÓN FISICA DEL EFECTIVO POLICIAL","A LA EDAD DE LA PERSONA A INTERVENIR","AL NIVEL DE RESISTENCIA DE LA PERSONA A INTERVENIR"]'::jsonb, 'AL NIVEL DE RESISTENCIA DE LA PERSONA A INTERVENIR', 4, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185991', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1405, 1405, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- RESPECTO A LA INTERVENCIÓN CON FINES DE IDENTIFICACIÓN, ES CONVENIENTE TENER EN CONSIDERACIÓN LOS SIGUIENTES ASPECTOS:', '["IDENTIFICARSE (SALUDO, GRADO, APELLIDOS, UNIDAD EN LA QUE PRESTA SERVICIO), HACIÉNDOLE CONOCER EL MOTIVO DE LA INTERVENCIÓN","PUEDEN PRESENTARSE DURANTE EL PATRULLAJE O A MÉRITO DE UNA COMUNICACIÓN RADIAL O TELEFÓNICA DE LA UNIDAD POLICIAL","ESTAS INTERVENCIONES SON LAS QUE REPRESENTAN UN MAYOR NIVEL DE RIESGO PARA LOS EFECTIVOS POLICIALES","ES DE SUMA IMPORTANCIA QUE LA INFORMACIÓN QUE RECABEN LOS EFECTIVOS QUE VAN A INTERVENIR SEA DETALLADA CON LA FINALIDAD DE TOMAR CONOCIMIENTO DE LA SITUACIÓN","EL POLICÍA DEBE IDENTIFICARSE COMO TAL EXPRESANDO EN VOZ ALTA: ¡ALTO POLICÍA!"]'::jsonb, 'IDENTIFICARSE (SALUDO, GRADO, APELLIDOS, UNIDAD EN LA QUE PRESTA SERVICIO), HACIÉNDOLE CONOCER EL MOTIVO DE LA INTERVENCIÓN', 0, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185992', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1406, 1406, '¿QUÉ ASPECTOS IMPORTANTES SE TIENEN QUE TENER EN CUENTA EN LAS TÉCNICAS DE INTERVENCIÓN?', '["EL NÚMERO DE EFECTIVOS","EL CONO DE SEGURIDAD","LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD","EL NIVEL DE FUERZA A EMPLEAR","LA LÍNEA IMAGINARIA QUE DIVIDE LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD"]'::jsonb, 'EL NIVEL DE FUERZA A EMPLEAR', 3, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185993', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1421, 1421, 'RESPECTO A LAS TÉCNICAS DE INTERVENCIÓN, EN CASO QUE LA INTERVENCIÓN SEA EJECUTADA POR DOS POLICIAS A PIE, ÉSTOS DEBEN FORMAR EN LO POSIBLE UN (. ...................... ), EN CUYA BASE DEBEN UBICARSE LOS POLICÍAS INTERVENTORES, Y EN EL VÉRTICE O PUNTO MEDIO PROYECTADO DEL TRIÁNGULO', '["TRIÁNGULO DE RESPUESTA","TRIÁNGULO DE SEGURIDAD","LÍNEA IMAGINARIA","TRIÁNGULO IMAGINARIO","ÁREA DE SEGURIDAD"]'::jsonb, 'TRIÁNGULO DE SEGURIDAD', 1, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186008', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1422, 1422, 'AL SER COMUNICADO DE UNA INTERVENCIÓN EN INMUEBLES O EN OTROS LUGARES QUE AMERITEN DESPLAZARSE POR UNA ZONA NO RECONOCIDA E INSEGURA, SE DEBE UTILIZAR LOS PRINCIPIOS DEL PENSAMIENTO TÁCTICO PARA EVALUAR LAS POSIBLES ÁREAS DE RIESGO. SE DEBEN ANTICIPAR LAS SITUACIONES PELIGROSAS Y MANTENERSE LISTOS PARA DEFENDERSE. EL ENUNCIADO ANTERIOR CORRESPONDE A:', '["INTERVENCIÓN EN INMUEBLES: INGRESO","INTERVENCIÓN EN INMUEBLES: DESPLAZAMIENTOS","INTERVENCIÓN EN INMUEBLES: RECONOCIMIENTO","INTERVENCIÓN EN INMUEBLES: PASADIZOS","INTERVENCIÓN EN INMUEBLES: ESCALERAS"]'::jsonb, 'INTERVENCIÓN EN INMUEBLES: DESPLAZAMIENTOS', 1, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186009', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1407, 1407, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INDIQUE LA ALTERNATIVA QUE FORMA PARTE DE LOS PASOS QUE SE DEBEN TENER EN CUENTA AL MOMENTO DE UNA INTERVENCIÓN A UN PRESUNTO INFRACTOR:', '["CULMINADA LA INTERVENCIÓN SIN NOVEDAD, EL POLICÍA DE CONTACTO (P1) AGRADECERÁ SU COLABORACIÓN, DESPLAZÁNDOSE LUEGO HACIA LA UBICACIÓN DEL POLICÍA DE SEGURIDAD (P2), PARA QUE EL CIUDADANO REINICIE SU CAMINO ACOMPAÑÁNDOLO CON LA MIRADA HASTA CIERTA DISTANCIA","EFECTUAR PREGUNTAS RELACIONADAS A LOS DATOS CONSIGNADOS EN EL DOCUMENTO DE IDENTIDAD CON LA FINALIDAD DE CONTRASTARLOS, O FORMULAR PREGUNTAS MODIFICANDO ALGUNOS DATOS QUE PERMITAN ESTABLECER LA TITULARIDAD DE LOS MISMOS; POR EJEMPLO, MENCIONARLE COMO SU SEGUNDO NOMBRE UNO QUE NO LE CORRESPONDE","SOLICITARLE SUS DOCUMENTOS DE IDENTIFICACIÓN PERSONAL, PERMANECIENDO SIEMPRE EN UNA ACTITUD VIGILANTE, SIN DESCUIDAR EL CONTACTO VISUAL","AL VERIFICAR LOS DOCUMENTOS, HACERLO EN UNA POSICIÓN TAL QUE NO OBSTACULICE EL DOMINIO VISUAL, PRINCIPALMENTE DE LAS MANOS DEL INTERVENIDO","HACERLE SABER EL MOTIVO DE LA INTERVENCIÓN, POR EJEMPLO: ES USTED SOSPECHOSO DE ; O HA COMETIDO EL DELITO DE ;"]'::jsonb, 'HACERLE SABER EL MOTIVO DE LA INTERVENCIÓN, POR EJEMPLO: ES USTED SOSPECHOSO DE ........ ; O HA COMETIDO EL DELITO DE ......... ;', null, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185994', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1408, 1408, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- RESPECTO A LA INTERVENCIÓN A UN PRESUNTO INFRACTOR, INDIQUE EL ENUNCIADO CORRECTO:', '["ESTAS INTERVENCIONES SON LAS QUE REPRESENTAN UN MAYOR NIVEL DE RIESGO PARA EL PERSONAL POLICIAL. PUEDEN PRESENTARSE DURANTE EL PATRULLAJE O A MÉRITO DE UNA COMUNICACIÓN RADIAL O TELEFÓNICA DE LA UNIDAD POLICIAL. EN ESE SENTIDO, ES DE SUMA IMPORTANCIA QUE LA INFORMACIÓN QUE RECABE EL PERSONAL POLICIAL QUE VA A INTERVENIR SEA DETALLADA CON LA FINALIDAD DE TOMAR CONOCIMIENTO DE LA SITUACIÓN","SE INDIVIDUALIZA CLARAMENTE A LA PERSONA A INTERVENIR (VESTIMENTA, CARACTERÍSTICAS FÍSICAS, SEXO, ETC.)","SE RECIBE LOS DOCUMENTOS CON LA MANO QUE NO PORTE EL ARMA DE FUEGO; ESTO PARA PERMITIR QUE ANTE UNA EVENTUAL REACCIÓN PUEDA USARLA CON LIBERTAD DE ACCIÓN","IDENTIFICARSE (GRADO, APELLIDOS Y UNIDAD EN LA QUE PRESTA SERVICIO), HACIÉNDOLE CONOCER EL MOTIVO DE LA INTERVENCIÓN","SE SOLICITA SUS DOCUMENTOS DE IDENTIFICACIÓN PERSONAL, PERMANECIENDO SIEMPRE EN UNA ACTITUD VIGILANTE, SIN DESCUIDAR EL CONTACTO VISUAL"]'::jsonb, 'ESTAS INTERVENCIONES SON LAS QUE REPRESENTAN UN MAYOR NIVEL DE RIESGO PARA EL PERSONAL POLICIAL. PUEDEN PRESENTARSE DURANTE EL PATRULLAJE O A MÉRITO DE UNA COMUNICACIÓN RADIAL O TELEFÓNICA DE LA UNIDAD POLICIAL. EN ESE SENTIDO, ES DE SUMA IMPORTANCIA QUE LA INFORMACIÓN QUE RECABE EL PERSONAL POLICIAL QUE VA A INTERVENIR SEA DETALLADA CON LA FINALIDAD DE TOMAR CONOCIMIENTO DE LA SITUACIÓN', 0, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185995', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1409, 1409, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- RESPECTO A LA INTERVENCIÓN A UN PRESUNTO INFRACTOR, INDIQUE EL ENUNCIADO CORRECTO', '["SE FORMAR EL CONO DE SEGURIDAD, TOMANDO UNA DISTANCIA APROXIMADA DE DOS BRAZOS EXTENDIDOS, QUE IMPIDA AL INTERVENIDO ATENTAR CONTRA LA INTEGRIDAD FÍSICA DEL O LOS EFECTIVOS POLICIALES; DE EXISTIR UNA PARED (INMUEBLE), EL EFECTIVO QUE DA LA SEGURIDAD DEBE UBICARSE DE ESPALDAS A ÉSTA","SE INDIVIDUALIZA CLARAMENTE A LA PERSONA A INTERVENIR (VESTIMENTA, CARACTERÍSTICAS FÍSICAS, SEXO, ETC.)","ESTA INTERVENCION SON LA QUE REPRESENTA UN MAYOR NIVEL DE RIESGO PARA EL PERSONAL POLICIAL","IDENTIFICARSE (GRADO, APELLIDOS Y UNIDAD EN LA QUE PRESTA SERVICIO), HACIÉNDOLE CONOCER EL MOTIVO DE LA INTERVENCIÓN","SE SOLICITA SUS DOCUMENTOS DE IDENTIFICACIÓN PERSONAL, PERMANECIENDO SIEMPRE EN UNA ACTITUD VIGILANTE, SIN DESCUIDAR EL CONTACTO VISUAL"]'::jsonb, 'ESTA INTERVENCION SON LA QUE REPRESENTA UN MAYOR NIVEL DE RIESGO PARA EL PERSONAL POLICIAL', 2, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185996', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1410, 1410, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INDIQUE LA ALTERNATIVA QUE NO FORMA PARTE DE LOS PASOS QUE SE DEBEN TENER EN CUENTA AL MOMENTO DE UNA INTERVENCIÓN A UN PRESUNTO INFRACTOR:', '["EL POLICÍA DEBE IDENTIFICARSE COMO TAL EXPRESANDO EN VOZ ALTA: ¡ALTO POLICÍA!","¡LEVANTE LAS MANOS, MÍREME!","HACERLE SABER EL MOTIVO DE LA INTERVENCIÓN, POR EJEMPLO: ES USTED SOSPECHOSO DE.........O HA COMETIDO EL DELITO DE","INDICARLE QUE SE LE VA A IDENTIFICAR Y REGISTRAR, PARA QUE ASÍ PUEDA COLABORAR CON LA INTERVENCIÓN. DE SER NECESARIO, ORDENAR QUE ADOPTE UNA POSICIÓN APROPIADA PARA LA INMOVILIZACIÓN TEMPORAL (COLOCÁNDOLE LOS GRILLETES) Y REALIZAR EL REGISTRO PRELIMINAR","CULMINADA LA INTERVENCIÓN SIN NOVEDAD, EL POLICÍA DE CONTACTO (P1) AGRADECERÁ SU COLABORACIÓN, DESPLAZÁNDOSE LUEGO HACIA LA UBICACIÓN DEL POLICÍA DE SEGURIDAD (P2), PARA QUE EL CIUDADANO REINICIE SU CAMINO ACOMPAÑÁNDOLO CON LA MIRADA HASTA CIERTA DISTANCIA"]'::jsonb, 'CULMINADA LA INTERVENCIÓN SIN NOVEDAD, EL POLICÍA DE CONTACTO (P1) AGRADECERÁ SU COLABORACIÓN, DESPLAZÁNDOSE LUEGO HACIA LA UBICACIÓN DEL POLICÍA DE SEGURIDAD (P2), PARA QUE EL CIUDADANO REINICIE SU CAMINO ACOMPAÑÁNDOLO CON LA MIRADA HASTA CIERTA DISTANCIA', 4, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185997', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1411, 1411, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- COMPLETE CORRECTAMENTE RESPECTO A LA INTERVENCIÓN A UN PRESUNTO INFRACTOR: UNA ACCIÓN QUE AYUDARÁ A MINIMIZAR LOS RIESGOS ES (. .................. ). ELLO NOS PERMITIRÁ UBICAR CUALQUIER TIPO DE AMENAZA (ARMA U OBJETO). ESTA ACCIÓN SE EFECTÚA EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA FRENTE AL EFECTIVO POLICIAL QUE REALIZA EL CONTACTO VERBAL, DESDE LA LÍNEA IMAGINARIA QUE DIVIDE EL ÁREA DE SEGURIDAD Y LA DE RIESGO', '["EFECTUAR UN REGISTRO CORPORAL DEL INTERVENIDO","EFECTUAR UN ALLANAMIENTO AL DOMICILIO DEL INTERVENIDO","EFECTUAR UN REGISTRO AL DOMICILIO DEL INTERVENIDO","EFECTUAR UN REGISTRO PERSONAL DEL INTERVENIDO","EFECTUAR UN REGISTRO VISUAL DEL INTERVENIDO"]'::jsonb, 'EFECTUAR UN REGISTRO VISUAL DEL INTERVENIDO', 4, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185998', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1412, 1412, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- COMPLETE CORRECTAMENTE RESPECTO A LA INTERVENCIÓN A UN PRESUNTO INFRACTOR: UNA ACCIÓN QUE AYUDARÁ A MINIMIZAR LOS RIESGOS ES EFECTUAR UN REGISTRO VISUAL DEL INTERVENIDO. ELLO NOS PERMITIRÁ UBICAR CUALQUIER TIPO DE AMENAZA (ARMA U OBJETO). ESTA ACCIÓN SE EFECTÚA (.................... ), DESDE LA LÍNEA IMAGINARIA QUE DIVIDE EL ÁREA DE SEGURIDAD Y LA DE RIESGO', '["EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA FRENTE AL POLICÍA QUE REALIZA EL CONTACTO VERBAL","EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA FRENTE AL EFECTIVO POLICIAL QUE REALIZA EL CONTACTO VISUAL","DESPUÉS QUE SE REALIZA EL CONTACTO VISUAL","EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA DISTANTE AL EFECTIVO POLICIAL QUE REALIZA EL CONTACTO VERBAL","EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA LEJOS AL EFECTIVO POLICIAL QUE REALIZA EL CONTACTO VERBAL"]'::jsonb, 'EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA FRENTE AL POLICÍA QUE REALIZA EL CONTACTO VERBAL', 0, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '185999', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1435, 1435, 'A QUE NIVEL DE ALERTA CORRESPONDE EL SIGUIENTE ENUNCIADO: SE DISTRAE CON LO QUE ESTÁ SUCEDIENDO A SU ALREDEDOR, LO QUE PUEDE SER OCASIONADO POR EL CANSANCIO O LA CREENCIA DE QUE NO HAY POSIBILIDAD DE PROBLEMAS', '["NIVEL DE ATENCIÓN","NIVEL DE SEGURIDAD","NIVEL DE DISTRACCIÓN","NIVEL DE ALERTA MÁXIMA","NIVEL DE REACCIÓN"]'::jsonb, 'NIVEL DE DISTRACCIÓN', 2, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186022', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1413, 1413, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INTERVENCIÓN A UN PRESUNTO INFRACTOR: PARA EFECTUAR EL ARRESTO, EL EFECTIVO POLICIAL PUEDE UTILIZAR BÁSICAMENTE TRES POSICIONES, LAS CUALES SON: DE PIE, DE RODILLAS, Y TENDIDO O ECHADO. ELIJA LA ALTERNATIVA QUE SE RELACIONE CON LA POSICIÓN DE PIE:', '["ES RECOMENDABLE EMPLEAR ESTA TÉCNICA CUANDO EL INFRACTOR SE ENCUENTRA EN UN AMBIENTE ABIERTO","ESTA POSICIÓN ES RECOMENDABLE CUANDO EN EL LUGAR DE LA INTERVENCIÓN EXISTE UN MURO, PARED, ETC. DONDE EL INFRACTOR SE PUEDA APOYARSE","EFECTUADO EL CONTACTO VISUAL E INICIADA LA VERBALIZACIÓN, SE ORDENARÁ AL INTERVENIDO COLOCARSE FRENTE A LOS POLICÍAS, A UNA DISTANCIA QUE PERMITA DOMINAR LA SITUACIÓN, FORMANDO EL CONO DE SEGURIDAD; SE LE INDICA QUE LEVANTE LOS BRAZOS, CON LAS MANOS TOTALMENTE ALEJADAS UNA DE OTRA Y LOS DEDOS SEPARADOS","ESTA POSICIÓN ES LA MÁS SEGURA, REPRESENTA MENOS RIESGO O POSIBILIDAD DE REACCIÓN DEL INFRACTOR. ES LA MÁS RECOMENDABLE CUANDO EXISTA MÁS DE UN INTERVENIDO","UTILIZANDO LA VERBALIZACIÓN SE ORDENARÁ AL INTERVENIDO UBICARSE FRENTE A LOS EFECTIVOS POLICIALES, A UNA DISTANCIA QUE LES PERMITA DOMINAR LA SITUACIÓN Y FORMAR EL CONO DE SEGURIDAD, INDICÁNDOLE QUE LEVANTE LOS BRAZOS, CON LAS MANOS TOTALMENTE ALEJADAS UNA DE OTRA Y LOS DEDOS SEPARADOS"]'::jsonb, 'ESTA POSICIÓN ES RECOMENDABLE CUANDO EN EL LUGAR DE LA INTERVENCIÓN EXISTE UN MURO, PARED, ETC. DONDE EL INFRACTOR SE PUEDA APOYARSE', 1, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186000', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1414, 1414, '¿QUÉ ASPECTOS IMPORTANTES SE TIENEN QUE TENER EN CUENTA EN LAS TÉCNICAS DE INTERVENCIÓN?', '["EL NÚMERO DE EFECTIVOS POLICIALES","LA ACTITUD DE LA PERSONA A SER INTERVENIDA","LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD","LA LÍNEA IMAGINARIA QUE DIVIDE LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD","EL CONO DE SEGURIDAD"]'::jsonb, 'LA ACTITUD DE LA PERSONA A SER INTERVENIDA', 1, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186001', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1415, 1415, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INTERVENCIÓN A UN PRESUNTO INFRACTOR: PARA EFECTUAR EL ARRESTO, EL EFECTIVO POLICIAL PUEDE UTILIZAR BÁSICAMENTE TRES POSICIONES, LAS CUALES SON: DE PIE, DE RODILLAS, Y TENDIDO O ECHADO. SI DURANTE LA EJECUCIÓN DEL PROCEDIMIENTO DEL ARRESTO EN LA POSICIÓN TENDIDO O ECHADO, EL INTERVENIDO SE TORNA VIOLENTO, EL EFECTIVO POLICIAL DE CONTACTO SE ALEJARA RÁPIDAMENTE DE ÉL, RETORNANDO A SU ÁREA DE SEGURIDAD EMPUÑANDO SU ARMA, Y REINICIANDO LA (. ............... ) PARA RETOMAR EL PROCEDIMIENTO', '["INTERVENCIÓN","VERBALIZACIÓN","TÉCNICA DE CONDUCCIÓN","TÉCNICA DE INTERVENCIÓN","SECUENCIA DE INTERVENCIÓN"]'::jsonb, 'VERBALIZACIÓN', 1, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186002', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1416, 1416, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INTERVENCIÓN A UN PRESUNTO INFRACTOR: PARA EFECTUAR EL ARRESTO, EL EFECTIVO POLICIAL PUEDE UTILIZAR BÁSICAMENTE TRES POSICIONES, LAS CUALES SON: DE PIE, DE RODILLAS, Y TENDIDO O ECHADO. SI DURANTE LA EJECUCIÓN DEL PROCEDIMIENTO DEL ARRESTO EN LA POSICIÓN TENDIDO O ECHADO, EL INTERVENIDO SE TORNA VIOLENTO, EL (. ...................) SE ALEJARA RÁPIDAMENTE DE ÉL, RETORNANDO A SU ÁREA DE SEGURIDAD EMPUÑANDO SU ARMA, Y REINICIANDO LA VERBALIZACIÓN PARA RETOMAR EL PROCEDIMIENTO', '["POLICÍA DE CONTACTO","INTERVENIDO","EFECTIVO POLICIAL QUE INTERVIENE","EFECTIVO POLICIAL DE SEGURIDAD","EFECTIVO POLICIAL DE APOYO"]'::jsonb, 'POLICÍA DE CONTACTO', 0, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186003', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1427, 1427, 'INTERVENCIÓN EN INMUEBLES.- INDIQUE LA ALTERNATIVA QUE SE RELACIONE CON LA SIGUIENTE TÉCNICA DE INGRESO A INMUEBLES: EL PERONAL POLICIAL INTERVINIENTES SE DEBEN UBICAR A AMBOS LADOS DE LA PUERTA, ORIENTANDO SUS ARMAS HACIA ÉSTA. EL MÁS CARACTERIZADO SEÑALA CUÁNDO HAY QUE MOVERSE. RECORDAR: EL QUE INGRESE PRIMERO DEBERÁ CUBRIR LA PARTE DE LA HABITACIÓN QUE GENERALMENTE ESTÁ DEL LADO DE LAS BISAGRAS', '["INGRESO EN X","INGRESO EN J","INGRESO POR EL LADO LARGO","INGRESO DINÁMICO","INGRESO POR EL LADO CORTO"]'::jsonb, 'INGRESO EN X', 0, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186014', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1417, 1417, 'LA PERCEPCIÓN DEL RIESGO ES UNO DE LOS ASPECTOS IMPORTANTES QUE SE TIENEN QUE TENER EN CUENTA EN LAS TECNICAS DE INTERVENCION, Y SE REFIERE A:', '["SE DEBE CONSIDERAR LAS CARACTERÍSTICAS DEL LUGAR DE LA INTERVENCIÓN (UBICACIÓN, ESTRUCTURAS DESCONOCIDAS, CALLEJONES, EDIFICACIONES, ILUMINACIÓN, ENTRE OTROS) QUE PUEDAN REPRESENTAR UN RIESGO PARA LA INTEGRIDAD DEL EFECTIVO POLICIAL O DE TERCEROS, ASÍ COMO EL POSIBLE APOYO DE OTRAS PERSONAS AL INFRACTOR","EL EFECTIVO POLICIAL DEBE TENER EN CUENTA EL COMPORTAMIENTO DE LA PERSONA A INTERVENIR, QUE PUEDE SER DE COLABORACIÓN, RESISTENCIA PASIVA O ACTIVA, LLEGANDO INCLUSIVE A LA AGRESIÓN LETAL","INTERVENCIONES CON ARMA DE FUEGO","LUEGO DE UNA APRECIACIÓN DE LA SITUACIÓN Y LAS CIRCUNSTANCIAS QUE SE PRESENTAN EN LA INTERVENCIÓN, EL EFECTIVO POLICIAL EMPLEARÁ LA FUERZA, DE ACUERDO AL NIVEL DE RESISTENCIA DE LA PERSONA A INTERVENIR","EL POLICÍA DEBE IDENTIFICARSE COMO TAL EXPRESANDO EN VOZ ALTA: !ALTO POLICÍA!"]'::jsonb, 'SE DEBE CONSIDERAR LAS CARACTERÍSTICAS DEL LUGAR DE LA INTERVENCIÓN (UBICACIÓN, ESTRUCTURAS DESCONOCIDAS, CALLEJONES, EDIFICACIONES, ILUMINACIÓN, ENTRE OTROS) QUE PUEDAN REPRESENTAR UN RIESGO PARA LA INTEGRIDAD DEL EFECTIVO POLICIAL O DE TERCEROS, ASÍ COMO EL POSIBLE APOYO DE OTRAS PERSONAS AL INFRACTOR', 0, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186004', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1418, 1418, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INTERVENCIÓN A UN PRESUNTO INFRACTOR: PARA EFECTUAR EL ARRESTO, EL EFECTIVO POLICIAL PUEDE UTILIZAR BÁSICAMENTE TRES POSICIONES, LAS CUALES SON: DE PIE, DE RODILLAS, Y TENDIDO O ECHADO. DURANTE LA EJECUCIÓN DEL PROCEDIMIENTO DEL ARRESTO EN LA POSICIÓN DE RODILLAS, EFECTUADO EL CONTACTO VISUAL E INICIADA LA VERBALIZACIÓN, SE ORDENARÁ AL INTERVENIDO COLOCARSE FRENTE A LOS POLICÍAS, A UNA DISTANCIA (. ............. ), FORMANDO EL TRIÁNGULO DE SEGURIDAD; SE LE INDICA QUE LEVANTE LOS BRAZOS, CON LAS MANOS TOTALMENTE ALEJADAS UNA DE OTRA Y LOS DEDOS SEPARADOS', '["DE 10 METROS","DE 5 METROS","DE UN METRO","DE OCHO METROS","QUE PERMITA DOMINAR LA SITUACIÓN"]'::jsonb, 'QUE PERMITA DOMINAR LA SITUACIÓN', 4, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186005', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1419, 1419, 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INTERVENCIÓN A UN PRESUNTO INFRACTOR: PARA EFECTUAR EL ARRESTO, EL EFECTIVO POLICIAL PUEDE UTILIZAR BÁSICAMENTE TRES POSICIONES, LAS CUALES SON: DE PIE, DE RODILLAS, Y TENDIDO O ECHADO. DURANTE LA EJECUCIÓN DEL PROCEDIMIENTO DEL ARRESTO EN LA POSICIÓN DE RODILLAS, LUEGO DE COLOCARLE LAS GRILLETES SE PROCEDERÁ ....:', '["A LA VERBALIZACIÓN","AL REGISTRO MINUCIOSO DEL INFRACTOR","A LA CONDUCCIÓN INMEDIATA DEL INFRACTOR","A LEERLE SUS DERECHOS AL INFRACTOR","A IDENTIFICAR AL INFRACTOR"]'::jsonb, 'AL REGISTRO MINUCIOSO DEL INFRACTOR', 1, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186006', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1420, 1420, 'LA POLICÍA DE SEGURIDAD EN LA POSICIÓN DE TENDIDO O ECHADO DEBE VERBALIZAR PARA OBTENER INFORMACIÓN Y NO PERMITIR QUE EL INTERVENIDO SE CONCENTRE EN:', '["PLANIFICAR UNA RESPUESTA VIOLENTA CONTRA SU INTEGRIDAD FÍSICA","PLANIFICAR SU FUGA","SU FAMILIA","PLANIFICAR UNA RESPUESTA VIOLENTA CONTRA LA ACCIÓN DEL POLICÍA DE CONTACTO","PLANIFICAR UNA RESPUESTA PACÍFICA CONTRA LA ACCIÓN DEL POLICÍA DE SEGURIDAD"]'::jsonb, 'PLANIFICAR UNA RESPUESTA VIOLENTA CONTRA LA ACCIÓN DEL POLICÍA DE CONTACTO', 3, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186007', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1423, 1423, 'SE DEBE TENER SIEMPRE PRESENTE QUE POR MÁS INFORMACIÓN QUE SE OBTENGA DEL INMUEBLE, LOS AMBIENTES INTERIORES CONSTITUYEN ZONAS DE RIESGO PERMANENTE. ESTAS ZONAS SON CONTROLADAS Y CONVERTIDAS EN ÁREAS SEGURAS UNA POR UNA. OTRO ASPECTO A CONSIDERAR ES EL DISEÑO Y MATERIAL EMPLEADOS EN SU CONSTRUCCIÓN, ELLO CONLLEVA UN TRABAJO PROFESIONAL ALTAMENTE COORDINADO, DONDE PRIME LA SEGURIDAD COMO NORMA BÁSICA Y SE LA EJECUTE CON SIGILO, DINAMISMO, DESTREZA Y CONTROL EMOCIONAL. EL ENUNCIADO ANTERIOR CORRESPONDE A:', '["INTERVENCIÓN EN INMUEBLES: INGRESO","INTERVENCIÓN EN INMUEBLES: DESPLAZAMIENTOS","INTERVENCIÓN EN INMUEBLES: RECONOCIMIENTO","INTERVENCIÓN EN INMUEBLES: PASADIZOS","INTERVENCIÓN EN INMUEBLES: ESCALERAS"]'::jsonb, 'INTERVENCIÓN EN INMUEBLES: RECONOCIMIENTO', 2, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186010', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1424, 1424, 'EN CASO QUE LA INTERVENCIÓN SEA EJECUTADA POR DOS POLICÍAS A PIE, ÉSTOS DEBEN FORMAR EN LO POSIBLE UN TRIÁNGULO DE SEGURIDAD, EN CUYA BASE DEBEN UBICARSE:', '["LAS VÍCTIMAS","LOS VEHÍCULOS POLICIALES","LOS PRESUNTOS INFRACTORES","LOS VEHÍCULOS DE LOS PRESUNTOS INFRACTORES","LOS POLICÍAS INTERVENTORES"]'::jsonb, 'LOS POLICÍAS INTERVENTORES', 4, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186011', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1425, 1425, 'DENTRO DE UN INMUEBLE EL CONTROL DE UNA ESCALERA ES UNA ACCIÓN DE GRAN RIESGO Y PELIGRO. LA COORDINACIÓN, COMUNICACIÓN Y COOPERACIÓN SON ABSOLUTAMENTE NECESARIAS. LA TÉCNICA A EMPLEARSE SE DEBERÁ ACONDICIONAR AL TIPO, ESTRUCTURA Y UBICACIÓN ESPECÍFICA DE LA ESCALERA, TENIENDO ESPECIAL CUIDADO EN LOS DESCANSOS. SI SE TIENE HERRAMIENTAS DE OBSERVACIÓN DEBERÁN SER EMPLEADAS. EL ENUNCIADO ANTERIOR CORRESPONDE A:', '["INTERVENCIÓN EN INMUEBLES: CONFORMACIÓN DE LOS EQUIPOS","INTERVENCIÓN EN INMUEBLES: DESPLAZAMIENTOS","INTERVENCIÓN EN INMUEBLES: INTERVENCIÓN EN EQUIPO","INTERVENCIÓN EN INMUEBLES: PASADIZOS","INTERVENCIÓN EN INMUEBLES: ESCALERAS"]'::jsonb, 'INTERVENCIÓN EN INMUEBLES: ESCALERAS', 4, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186012', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1426, 1426, 'INTERVENCIÓN EN INMUEBLES.- RECONOCIMIENTO.- ¿CUÁL ES EL MAYOR PROBLEMA EN LA INTERVENCIÓN EN INMUEBLES?', '["LA EXISTENCIA DE MASCOTAS","EL TIPO DE INMUEBLE","EL CERCO PERIMÉTRICO EXTERIOR","LOS PUNTOS DE ENTRADA O INGRESO","EL CERCO PERIMÉTRICO INTERIOR"]'::jsonb, 'LOS PUNTOS DE ENTRADA O INGRESO', 3, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186013', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1441, 1441, 'RESPECTO A LA INSTRUCCIÓN BÁSICA: ESTA INSTRUCCIÓN SE DEBE MANTENER EN LOS DIFERENTES NIVELES EDUCATIVOS. TAMBIÉN SE DEBE GARANTIZAR UNA EVALUACIÓN REAL SOSTENIDA QUE PERMITA APRECIAR LA CALIFICACIÓN DE LA APTITUD Y ACTITUD PARA CUMPLIR CON:', '["EL SERVICIO POLICIAL","LA FUNCIÓN PRIMORDIAL","LA MISIÓN","LA FUNCIÓN POLICIAL","LAS DISPOSICIONES DEL COMANDO"]'::jsonb, 'LA FUNCIÓN POLICIAL', 3, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186028', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1428, 1428, 'INTERVENCIÓN EN INMUEBLES.- INDIQUE LOS TIPOS DE INGRESO, QUE PUEDE APLICAR UN EFECTIVO PNP AL MOMENTO QUE PARTICIPA EN LA INTERVENCIÓN A UN INMUEBLE:', '["INGRESO DINÁMICO, INGRESO EN Y, INGRESO EN J, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO CORTO, INGRESO POR BARRIDA O GANADA DE ÁNGULO (CORTE PASTEL)","INGRESO DINÁMICO, INGRESO EN X, INGRESO EN J, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO CORTO, INGRESO POR BARRIDA O GANADA DE ANGULO(CORTE PASTEL)","INGRESO DINÁMICO, INGRESO EN X, INGRESO EN G, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO CORTO, INGRESO POR BARRIDA O GANADA DE ÁNGULO (CORTE PASTEL)","INGRESO DINÁMICO, INGRESO EN PEINE, INGRESO EN X, INGRESO EN J, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO CORTO, INGRESO POR BARRIDA O GANADA DE ÁNGULO (CORTE PASTEL)","INGRESO RÁPIDO, INGRESO EN X, INGRESO EN G, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO CORTO, INGRESO POR BARRIDA O GANADA DE ÁNGULO (CORTE PASTEL)"]'::jsonb, 'INGRESO DINÁMICO, INGRESO EN X, INGRESO EN J, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO CORTO, INGRESO POR BARRIDA O GANADA DE ANGULO(CORTE PASTEL)', 1, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186015', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1429, 1429, 'INTERVENCIÓN EN INMUEBLES.- INDIQUE LA ALTERNATIVA QUE SE RELACIONE CON LA SIGUIENTE TÉCNICA DE INGRESO A INMUEBLES: SE ENTIENDE POR LADO LARGO, LA MAYOR EXTENSIÓN DE PARED EN LA QUE ESTÁ LA PUERTA; LOS DOS EFECTIVOS POLICIALES ESTÁN EN EL MISMO LADO DE LA PARED; EL PRIMER EFECTIVO POLICIAL DEBE ASEGURARSE QUE LA PUERTA NO ESTÉ CERRADA O TRANCADA', '["INGRESO EN X","INGRESO EN J","INGRESO POR EL LADO LARGO","INGRESO DINÁMICO","INGRESO POR EL LADO CORTO"]'::jsonb, 'INGRESO POR EL LADO LARGO', 2, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186016', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1430, 1430, '¿QUÉ ASPECTOS IMPORTANTES SE TIENEN QUE TENER EN CUENTA EN LAS TÉCNICAS DE INTERVENCIÓN?', '["EL NÚMERO DE EFECTIVOS POLICIALES","EL CONO DE SEGURIDAD","LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD","LA LÍNEA IMAGINARIA QUE DIVIDE LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD","LA PERCEPCIÓN DEL RIESGO"]'::jsonb, 'LA PERCEPCIÓN DEL RIESGO', 4, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186017', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1431, 1431, '¿BAJO QUÉ CIRCUNSTANCIAS SE PUEDE QUEBRANTAR LOS PRINCIPIOS DE DERECHO NACIONAL E INTERNACIONAL QUE REGULAN LA RESPUESTA A UNA CRISIS?', '["EN SITUACIÓN PÚBLICA DE EMERGENCIA","EN GRAVE SITUACIÓN PÚBLICA DE EMERGENCIA","EN GRAVE SITUACIÓN PÚBLICA DE EMERGENCIA QUE JUSTIFIQUE LOS MEDIOS EMPLEADOS","BAJO NINGUNA CIRCUNSTANCIA","CUANDO ESTÁ EN RIESGO LA PROPIEDAD PÚBLICA Y PRIVADA"]'::jsonb, 'BAJO NINGUNA CIRCUNSTANCIA', 3, '(texto: II-V)** [PARTE SEGUNDA] [CAPITULO V]', '186018', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1432, 1432, 'CON FRECUENCIA LOS EFECTIVOS POLICIALES SON LESIONADOS POR ALGO QUE NO ANTICIPARON, NO RESPONDIERON NI ESTABAN MENTALMENTE PREPARADOS PARA ENFRENTAR;. EL SIGUIENTE ENUNCIADO CORRESPONDE AL:', '["NIVEL DE REACCIÓN","NIVEL DE SEGURIDAD","NIVEL DE ALERTA MÁXIMA","NIVEL DE DISTRACCIÓN","NIVEL DE ATENCIÓN"]'::jsonb, 'NIVEL DE ATENCIÓN', 4, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186019', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1433, 1433, 'DEBEN GARANTIZAR UNA ALTA PROFESIONALIZACIÓN, INDIVIDUAL Y COLECTIVA, INCIDIENDO EN ASPECTOS IMPORTANTES PARA EL DESARROLLO DE LA FUNCIÓN POLICIAL COMO SON: USO DE LA FUERZA, ARMAS DE FUEGO, TÉCNICAS DE INTERVENCIÓN POLICIAL, TÁCTICAS DEFENSIVAS NO LETALES, CONTROL FÍSICO DE INTERVENIDOS, ÉTICA EN LA FUNCIÓN POLICIAL. ESTA INSTRUCCIÓN SE DEBE MANTENER EN LOS DIFERENTES NIVELES EDUCATIVOS. TAMBIÉN SE DEBE GARANTIZAR UNA EVALUACIÓN REAL SOSTENIDA QUE PERMITA APRECIAR LA CALIFICACIÓN DE LA APTITUD Y ACTITUD PARA CUMPLIR CON LA FUNCIÓN POLICIAL. EL PÁRRAFO ANTERIOR SE REFIERE A:', '["USO DE ARMAS DE FUEGO","LOS PLANES Y PROGRAMAS DE LA INSTITUCIÓN POLICIAL","EL PLANEAMIENTO OPERATIVO DE LOS SERVICIOS POLICIALES","LA INSTRUCCIÓN BÁSICA POLICIAL","LOS PLANES Y PROGRAMAS DEL SISTEMA EDUCATIVO POLICIAL"]'::jsonb, 'LOS PLANES Y PROGRAMAS DEL SISTEMA EDUCATIVO POLICIAL', 4, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186020', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1434, 1434, 'VERIFICAR QUE EL PERSONAL ESTÉ ADECUADAMENTE EQUIPADO. EL ENUNCIADO ANTERIOR CORRESPONDE A:', '["MANTENIMIENTO DEL ORDEN PÚBLICO: PREPARACIÓN","MANTENIMIENTO DEL ORDEN PÚBLICO: COMUNICACIÓN","ANTES DE LA EJECUCIÓN DE LAS OPERACIONES","MANTENIMIENTO DEL ORDEN PÚBLICO: APARIENCIA","MANTENIMIENTO DEL ORDEN PÚBLICO: EMPLEO DE LA FUERZA"]'::jsonb, 'ANTES DE LA EJECUCIÓN DE LAS OPERACIONES', 2, '(texto: II-IV)** [PARTE SEGUNDA] [CAPITULO IV]', '186021', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1437, 1437, 'INTERVENCIÓN EN INMUEBLES.- INDIQUE LA ALTERNATIVA QUE SE RELACIONE CON LA SIGUIENTE TÉCNICA DE INGRESO A INMUEBLES: UBICADOS A UN SOLO LADO DE LA PUERTA O NIVEL DE LA PARED; ES NECESARIO ADOPTAR UNA POSICIÓN CÓMODA Y SEGURA, PUES SE ESTÁ PRESUMIENDO QUE AL DETECTAR UNA AMENAZA SE TENDRÁ QUE EMPLEAR EL ARMA DE FUEGO PARA NEUTRALIZARLE O CONTROLARLA; AMBOS EFECTIVOS POLICIALES DEBERÁN ALEJARSE DE LOS NIVELES DEL MARCO CENTRAL O PARED, PARA EVITAR QUE UNA PERSONA ESCONDIDA DETRÁS DE ELLOS LES PUEDA ARREBATAR EL ARMA', '["INGRESO EN X","INGRESO EN J","INGRESO POR EL LADO LARGO","INGRESO DINÁMICO","INGRESO POR BARRIDA O GANADA DE ÁNGULO (CORTE PASTEL)"]'::jsonb, 'INGRESO POR BARRIDA O GANADA DE ÁNGULO (CORTE PASTEL)', 4, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186024', '2026-07-14T01:12:29.113429+00:00');
