INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1439, 1439, 'CRISIS ES ...:', '["UNA FORMA DE ALTERACIÓN GRAVE DEL ORDEN INTERNO","ES LA ALTERACIÓN GRAVE DEL ORDEN CONSTITUCIONAL, DEMANDANDO UNA RESPUESTA ESPECIAL DE LA POLICÍA","ES LA ALTERACIÓN GRAVE DEL ORDEN INTERNO, ECONÓMICO Y SOCIAL","ES LA ALTERACIÓN GRAVE DEL ORDEN PÚBLICO","ES LA ALTERACIÓN GRAVE DEL ORDEN INTERNO Y PÚBLICO"]'::jsonb, 'ES LA ALTERACIÓN GRAVE DEL ORDEN PÚBLICO', 3, '(texto: II-V)** [PARTE SEGUNDA] [CAPITULO V]', '186026', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1440, 1440, 'RESPECTO A LA INSTRUCCIÓN BÁSICA: LA PREPARACIÓN DE LOS Y LAS POLICÍAS CONSTITUYA UN PROCESO PERMANENTE DE CAPACITACIÓN Y ENTRENAMIENTO QUE DEBE PERMITIRLES DESEMPEÑARSE ADECUADAMENTE ANTE LOS DIVERSOS REQUERIMIENTOS QUE EL CONTEXTO SOCIAL PRESENTA DURANTE EL CUMPLIMIENTO DE:', '["SUS ATRIBUCIONES","SU FUNCIÓN","SU MISIÓN","SU SERVICIO","SUS FACULTADES"]'::jsonb, 'SU MISIÓN', 2, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186027', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1442, 1442, 'RESPECTO A LA PREPARACIÓN PSICOLÓGICA: SI USTED NO SE PREPARA MENTALMENTE PARA LAS SITUACIONES O LO QUE RESULTE DE ELLAS, MUY PROBABLEMENTE TENDRÁ UN DESEMPEÑO NO DESEADO, PUDIENDO INCLUSO QUEDARSE PARALIZADO Y SER VÍCTIMA ....:', '["DE LAS FUERZAS OPONENTES","DEL ENEMIGO","DE LOS DD.CC","DE LOS ACONTECIMIENTOS","DE SU PROPIO MIEDO"]'::jsonb, 'DE LOS ACONTECIMIENTOS', 3, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186029', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1443, 1443, 'INTERVENCIÓN EN INMUEBLES.- DESPLAZAMIENTOS.- INDIQUE LA ALTERNATIVA QUE COMPLETE CORRECTAMENTE EL SIGUIENTE ENUNCIADO: DESPLAZARSE A TRAVÉS DE LA RUTA MÁS SEGURA Y CORTA, BUSCANDO LA PROTECCIÓN DE ABRIGOS (PARAPETOS) SUCESIVOS Y EVITANDO EXPONERSE A RIESGOS INNECESARIOS, ESPECIALMENTE EN ......:', '["ÁREAS SEGURAS","ÁREAS CONFLICTIVAS","ÁREAS LARGAS","ÁREAS CORTAS","ÁREAS LIBRES"]'::jsonb, 'ÁREAS LIBRES', 4, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186030', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1444, 1444, 'CONTROL DE EMOCIONES E INTELIGENCIA EMOCIONAL: ¿DE QUÉ DEPENDERÁ SU NIVEL DE ALERTA?', '["DE SU CONTROL DE EMOCIONES E INTELIGENCIA EMOCIONAL","DE SU PREPARACION MENTAL","DE SU CAPACIDAD DE ANTICIPACIÓN AL PELIGRO","DEL CONOCIMIENTO DE LA SITUACIÓN PREEXISTENTE","DEL CONOCIMIENTO DE LAS ACCIONES DEL ENEMIGO"]'::jsonb, 'DE SU CAPACIDAD DE ANTICIPACIÓN AL PELIGRO', 2, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186031', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1445, 1445, '¿CUÁL DE LAS ALTERNATIVAS SE RELACIONA CON UN NIVEL DE SEGURIDAD?', '["EL RIESGO ES REAL Y LA REACCIÓN DEBE SER INSTANTÁNEA","CUANDO EL PELIGRO SE MANTIENE POR UN TIEMPO PROLONGADO O EL EFECTIVO POLICIAL ENFRENTA UN PELIGRO PARA EL CUAL NO ESTÁ PREPARADO","ES EL NIVEL DE ALERTA QUE USTED DEBE TENER EN TODO MOMENTO CUANDO ESTÁ PATRULLANDO","SE DISTRAE CON LO QUE ESTÁ SUCEDIENDO A SU ALREDEDOR, LO QUE PUEDE SER OCASIONADO POR EL CANSANCIO O LA CREENCIA DE QUE NO HAY POSIBILIDAD DE PROBLEMAS","HAY CONCIENCIA DE LA EXISTENCIA DE UN PELIGRO. SIN EMBARGO, EL ENTRENAMIENTO, EXPERIENCIA, EDUCACIÓN Y BUEN SENTIDO LE PERMITEN EFECTUAR UN PLANEAMIENTO TÁCTICO A SEGUIR"]'::jsonb, 'HAY CONCIENCIA DE LA EXISTENCIA DE UN PELIGRO. SIN EMBARGO, EL ENTRENAMIENTO, EXPERIENCIA, EDUCACIÓN Y BUEN SENTIDO LE PERMITEN EFECTUAR UN PLANEAMIENTO TÁCTICO A SEGUIR', 4, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186032', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1446, 1446, '¿CUÁL DE LAS ALTERNATIVAS SE RELACIONA CON EL NIVEL DE ALERTA, NIVEL DE ATENCIÓN?', '["CUANDO EL PELIGRO SE MANTIENE POR UN TIEMPO PROLONGADO O EL EFECTIVO POLICIAL ENFRENTA UN PELIGRO PARA EL CUAL NO ESTÁ PREPARADO","HAY CONCIENCIA DE LA EXISTENCIA DE UN PELIGRO, SIN EMBARGO SU ENTRENAMIENTO, EXPERIENCIA, EDUCACIÓN Y BUEN SENTIDO LE PERMITEN EFECTUAR UN PLANEAMIENTO TÁCTICO A SEGUIR","SU ESTADO MENTAL NO ESTÁ PREPARADO PARA UN EVENTUAL ENFRENTAMIENTO, AUMENTANDO SU PROPIA INSEGURIDAD Y TAMBIÉN LA DE SU EQUIPO DURANTE EL SERVICIO POLICIAL","EL RIESGO ES REAL Y LA REACCIÓN DEBE SER INSTANTÁNEA","ES EL NIVEL DE ALERTA QUE EL PERSONAL POLICIAL DEBE TENER EN TODO MOMENTO CUANDO ESTÁ PATRULLANDO, DANDO PRIORIDAD A LA BÚSQUEDA DE UNA AMENAZA POTENCIAL"]'::jsonb, 'ES EL NIVEL DE ALERTA QUE EL PERSONAL POLICIAL DEBE TENER EN TODO MOMENTO CUANDO ESTÁ PATRULLANDO, DANDO PRIORIDAD A LA BÚSQUEDA DE UNA AMENAZA POTENCIAL', 4, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186033', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1447, 1447, 'INTERVENCIÓN EN INMUEBLES.- ESCALERAS.- ELIJA LA ALTERNATIVA QUE COMPLETE CORRECTAMENTE EL SIGUIENTE ENUNCIADO: EXISTE MAYOR RIESGO EN CONTROLAR UNA ESCALERA (...................... )', '["HACIA ABAJO","HACIA ARRIBA","CARACOL","MARINERO","DE METAL"]'::jsonb, 'HACIA ARRIBA', 1, '(texto: II-III)** [PARTE SEGUNDA] [CAPITULO III]', '186034', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1448, 1448, '¿CUÁL DE LAS ALTERNATIVAS SE RELACIONA CON EL NIVEL DE ALERTA, NIVEL DE REACCIÓN POSITIVA?', '["EN ESTE ESTADO SUS OJOS PUEDEN VER LA AMENAZA, PERO SU MENTE NO ESTARÁ PREPARADA PARA SUMINISTRAR LAS RESPUESTAS CORRECTAS DE REACCIÓN","EL NIVEL DE SEGURIDAD DISMINUYE LOS RIESGOS DE USTED Y SU EQUIPO. SI SON SORPRENDIDOS SE ENCONTRARÁN LISTOS PARA DAR LAS RESPUESTAS QUE LA SITUACIÓN EXIJA","HAY CONCIENCIA DE LA EXISTENCIA DE UN PELIGRO, SIN EMBARGO SU ENTRENAMIENTO, EXPERIENCIA, EDUCACIÓN Y BUEN SENTIDO LE PERMITEN EFECTUAR UN PLANEAMIENTO TÁCTICO A SEGUIR","ES EL NIVEL DE ALERTA QUE USTED DEBE TENER EN TODO MOMENTO CUANDO ESTÁ PATRULLANDO","EL RIESGO ES REAL Y LA REACCIÓN DEBE SER INSTANTÁNEA"]'::jsonb, 'EL RIESGO ES REAL Y LA REACCIÓN DEBE SER INSTANTÁNEA', 4, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186035', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1449, 1449, '¿CUÁLES SON LAS DOS ÁREAS QUE SE DEBE DELIMITAR OBJETIVAMENTE PARA UN BUEN PENSAMIENTO TÁCTICO?', '["ÁREA DE SEGURIDAD Y ÁREA DE ACCIÓN","ÁREA DE SEGURIDAD Y ÁREA DE RIESGO","ÁREA DE SEGURIDAD Y ÁREA DE INTERVENCIÓN","ÁREA DE SEGURIDAD Y CORDÓN DE SEGURIDAD","ÁREA DE SEGURIDAD Y ÁREA DE COMANDO"]'::jsonb, 'ÁREA DE SEGURIDAD Y ÁREA DE RIESGO', 1, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186036', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1450, 1450, 'EL ÁREA DE RIESGO YA DOMINADA SE CONVIERTE EN:', '["ÁREA CONTROLADA","ÁREA DESPEJADA","ÁREA DE SEGURIDAD","ÁREA DOMINADA","ÁREA CONFLICTIVA"]'::jsonb, 'ÁREA DE SEGURIDAD', 2, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186037', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1451, 1451, 'INDIQUE LA ALTERNATIVA CORRECTA RESPECTO A LA VERBALIZACIÓN:', '["EL ENSEÑAR EL ARMA AL INTERVENIDO TAMBIÉN AYUDA EN LA VERBALIZACIÓN","LA POSICIÓN EN LA QUE EL POLICÍA SOSTIENE SU ARMA TAMBIÉN AYUDA EN LA VERBALIZACIÓN","SOSTENER EL ARMA DE MANERA FIRME APUNTANDO AL SOSPECHOSO TAMBIÉN AYUDA EN LA VERBALIZACIÓN","HACER UN PREVIO DISPARO AL AIRE TAMBIÉN AYUDA EN LA VERBALIZACIÓN","EL POLICÍA DEBE APUNTAR EL ARMA EN FUNCIÓN DE LA PERCEPCIÓN DEL RIESGO Y LA REACCIÓN DEL INTERVENIDO"]'::jsonb, 'LA POSICIÓN EN LA QUE EL POLICÍA SOSTIENE SU ARMA TAMBIÉN AYUDA EN LA VERBALIZACIÓN', 1, '(texto: II-I)** [PARTE SEGUNDA] [CAPITULO I]', '186038', '2026-07-14T01:12:29.113429+00:00');
