INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1478, 1478, 'PROMOVER LA COOPERACIÓN ENTRE AUTORIDADES, ENTIDADES PÚBLICAS Y PRIVADAS, PERSONAS NATURALES Y JURÍDICAS, SOCIEDAD CIVIL Y COMUNIDAD EN GENERAL PARA LA DIFUSIÓN, INVESTIGACIÓN, BÚSQUEDA Y UBICACIÓN DE PERSONAS DESAPARECIDAS, ASÍ COMO DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS. EL PRESENTE ENUNCIADO CORRESPONDE A:', '["ÁMBITO DE APLICACIÓN","FINALIDAD","PRINCIPIO","PROPÓSITO","ACTUACIÓN"]'::jsonb, 'FINALIDAD', 1, 'ARTÍCULO 2°, b., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185861', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1479, 1479, 'IMPLEMENTAR MECANISMOS TECNOLÓGICOS PARA EL INTERCAMBIO DE INFORMACIÓN SOBRE CASOS DE DESAPARICIÓN DE PERSONAS, ASÍ COMO DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS. EL PRESENTE ENUNCIADO CORRESPONDE A:', '["PRINCIPIO","PROPÓSITO","FINALIDAD","ÁMBITO DE APLICACIÓN","ACTUACIÓN"]'::jsonb, 'FINALIDAD', 2, 'ARTÍCULO 2°, c., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185862', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1480, 1480, 'LAS AUTORIDADES, ENTIDADES PÚBLICAS Y PRIVADAS, SOCIEDAD CIVIL Y COMUNIDAD EN GENERAL BRINDAN APOYO A LA POLICÍA NACIONAL DEL PERÚ EN LA DIFUSIÓN, INVESTIGACIÓN, BÚSQUEDA Y UBICACIÓN DE PERSONAS DESAPARECIDAS, ASÍ COMO DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS, EN EL MARCO DE LA OBLIGACIÓN SEÑALADA EN EL ARTÍCULO VI DEL TÍTULO PRELIMINAR DEL DECRETO LEGISLATIVO N° 1267, LEY DE LA POLICÍA NACIONAL DEL PERÚ. EL PRESENTE ENUNCIADO CORRESPONDE A:', '["APOYO A LA POLICÍA NACIONAL DEL PERÚ","PROPÓSITO","ÁMBITO DE APLICACIÓN","COLABORACIÓN","ACTUACIÓN"]'::jsonb, 'APOYO A LA POLICÍA NACIONAL DEL PERÚ', 0, 'ARTÍCULO 4°, 4.1., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185865', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1481, 1481, 'LAS INSTITUCIONES PÚBLICAS O PRIVADAS APOYAN LA DIFUSIÓN DE LA NOTA DE ALERTA Y LA ALERTA AMBER UNA VEZ QUE LA POLICÍA NACIONAL DEL PERÚ HAYA DIFUNDIDO LA DESAPARICIÓN. PARA DICHO EFECTO, ESTAS INSTITUCIONES PONEN A DISPOSICIÓN DE LA AUTORIDAD POLICIAL LOS CANALES DE COORDINACIÓN Y ARTICULACIÓN PERTINENTES, INCLUYENDO LA ALERTA AMBER. EL PRESENTE ENUNCIADO CORRESPONDE A:', '["APOYO A LA POLICÍA NACIONAL DEL PERÚ","ACTUACIÓN","ÁMBITO DE APLICACIÓN","COLABORACIÓN","PROPÓSITO"]'::jsonb, 'APOYO A LA POLICÍA NACIONAL DEL PERÚ', 0, 'ARTÍCULO 4°, 4.2., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185866', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1482, 1482, 'SE CONSIDERA ............................... AQUELLA QUE SE ENCUENTRA AUSENTE DE SU DOMICILIO HABITUAL Y RESPECTO DEL CUAL SE DESCONOCE SU PARADERO. DEFINICIÓN QUE CORRESPONDE A:', '["PERSONA DESAPARECIDA","NOTA DE ALERTA","PERSONAS EN SITUACIÓN DE VULNERABILIDAD","COLABORACIÓN","PROPÓSITO"]'::jsonb, 'PERSONA DESAPARECIDA', 0, 'ARTÍCULO 5°, a., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185867', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1483, 1483, 'PERSONAS QUE SUFREN DISCRIMINACIÓN O SITUACIONES DE DESPROTECCIÓN, ENTRE ELLAS: NIÑAS, NIÑOS, ADOLESCENTES, PERSONAS ADULTAS MAYORES, PERSONAS CON DISCAPACIDAD, DESPLAZADOS, MIGRANTES, MUJERES VÍCTIMAS DE VIOLENCIA, INTEGRANTES DE PUEBLOS INDÍGENAS, PERSONAS LGTBQ+, SITUACIÓN DE POBREZA, ENTRE OTRAS PERSONAS QUE SE ENCUENTREN EN ESTA SITUACIÓN. DEFINICIÓN QUE CORRESPONDE A:', '["PERSONAS EN SITUACION DE VULNERABILIDAD","PERSONA DESAPARECIDA","COLABORACIÓN","PROPÓSITO","NOTA DE ALERTA"]'::jsonb, 'PERSONAS EN SITUACION DE VULNERABILIDAD', 0, 'ARTÍCULO 5°, b., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185868', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1484, 1484, 'ANTE LA AUSENCIA DE UNA PERSONA DE SU DOMICILIO HABITUAL Y DE LA CUAL SE DESCONOCE SU PARADERO, CUALQUIER PERSONA PUEDE PRESENTAR UNA DENUNCIA ANTE LA POLICÍA NACIONAL DEL PERÚ. EL PRESENTE ENUNCIADO CORRESPONDE A:', '["PROPÓSITO DE LA DENUNCIA","REGISTRO DE LA DENUNCIA","PRESENTACION DE DENUNCIA","OMISIÓN DE LA DENUNCIA","DIFUSIÓN DE LA DENUNCIA"]'::jsonb, 'PRESENTACION DE DENUNCIA', 2, 'ARTÍCULO 6°, 6.1', '185873', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1485, 1485, 'LA POLICÍA NACIONAL DEL PERÚ ATIENDE LAS DENUNCIAS SOBRE DESAPARICIÓN DE MANERA INMEDIATA Y EN CUALQUIER MOMENTO, ENCONTRÁNDOSE A CARGO DE SU RECEPCIÓN Y TRÁMITE, BAJO RESPONSABILIDAD FUNCIONAL. EL PRESENTE ENUNCIADO CORRESPONDE A:', '["ATENCIÓN DE LA DENUNCIA","REGISTRO DE LA DENUNCIA","PROPÓSITO DE LA DENUNCIA","DIFUSIÓN DE LA DENUNCIA","OMISIÓN DE LA DENUNCIA"]'::jsonb, 'ATENCIÓN DE LA DENUNCIA', 0, 'ARTÍCULO 7°, 7.1., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185876', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1486, 1486, 'LA POLICÍA NACIONAL DEL PERÚ RECIBE LA DENUNCIA, LA REGISTRA EN EL SISTEMA DE DENUNCIAS POLICIALES (SIDPOL) O EN EL SISTEMA DE REGISTRO DE DENUNCIAS DE INVESTIGACIÓN CRIMINAL (SIRDIQ), E INSCRIBE LA INFORMACIÓN EN EL REGISTRO NACIONAL DE INFORMACIÓN DE PERSONAS DESAPARECIDAS. EL PRESENTE ENUNCIADO CORRESPONDE A:', '["REGISTRO DE LA DENUNCIA","ATENCIÓN DE LA DENUNCIA","PROPÓSITO DE LA DENUNCIA","DIFUSIÓN DE LA DENUNCIA","OMISIÓN DE LA DENUNCIA"]'::jsonb, 'ATENCIÓN DE LA DENUNCIA', 1, 'ARTÍCULO 7°, 7.3., MODIFICADO POR EL ARTÍCULO ÚNICO DE LA LEY N° 32305, PUBLICADO EL 24 ABRIL 2025', '185878', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1487, 1487, 'EN EL CASO DE QUE LA DENUNCIA NO FUESE RECIBIDA EN FORMA INMEDIATA POR LA POLICÍA NACIONAL DEL PERÚ, LA PERSONA AFECTADA PUEDE DENUNCIAR ESTE HECHO A LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ Y/O A LA CENTRAL ÚNICA DE DENUNCIAS DEL MINISTERIO DEL INTERIOR, SEGÚN CORRESPONDA. EL PRESENTE ENUNCIADO CORRESPONDE A:', '["PROPÓSITO DE LA DENUNCIA","ATENCIÓN DE LA DENUNCIA","REGISTRO DE LA DENUNCIA","DIFUSIÓN DE LA DENUNCIA","OMISIÓN DE LA DENUNCIA"]'::jsonb, 'ATENCIÓN DE LA DENUNCIA', 1, 'ARTÍCULO 7°, 7.3., MODIFICADO POR EL ARTÍCULO ÚNICO DE LA LEY N° 32305, PUBLICADO EL 24 ABRIL 2025', '185879', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1488, 1488, 'SI DE LAS CIRCUNSTANCIAS EN QUE SE TOMA CONOCIMIENTO LA DESAPARICIÓN Y/O INVESTIGACIÓN POLICIAL, SE DETERMINE O COMPRUEBE LA PRESENCIA DE DELITOS CONCURRENTES, LOS ÓRGANOS ESPECIALIZADOS DE LA POLICÍA NACIONAL DEL PERÚ ARTICULAN ESFUERZOS E INTERVIENEN, CONFORME A SUS PROCEDIMIENTOS OPERATIVOS Y NORMATIVA APLICABLE. EL PRESENTE ENUNCIADO CORRESPONDE A:', '["INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO NO UBICABLES","BÚSQUEDA DE PERSONAS DENUNCIADAS COMO NO UBICABLES","INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS","INVESTIGACIÓN DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS","BÚSQUEDA DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS"]'::jsonb, 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 2, 'ARTÍCULO 9°, 9.2., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185881', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1489, 1489, 'LAS EMPRESAS OPERADORAS DE TELEFONÍA MÓVIL Y TELEFONÍA FIJA PROPORCIONAN EL LISTADO DE NÚMEROS TELEFÓNICOS DE LLAMADAS ENTRANTES Y SALIENTES, CON LOS NOMBRES Y APELLIDOS DE LOS TITULARES, DE LAS LÍNEAS TELEFÓNICAS VINCULADAS A LA DESAPARICIÓN DE PERSONAS QUE REQUIERA LA POLICÍA NACIONAL DEL PERÚ, OBSERVANDO LO DISPUESTO POR EL ARTÍCULO 2, INCISO 10 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ. EN EL REGLAMENTO DEL PRESENTE DECRETO LEGISLATIVO SE REGULA EL PERIODO DE LA INFORMACIÓN REQUERIDA. EL PRESENTE ENUNCIADO CORRESPONDE A:', '["INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO NO UBICABLES","BÚSQUEDA DE PERSONAS DENUNCIADAS COMO NO UBICABLES","INVESTIGACIÓN DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS","BÚSQUEDA DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS","INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS"]'::jsonb, 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 4, 'ARTÍCULO 9°, 9.5., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185885', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1490, 1490, 'RESPECTO A LA ALERTA AMBER POR DESAPARICIÓN DE NIÑAS, NIÑOS Y ADOLESCENTES: (MARQUE LA ALTERNATIVA CORRECTA)', '["LA ALERTA AMBER SE EMITE PARA LOS CASOS DE DESAPARICIÓN DE NIÑAS, NIÑOS Y ADOLESCENTES","LA ALERTA AMBER SE EMITE PARA LOS CASOS DE DESAPARICIÓN PERSONAS LGTBIQ+","LA ALERTA AMBER SE EMITE PARA LOS CASOS DE DESAPARICIÓN DE MUJERES EN ESTADO DE GESTACIÓN","LA ALERTA AMBER SE EMITE PARA LOS CASOS DE DESAPARICIÓN DE PERSONAS CON DISCAPACIDAD","LA ALERTA AMBER SE EMITE PARA LOS CASOS DE DESAPARICIÓN DE PERSONAS ADULTAS MAYORES"]'::jsonb, 'LA ALERTA AMBER SE EMITE PARA LOS CASOS DE DESAPARICIÓN DE NIÑAS, NIÑOS Y ADOLESCENTES', 0, 'ARTÍCULO 12°, 12.1, MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185897', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1491, 1491, 'LA DIFUSIÓN DE LOS CASOS DE DESAPARICIÓN DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD SE REALIZA MEDIANTE LAS… (MARQUE LA ALTERNATIVA CORRECTA)', '["NOTAS INFORMATIVAS Y NOTAS DE INFORMACIÓN","NOTAS INFORMATIVAS","NOTAS DE INFORMACIÓN","ALERTAS INFORMATIVAS","NOTAS DE ALERTA Y ALERTAS AMBER"]'::jsonb, 'NOTAS DE ALERTA Y ALERTAS AMBER', 4, 'ARTÍCULO 16° MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21 DICIEMBRE 2023', '185902', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1492, 1492, 'SEGÚN EL ARTÍCULO 11 DEL D.LEG. 1428, ¿CUÁL ES EL OBJETIVO PRIMORDIAL DE LA ARTICULACIÓN ESTATAL EN LA ATENCIÓN DE CASOS DE DESAPARICIÓN DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD?', '["ASEGURAR LA OBTENCIÓN DE PRUEBAS SUFICIENTES PARA SENTENCIAR AL PRESUNTO RESPONSABLE","GARANTIZAR LA DIFUSIÓN MEDIÁTICA MASIVA DEL CASO A NIVEL NACIONAL E INTERNACIONAL","SALVAGUARDAR LA INTEGRIDAD Y VIDA DE LA PERSONA DESAPARECIDA","OBTENER LA MAYOR CANTIDAD DE FONDOS ESTATALES PARA LA BÚSQUEDA DE LA PERSONA","BRINDAR ATENCIÓN PRIORITARIA A CASOS CON SENTENCIA FIRME DE DESAPARICIÓN"]'::jsonb, 'SALVAGUARDAR LA INTEGRIDAD Y VIDA DE LA PERSONA DESAPARECIDA', 2, '(texto: (ART: 11)** Articulo 11.- Articulacion estatal)**', '185908', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1493, 1493, 'DE ACUERDO AL ARTÍCULO 11, ¿A QUIÉN CORRESPONDE LA COLABORACIÓN EN LABORES DE DIFUSIÓN Y BÚSQUEDA VINCULADAS A LAS TELECOMUNICACIONES Y TRANSPORTES?', '["MINISTERIO DEL INTERIOR","MINISTERIO DE TRANSPORTES Y COMUNICACIONES","MINISTERIO DE SALUD Y EDUCACIÓN","MINISTERIO DE DEFENSA CONJUNTAMENTE CON EL INPE","OFICINAS CONSULARES EXTRANJERAS BAJO SUPERVISIÓN DE INTERPOL"]'::jsonb, 'MINISTERIO DE TRANSPORTES Y COMUNICACIONES', 1, '(texto: (ART: 11)** Articulo 11.- Articulacion estatal)**', '185910', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1494, 1494, '¿QUÉ ENTIDAD TIENE EL ENCARGO DE BRINDAR ATENCIÓN PSICOLÓGICA GRATUITA A LOS FAMILIARES DE LA PERSONA DESAPARECIDA SEGÚN SUS COMPETENCIAS?', '["MINISTERIO DE DEFENSA EN COORDINACIÓN CON LA POLICÍA NACIONAL DEL PERÚ","MINISTERIO DE SALUD A TRAVÉS DE LAS ENTIDADES QUE FORMAN PARTE DEL SISTEMA DE SALUD","MINISTERIO DE RELACIONES EXTERIORES DE MANERA AUTÓNOMA","SOCIEDADES DE BENEFICENCIA SUPERVISADAS POR EL INPE","CENTROS EMERGENCIA MUJER DEPENDIENTES DE LOS GOBIERNOS LOCALES"]'::jsonb, 'MINISTERIO DE SALUD A TRAVÉS DE LAS ENTIDADES QUE FORMAN PARTE DEL SISTEMA DE SALUD', 1, '(texto: (ART: 11)** Articulo 11.- Articulacion estatal)**', '185911', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1495, 1495, '¿QUÉ FUNCIÓN ESPECÍFICA CUMPLE EL INSTITUTO DE MEDICINA LEGAL Y CIENCIAS FORENSES DEL MINISTERIO PÚBLICO EN EL PROCEDIMIENTO ESTABLECIDO POR EL D.LEG. 1428?', '["COLABORAR EN LABORES DE DIFUSIÓN, UBICACIÓN Y PROPORCIONAR SERVICIO DE MEDICINA LEGAL Y CIENCIAS FORENSES","BRINDAR RECURSOS DE ALOJAMIENTO TEMPORAL PARA PERSONAS DESAPARECIDAS ENCONTRADAS","GESTIONAR LA COMUNICACIÓN INTERNACIONAL MEDIANTE INTERPOL","OTORGAR APOYOS ECONÓMICOS A LAS FAMILIAS DE LOS DESAPARECIDOS","SUPERVISAR SOLO LOS PROCEDIMIENTOS ADMINISTRATIVOS EN LA BÚSQUEDA Y LOCALIZACIÓN"]'::jsonb, 'COLABORAR EN LABORES DE DIFUSIÓN, UBICACIÓN Y PROPORCIONAR SERVICIO DE MEDICINA LEGAL Y CIENCIAS FORENSES', 0, '(texto: (ART: 11)** Articulo 11.- Articulacion estatal)**', '185914', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1496, 1496, 'EN CASO LA PERSONA DESAPARECIDA HAYA SIDO LOCALIZADA PERO NO CUENTE CON FAMILIARES O PERSONAS CERCANAS PARA SU ACOGIDA INMEDIATA, ¿QUIÉN ASUME LA ESTADÍA TEMPORAL SEGÚN EL TEXTO LEGAL?', '["LAS OFICINAS CONSULARES DEL PAÍS DE ORIGEN","LOS GOBIERNOS REGIONALES A TRAVÉS DE SUS PROGRAMAS SOCIALES","LAS SOCIEDADES DE BENEFICENCIA U HOGARES DE REFUGIO TEMPORAL, EN COORDINACIÓN CON LOS CENTROS EMERGENCIA MUJER","EL MINISTERIO DE DEFENSA AUTORIZANDO BASES MILITARES PARA ESTANCIA TEMPORAL","EL MINISTERIO DE SALUD DENTRO DE HOSPITALES DESIGNADOS"]'::jsonb, 'LAS SOCIEDADES DE BENEFICENCIA U HOGARES DE REFUGIO TEMPORAL, EN COORDINACIÓN CON LOS CENTROS EMERGENCIA MUJER', 2, '(texto: (ART: 11)** Articulo 11.- Articulacion estatal)**', '185915', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1497, 1497, 'DE ACUERDO AL ARTÍCULO 11 DEL D.LEG. 1428, PARA CONFIRMAR SI UNA PERSONA DENUNCIADA COMO DESAPARECIDA SE ENCUENTRA EN UN ESTABLECIMIENTO PENITENCIARIO, ¿A QUÉ ENTIDAD DEBE REQUERIRSE INFORMACIÓN Y BAJO QUÉ CONDICIÓN?', '["A LA POLICÍA NACIONAL DIRECTAMENTE, SIN NECESIDAD DE REQUERIMIENTO PREVIO","AL INSTITUTO NACIONAL PENITENCIARIO (INPE), PREVIO REQUERIMIENTO DE LA POLICÍA NACIONAL DEL PERÚ","A LOS GOBIERNOS REGIONALES, PREVIA EVALUACIÓN DEL MINISTERIO PÚBLICO","A LOS JUZGADOS PENALES CORRESPONDIENTES, CON AUTORIZACIÓN DEL MINISTERIO DE JUSTICIA","A LAS OFICINAS CONSULARES EXTRANJERAS SI LA PERSONA ES EXTRANJERA"]'::jsonb, 'AL INSTITUTO NACIONAL PENITENCIARIO (INPE), PREVIO REQUERIMIENTO DE LA POLICÍA NACIONAL DEL PERÚ', 1, '(texto: (ART: 11)** Articulo 11.- Articulacion estatal)**', '185916', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1498, 1498, '¿CUÁL ES LA FORMA EN QUE LOS GOBIERNOS REGIONALES Y LOCALES CONTRIBUYEN EN LA BÚSQUEDA E INVESTIGACIÓN DE PERSONAS DESAPARECIDAS, SEGÚN EL D.LEG. 1428?', '["PROVEYENDO SOLO ASISTENCIA FINANCIERA A LA FAMILIA DE LA PERSONA DESAPARECIDA","FACILITANDO EL USO DE SERENAZGO Y LA PROVISIÓN DE IMÁGENES DE VIDEOVIGILANCIA, CONFORME A LO DISPUESTO EN EL DECRETO LEGISLATIVO N° 1218","DISOLVIENDO LAS UNIDADES DE SERENAZGO PARA EVITAR DUPLICIDAD DE FUNCIONES","SOLICITANDO EXCLUSIVAMENTE LA INTERVENCIÓN DEL MINISTERIO DE DEFENSA PARA OPERATIVOS DE BÚSQUEDA","RESTRINGIENDO LA INFORMACIÓN DE VIDEO VIGILANCIA A LA POLICÍA NACIONAL"]'::jsonb, 'FACILITANDO EL USO DE SERENAZGO Y LA PROVISIÓN DE IMÁGENES DE VIDEOVIGILANCIA, CONFORME A LO DISPUESTO EN EL DECRETO LEGISLATIVO N° 1218', 1, '(texto: (ART: 11)** Articulo 11.- Articulacion estatal)**', '185917', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1499, 1499, 'SEGÚN EL ARTÍCULO 11, ¿BAJO QUÉ CIRCUNSTANCIA LAS ENTIDADES PÚBLICAS PUEDEN CELEBRAR CONVENIOS CON ENTIDADES PRIVADAS DENTRO DEL MARCO DE LA ATENCIÓN A PERSONAS DESAPARECIDAS EN SITUACIÓN DE VULNERABILIDAD?', '["PARA LA OBTENCIÓN DE FONDOS ECONÓMICOS PARA CAMPAÑAS DE BÚSQUEDA GENERAL","PARA ASEGURAR LA ESTADÍA TEMPORAL DE LAS PERSONAS UBICADAS EN SITUACIÓN DE VULNERABILIDAD","PARA LOS TRÁMITES ANTE EL MINISTERIO DE RELACIONES EXTERIORES DE PERSONAS EXTRANJERAS","PARA LA REALIZACIÓN DE PROCESOS JUDICIALES ABREVIADOS","PARA SERVICIOS MÉDICOS FORENSES ESPECIALIZADOS EXCLUSIVAMENTE A EXTRANJEROS"]'::jsonb, 'PARA ASEGURAR LA ESTADÍA TEMPORAL DE LAS PERSONAS UBICADAS EN SITUACIÓN DE VULNERABILIDAD', 1, '(texto: (ART: 11)** Articulo 11.- Articulacion estatal)**', '185918', '2026-07-14T01:12:29.113429+00:00');
INSERT INTO public.preguntas (id, numero, pregunta, opciones, respuesta_correcta, indice_correcto, ubicacion, codigo, created_at) VALUES (1500, 1500, 'EN RELACIÓN AL PRINCIPIO QUE RIGE LA EVALUACIÓN Y ACTIVACIÓN DE LA ALERTA AMBER, ¿CUÁL ES EL CRITERIO FUNDAMENTAL QUE DEBE SEGUIR LA DIVISIÓN DE INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DESAPARECIDAS?', '["PRINCIPIO DE PROPORCIONALIDAD","PRINCIPIO DE EFICIENCIA","PRINCIPIO DE LEGALIDAD","PRINCIPIO DE INMEDIATEZ","PRINCIPIO DE RESERVA"]'::jsonb, 'PRINCIPIO DE INMEDIATEZ', 3, '(texto: (ART: 12-A)** Articulo 12-A.- De la activacion de la Alerta Amber)**', '185921', '2026-07-14T01:12:29.113429+00:00');
